    /// Validate constraints for a batch before insertion
    pub fn validate_constraints(
        &self,
        database: &str,
        table: &str,
        batch: &arrow_array::RecordBatch,
    ) -> Result<crate::constraint_validator::ValidationResult, EngineError> {
        let validator = self.constraint_validator.as_ref().ok_or_else(|| {
            EngineError::Configuration("Constraint validation is disabled".to_string())
        })?;

        // Get table metadata
        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
        };

        let table_meta = table_meta.ok_or_else(|| {
            EngineError::NotFound(format!("Table {}.{} not found", database, table))
        })?;

        // For now, we don't have an existing data provider integrated
        // In a full implementation, we'd pass a provider that can check existing data
        validator.validate_constraints(&table_meta, batch, None)
    }

    // --- Backup and Point-in-Time Recovery (PITR) Methods ---

    /// Get or create the recovery manager
    fn get_or_create_recovery_manager(
        &self,
    ) -> Result<std::sync::Arc<crate::pitr::RecoveryManager>, EngineError> {
        // Fast path: check if already initialized
        {
            let guard = self.recovery_manager.read();
            if let Some(ref mgr) = *guard {
                return Ok(mgr.clone());
            }
        }

        // Slow path: create new recovery manager
        let mut guard = self.recovery_manager.write();
        // Double-check after acquiring write lock
        if let Some(ref mgr) = *guard {
            return Ok(mgr.clone());
        }

        // Create recovery manager with default paths based on data_dir
        let config = crate::pitr::RecoveryConfig {
            backup_path: self.cfg.data_dir.join("backups"),
            wal_archive_path: self.cfg.data_dir.join("wal_archive"),
            recovery_path: self.cfg.data_dir.join("recovery"),
            verify_checksums: true,
            apply_all_wal: true,
            target_timestamp: None,
            target_lsn: None,
            target_name: None,
            standby_mode: false,
            parallel_workers: 4,
        };

        let mgr = std::sync::Arc::new(crate::pitr::RecoveryManager::new(config)?);
        *guard = Some(mgr.clone());
        Ok(mgr)
    }

    /// Create a backup of the database
    ///
    /// # Arguments
    /// * `label` - Optional user-provided label for the backup
    ///
    /// # Returns
    /// BackupInfo containing details about the created backup
    pub fn create_backup(
        &self,
        label: Option<String>,
    ) -> Result<crate::pitr::BackupInfo, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;

        // Get current LSN from WAL
        let current_lsn = self
            .wal
            .lock()
            .map(|wal| Some(wal.current_lsn()))
            .unwrap_or(None);

        recovery_mgr.create_backup(&self.cfg.data_dir, label, current_lsn)
    }

    /// List all available backups
    pub fn list_backups(&self) -> Result<Vec<crate::pitr::BackupInfo>, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;
        Ok(recovery_mgr.list_backups())
    }

    /// Delete a specific backup
    pub fn delete_backup(&self, backup_id: &str) -> Result<(), EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;
        recovery_mgr.delete_backup(backup_id)
    }

    /// Get WAL archiving status
    pub fn get_wal_status(&self) -> Result<crate::pitr::WalStatus, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;
        recovery_mgr.wal_status()
    }

    /// Recover to a specific timestamp (Point-in-Time Recovery)
    ///
    /// # Arguments
    /// * `timestamp` - Target timestamp in ISO 8601 format or microseconds since epoch
    ///
    /// # Returns
    /// RecoveryResult with details about the recovery operation
    pub fn recover_to_timestamp(
        &self,
        timestamp: &str,
    ) -> Result<crate::pitr::RecoveryResult, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;

        // Parse timestamp - try ISO 8601 first, then microseconds
        let target_micros = if let Ok(micros) = timestamp.parse::<u64>() {
            micros
        } else {
            // Try parsing ISO 8601 format
            chrono::DateTime::parse_from_rfc3339(timestamp)
                .or_else(|_| chrono::DateTime::parse_from_str(timestamp, "%Y-%m-%d %H:%M:%S"))
                .map_err(|e| {
                    EngineError::InvalidArgument(format!(
                        "Invalid timestamp format '{}': {}",
                        timestamp, e
                    ))
                })?
                .timestamp_micros() as u64
        };

        recovery_mgr.recover_to_time(target_micros)
    }

    /// Recover to a specific LSN (Log Sequence Number)
    ///
    /// # Arguments
    /// * `lsn` - Target LSN to recover to
    ///
    /// # Returns
    /// RecoveryResult with details about the recovery operation
    pub fn recover_to_lsn(&self, lsn: u64) -> Result<crate::pitr::RecoveryResult, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;
        recovery_mgr.recover_to_lsn(lsn)
    }

    /// Recover to the latest available state
    pub fn recover_latest(&self) -> Result<crate::pitr::RecoveryResult, EngineError> {
        let recovery_mgr = self.get_or_create_recovery_manager()?;
        recovery_mgr.recover_latest()
    }

    pub fn ingest_ipc(&self, batch: IngestBatch) -> Result<(), EngineError> {
        self.require_writable()?;

        let current_segments = self.segment_count();

        // Check hard segment limit - reject writes if exceeded
        if self.is_segment_limit_exceeded() {
            // Try emergency compaction before rejecting
            if self.cfg.emergency_compaction_bypass_cooldown {
                let _ = self.run_emergency_compaction();
            }

            // Check again after emergency compaction
            if self.is_segment_limit_exceeded() {
                self.metrics.ingests_errors.fetch_add(1, Ordering::Relaxed);
                return Err(EngineError::Backpressure(format!(
                    "segment limit exceeded ({} >= {}), run compaction or increase max_segments_hard_limit",
                    current_segments,
                    self.cfg.max_segments_hard_limit
                )));
            }
        }

        // Trigger emergency compaction when approaching limit (at 80%)
        if self.cfg.max_segments_emergency_threshold > 0
            && current_segments >= (self.cfg.max_segments_emergency_threshold * 80 / 100)
        {
            // Run compaction in background, don't block ingest
            self.compaction_state.notify_work_available();
        }

        // Apply adaptive backpressure delay if enabled
        let delay_ms = self.calculate_backpressure_delay();
        if delay_ms > 0 {
            tracing::debug!(delay_ms = delay_ms, segments = current_segments, "Applying adaptive backpressure");
            std::thread::sleep(std::time::Duration::from_millis(delay_ms));
        }

        let payload_len = batch.payload_ipc.len() as u64;

        // Write buffering: if enabled and payload is small, buffer it
        // Flush when buffer exceeds threshold or time expires
        if self.cfg.write_buffer_enabled && payload_len < self.cfg.min_segment_bytes {
            let db_name = batch.database.as_deref().filter(|s| !s.is_empty()).unwrap_or("default");
            let table_name = batch.table.as_deref().filter(|s| !s.is_empty()).unwrap_or("default");

            let should_flush = {
                let mut buffer = self.write_buffer.lock();
                buffer.add(
                    db_name,
                    table_name,
                    batch.payload_ipc.clone(),
                    batch.shard_override.unwrap_or(0) as u16,
                    batch.watermark_micros,
                    None, // Schema will be inferred when flushing
                );
                buffer.should_flush(self.cfg.write_buffer_max_bytes)
            };

            if should_flush {
                self.flush_write_buffer()?;
            }

            self.metrics.ingests_total.fetch_add(1, Ordering::Relaxed);
            self.metrics.ingests_bytes.fetch_add(payload_len, Ordering::Relaxed);
            return Ok(());
        }
        if batch.payload_ipc.is_empty() {
            self.metrics.ingests_errors.fetch_add(1, Ordering::Relaxed);
            return Err(EngineError::InvalidArgument(
                "empty ingest payload".to_string(),
            ));
        }

        // Pre-flight disk space check (estimate: payload + overhead for manifest/WAL)
        let estimated_bytes = payload_len + 4096; // payload + 4KB overhead
        self.check_disk_space(estimated_bytes)?;

        let db_name = batch
            .database
            .as_deref()
            .filter(|s| !s.is_empty())
            .unwrap_or("default");
        let table_name = batch
            .table
            .as_deref()
            .filter(|s| !s.is_empty())
            .unwrap_or("default");

        // Validate identifiers to prevent path traversal and injection
        validate_identifier(db_name, "database")?;
        validate_identifier(table_name, "table")?;

        // Lookup existing schema for enforcement (if any).
        let existing_table = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .tables
                .iter()
                .find(|t| t.database == db_name && t.name == table_name)
                .cloned()
        };

        // Validate IPC payload decodes and collect simple stats (min/max) for pruning.
        let validated = validate_and_stats(&batch.payload_ipc, existing_table.as_ref())?;

        // Validate constraints (NOT NULL, PRIMARY KEY, UNIQUE, CHECK, FOREIGN KEY)
        if let Some(ref table_meta) = existing_table {
            if !table_meta.constraints.is_empty() {
                if let Some(ref validator) = self.constraint_validator {
                    // Decode batch for constraint validation
                    let batches = read_ipc_batches(&batch.payload_ipc)?;
                    for batch in &batches {
                        // Create a data provider for existing data lookups (for UNIQUE, FK validation)
                        let data_provider = EngineDataProvider {
                            engine: self,
                            database: db_name.to_string(),
                        };
                        let result = validator.validate_constraints(
                            table_meta,
                            batch,
                            Some(&data_provider),
                        )?;
                        if !result.valid {
                            let violation_msgs: Vec<String> = result
                                .violations
                                .iter()
                                .map(|v| format!("{}: {}", v.constraint_type, v.message))
                                .collect();
                            return Err(EngineError::ConstraintViolation(
                                violation_msgs.join("; "),
                            ));
                        }
                    }
                }
            }
        }

        // Apply on-ingest deduplication if configured
        let deduped_payload = if let Some(ref dedup_config) = existing_table
            .as_ref()
            .and_then(|t| t.deduplication.clone())
        {
            use crate::sql::DeduplicationMode;
            match dedup_config.mode {
                DeduplicationMode::OnIngest | DeduplicationMode::Both => {
                    // Deduplicate within this batch
                    let batches = read_ipc_batches(&batch.payload_ipc)?;
                    if batches.is_empty() {
                        batch.payload_ipc.clone()
                    } else {
                        let schema = batches[0].schema();
                        let merged = if batches.len() == 1 {
                            batches.into_iter().next().unwrap()
                        } else {
                            arrow_select::concat::concat_batches(&schema, &batches).map_err(
                                |e| EngineError::Internal(format!("concat batches for dedup: {e}")),
                            )?
                        };
                        let deduped = self.deduplicate_batch(
                            &merged,
                            &dedup_config.key_columns,
                            dedup_config.version_column.as_deref(),
                        )?;
                        tracing::debug!(
                            "On-ingest deduplication: {} -> {} rows",
                            merged.num_rows(),
                            deduped.num_rows()
                        );
                        record_batches_to_ipc(schema.as_ref(), &[deduped])?
                    }
                }
                DeduplicationMode::OnCompaction => batch.payload_ipc.clone(),
            }
        } else {
            batch.payload_ipc.clone()
        };

        // Sort hot payload for faster reads (stable by event_time/tenant/route when present)
        let sorted_payload = sort_hot_payload(&deduped_payload, self.cfg.index_granularity_rows)?;

        // Re-validate stats after deduplication/sort (stats may have changed)
        let validated = if sorted_payload != batch.payload_ipc {
            validate_and_stats(&sorted_payload, existing_table.as_ref())?
        } else {
            validated
        };

        // Get row count for auto-stats tracking before moving stats
        let ingested_row_count = validated
            .stats
            .column_stats
            .values()
            .next()
            .map(|cs| cs.row_count)
            .unwrap_or(0);

        let stats = validated.stats;
        let schema_json = serde_json::to_string(&validated.schema_spec)
            .map_err(|e| EngineError::Internal(format!("serialize schema spec failed: {e}")))?;
        // Use table-specific compression, or fall back to tier hot compression default
        let table_compression = normalize_compression(
            existing_table
                .as_ref()
                .and_then(|t| t.compression.clone())
                .or_else(|| self.cfg.tier_hot_compression.clone()),
        )?;
        let encodings = column_encodings_from_schema_json(
            existing_table.as_ref().and_then(|t| t.schema_json.as_ref()),
        )?;
        let encoded_payload = apply_column_encodings(&sorted_payload, &encodings)?;
        let stored_payload = compress_payload(&encoded_payload, table_compression.as_deref())?;
        let existing_schema = existing_table
            .as_ref()
            .and_then(|t| t.schema_json.as_ref())
            .map(|s| canonical_schema_from_json(s))
            .transpose()?;

        // Choose shard deterministically to avoid hot locks; prefer caller-provided shard override (e.g., tenant hash).
        // Choose shard deterministically using ShardMap
        let seq = self.segment_seq.fetch_add(1, Ordering::SeqCst);

        let global_shard_id = if let Some(hint) = batch.shard_override {
            // Hint provided (e.g. from upstream router or client explicit shard)
            // Existing logic was mix64(hint) % len. We should respect explicit override if it looks like a shard ID?
            // Or assume hint is a partition key?
            // Let's assume hint is a partition key (like tenant_id) to be consistent with get_shard_id.
            self.shard_map.read().unwrap().get_shard_id(hint)
        } else if let Some(tid) = stats.tenant_id_min {
            self.shard_map.read().unwrap().get_shard_id(tid)
        } else {
            // No partition key, round robin across global shards
            (seq % self.shard_map.read().unwrap().total_shards.max(1) as u64) as u16
        };

        // Map global shard to local concurrency lane (write lock)
        let local_shard_idx = (global_shard_id as usize) % self.shards.len();

        let shard = self
            .shards
            .get(local_shard_idx)
            .ok_or_else(|| EngineError::Internal("shard missing".into()))?;

        shard
            .ingest_bytes
            .fetch_add(batch.payload_ipc.len() as u64, Ordering::SeqCst);
        shard
            .last_watermark_micros
            .store(batch.watermark_micros, Ordering::SeqCst);

        let segment_id = format!("seg-{global_shard_id}-{seq}");
        let manifest_entry = ManifestEntry {
            segment_id,
            shard_id: global_shard_id,
            version_added: 0, // will be updated below when manifest version advances
            size_bytes: stored_payload.len() as u64,
            checksum: compute_checksum(&stored_payload),
            tier: SegmentTier::Hot,
            database: db_name.to_string(),
            table: table_name.to_string(),
            compression: table_compression.clone(),
            watermark_micros: batch.watermark_micros,
            event_time_min: stats.event_time_min,
            event_time_max: stats.event_time_max,
            tenant_id_min: stats.tenant_id_min,
            tenant_id_max: stats.tenant_id_max,
            route_id_min: stats.route_id_min,
            route_id_max: stats.route_id_max,
            bloom_tenant: stats.bloom_tenant,
            bloom_route: stats.bloom_route,
            column_stats: if stats.column_stats.is_empty() {
                None
            } else {
                Some(stats.column_stats)
            },
            schema_hash: Some(validated.schema_hash),
            // MVCC fields - default to None for non-transactional writes
            created_txn: None,
            deleted_txn: None,
            deleted_version: None,
        };
        let use_memtable = self.cfg.memtable_max_bytes > 0 && self.cfg.memtable_max_entries > 0;
        if !use_memtable {
            persist_segment_ipc(&self.storage, &manifest_entry.segment_id, &stored_payload)?;
        }

        let (entry, _current_version, should_persist) = {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            if !manifest.databases.iter().any(|d| d.name == db_name) {
                manifest.databases.push(crate::replication::DatabaseMeta {
                    name: db_name.into(),
                });
            }
            let existing_table = manifest
                .tables
                .iter_mut()
                .find(|t| t.database == db_name && t.name == table_name);
            match existing_table {
                Some(tbl) => {
                    if let Some(existing_schema) = existing_schema.as_ref() {
                        // Compare schemas by comparing field count and names instead of hash
                        // This is more robust against serialization order differences
                        let schemas_compatible = schemas_are_compatible(
                            &existing_schema.json,
                            validated.schema_spec.as_deref().unwrap_or("[]"),
                        );
                        if !schemas_compatible
                            && existing_schema.hash != 0
                            && validated.schema_hash != 0
                        {
                            // Only fail if both hashes are non-zero and schemas don't match
                            if existing_schema.hash != validated.schema_hash {
                                return Err(EngineError::InvalidArgument(
                                    "schema mismatch for existing table".into(),
                                ));
                            }
                        }
                        if tbl.schema_json.as_deref() != Some(existing_schema.json.as_str()) {
                            tbl.schema_json = Some(existing_schema.json.clone());
                        }
                    } else {
                        tbl.schema_json = Some(schema_json.clone());
                    }

                    if tbl.compression.is_none() {
                        tbl.compression = table_compression.clone();
                    }
                }
                None => {
                    manifest.tables.push(crate::replication::TableMeta {
                        database: db_name.into(),
                        name: table_name.into(),
                        schema_json: Some(schema_json.clone()),
                        compression: table_compression.clone(),
                        deduplication: None,
                        constraints: Vec::new(),
                        retention_policy: None,
                        partition_config: None,
                    });
                }
            }
            manifest.bump_version();
            let mut entry = manifest_entry.clone();
            entry.version_added = manifest.version;
            let entry_index = manifest.entries.len();
            manifest.entries.push(entry.clone());
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                index.add_entry(entry_index, &entry);
            }
            let current_version = manifest.version;
            let last_persisted = self.last_persisted_version.load(Ordering::Acquire);
            let should_persist = current_version >= last_persisted + 10;

            (entry, current_version, should_persist)
        };

        // CRITICAL: WAL must be synced BEFORE manifest is persisted.
        // This ensures we can always recover from WAL if crash occurs after manifest update.
        // Order: segment file -> WAL sync -> manifest persist
        //
        // With group commit enabled, multiple writes are batched together for a single fsync.
        // This dramatically improves throughput for workloads with many small writes.
        {
            let mut wal = self
                .wal
                .lock()
                .map_err(|_| EngineError::Internal("wal lock poisoned".into()))?;

            // Use group commit if enabled, otherwise direct write
            let _group_seq = wal.append_segment_grouped(&entry, &stored_payload)?;

            // Force sync WAL before manifest persist to ensure crash consistency
            if should_persist {
                // Flush all pending group commit writes
                wal.flush_group_commit()?;
                wal.flush_sync()?;
            } else if self.cfg.group_commit_enabled {
                // With group commit, batch writes and flush when thresholds are met
                wal.maybe_flush_group_commit()?;
            } else {
                wal.maybe_sync(self.cfg.wal_sync_bytes, self.cfg.wal_sync_interval_ms)?;
            }
            wal.maybe_rotate(self.cfg.wal_max_bytes)?;
        }

        // Now safe to persist manifest - WAL has the data for recovery
        if should_persist {
            self.maybe_persist_manifest()?;
        }

        if use_memtable {
            self.buffer_memtable_entry(
                db_name,
                table_name,
                shard.id,
                MemtableEntry {
                    entry: entry.clone(),
                    payload: stored_payload.clone(),
                },
            )?;
        }

        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(&entry.database, &entry.table);
        }
        self.spawn_background_index_build_for_segment(
            &entry.database,
            &entry.table,
            &entry.segment_id,
        );
        // Update metrics
        self.metrics.ingests_total.fetch_add(1, Ordering::Relaxed);
        self.metrics
            .ingests_bytes
            .fetch_add(payload_len, Ordering::Relaxed);

        // Track rows for auto-stats (use pre-computed row count)
        self.track_rows_and_maybe_update_stats(
            db_name,
            table_name,
            if ingested_row_count > 0 {
                ingested_row_count
            } else {
                payload_len / 100 // Estimate ~100 bytes per row if no stats
            },
        );

        // Notify compaction threads that new work may be available (event-driven compaction)
        self.compaction_state.notify_work_available();

        // Aggressive segment elimination: sync compact if segment count is high
        if self.cfg.sync_compact_threshold > 0 {
            let segment_count = self.get_table_segment_count(db_name, table_name);
            if segment_count > self.cfg.sync_compact_threshold {
                // Run one compaction pass synchronously to help reduce segment count
                let _ = self.run_table_compaction_pass(db_name, table_name);
            }
        }

        Ok(())
    }

    /// Get segment count for a specific table
    fn get_table_segment_count(&self, database: &str, table: &str) -> usize {
        if let Ok(index) = self.manifest_index.read() {
            index.get_table_entries(database, table)
                .map(|entries| entries.len())
                .unwrap_or(0)
        } else {
            0
        }
    }

    /// Run a single compaction pass for a specific table
    fn run_table_compaction_pass(&self, database: &str, table: &str) -> Result<usize, EngineError> {
        let filter = Some((database.to_string(), table.to_string()));
        let candidate = self.pick_compaction_candidate(
            self.cfg.compaction_target_bytes,
            self.cfg.compact_min_segments,
            filter,
        )?;

        if let Some((entries, table_meta)) = candidate {
            let count = entries.len();
            self.compact_entries(entries, table_meta)?;
            Ok(count)
        } else {
            Ok(0)
        }
    }

    /// Direct ingest bypassing write buffer (used when flushing buffer)
    fn ingest_ipc_direct(&self, batch: IngestBatch) -> Result<(), EngineError> {
        // Save original config and temporarily disable buffering
        let was_buffering = self.cfg.write_buffer_enabled;
        // We can't modify cfg, so we just proceed with normal ingest
        // The check at the start of ingest_ipc will skip buffering for large payloads
        // Since flushed payloads are combined to be large, they won't re-buffer

        // Call the regular ingest - the combined payload will be >= min_segment_bytes
        // so it won't be buffered again
        self.ingest_ipc(batch)
    }

    /// Ingest multiple batches in a single call (optimized for frequent small updates)
    ///
    /// This is more efficient than calling `ingest_ipc` multiple times because:
    /// 1. Single manifest lock acquisition for all batches
    /// 2. Single WAL fsync for all batches (with group commit)
    /// 3. Reduced per-call overhead
    ///
    /// Returns the number of successfully ingested batches.
    /// If any batch fails validation, all batches are rejected (atomic).
    pub fn ingest_ipc_batch(&self, batches: Vec<IngestBatch>) -> Result<usize, EngineError> {
        self.require_writable()?;

        // Check hard segment limit - reject writes if exceeded
        if self.is_segment_limit_exceeded() {
            self.metrics.ingests_errors.fetch_add(1, Ordering::Relaxed);
            return Err(EngineError::Backpressure(format!(
                "segment limit exceeded ({} >= {}), run compaction or increase max_segments_hard_limit",
                self.segment_count(),
                self.cfg.max_segments_hard_limit
            )));
        }

        // Apply adaptive backpressure delay if enabled
        let delay_ms = self.calculate_backpressure_delay();
        if delay_ms > 0 {
            tracing::debug!(delay_ms = delay_ms, segments = self.segment_count(), "Applying adaptive backpressure");
            std::thread::sleep(std::time::Duration::from_millis(delay_ms));
        }

        if batches.is_empty() {
            return Ok(0);
        }

        // Pre-flight disk space check for all batches
        let total_bytes: u64 = batches.iter().map(|b| b.payload_ipc.len() as u64).sum();
        self.check_disk_space(total_bytes + 4096 * batches.len() as u64)?;

        // Collect validated entries and payloads
        let mut validated_entries: Vec<(
            ManifestEntry,
            Vec<u8>,  // stored_payload
            String,   // db_name
            String,   // table_name
            u16,      // shard_id
            u64,      // row_count
        )> = Vec::with_capacity(batches.len());

        // Phase 1: Validate all batches (no locks held yet)
        for batch in &batches {
            if batch.payload_ipc.is_empty() {
                return Err(EngineError::InvalidArgument(
                    "empty ingest payload in batch".to_string(),
                ));
            }

            let db_name = batch
                .database
                .as_deref()
                .filter(|s| !s.is_empty())
                .unwrap_or("default");
            let table_name = batch
                .table
                .as_deref()
                .filter(|s| !s.is_empty())
                .unwrap_or("default");

            validate_identifier(db_name, "database")?;
            validate_identifier(table_name, "table")?;

            // Look up existing schema
            let existing_table = {
                let manifest = self
                    .manifest
                    .read()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest
                    .tables
                    .iter()
                    .find(|t| t.database == db_name && t.name == table_name)
                    .cloned()
            };

            // Validate and get stats
            let validated = validate_and_stats(&batch.payload_ipc, existing_table.as_ref())?;
            let stats = validated.stats;

            // Get row count
            let row_count = stats
                .column_stats
                .values()
                .next()
                .map(|cs| cs.row_count)
                .unwrap_or(0);

            // Compression and encoding with adaptive optimization
            let table_compression = normalize_compression(
                existing_table
                    .as_ref()
                    .and_then(|t| t.compression.clone())
                    .or_else(|| self.cfg.tier_hot_compression.clone()),
            )?;
            let stored_payload = compress_payload_adaptive(
                &batch.payload_ipc,
                table_compression.as_deref(),
                self.cfg.compression_skip_threshold_bytes,
                self.cfg.adaptive_compression_levels,
            )?;

            // Choose shard
            let seq = self.segment_seq.fetch_add(1, Ordering::SeqCst);
            let global_shard_id = if let Some(hint) = batch.shard_override {
                self.shard_map.read().unwrap().get_shard_id(hint)
            } else if let Some(tid) = stats.tenant_id_min {
                self.shard_map.read().unwrap().get_shard_id(tid)
            } else {
                (seq % self.shard_map.read().unwrap().total_shards.max(1) as u64) as u16
            };

            let segment_id = format!("seg-{global_shard_id}-{seq}");
            let manifest_entry = ManifestEntry {
                segment_id,
                shard_id: global_shard_id,
                version_added: 0,
                size_bytes: stored_payload.len() as u64,
                checksum: compute_checksum(&stored_payload),
                tier: SegmentTier::Hot,
                database: db_name.to_string(),
                table: table_name.to_string(),
                compression: table_compression.clone(),
                watermark_micros: batch.watermark_micros,
                event_time_min: stats.event_time_min,
                event_time_max: stats.event_time_max,
                tenant_id_min: stats.tenant_id_min,
                tenant_id_max: stats.tenant_id_max,
                route_id_min: stats.route_id_min,
                route_id_max: stats.route_id_max,
                bloom_tenant: stats.bloom_tenant,
                bloom_route: stats.bloom_route,
                column_stats: if stats.column_stats.is_empty() {
                    None
                } else {
                    Some(stats.column_stats)
                },
                schema_hash: Some(validated.schema_hash),
                created_txn: None,
                deleted_txn: None,
                deleted_version: None,
            };

            validated_entries.push((
                manifest_entry,
                stored_payload,
                db_name.to_string(),
                table_name.to_string(),
                global_shard_id,
                row_count,
            ));
        }

        let count = validated_entries.len();
        let use_memtable = self.cfg.memtable_max_bytes > 0 && self.cfg.memtable_max_entries > 0;

        // Phase 2: Persist segments (if not using memtable)
        if !use_memtable {
            for (entry, payload, _, _, _, _) in &validated_entries {
                persist_segment_ipc(&self.storage, &entry.segment_id, payload)?;
            }
        }

        // Phase 3: Update manifest (single lock acquisition for all entries)
        let entries_for_wal: Vec<(ManifestEntry, Vec<u8>)>;
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            entries_for_wal = validated_entries
                .iter()
                .map(|(entry, payload, db_name, table_name, _, _)| {
                    // Ensure database exists
                    if !manifest.databases.iter().any(|d| d.name == db_name.as_str()) {
                        manifest.databases.push(crate::replication::DatabaseMeta {
                            name: db_name.clone(),
                        });
                    }

                    // Ensure table exists
                    if !manifest.tables.iter().any(|t| {
                        t.database == db_name.as_str() && t.name == table_name.as_str()
                    }) {
                        manifest.tables.push(crate::replication::TableMeta {
                            database: db_name.clone(),
                            name: table_name.clone(),
                            schema_json: None,
                            compression: None,
                            deduplication: None,
                            constraints: Vec::new(),
                            retention_policy: None,
                            partition_config: None,
                        });
                    }

                    manifest.bump_version();
                    let mut entry = entry.clone();
                    entry.version_added = manifest.version;
                    let entry_index = manifest.entries.len();
                    manifest.entries.push(entry.clone());

                    // Update index
                    let mut index = self.manifest_index.write().unwrap();
                    index.add_entry(entry_index, &entry);

                    (entry, payload.clone())
                })
                .collect();
        }

        // Phase 4: WAL writes (single fsync for all entries with group commit)
        {
            let mut wal = self
                .wal
                .lock()
                .map_err(|_| EngineError::Internal("wal lock poisoned".into()))?;

            // Write all entries to WAL
            for (entry, payload) in &entries_for_wal {
                wal.append_segment_grouped(entry, payload)?;
            }

            // Single flush for all writes
            if self.cfg.group_commit_enabled {
                wal.flush_group_commit()?;
            }
            wal.flush_sync()?;
            wal.maybe_rotate(self.cfg.wal_max_bytes)?;
        }

        // Phase 5: Buffer in memtable if enabled
        if use_memtable {
            for (entry, payload, db_name, table_name, shard_id, _) in &validated_entries {
                let local_shard_idx = (*shard_id as usize) % self.shards.len();
                let shard = self.shards.get(local_shard_idx).unwrap();
                self.buffer_memtable_entry(
                    db_name,
                    table_name,
                    shard.id,
                    MemtableEntry {
                        entry: entry.clone(),
                        payload: payload.clone(),
                    },
                )?;
            }
        }

        // Phase 6: Invalidate caches and update metrics
        {
            let mut cache = self.query_cache.lock();
            for (entry, _, _, _, _, _) in &validated_entries {
                cache.invalidate_table(&entry.database, &entry.table);
            }
        }

        let total_bytes: u64 = validated_entries.iter().map(|(e, _, _, _, _, _)| e.size_bytes).sum();
        self.metrics.ingests_total.fetch_add(count as u64, Ordering::Relaxed);
        self.metrics.ingests_bytes.fetch_add(total_bytes, Ordering::Relaxed);

        // Track rows for auto-stats
        for (_, _, db_name, table_name, _, row_count) in validated_entries {
            self.track_rows_and_maybe_update_stats(&db_name, &table_name, row_count);
        }

        // Notify compaction threads that new work may be available (event-driven compaction)
        self.compaction_state.notify_work_available();

        Ok(count)
    }

    /// Ingest data within a transaction context
    /// The transaction must be active and will acquire necessary locks
    pub fn ingest_ipc_txn(
        &self,
        batch: IngestBatch,
        txn_id: Option<crate::transaction::TransactionId>,
    ) -> Result<(), EngineError> {
        self.require_writable()?;

        // Check hard segment limit - reject writes if exceeded
        if self.is_segment_limit_exceeded() {
            return Err(EngineError::Backpressure(format!(
                "segment limit exceeded ({} >= {}), run compaction or increase max_segments_hard_limit",
                self.segment_count(),
                self.cfg.max_segments_hard_limit
            )));
        }

        // Apply adaptive backpressure delay if enabled
        let delay_ms = self.calculate_backpressure_delay();
        if delay_ms > 0 {
            std::thread::sleep(std::time::Duration::from_millis(delay_ms));
        }

        let db_name = batch.database.as_deref().unwrap_or("default");
        let table_name = batch.table.as_deref().unwrap_or("default");

        // If transaction is provided, validate and acquire locks
        if let Some(tid) = txn_id {
            if let Some(ref txn_mgr) = self.transaction_manager {
                // Verify transaction is active
                let txn = txn_mgr.get_transaction(tid).ok_or_else(|| {
                    EngineError::InvalidArgument(format!("Transaction {} not found", tid))
                })?;
                if !txn.state.is_active() {
                    return Err(EngineError::InvalidArgument(format!(
                        "Transaction {} is not active (state: {:?})",
                        tid, txn.state
                    )));
                }

                // Acquire exclusive lock on the table
                txn_mgr.acquire_lock(
                    tid,
                    db_name,
                    table_name,
                    None,
                    crate::lock_manager::LockMode::Exclusive,
                )?;
            }
        }

        // Perform the actual ingest
        self.ingest_ipc(batch)
    }

    fn buffer_memtable_entry(
        &self,
        database: &str,
        table: &str,
        shard_id: u16,
        entry: MemtableEntry,
    ) -> Result<(), EngineError> {
        let key = MemtableKey {
            database: database.to_string(),
            table: table.to_string(),
            shard_id,
        };
        let mut entries_to_flush = Vec::new();
        {
            // Use sharded lock to reduce contention during concurrent inserts
            let mut memtable_shard = self.memtables.lock_shard(&key);
            let memtable = memtable_shard.entry(key.clone()).or_insert(Memtable {
                entries: Vec::new(),
                bytes: 0,
            });
            memtable.bytes = memtable.bytes.saturating_add(entry.payload.len() as u64);
            memtable.entries.push(MemtableEntry {
                entry: entry.entry.clone(),
                payload: entry.payload.clone(),
            });
            let should_flush = memtable.bytes >= self.cfg.memtable_max_bytes
                || memtable.entries.len() >= self.cfg.memtable_max_entries;
            if should_flush {
                entries_to_flush = memtable.entries.drain(..).collect();
                memtable.bytes = 0;
            }
        }
        {
            let mut index = self.memtable_index.lock();
            index.insert(entry.entry.segment_id.clone(), entry);
        }
        if !entries_to_flush.is_empty() {
            self.flush_memtable_entries(entries_to_flush)?;
        }
        Ok(())
    }

    fn flush_memtable_entries(&self, entries: Vec<MemtableEntry>) -> Result<(), EngineError> {
        if entries.is_empty() {
            return Ok(());
        }
        {
            let mut index = self.memtable_index.lock();
            for mem_entry in &entries {
                index.remove(&mem_entry.entry.segment_id);
            }
        }
        // Persist segment files first so manifest never points to missing data.
        for mem_entry in &entries {
            persist_segment_ipc(
                &self.storage,
                &mem_entry.entry.segment_id,
                &mem_entry.payload,
            )?;
        }
        Ok(())
    }

    fn flush_all_memtables(&self) -> Result<(), EngineError> {
        let mut all_entries = Vec::new();
        // Iterate over all shards and collect entries to flush
        for mut shard in self.memtables.iter_all_shards() {
            for (_, memtable) in shard.iter_mut() {
                all_entries.extend(memtable.entries.drain(..));
                memtable.bytes = 0;
            }
        }
        if !all_entries.is_empty() {
            self.flush_memtable_entries(all_entries)?;
        }
        Ok(())
    }

    fn append_manifest_entries(
        &self,
        mut entries: Vec<ManifestEntry>,
    ) -> Result<usize, EngineError> {
        if entries.is_empty() {
            return Ok(0);
        }

        // Phase 1: Quick manifest update (short write lock duration)
        // Collect entries to add and their indices for index update
        let (entries_to_index, should_persist) = {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            let mut entries_to_index: Vec<(usize, ManifestEntry)> = Vec::new();

            for entry in &mut entries {
                if manifest
                    .entries
                    .iter()
                    .any(|existing| existing.segment_id == entry.segment_id)
                {
                    continue;
                }
                manifest.bump_version();
                entry.version_added = manifest.version;
                let entry_index = manifest.entries.len();
                manifest.entries.push(entry.clone());
                entries_to_index.push((entry_index, entry.clone()));
            }

            let current_version = manifest.version;
            let last_persisted = self.last_persisted_version.load(Ordering::Acquire);
            let should_persist = current_version >= last_persisted + 10;
            (entries_to_index, should_persist)
            // Manifest write lock released here
        };

        let added = entries_to_index.len();

        // Phase 2: Index update (can overlap with reads, shorter critical section)
        if !entries_to_index.is_empty() {
            let mut index = self.manifest_index.write().map_err(|_| {
                EngineError::Internal("manifest index lock poisoned".into())
            })?;
            for (entry_index, entry) in &entries_to_index {
                index.add_entry(*entry_index, entry);
            }
        }

        if should_persist {
            self.maybe_persist_manifest()?;
        }
        Ok(added)
    }

    fn maybe_persist_manifest(&self) -> Result<(), EngineError> {
        if let Ok(_guard) = self.manifest_persist_lock.try_lock() {
            let last_persisted = self.last_persisted_version.load(Ordering::Acquire);
            let current_version = {
                let manifest = self
                    .manifest
                    .read()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest.version
            };
            if current_version > last_persisted {
                // CRITICAL: Flush all memtables BEFORE persisting manifest.
                // This ensures segment files exist on disk before manifest references them.
                // Without this, a crash after manifest persist but before memtable flush
                // would result in missing segments (manifest has entries, files don't exist).
                self.flush_all_memtables()?;

                let manifest_snapshot = {
                    let manifest = self
                        .manifest
                        .read()
                        .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                    manifest.clone()
                };
                persist_manifest(&self.cfg.manifest_path, &manifest_snapshot)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
                self.last_persisted_version
                    .store(current_version, Ordering::Release);
            }
        }
        Ok(())
    }

    /// Force persist manifest to disk. Call this on shutdown to ensure all entries are saved.
    pub fn flush_manifest(&self) -> Result<(), EngineError> {
        self.flush_all_memtables()?;
        let _guard = self
            .manifest_persist_lock
            .lock()
            .map_err(|_| EngineError::Internal("manifest persist lock poisoned".into()))?;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        self.last_persisted_version
            .store(manifest.version, Ordering::Release);
        Ok(())
    }

    pub fn checkpoint(&self) -> Result<(), EngineError> {
        self.require_writable()?;
        self.flush_manifest()?;
        let mut wal = self
            .wal
            .lock()
            .map_err(|_| EngineError::Internal("wal lock poisoned".into()))?;
        wal.checkpoint()
    }

    pub fn query(&self, request: QueryRequest) -> Result<QueryResponse, EngineError> {
        // Start timing for stats collection
        let query_start = std::time::Instant::now();
        let collect_stats = request.collect_stats;

        if request.sql.trim().is_empty() {
            self.metrics.queries_errors.fetch_add(1, Ordering::Relaxed);
            return Err(EngineError::InvalidArgument("empty SQL".into()));
        }
        let _read_guard = self.read_guard();

        // Get current manifest version for cache key validation
        let manifest_version = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest.version
        };

        // Check cache first (using SQL string directly, no clone needed)
        {
            let mut cache = self.query_cache.lock();
            if let Some(mut cached) = cache.get(&request.sql, manifest_version) {
                self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
                self.metrics.queries_cached.fetch_add(1, Ordering::Relaxed);
                self.metrics.cache_hits.fetch_add(1, Ordering::Relaxed);
                // Add cache hit stats if requested
                let latency_us = query_start.elapsed().as_micros() as u64;
                if collect_stats {
                    cached.execution_stats = Some(QueryExecutionStats {
                        cache_hit: true,
                        execution_time_micros: latency_us,
                        ..Default::default()
                    });
                }
                self.metrics.record_query_latency(latency_us);
                return Ok(cached);
            }
        }
        self.metrics.cache_misses.fetch_add(1, Ordering::Relaxed);

        // Check for information_schema queries (virtual tables)
        if let Some(response) = self.handle_information_schema_query(&request.sql)? {
            self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
            self.metrics.record_query_latency(query_start.elapsed().as_micros() as u64);
            return Ok(response);
        }

        // Calculate deadline for timeout enforcement
        let deadline = if request.timeout_millis > 0 {
            Some(
                std::time::Instant::now()
                    + std::time::Duration::from_millis(request.timeout_millis as u64),
            )
        } else {
            None
        };

        let plan = self.get_or_parse_plan(&request.sql)?;

        // Try distributed execution if clustered
        if self.cluster_manager.read().map_or(false, |g| g.is_some()) {
            if let Some((local, global)) = crate::planner_distributed::distribute_plan(&plan.kind) {
                use crate::executor_distributed::DistributedExecutor;
                let executor = DistributedExecutor::new();
                // TODO: Handle fallback or specific errors? For now propagate.
                // If executor returns valid result, return it.
                // If it returns error, we might want to fallback? But usually distributed failure is fatal.
                return executor.execute(self, global, local);
            }
        }

        let result = match plan.kind {
            PlanKind::Join => self.execute_join_query(&request, deadline, manifest_version),
            PlanKind::SetOperation => {
                self.execute_set_operation(&request, deadline, manifest_version)
            }
            PlanKind::Subquery => self.execute_subquery_query(&request, deadline, manifest_version),
            PlanKind::Cte => self.execute_cte_query(&request, deadline, manifest_version),
            PlanKind::Transaction(_) => {
                // Return empty response for transaction control stubs
                Ok(QueryResponse {
                    records_ipc: Vec::new(),
                    data_skipped_bytes: 0,
                    segments_scanned: 0,
                    execution_stats: None,
                })
            }
            PlanKind::Simple {
                agg,
                db,
                table,
                projection,
                filter,
                computed_columns,
            } => self.execute_simple_plan(
                agg,
                db,
                table,
                projection,
                filter,
                computed_columns,
                deadline,
                manifest_version,
                collect_stats,
                query_start,
                request.transaction_id,
            ),
        };

        // Record query latency for all execution paths
        self.metrics.record_query_latency(query_start.elapsed().as_micros() as u64);
        result
    }

    /// Execute a simple SELECT query and write IPC batches directly to the writer.
    /// Only supports non-aggregated queries without JOINs, ORDER BY, DISTINCT, OFFSET, or set ops.
    pub fn query_ipc_to_writer<W: Write>(
        &self,
        request: QueryRequest,
        writer: &mut W,
    ) -> Result<QueryResponse, EngineError> {
        let query_start = std::time::Instant::now();
        let collect_stats = request.collect_stats;

        if request.sql.trim().is_empty() {
            self.metrics.queries_errors.fetch_add(1, Ordering::Relaxed);
            return Err(EngineError::InvalidArgument("empty SQL".into()));
        }
        let _read_guard = self.read_guard();

        let deadline = if request.timeout_millis > 0 {
            Some(
                std::time::Instant::now()
                    + std::time::Duration::from_millis(request.timeout_millis as u64),
            )
        } else {
            None
        };

        let plan = self.get_or_parse_plan(&request.sql)?;
        let (agg, db, table, projection, filter) = match plan.kind {
            PlanKind::Join => {
                return Err(EngineError::NotImplemented(
                    "streaming does not support JOIN queries".into(),
                ))
            }
            PlanKind::SetOperation => {
                return Err(EngineError::NotImplemented(
                    "streaming does not support set operations".into(),
                ))
            }
            PlanKind::Subquery => {
                return Err(EngineError::NotImplemented(
                    "streaming does not support subqueries".into(),
                ))
            }
            PlanKind::Cte => {
                return Err(EngineError::NotImplemented(
                    "streaming does not support CTEs".into(),
                ))
            }
            PlanKind::Transaction(_) => {
                // Return empty result for transactions (auto-commit behavior)
                (None, None, None, None, QueryFilter::default())
            }
            PlanKind::Simple {
                agg,
                db,
                table,
                projection,
                filter,
                computed_columns: _,
            } => (agg, db, table, projection, filter),
        };

        if agg.is_some() {
            return Err(EngineError::NotImplemented(
                "streaming does not support aggregation queries".into(),
            ));
        }
        if filter.order_by.is_some() || filter.distinct {
            return Err(EngineError::NotImplemented(
                "streaming does not support ORDER BY or DISTINCT".into(),
            ));
        }

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let expected_schema: Option<Vec<TableFieldSpec>> = manifest
            .tables
            .iter()
            .find(|t| {
                t.database == db.as_deref().unwrap_or("default")
                    && t.name == table.as_deref().unwrap_or("unknown")
            })
            .and_then(|t| {
                t.schema_json
                    .as_ref()
                    .and_then(|s| serde_json::from_str::<Vec<TableFieldSpec>>(s).ok())
            });
        let schema_map = self
            .table_schema_map(
                db.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown"),
            )
            .unwrap_or_default();
        // Use references to avoid cloning IndexMeta (manifest lock is held)
        let index_list: Vec<&IndexMeta> = manifest
            .indexes
            .iter()
            .filter(|idx| {
                idx.database == db.as_deref().unwrap_or("default")
                    && idx.table == table.as_deref().unwrap_or("unknown")
                    && idx.state == IndexState::Ready
            })
            .collect();

        let manifest_index = self
            .manifest_index
            .read()
            .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;

        let table_indices = manifest_index.get_table_entries(
            db.as_deref().unwrap_or("default"),
            table.as_deref().unwrap_or("unknown"),
        );
        if table_indices.is_none() {
            return Err(EngineError::NotFound(format!(
                "no segments for {}.{}",
                db.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown")
            )));
        }
        let table_indices = table_indices.unwrap();
        let total_segments = table_indices.len();

        let mut matching = Vec::with_capacity(table_indices.len());
        for &idx in table_indices {
            let e = &manifest.entries[idx];

            if let Some(ge) = filter.watermark_ge {
                if e.watermark_micros < ge {
                    continue;
                }
            }
            if let Some(le) = filter.watermark_le {
                if e.watermark_micros > le {
                    continue;
                }
            }

            if filter.event_time_ge.is_some() || filter.event_time_le.is_some() {
                let min = e.event_time_min.unwrap_or(0);
                let max = e.event_time_max.unwrap_or(u64::MAX);
                if let Some(ge) = filter.event_time_ge {
                    if max < ge {
                        continue;
                    }
                }
                if let Some(le) = filter.event_time_le {
                    if min > le {
                        continue;
                    }
                }
            }

            if let Some(eq) = filter.tenant_id_eq {
                let range_ok = match (e.tenant_id_min, e.tenant_id_max) {
                    (Some(min), Some(max)) => eq >= min && eq <= max,
                    _ => true,
                };
                if !range_ok {
                    continue;
                }
                if let Some(b) = &e.bloom_tenant {
                    let bloom = self.bloom_cache.get_or_insert(&e.segment_id, 0, b, 1000);
                    if !bloom.check(&eq) {
                        continue;
                    }
                }
            }

            if let Some(eq) = filter.route_id_eq {
                let range_ok = match (e.route_id_min, e.route_id_max) {
                    (Some(min), Some(max)) => eq >= min && eq <= max,
                    _ => true,
                };
                if !range_ok {
                    continue;
                }
                if let Some(b) = &e.bloom_route {
                    let bloom = self.bloom_cache.get_or_insert(&e.segment_id, 1, b, 1000);
                    if !bloom.check(&eq) {
                        continue;
                    }
                }
            }

            if false {
                // Optimization stubbed out
                continue;
            }
            if !index_list.is_empty() && !schema_map.is_empty() {
                if !self.entry_matches_index_filters(e, &filter, &schema_map, &index_list)? {
                    continue;
                }
            }

            matching.push(e.clone());
        }

        drop(manifest_index);

        if matching.is_empty() {
            return Err(EngineError::NotFound(format!(
                "no segments for {}.{} matching filters",
                db.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown")
            )));
        }

        let check_timeout = || -> Result<(), EngineError> {
            if let Some(dl) = deadline {
                if std::time::Instant::now() > dl {
                    return Err(EngineError::Timeout(format!(
                        "query exceeded timeout of {}ms",
                        request.timeout_millis
                    )));
                }
            }
            Ok(())
        };

        let mut remaining_offset = filter.offset.unwrap_or(0);
        let mut remaining_limit = filter.limit.unwrap_or(usize::MAX);
        let mut data_skipped_bytes: u64 = 0;
        let mut stream_writer: Option<StreamWriter<&mut W>> = None;

        let mut entries_iter = matching.iter();
        while let Some(entry) = entries_iter.next() {
            if remaining_limit == 0 {
                break;
            }
            check_timeout()?;
            // Use try_load to skip damaged segments
            let payload = match self.try_load_segment_cached(entry)? {
                Some(p) => p,
                None => continue, // Skip damaged segment
            };
            let original_size = payload.len() as u64;

            let mut segment_filter = filter.clone();
            segment_filter.limit = None;
            segment_filter.offset = None;

            let batches = filter_ipc_batches(read_ipc_batches(&payload)?, &segment_filter)?;

            if batches.is_empty() {
                data_skipped_bytes += original_size;
                continue;
            }

            let sliced =
                apply_offset_limit_to_batches(batches, &mut remaining_offset, &mut remaining_limit);
            if sliced.is_empty() {
                continue;
            }

            stream_writer = Some(
                StreamWriter::try_new(&mut *writer, sliced[0].schema().as_ref())
                    .map_err(|e| EngineError::Internal(format!("ipc writer init failed: {e}")))?,
            );

            if let Some(w) = stream_writer.as_mut() {
                for batch in &sliced {
                    if batch.num_rows() == 0 {
                        continue;
                    }
                    w.write(batch)
                        .map_err(|e| EngineError::Internal(format!("ipc write failed: {e}")))?;
                    if remaining_limit == 0 {
                        break;
                    }
                }
            }
            break;
        }

        if remaining_limit > 0 {
            for entry in entries_iter {
                if remaining_limit == 0 {
                    break;
                }
                check_timeout()?;
                // Use try_load to skip damaged segments
                let payload = match self.try_load_segment_cached(entry)? {
                    Some(p) => p,
                    None => continue, // Skip damaged segment
                };
                let original_size = payload.len() as u64;

                let mut segment_filter = filter.clone();
                segment_filter.limit = None;
                segment_filter.offset = None;

                let batches = filter_ipc_batches(read_ipc_batches(&payload)?, &segment_filter)?;

                if batches.is_empty() {
                    data_skipped_bytes += original_size;
                    continue;
                }

                let sliced = apply_offset_limit_to_batches(
                    batches,
                    &mut remaining_offset,
                    &mut remaining_limit,
                );
                if sliced.is_empty() {
                    continue;
                }

                if let Some(w) = stream_writer.as_mut() {
                    for batch in &sliced {
                        if batch.num_rows() == 0 {
                            continue;
                        }
                        w.write(batch)
                            .map_err(|e| EngineError::Internal(format!("ipc write failed: {e}")))?;
                        if remaining_limit == 0 {
                            break;
                        }
                    }
                } else {
                    return Err(EngineError::Internal(
                        "stream writer missing for batches".into(),
                    ));
                }
            }
        }

        if let Some(mut w) = stream_writer {
            w.finish()
                .map_err(|e| EngineError::Internal(format!("ipc finish failed: {e}")))?;
        }

        let execution_stats = if collect_stats {
            let bytes_read: u64 = matching.iter().map(|e| e.size_bytes).sum();
            Some(QueryExecutionStats {
                execution_time_micros: query_start.elapsed().as_micros() as u64,
                segments_scanned: matching.len(),
                segments_pruned: total_segments.saturating_sub(matching.len()),
                segments_total: total_segments,
                bytes_read,
                bytes_skipped: data_skipped_bytes,
                cache_hit: false,
                ..Default::default()
            })
        } else {
            None
        };

        self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
        self.metrics.record_query_latency(query_start.elapsed().as_micros() as u64);

        Ok(QueryResponse {
            records_ipc: Vec::new(),
            data_skipped_bytes,
            segments_scanned: matching.len(),
            execution_stats,
        })
    }

    pub fn execute_distributed_plan(&self, plan: PlanKind) -> Result<QueryResponse, EngineError> {
        let manifest_version = self.get_manifest_version()?;
        let query_start = std::time::Instant::now();
        // TODO: Support timeout in distributed request
        let deadline = None;

        let result = match plan {
            PlanKind::Simple {
                agg,
                db,
                table,
                projection,
                filter,
                computed_columns,
            } => self.execute_simple_plan(
                agg,
                db,
                table,
                projection,
                filter,
                computed_columns,
                deadline,
                manifest_version,
                false,
                query_start,
                None, // Distributed queries don't support transactions yet
            ),
            _ => Err(EngineError::NotImplemented(
                "Distributed execution supports Simple plans only".into(),
            )),
        };

        self.metrics.record_query_latency(query_start.elapsed().as_micros() as u64);
        result
    }

    fn execute_simple_plan(
        &self,
        agg: Option<AggPlan>,
        database: Option<String>,
        table: Option<String>,
        projection: Option<Vec<String>>,
        filter: QueryFilter,
        computed_columns: Vec<crate::sql::SelectColumn>,
        deadline: Option<std::time::Instant>,
        _manifest_version: u64,
        collect_stats: bool,
        query_start: std::time::Instant,
        transaction_id: Option<crate::transaction::TransactionId>,
    ) -> Result<QueryResponse, EngineError> {
        // Create MVCC snapshot for visibility filtering if within a transaction
        let mvcc_snapshot = if let Some(txn_id) = transaction_id {
            if let Some(txn_mgr) = self.get_transaction_manager() {
                txn_mgr.mvcc_manager.create_snapshot(txn_id).ok()
            } else {
                None
            }
        } else {
            None
        };
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Handle scalar queries (no table source)
        if database.is_none() && table.is_none() {
            if let Some(exprs) = projection {
                let mut columns: Vec<ArrayRef> = Vec::new();
                let mut fields: Vec<Field> = Vec::new();

                for (i, expr_str) in exprs.iter().enumerate() {
                    let col_name = format!("col_{}", i);
                    if let Ok(val) = expr_str.parse::<i64>() {
                        columns.push(Arc::new(Int64Array::from(vec![val])));
                        fields.push(Field::new(col_name, DataType::Int64, false));
                    } else if let Ok(val) = expr_str.parse::<f64>() {
                        columns.push(Arc::new(arrow_array::Float64Array::from(vec![val])));
                        fields.push(Field::new(col_name, DataType::Float64, false));
                    } else {
                        // Treat as string (strip quotes if present)
                        let val = expr_str.trim().trim_matches('\'').trim_matches('"');
                        columns.push(Arc::new(StringArray::from(vec![val])));
                        fields.push(Field::new(col_name, DataType::Utf8, false));
                    }
                }

                let schema = Arc::new(Schema::new(fields));
                let batch = RecordBatch::try_new(schema.clone(), columns)
                    .map_err(|e| EngineError::Internal(format!("failed to create batch: {e}")))?;

                // Serialize to IPC
                let mut buffer = Vec::new();
                {
                    let mut writer = arrow_ipc::writer::StreamWriter::try_new(&mut buffer, &schema)
                        .map_err(|e| EngineError::Internal(format!("ipc init error: {e}")))?;
                    writer
                        .write(&batch)
                        .map_err(|e| EngineError::Internal(format!("ipc write error: {e}")))?;
                    writer
                        .finish()
                        .map_err(|e| EngineError::Internal(format!("ipc finish error: {e}")))?;
                }

                return Ok(QueryResponse {
                    records_ipc: buffer,
                    data_skipped_bytes: 0,
                    segments_scanned: 0,
                    execution_stats: Some(QueryExecutionStats {
                        execution_time_micros: query_start.elapsed().as_micros() as u64,
                        ..Default::default()
                    }),
                });
            } else if !computed_columns.is_empty() {
                let mut schema_fields = Vec::new();
                let mut columns: Vec<ArrayRef> = Vec::new();

                for (i, col) in computed_columns.iter().enumerate() {
                    let name = col
                        .alias
                        .clone()
                        .unwrap_or_else(|| format!("col_{}", i + 1));
                    match &col.expr {
                        crate::sql::SelectExpr::Literal(val) => match val {
                            crate::sql::LiteralValue::Integer(n) => {
                                schema_fields.push(Field::new(name, DataType::Int64, false));
                                columns.push(std::sync::Arc::new(Int64Array::from(vec![*n])));
                            }
                            crate::sql::LiteralValue::String(s) => {
                                schema_fields.push(Field::new(name, DataType::Utf8, false));
                                columns
                                    .push(std::sync::Arc::new(StringArray::from(vec![s.clone()])));
                            }
                            _ => {
                                return Err(EngineError::NotImplemented(format!(
                                    "unsupported literal type: {:?}",
                                    val
                                )))
                            }
                        },
                        _ => {
                            return Err(EngineError::NotImplemented(
                                "only literals supported in scalar SELECT".into(),
                            ))
                        }
                    }
                }
                let schema = std::sync::Arc::new(Schema::new(schema_fields));
                let batch = RecordBatch::try_new(schema.clone(), columns)
                    .map_err(|e| EngineError::Internal(e.to_string()))?;

                let mut buffer = Vec::new();
                {
                    let mut writer = arrow_ipc::writer::StreamWriter::try_new(&mut buffer, &schema)
                        .map_err(|e| EngineError::Internal(format!("ipc init error: {e}")))?;
                    writer
                        .write(&batch)
                        .map_err(|e| EngineError::Internal(format!("ipc write error: {e}")))?;
                    writer
                        .finish()
                        .map_err(|e| EngineError::Internal(format!("ipc finish error: {e}")))?;
                }
                return Ok(QueryResponse {
                    records_ipc: buffer,
                    data_skipped_bytes: 0,
                    segments_scanned: 0,
                    execution_stats: Some(QueryExecutionStats {
                        execution_time_micros: query_start.elapsed().as_micros() as u64,
                        ..Default::default()
                    }),
                });
            } else {
                // Empty SELECT or Transaction stub (BEGIN/COMMIT)
                // Return empty result
                return Ok(QueryResponse {
                    records_ipc: Vec::new(), // Empty IPC for non-data queries
                    data_skipped_bytes: 0,
                    segments_scanned: 0,
                    execution_stats: Some(QueryExecutionStats {
                        execution_time_micros: query_start.elapsed().as_micros() as u64,
                        ..Default::default()
                    }),
                });
            }
        }

        let expected_schema: Option<Vec<TableFieldSpec>> = manifest
            .tables
            .iter()
            .find(|t| {
                t.database == database.as_deref().unwrap_or("default")
                    && t.name == table.as_deref().unwrap_or("unknown")
            })
            .and_then(|t| {
                t.schema_json
                    .as_ref()
                    .and_then(|s| serde_json::from_str::<Vec<TableFieldSpec>>(s).ok())
            });
        let schema_map = self
            .table_schema_map(
                database.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown"),
            )
            .unwrap_or_default();
        // Use references to avoid cloning IndexMeta (manifest lock is held)
        let index_list: Vec<&IndexMeta> = manifest
            .indexes
            .iter()
            .filter(|idx| {
                idx.database == database.as_deref().unwrap_or("default")
                    && idx.table == table.as_deref().unwrap_or("unknown")
                    && idx.state == IndexState::Ready
            })
            .collect();

        // OPTIMIZATION: Use manifest index for O(1) table lookup instead of O(n) linear scan
        let manifest_index = self
            .manifest_index
            .read()
            .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;

        let table_indices = manifest_index
            .get_table_entries(
                database.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown"),
            )
            .ok_or_else(|| {
                EngineError::NotFound(format!(
                    "no segments for {}.{}",
                    database.as_deref().unwrap_or("default"),
                    table.as_deref().unwrap_or("unknown")
                ))
            })?;

        // Track total segments for stats
        let total_segments = table_indices.len();

        // Pre-allocate with expected capacity - store indices to avoid cloning heavy ManifestEntry
        let mut matching_indices = Vec::with_capacity(table_indices.len());

        // Apply remaining filters only to entries for this table
        for &idx in table_indices {
            let e = &manifest.entries[idx];

            if let Some(ge) = filter.watermark_ge {
                if e.watermark_micros < ge {
                    continue;
                }
            }
            if let Some(le) = filter.watermark_le {
                if e.watermark_micros > le {
                    continue;
                }
            }
            if filter.event_time_ge.is_some() || filter.event_time_le.is_some() {
                let min = e.event_time_min.unwrap_or(0);
                let max = e.event_time_max.unwrap_or(u64::MAX);
                if let Some(ge) = filter.event_time_ge {
                    if max < ge {
                        continue;
                    }
                }
                if let Some(le) = filter.event_time_le {
                    if min > le {
                        continue;
                    }
                }
            }
            if let Some(eq) = filter.tenant_id_eq {
                let range_ok = match (e.tenant_id_min, e.tenant_id_max) {
                    (Some(min), Some(max)) => eq >= min && eq <= max,
                    _ => true,
                };
                if !range_ok {
                    continue;
                }
                if let Some(b) = &e.bloom_tenant {
                    let bloom = self.bloom_cache.get_or_insert(&e.segment_id, 0, b, 1000);
                    if !bloom.check(&eq) {
                        continue;
                    }
                }
            }
            if let Some(eq) = filter.route_id_eq {
                let range_ok = match (e.route_id_min, e.route_id_max) {
                    (Some(min), Some(max)) => eq >= min && eq <= max,
                    _ => true,
                };
                if !range_ok {
                    continue;
                }
                if let Some(b) = &e.bloom_route {
                    let bloom = self.bloom_cache.get_or_insert(&e.segment_id, 1, b, 1000);
                    if !bloom.check(&eq) {
                        continue;
                    }
                }
            }

            if !entry_matches_string_filters(e, &filter) {
                continue;
            }
            if !index_list.is_empty() && !schema_map.is_empty() {
                if !self.entry_matches_index_filters(e, &filter, &schema_map, &index_list)? {
                    continue;
                }
            }

            // Zone-map pruning using column_stats
            if !segment_matches_column_stats(e, &filter) {
                continue;
            }

            // MVCC visibility filtering - skip segments not visible to this transaction
            if let Some(ref snapshot) = mvcc_snapshot {
                use crate::mvcc::MvccVisibility;
                if !e.is_visible_to(snapshot) {
                    continue;
                }
            }

            // Store index instead of cloning entire entry (saves memory for bloom filters, column_stats)
            matching_indices.push(idx);
        }
        drop(manifest_index);

        // OPTIMIZATION: Clone matching entries and release manifest lock BEFORE I/O
        // This allows concurrent queries to proceed while we do segment I/O
        let matching: Vec<ManifestEntry> = matching_indices
            .iter()
            .map(|&idx| manifest.entries[idx].clone())
            .collect();

        // Release manifest lock before any I/O operations
        drop(manifest);

        // Enforce max_segments_per_query limit (ClickHouse-style protection)
        if self.cfg.max_segments_per_query > 0 && matching.len() > self.cfg.max_segments_per_query {
            return Err(EngineError::InvalidArgument(format!(
                "query would scan {} segments, exceeds limit of {} (add more filters or increase max_segments_per_query)",
                matching.len(),
                self.cfg.max_segments_per_query
            )));
        }

        if matching.is_empty() {
            return Err(EngineError::NotFound(format!(
                "no segments for {}.{} matching filters",
                database.as_deref().unwrap_or("default"),
                table.as_deref().unwrap_or("unknown")
            )));
        }

        let estimated_capacity = filter
            .limit
            .unwrap_or(matching.len().saturating_mul(64))
            .min(64 * 1024);
        let mut records = Vec::with_capacity(estimated_capacity);
        let mut data_skipped_bytes: u64 = 0;

        let check_timeout = || -> Result<(), EngineError> {
            if let Some(dl) = deadline {
                if std::time::Instant::now() > dl {
                    return Err(EngineError::Timeout("query exceeded timeout".into()));
                }
            }
            Ok(())
        };

        if agg.is_none() {
            let offset_pushdown =
                filter.offset.is_some() && filter.order_by.is_none() && !filter.distinct;

            // Adaptive parallel scan decision based on workload characteristics
            // Thresholds lowered for better performance with large segment counts
            let use_parallel = {
                let segment_count = matching.len();
                let estimated_bytes: u64 = matching.iter().map(|e| e.size_bytes).sum();
                let avg_segment_size = if segment_count > 0 {
                    estimated_bytes / segment_count as u64
                } else {
                    0
                };

                // Use parallel scan if:
                // 1. Multiple segments (>= 2) AND
                // 2. Either large total data (> 8MB) OR many small segments (> 8)
                // 3. Not using offset pushdown (which benefits from early termination)
                // 4. Always parallel for very large segment counts (> 1000)
                let has_enough_segments = segment_count >= 2;
                let has_large_data = estimated_bytes > 8 * 1024 * 1024;
                let has_many_segments = segment_count > 8;
                let very_large_scan = segment_count > 1000;
                let worth_parallelizing =
                    very_large_scan || has_large_data || has_many_segments || avg_segment_size > 4 * 1024 * 1024;

                has_enough_segments && worth_parallelizing && !offset_pushdown
            };

            if use_parallel {
                let filter_ref = &filter;
                let projection_ref = projection.as_deref();
                let expected_schema_ref = expected_schema
                    .as_ref()
                    .map(|v: &Vec<TableFieldSpec>| Arc::new(v.clone()));
                let this = self;
                let limit = filter.limit.unwrap_or(usize::MAX);
                let collected_rows = AtomicU64::new(0);
                let collected_rows_ref = &collected_rows;

                let results: Vec<Result<(Vec<u8>, u64), EngineError>> = matching
                    .par_iter()
                    .filter_map(|entry| {
                        // Check limit ONLY when we have a meaningful limit (not MAX)
                        // For full table scans without LIMIT, we must scan ALL segments
                        if limit < usize::MAX && collected_rows_ref.load(Ordering::Relaxed) >= limit as u64 {
                            return None;
                        }
                        // Use try_load to skip damaged segments
                        let payload = match this.try_load_segment_cached(entry) {
                            Ok(Some(p)) => p,
                            Ok(None) => return None, // Skip damaged segment
                            Err(e) => return Some(Err(e)),
                        };
                        // Use projection pushdown when projection is available
                        let filtered = match filter_ipc_with_projection(&payload, filter_ref, projection_ref) {
                            Ok(f) => f,
                            Err(e) => return Some(Err(e)),
                        };
                        if !filtered.is_empty() {
                            // Get actual row count from segment metadata or decode IPC
                            // Use segment metadata if available for efficiency
                            let actual_rows = entry
                                .column_stats
                                .as_ref()
                                .and_then(|cs| cs.values().next())
                                .map(|s| s.row_count)
                                .unwrap_or_else(|| {
                                    // Fall back to decoding IPC to get accurate row count
                                    read_ipc_batches(&filtered)
                                        .map(|batches| batches.iter().map(|b| b.num_rows() as u64).sum())
                                        .unwrap_or(1)
                                });
                            collected_rows_ref.fetch_add(actual_rows, Ordering::Relaxed);
                        }
                        let skipped = if filtered.is_empty() {
                            payload.len() as u64
                        } else {
                            0
                        };
                        Some(Ok((filtered, skipped)))
                    })
                    .collect();

                for result in results {
                    check_timeout()?;
                    let (filtered, skipped) = result?;
                    data_skipped_bytes += skipped;
                    records.extend_from_slice(&filtered);
                }
            } else {
                let limit = filter.limit.unwrap_or(usize::MAX);
                let mut estimated_rows: usize = 0;
                let mut remaining_offset = if offset_pushdown {
                    filter.offset.unwrap_or(0)
                } else {
                    0
                };
                let mut remaining_limit = if offset_pushdown {
                    filter.limit.unwrap_or(usize::MAX)
                } else {
                    usize::MAX
                };

                // Pre-create segment filter outside loop to avoid repeated cloning
                let segment_filter = if offset_pushdown {
                    let mut sf = filter.clone();
                    sf.limit = None;
                    sf.offset = None;
                    Some(sf)
                } else {
                    None
                };

                for entry in &matching {
                    if estimated_rows >= limit || remaining_limit == 0 {
                        break;
                    }
                    check_timeout()?;
                    // Use try_load to skip damaged segments
                    let payload = match self.try_load_segment_cached(entry)? {
                        Some(p) => p,
                        None => continue, // Skip damaged segment
                    };
                    let original_size = payload.len() as u64;
                    if let Some(ref seg_filter) = segment_filter {
                        let batches =
                            filter_ipc_batches(read_ipc_batches(&payload)?, seg_filter)?;
                        if batches.is_empty() {
                            data_skipped_bytes += original_size;
                            continue;
                        }
                        let sliced = apply_offset_limit_to_batches(
                            batches,
                            &mut remaining_offset,
                            &mut remaining_limit,
                        );
                        if sliced.is_empty() {
                            continue;
                        }
                        let ipc = record_batches_to_ipc(sliced[0].schema().as_ref(), &sliced)?;
                        estimated_rows += sliced.iter().map(|b| b.num_rows()).sum::<usize>();
                        records.extend_from_slice(&ipc);
                    } else {
                        // Use projection pushdown when available
                        let filtered = filter_ipc_with_projection(&payload, &filter, projection.as_deref())?;
                        if filtered.is_empty() {
                            data_skipped_bytes += original_size;
                        } else {
                            // Get actual row count from segment metadata or decode IPC
                            let actual_rows = entry
                                .column_stats
                                .as_ref()
                                .and_then(|cs| cs.values().next())
                                .map(|s| s.row_count as usize)
                                .unwrap_or_else(|| {
                                    // Fall back to decoding IPC to get accurate row count
                                    read_ipc_batches(&filtered)
                                        .map(|batches| batches.iter().map(|b| b.num_rows()).sum())
                                        .unwrap_or(1)
                                });
                            estimated_rows += actual_rows;
                        }
                        records.extend_from_slice(&filtered);
                    }
                }
            }

            if filter.order_by.is_some() && !records.is_empty() {
                records = apply_order_by(&records, &filter)?;
            }
            // Apply projection before DISTINCT so we deduplicate on selected columns only
            if let Some(ref cols) = projection {
                if !records.is_empty() {
                    // Convert expected_schema to Arrow Schema for handling missing columns
                    let arrow_schema = expected_schema.as_ref().map(|fields| {
                        let arrow_fields: Vec<Field> = fields
                            .iter()
                            .map(|f| {
                                let dt =
                                    arrow_type_from_str(&f.data_type).unwrap_or(DataType::Utf8);
                                Field::new(&f.name, dt, f.nullable)
                            })
                            .collect();
                        Schema::new(arrow_fields)
                    });
                    records = apply_projection_with_schema(&records, cols, arrow_schema.as_ref())?;
                }
            }
            if filter.distinct && !records.is_empty() {
                records = apply_distinct(&records)?;
            }
            // Apply DISTINCT ON after ordering (keeps first row per unique combination)
            if let Some(ref distinct_on_cols) = filter.distinct_on {
                if !records.is_empty() && !distinct_on_cols.is_empty() {
                    records = apply_distinct_on(&records, distinct_on_cols)?;
                }
            }
            if let Some(offset) = filter.offset {
                if !records.is_empty() && (filter.order_by.is_some() || filter.distinct) {
                    records = apply_offset(&records, offset)?;
                }
            }
        } else if let Some(agg_plan) = agg.clone() {
            let default_filter = QueryFilter::default();
            let _agg_projection = aggregation_projection(agg.as_ref().expect("agg present"), &[]);

            // FAST PATH: COUNT(*) without GROUP BY can use segment metadata
            // This enables sub-second COUNT on billions of rows
            let has_no_filters = filter.watermark_ge.is_none()
                && filter.watermark_le.is_none()
                && filter.tenant_id_eq.is_none()
                && filter.route_id_eq.is_none()
                && filter.string_eq_filters.is_empty()
                && filter.numeric_eq_filters.is_empty();
            let is_simple_count_star = agg_plan.aggs.len() == 1
                && matches!(agg_plan.aggs[0].kind, AggKind::CountStar)
                && matches!(agg_plan.group_by, GroupBy::None)
                && has_no_filters;

            if is_simple_count_star {
                // Use row_count from segment metadata or count rows from column_stats
                let mut total_count: u64 = 0;
                for entry in &matching {
                    // Try to get row count from column stats first
                    if let Some(ref col_stats) = entry.column_stats {
                        if let Some(stats) = col_stats.values().next() {
                            if stats.row_count > 0 {
                                total_count += stats.row_count;
                                continue;
                            }
                        }
                    }
                    // Fall back to loading segment and counting
                    let payload = self.load_segment_cached(entry)?;
                    if let Ok(batches) = read_ipc_batches(&payload) {
                        for batch in batches {
                            total_count += batch.num_rows() as u64;
                        }
                    }
                }

                // Build COUNT(*) result - use alias if provided, otherwise default to "count"
                let col_name = agg_plan.aggs[0].output_name();
                let schema = Arc::new(Schema::new(vec![Field::new(&col_name, DataType::UInt64, false)]));
                let count_array = UInt64Array::from(vec![total_count]);
                let batch = RecordBatch::try_new(schema.clone(), vec![Arc::new(count_array)])
                    .map_err(|e| EngineError::Internal(format!("count result: {e}")))?;
                let mut buf = Vec::new();
                {
                    let mut writer = StreamWriter::try_new(&mut buf, &schema)
                        .map_err(|e| EngineError::Internal(format!("ipc writer: {e}")))?;
                    writer.write(&batch)
                        .map_err(|e| EngineError::Internal(format!("ipc write: {e}")))?;
                    writer.finish()
                        .map_err(|e| EngineError::Internal(format!("ipc finish: {e}")))?;
                }
                records = buf;
            } else
            // OPTIMIZATION: Parallel aggregation with partial results for billion-row scale
            // Each thread computes partial aggregates, then merge at the end
            if matching.len() >= self.cfg.parallel_scan_threshold {
                let this = self;
                let filter_ref = &filter;
                let agg_plan_ref = &agg_plan;

                // Process segments in parallel, each producing partial aggregate IPC
                let partial_results: Vec<Result<Vec<u8>, EngineError>> = matching
                    .par_iter()
                    .map(|entry| {
                        let payload = this.load_segment_cached(entry)?;
                        let filtered = filter_ipc(&payload, filter_ref)?;
                        if filtered.is_empty() {
                            return Ok(Vec::new());
                        }
                        // Create per-segment aggregator and process
                        let mut seg_agg = Aggregator::new(agg_plan_ref.clone())?;
                        seg_agg.consume_ipc(&filtered, &QueryFilter::default())?;
                        seg_agg.finish()
                    })
                    .collect();

                // Merge partial results
                let mut final_agg = Aggregator::new(agg_plan)?;
                for partial in partial_results {
                    check_timeout()?;
                    let partial_ipc = partial?;
                    if !partial_ipc.is_empty() {
                        // Feed partial aggregates into final aggregator
                        final_agg.consume_ipc(&partial_ipc, &default_filter)?;
                    }
                }
                records = final_agg.finish()?;
            } else {
                // Sequential path for small number of segments
                let mut agg_state = Aggregator::new(agg_plan)?;
                for entry in &matching {
                    check_timeout()?;
                    let payload = self.load_segment_cached(entry)?;
                    let filtered = filter_ipc(&payload, &filter)?;
                    agg_state.consume_ipc(&filtered, &default_filter)?;
                }
                records = agg_state.finish()?;
            }
        }

        let execution_stats = if collect_stats {
            let bytes_read: u64 = matching.iter().map(|e| e.size_bytes).sum();
            Some(QueryExecutionStats {
                execution_time_micros: query_start.elapsed().as_micros() as u64,
                segments_scanned: matching.len(),
                segments_pruned: total_segments.saturating_sub(matching.len()),
                segments_total: total_segments,
                bytes_read,
                bytes_skipped: data_skipped_bytes,
                cache_hit: false,
                ..Default::default()
            })
        } else {
            None
        };

        self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);

        Ok(QueryResponse {
            records_ipc: records,
            data_skipped_bytes,
            segments_scanned: matching.len(),
            execution_stats,
        })
    }

    /// Export metrics in Prometheus text format
    pub fn prometheus_metrics(&self) -> String {
        self.metrics.to_prometheus()
    }

    /// Export metrics with connection stats from the server layer
    pub fn prometheus_metrics_with_connections(
        &self,
        conn_current: usize,
        conn_max: usize,
        queries_admitted: u64,
        queries_rejected: u64,
        queries_active: usize,
        queries_max: usize,
    ) -> String {
        self.metrics.to_prometheus_with_connections(
            conn_current,
            conn_max,
            queries_admitted,
            queries_rejected,
            queries_active,
            queries_max,
        )
    }

    /// Load segment with LRU caching and Arc for zero-copy sharing
    /// Uses sharded cache for high-concurrency parallel access without blocking I/O
    fn load_segment_cached(&self, entry: &ManifestEntry) -> Result<Arc<Vec<u8>>, EngineError> {
        // Check if caching is disabled
        if self.cfg.segment_cache_bytes == 0 || !self.cache_enabled_for_tier(&entry.tier) {
            return Ok(Arc::new(load_segment(&self.storage, entry)?));
        }

        // Check memtable first (fast path for recent writes)
        if let Some(mem_entry) = self.memtable_index.lock().get(&entry.segment_id) {
            let payload =
                decompress_payload(mem_entry.payload.clone(), entry.compression.as_deref())?;
            return Ok(Arc::new(payload));
        }

        // Check sharded cache (each shard has independent lock - no global contention)
        if let Some(payload) = self.segment_cache.get(&entry.segment_id) {
            return Ok(payload);
        }

        // Cache miss - load from disk OUTSIDE of any cache lock
        // This is the key optimization: I/O happens without holding any locks
        let payload = load_segment(&self.storage, entry)?;

        // Insert into sharded cache (only locks one shard briefly)
        let arc_payload = self.segment_cache.insert(entry.segment_id.clone(), payload);
        Ok(arc_payload)
    }

    /// Try to load segment, returning None if damaged and skip_damaged_segments is enabled
    /// Returns Ok(Some(payload)) on success, Ok(None) if skipped, Err if skip is disabled
    fn try_load_segment_cached(
        &self,
        entry: &ManifestEntry,
    ) -> Result<Option<Arc<Vec<u8>>>, EngineError> {
        match self.load_segment_cached(entry) {
            Ok(payload) => Ok(Some(payload)),
            Err(e) if self.cfg.skip_damaged_segments => {
                tracing::warn!(
                    "Skipping damaged segment {} ({}.{}): {}",
                    entry.segment_id,
                    entry.database,
                    entry.table,
                    e
                );
                self.metrics.skipped_segments.fetch_add(1, Ordering::Relaxed);
                Ok(None)
            }
            Err(e) => Err(e),
        }
    }

    fn load_segment_batches_cached(
        &self,
        entry: &ManifestEntry,
    ) -> Result<Arc<Vec<RecordBatch>>, EngineError> {
        if self.cfg.batch_cache_bytes == 0 || !self.cache_enabled_for_tier(&entry.tier) {
            let payload = self.load_segment_cached(entry)?;
            let batches = read_ipc_batches(&payload)?;
            return Ok(Arc::new(batches));
        }

        // Fast path: check sharded batch cache (each shard has independent lock)
        if let Some(batches) = self.batch_cache.get(&entry.segment_id) {
            self.metrics
                .batch_cache_hits
                .fetch_add(1, Ordering::Relaxed);
            return Ok(batches);
        }
        self.metrics
            .batch_cache_misses
            .fetch_add(1, Ordering::Relaxed);

        // Cache miss: load and decode segment OUTSIDE of any cache lock
        let payload = self.load_segment_cached(entry)?;
        let batches = read_ipc_batches(&payload)?;

        // Insert into sharded cache (only locks one shard briefly)
        Ok(self.batch_cache.insert(entry.segment_id.clone(), batches))
    }

    fn cache_enabled_for_tier(&self, tier: &SegmentTier) -> bool {
        match tier {
            SegmentTier::Hot => self.cfg.cache_hot_segments,
            SegmentTier::Warm => self.cfg.cache_warm_segments,
            SegmentTier::Cold => self.cfg.cache_cold_segments,
        }
    }

    /// Execute a query with JOIN clauses
    ///
    /// Supports multiple JOINs chained together and all JOIN types:
    /// - INNER JOIN: Only matching rows from both tables
    /// - LEFT JOIN: All rows from left + matching rows from right (NULLs for non-matches)
    /// - RIGHT JOIN: All rows from right + matching rows from left (NULLs for non-matches)
    /// - FULL OUTER JOIN: All rows from both tables (NULLs for non-matches)
    /// - CROSS JOIN: Cartesian product of both tables
    ///
    /// **Note:** This is an in-memory implementation suitable for small to medium datasets.
    fn execute_join_query(
        &self,
        request: &QueryRequest,
        deadline: Option<std::time::Instant>,
        manifest_version: u64,
    ) -> Result<QueryResponse, EngineError> {
        use crate::sql::{parse_sql, JoinType, SqlStatement};
        use arrow_ipc::writer::StreamWriter;

        let max_join_bytes = self.cfg.join_max_bytes;
        let join_partition_bytes = self.cfg.join_partition_bytes;
        let join_max_partitions = self.cfg.join_max_partitions.max(1);

        // Create MVCC snapshot for visibility filtering if within a transaction
        let mvcc_snapshot = if let Some(txn_id) = request.transaction_id {
            if let Some(txn_mgr) = self.get_transaction_manager() {
                txn_mgr.mvcc_manager.create_snapshot(txn_id).ok()
            } else {
                None
            }
        } else {
            None
        };

        // Parse the SQL to get JOIN information
        let parsed = match parse_sql(&request.sql)? {
            SqlStatement::Query(q) => q,
            _ => {
                return Err(EngineError::InvalidArgument(
                    "expected SELECT query with JOIN".into(),
                ))
            }
        };

        if parsed.joins.is_empty() {
            return Err(EngineError::InvalidArgument("no JOIN clause found".into()));
        }

        let mut remaining_filter = query_filter_from_sql(&parsed.filter);

        // Check timeout helper
        let check_timeout = || -> Result<(), EngineError> {
            if let Some(dl) = deadline {
                if std::time::Instant::now() > dl {
                    return Err(EngineError::Timeout(format!(
                        "query exceeded timeout of {}ms",
                        request.timeout_millis
                    )));
                }
            }
            Ok(())
        };

        let mut segments_scanned = 0usize;

        // Load data from the left (main) table with MVCC visibility
        let left_entries = self.table_entries_with_visibility(
            parsed.database.as_deref().unwrap_or("default"),
            parsed.table.as_deref().unwrap_or("dual"),
            mvcc_snapshot.as_ref(),
        )?;
        segments_scanned += left_entries.len();

        // Decode left table to RecordBatches
        let mut current_batches = self.load_table_batches(
            parsed.database.as_deref().unwrap_or("default"),
            parsed.table.as_deref().unwrap_or("dual"),
        )?;
        let mut current_spilled: Option<(Vec<PathBuf>, Arc<Schema>)> = None;
        let mut spill_dirs: Vec<TempDir> = Vec::new();
        check_timeout()?;

        let join_projection = parsed.projection.as_deref();

        // Iterate through all JOINs, chaining results
        for (join_idx, join) in parsed.joins.iter().enumerate() {
            let right_entries = self.table_entries_with_visibility(
                &join.database,
                &join.table,
                mvcc_snapshot.as_ref(),
            )?;
            let right_size = Self::entries_total_bytes(&right_entries);
            let (left_bytes, left_schema) = if let Some((paths, schema)) = &current_spilled {
                (Self::paths_total_bytes(paths)?, Some(schema.clone()))
            } else {
                (
                    Self::estimate_batches_bytes(&current_batches),
                    current_batches.get(0).map(|b| b.schema()),
                )
            };
            let total_bytes = left_bytes.saturating_add(right_size);
            let right_schema = self.first_batch_schema_from_entries(&right_entries)?;
            let (left_filter, right_filter, next_remaining) = split_filter_for_join(
                &remaining_filter,
                left_schema.as_deref(),
                right_schema.as_deref(),
            );
            remaining_filter = next_remaining;

            if total_bytes as usize > max_join_bytes {
                if join.join_type == JoinType::Cross {
                    return Err(EngineError::InvalidArgument(
                        "CROSS JOIN spill is not supported; add WHERE filters or reduce JOIN size"
                            .into(),
                    ));
                }

                let max_side_bytes = left_bytes.max(right_size);
                let mut partitions =
                    (max_side_bytes + join_partition_bytes - 1) / join_partition_bytes;
                partitions = partitions.max(1).min(join_max_partitions as u64);
                let partitions = (partitions as usize).next_power_of_two();

                let tmp = TempDir::new()
                    .map_err(|e| EngineError::Io(format!("create join temp dir failed: {e}")))?;

                let mut left_needed: Option<Vec<String>> = None;
                let mut right_needed: Option<Vec<String>> = None;
                if let (Some(left_schema), Some(right_schema)) =
                    (current_batches.get(0).map(|b| b.schema()), right_schema)
                {
                    let remaining_left_keys = parsed.joins[join_idx..]
                        .iter()
                        .map(|j| j.on_condition.left_column.clone())
                        .collect::<Vec<_>>();
                    let (left_set, right_set) = join_projection_sets(
                        left_schema.as_ref(),
                        right_schema.as_ref(),
                        join_projection,
                        &join.on_condition.left_column,
                        &join.on_condition.right_column,
                        &remaining_left_keys,
                    )?;
                    left_needed = left_set;
                    right_needed = right_set;
                    if let Some(ref mut needed) = left_needed {
                        extend_needed_with_filter(needed, &left_filter, Some(left_schema.as_ref()));
                    }
                    if let Some(ref mut needed) = right_needed {
                        extend_needed_with_filter(
                            needed,
                            &right_filter,
                            Some(right_schema.as_ref()),
                        );
                    }
                    if let Some(ref needed) = left_needed {
                        if current_spilled.is_none() {
                            current_batches =
                                Self::project_batches_by_name(&current_batches, needed)?;
                        }
                    }
                }

                if !filter_is_empty(&left_filter) && current_spilled.is_none() {
                    current_batches =
                        filter_batches_with_query_filter(current_batches, &left_filter)?;
                }

                let left_paths = if let Some((paths, _schema)) = current_spilled.take() {
                    Self::partition_ipc_paths_to_ipc(
                        &paths,
                        &join.on_condition.left_column,
                        partitions,
                        tmp.path(),
                        "left",
                        left_needed.as_deref(),
                        if filter_is_empty(&left_filter) {
                            None
                        } else {
                            Some(&left_filter)
                        },
                    )?
                } else {
                    Self::partition_batches_to_ipc(
                        &current_batches,
                        &join.on_condition.left_column,
                        partitions,
                        tmp.path(),
                        "left",
                        left_needed.as_deref(),
                    )?
                };
                let right_paths = self.partition_table_to_ipc(
                    &right_entries,
                    &join.on_condition.right_column,
                    partitions,
                    tmp.path(),
                    "right",
                    right_needed.as_deref(),
                    if filter_is_empty(&right_filter) {
                        None
                    } else {
                        Some(&right_filter)
                    },
                )?;

                let mut joined_batches: Vec<RecordBatch> = Vec::new();
                for idx in 0..partitions {
                    check_timeout()?;
                    let left_batches = Self::read_ipc_batches_from_file(&left_paths[idx])?;
                    let right_batches = Self::read_ipc_batches_from_file(&right_paths[idx])?;

                    let joined_batch = match join.join_type {
                        JoinType::Inner => {
                            if left_batches.is_empty() || right_batches.is_empty() {
                                None
                            } else {
                                Self::hash_join_batches(
                                    &left_batches,
                                    &right_batches,
                                    &join.on_condition.left_column,
                                    &join.on_condition.right_column,
                                )?
                            }
                        }
                        JoinType::Left => {
                            if left_batches.is_empty() {
                                None
                            } else {
                                Self::left_join_batches(
                                    &left_batches,
                                    &right_batches,
                                    &join.on_condition.left_column,
                                    &join.on_condition.right_column,
                                )?
                            }
                        }
                        JoinType::Right => {
                            if right_batches.is_empty() {
                                None
                            } else {
                                Self::right_join_batches(
                                    &left_batches,
                                    &right_batches,
                                    &join.on_condition.left_column,
                                    &join.on_condition.right_column,
                                )?
                            }
                        }
                        JoinType::FullOuter => Self::full_outer_join_batches(
                            &left_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                        )?,
                        JoinType::Cross => None,
                        // ASOF joins match on closest timestamp/value
                        JoinType::AsOf => {
                            // ASOF join: match on closest timestamp (backward direction)
                            Self::asof_join_batches(
                                &left_batches,
                                &right_batches,
                                &join.on_condition.left_column,
                                &join.on_condition.right_column,
                                true, // backward: match <=
                            )?
                        }
                        JoinType::AsOfLeft => {
                            // ASOF LEFT: like ASOF but include unmatched left rows
                            // For now use same as ASOF (full LEFT ASOF needs null handling)
                            Self::asof_join_batches(
                                &left_batches,
                                &right_batches,
                                &join.on_condition.left_column,
                                &join.on_condition.right_column,
                                true, // backward
                            )?
                        }
                        // Semi join returns left rows that have matches in right
                        JoinType::Semi => {
                            if left_batches.is_empty() || right_batches.is_empty() {
                                None
                            } else {
                                Self::semi_join_batches(
                                    &left_batches,
                                    &right_batches,
                                    &join.on_condition.left_column,
                                    &join.on_condition.right_column,
                                    false, // not anti
                                )?
                            }
                        }
                        // Anti join returns left rows that have NO matches in right
                        JoinType::Anti => {
                            if left_batches.is_empty() {
                                None
                            } else if right_batches.is_empty() {
                                // All left rows have no match - return all left rows
                                Some(arrow_select::concat::concat_batches(
                                    &left_batches[0].schema(),
                                    &left_batches,
                                ).map_err(|e| EngineError::Internal(format!("concat failed: {e}")))?)
                            } else {
                                Self::semi_join_batches(
                                    &left_batches,
                                    &right_batches,
                                    &join.on_condition.left_column,
                                    &join.on_condition.right_column,
                                    true, // anti
                                )?
                            }
                        }
                    };

                    if let Some(batch) = joined_batch {
                        joined_batches.push(batch);
                    }
                }

                current_batches = joined_batches;
                segments_scanned += right_entries.len();
                if join_idx + 1 < parsed.joins.len() && !current_batches.is_empty() {
                    let joined_bytes = Self::estimate_batches_bytes(&current_batches);
                    if joined_bytes > max_join_bytes as u64 {
                        let tmp = TempDir::new().map_err(|e| {
                            EngineError::Io(format!("create join spill dir failed: {e}"))
                        })?;
                        let path = tmp.path().join("spill.ipc");
                        Self::write_batches_to_ipc_file(&current_batches, &path)?;
                        let schema = current_batches[0].schema();
                        current_batches.clear();
                        current_spilled = Some((vec![path], schema));
                        spill_dirs.push(tmp);
                    }
                }
                continue;
            }

            if let Some((paths, _schema)) = current_spilled.take() {
                current_batches = Self::read_ipc_batches_from_paths(&paths)?;
            }

            let mut right_batches = self.load_table_batches(&join.database, &join.table)?;
            check_timeout()?;
            segments_scanned += right_entries.len();

            if let (Some(left_schema), Some(right_schema)) = (
                current_batches.get(0).map(|b| b.schema()),
                right_batches.get(0).map(|b| b.schema()),
            ) {
                let remaining_left_keys = parsed.joins[join_idx..]
                    .iter()
                    .map(|j| j.on_condition.left_column.clone())
                    .collect::<Vec<_>>();
                let (left_needed, right_needed) = join_projection_sets(
                    left_schema.as_ref(),
                    right_schema.as_ref(),
                    join_projection,
                    &join.on_condition.left_column,
                    &join.on_condition.right_column,
                    &remaining_left_keys,
                )?;
                if let Some(needed) = left_needed {
                    let mut needed = needed;
                    extend_needed_with_filter(
                        &mut needed,
                        &left_filter,
                        Some(left_schema.as_ref()),
                    );
                    current_batches = Self::project_batches_by_name(&current_batches, &needed)?;
                }
                if let Some(needed) = right_needed {
                    let mut needed = needed;
                    extend_needed_with_filter(
                        &mut needed,
                        &right_filter,
                        Some(right_schema.as_ref()),
                    );
                    right_batches = Self::project_batches_by_name(&right_batches, &needed)?;
                }
            }

            if !filter_is_empty(&left_filter) {
                current_batches = filter_batches_with_query_filter(current_batches, &left_filter)?;
            }
            if !filter_is_empty(&right_filter) {
                right_batches = filter_batches_with_query_filter(right_batches, &right_filter)?;
            }

            // Handle empty tables based on join type
            if current_batches.is_empty() && right_batches.is_empty() {
                current_batches = Vec::new();
                continue;
            }

            // Perform the join based on type
            let joined_batch = match join.join_type {
                JoinType::Cross => self.cross_join_batches(&current_batches, &right_batches)?,
                JoinType::Inner => {
                    if current_batches.is_empty() || right_batches.is_empty() {
                        None
                    } else {
                        Self::hash_join_batches(
                            &current_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                        )?
                    }
                }
                JoinType::Left => {
                    if current_batches.is_empty() {
                        None
                    } else {
                        Self::left_join_batches(
                            &current_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                        )?
                    }
                }
                JoinType::Right => {
                    if right_batches.is_empty() {
                        None
                    } else {
                        // Right join is left join with tables swapped, then columns reordered
                        Self::right_join_batches(
                            &current_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                        )?
                    }
                }
                JoinType::FullOuter => Self::full_outer_join_batches(
                    &current_batches,
                    &right_batches,
                    &join.on_condition.left_column,
                    &join.on_condition.right_column,
                )?,
                JoinType::AsOf => {
                    // ASOF join: match on closest timestamp (backward direction)
                    Self::asof_join_batches(
                        &current_batches,
                        &right_batches,
                        &join.on_condition.left_column,
                        &join.on_condition.right_column,
                        true, // backward: match <=
                    )?
                }
                JoinType::AsOfLeft => {
                    // ASOF LEFT join
                    Self::asof_join_batches(
                        &current_batches,
                        &right_batches,
                        &join.on_condition.left_column,
                        &join.on_condition.right_column,
                        true, // backward
                    )?
                }
                JoinType::Semi => {
                    if current_batches.is_empty() || right_batches.is_empty() {
                        if matches!(join.join_type, JoinType::Semi) {
                            None
                        } else {
                            None
                        }
                    } else {
                        Self::semi_join_batches(
                            &current_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                            false, // not anti
                        )?
                    }
                }
                JoinType::Anti => {
                    if right_batches.is_empty() {
                        // No right rows means all left rows qualify for anti-join
                        if current_batches.is_empty() {
                            None
                        } else {
                            Some(arrow_select::concat::concat_batches(
                                &current_batches[0].schema(),
                                &current_batches,
                            ).map_err(|e| EngineError::Internal(format!("concat failed: {e}")))?)
                        }
                    } else if current_batches.is_empty() {
                        None
                    } else {
                        Self::semi_join_batches(
                            &current_batches,
                            &right_batches,
                            &join.on_condition.left_column,
                            &join.on_condition.right_column,
                            true, // anti
                        )?
                    }
                }
            };
            check_timeout()?;

            // Update current_batches for next JOIN in chain
            current_batches = match joined_batch {
                Some(batch) => vec![batch],
                None => Vec::new(),
            };
            if join_idx + 1 < parsed.joins.len() && !current_batches.is_empty() {
                let joined_bytes = Self::estimate_batches_bytes(&current_batches);
                if joined_bytes > max_join_bytes as u64 {
                    let tmp = TempDir::new().map_err(|e| {
                        EngineError::Io(format!("create join spill dir failed: {e}"))
                    })?;
                    let path = tmp.path().join("spill.ipc");
                    Self::write_batches_to_ipc_file(&current_batches, &path)?;
                    let schema = current_batches[0].schema();
                    current_batches.clear();
                    current_spilled = Some((vec![path], schema));
                    spill_dirs.push(tmp);
                }
            }
        }

        if let Some((paths, _schema)) = current_spilled.take() {
            current_batches = Self::read_ipc_batches_from_paths(&paths)?;
        }

        if !filter_is_empty(&remaining_filter) {
            current_batches = filter_batches_with_query_filter(current_batches, &remaining_filter)?;
        }

        // Encode result to IPC
        let result_ipc = if !current_batches.is_empty() {
            let mut batch = current_batches[0].clone();
            if let Some(projection) = parsed.projection.as_ref() {
                let mut indices = Vec::with_capacity(projection.len());
                for col in projection {
                    let idx = batch
                        .schema()
                        .fields()
                        .iter()
                        .position(|f| f.name() == col)
                        .ok_or_else(|| EngineError::NotFound(format!("column not found: {col}")))?;
                    indices.push(idx);
                }
                batch = batch
                    .project(&indices)
                    .map_err(|e| EngineError::Internal(format!("project failed: {e}")))?;
            }
            let mut ipc_data = Vec::new();
            {
                let mut writer = StreamWriter::try_new(&mut ipc_data, batch.schema().as_ref())
                    .map_err(|e| EngineError::Internal(format!("IPC writer error: {e}")))?;
                writer
                    .write(&batch)
                    .map_err(|e| EngineError::Internal(format!("IPC write error: {e}")))?;
                writer
                    .finish()
                    .map_err(|e| EngineError::Internal(format!("IPC finish error: {e}")))?;
            }
            ipc_data
        } else {
            Vec::new()
        };

        let response = QueryResponse {
            records_ipc: result_ipc,
            data_skipped_bytes: 0,
            segments_scanned,
            execution_stats: None,
        };

        // Cache the result
        let mut cache = self.query_cache.lock();
        cache.insert(
            &request.sql,
            response.clone(),
            manifest_version,
            parsed.database.as_deref().unwrap_or("default"),
            parsed.table.as_deref().unwrap_or("dual"),
        );

        self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
        Ok(response)
    }

    /// Perform CROSS JOIN (Cartesian product) of two tables
    fn cross_join_batches(
        &self,
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
    ) -> Result<Option<RecordBatch>, EngineError> {
        if left_batches.is_empty() || right_batches.is_empty() {
            return Ok(None);
        }

        let left_schema = left_batches[0].schema();
        let right_schema = right_batches[0].schema();

        // Build result schema
        let mut fields: Vec<arrow_schema::Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());
        fields.extend(left_schema.fields().iter().map(|f| f.as_ref().clone()));

        for field in right_schema.fields() {
            if left_schema.field_with_name(field.name()).is_ok() {
                fields.push(arrow_schema::Field::new(
                    format!("r_{}", field.name()),
                    field.data_type().clone(),
                    field.is_nullable(),
                ));
            } else {
                fields.push(field.as_ref().clone());
            }
        }

        let result_schema = Arc::new(arrow_schema::Schema::new(fields));

        // Count total rows
        let left_total: usize = left_batches.iter().map(|b| b.num_rows()).sum();
        let right_total: usize = right_batches.iter().map(|b| b.num_rows()).sum();

        if left_total == 0 || right_total == 0 {
            return Ok(None);
        }

        let max_cross_join_rows = self.cfg.cross_join_max_rows;
        let result_rows = left_total.saturating_mul(right_total);
        if result_rows > max_cross_join_rows {
            return Err(EngineError::InvalidArgument(format!(
                "CROSS JOIN would produce {} rows, exceeding limit of {}. \
                 Add WHERE clause or use a different join type.",
                result_rows, max_cross_join_rows
            )));
        }

        // Build indices for cross product
        let mut left_indices: Vec<(u32, u32)> = Vec::with_capacity(result_rows);
        let mut right_indices: Vec<(u32, u32)> = Vec::with_capacity(result_rows);

        for (l_batch_idx, l_batch) in left_batches.iter().enumerate() {
            for l_row in 0..l_batch.num_rows() {
                for (r_batch_idx, r_batch) in right_batches.iter().enumerate() {
                    for r_row in 0..r_batch.num_rows() {
                        left_indices.push((l_batch_idx as u32, l_row as u32));
                        right_indices.push((r_batch_idx as u32, r_row as u32));
                    }
                }
            }
        }

        // Build result arrays
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Perform LEFT JOIN - all rows from left, matching rows from right (NULLs for non-matches)
    fn left_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use rustc_hash::FxHashMap;

        if left_batches.is_empty() {
            return Ok(None);
        }

        let left_schema = left_batches[0].schema();
        let right_schema = if right_batches.is_empty() {
            // Create empty right schema - we need to return left rows with NULL right columns
            return Self::left_join_with_empty_right(left_batches, left_col);
        } else {
            right_batches[0].schema()
        };

        // Build hash table from right side
        let right_row_count: usize = right_batches.iter().map(|b| b.num_rows()).sum();
        let mut hash_table: FxHashMap<u64, Vec<(u32, u32)>> =
            FxHashMap::with_capacity_and_hasher(right_row_count, Default::default());

        for (batch_idx, batch) in right_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{right_col}' not found in right table"
                ))
            })?;

            let col = batch.column(col_idx);
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                hash_table
                    .entry(key)
                    .or_insert_with(|| Vec::with_capacity(4))
                    .push((batch_idx as u32, row_idx as u32));
            }
        }

        // Build result schema
        let mut fields: Vec<arrow_schema::Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());
        fields.extend(left_schema.fields().iter().map(|f| f.as_ref().clone()));

        for field in right_schema.fields() {
            let name = if left_schema.field_with_name(field.name()).is_ok() {
                format!("r_{}", field.name())
            } else {
                field.name().to_string()
            };
            // Right side columns are nullable in LEFT JOIN
            fields.push(arrow_schema::Field::new(
                name,
                field.data_type().clone(),
                true,
            ));
        }

        let result_schema = Arc::new(arrow_schema::Schema::new(fields));

        // Probe with left side - keep ALL left rows
        let left_row_count: usize = left_batches.iter().map(|b| b.num_rows()).sum();
        let mut left_indices: Vec<(u32, u32)> = Vec::with_capacity(left_row_count);
        let mut right_indices: Vec<Option<(u32, u32)>> = Vec::with_capacity(left_row_count);

        for (left_batch_idx, left_batch) in left_batches.iter().enumerate() {
            let col_idx = left_batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{left_col}' not found in left table"))
            })?;

            let col = left_batch.column(col_idx);
            for row_idx in 0..left_batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                if let Some(matches) = hash_table.get(&key) {
                    // Has matches - add one row per match
                    for &(right_batch_idx, right_row_idx) in matches {
                        left_indices.push((left_batch_idx as u32, row_idx as u32));
                        right_indices.push(Some((right_batch_idx, right_row_idx)));
                    }
                } else {
                    // No match - add row with NULL right side
                    left_indices.push((left_batch_idx as u32, row_idx as u32));
                    right_indices.push(None);
                }
            }
        }

        if left_indices.is_empty() {
            return Ok(None);
        }

        // Build result arrays
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Left side columns
        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        // Right side columns (with NULLs for non-matches)
        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches_nullable(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Handle LEFT JOIN when right table is empty
    fn left_join_with_empty_right(
        left_batches: &[RecordBatch],
        _left_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        if left_batches.is_empty() {
            return Ok(None);
        }

        // Just return left batches as-is (no right columns to add)
        // In practice, we'd need the right schema to add NULL columns
        // For now, return the left side only
        let left_schema = left_batches[0].schema();
        let mut all_arrays: Vec<ArrayRef> = Vec::new();

        for col_idx in 0..left_schema.fields().len() {
            let mut col_arrays: Vec<ArrayRef> = Vec::new();
            for batch in left_batches {
                col_arrays.push(batch.column(col_idx).clone());
            }
            let refs: Vec<&dyn Array> = col_arrays.iter().map(|a| a.as_ref()).collect();
            let concatenated = arrow_select::concat::concat(&refs)
                .map_err(|e| EngineError::Internal(format!("concat error: {e}")))?;
            all_arrays.push(concatenated);
        }

        let result_batch = RecordBatch::try_new(left_schema, all_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Perform RIGHT JOIN - all rows from right, matching rows from left (NULLs for non-matches)
    fn right_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        // Right join is essentially left join with tables swapped
        // But we want to preserve column order (left columns first, then right)
        use rustc_hash::FxHashMap;

        if right_batches.is_empty() {
            return Ok(None);
        }

        let right_schema = right_batches[0].schema();
        let left_schema = if left_batches.is_empty() {
            // Return right rows with NULL left columns
            return Self::right_join_with_empty_left(right_batches, right_col);
        } else {
            left_batches[0].schema()
        };

        // Build hash table from left side
        let left_row_count: usize = left_batches.iter().map(|b| b.num_rows()).sum();
        let mut hash_table: FxHashMap<u64, Vec<(u32, u32)>> =
            FxHashMap::with_capacity_and_hasher(left_row_count, Default::default());

        for (batch_idx, batch) in left_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{left_col}' not found in left table"))
            })?;

            let col = batch.column(col_idx);
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                hash_table
                    .entry(key)
                    .or_insert_with(|| Vec::with_capacity(4))
                    .push((batch_idx as u32, row_idx as u32));
            }
        }

        // Build result schema (left columns first, but nullable)
        let mut fields: Vec<arrow_schema::Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Left side columns are nullable in RIGHT JOIN
        for field in left_schema.fields() {
            fields.push(arrow_schema::Field::new(
                field.name(),
                field.data_type().clone(),
                true,
            ));
        }

        for field in right_schema.fields() {
            let name = if left_schema.field_with_name(field.name()).is_ok() {
                format!("r_{}", field.name())
            } else {
                field.name().to_string()
            };
            fields.push(arrow_schema::Field::new(
                name,
                field.data_type().clone(),
                field.is_nullable(),
            ));
        }

        let result_schema = Arc::new(arrow_schema::Schema::new(fields));

        // Probe with right side - keep ALL right rows
        let right_row_count: usize = right_batches.iter().map(|b| b.num_rows()).sum();
        let mut left_indices: Vec<Option<(u32, u32)>> = Vec::with_capacity(right_row_count);
        let mut right_indices: Vec<(u32, u32)> = Vec::with_capacity(right_row_count);

        for (right_batch_idx, right_batch) in right_batches.iter().enumerate() {
            let col_idx = right_batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{right_col}' not found in right table"
                ))
            })?;

            let col = right_batch.column(col_idx);
            for row_idx in 0..right_batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                if let Some(matches) = hash_table.get(&key) {
                    for &(left_batch_idx, left_row_idx) in matches {
                        left_indices.push(Some((left_batch_idx, left_row_idx)));
                        right_indices.push((right_batch_idx as u32, row_idx as u32));
                    }
                } else {
                    left_indices.push(None);
                    right_indices.push((right_batch_idx as u32, row_idx as u32));
                }
            }
        }

        if right_indices.is_empty() {
            return Ok(None);
        }

        // Build result arrays
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Left side columns (with NULLs for non-matches)
        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches_nullable(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        // Right side columns
        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Handle RIGHT JOIN when left table is empty
    fn right_join_with_empty_left(
        right_batches: &[RecordBatch],
        _right_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        if right_batches.is_empty() {
            return Ok(None);
        }

        let right_schema = right_batches[0].schema();
        let mut all_arrays: Vec<ArrayRef> = Vec::new();

        for col_idx in 0..right_schema.fields().len() {
            let mut col_arrays: Vec<ArrayRef> = Vec::new();
            for batch in right_batches {
                col_arrays.push(batch.column(col_idx).clone());
            }
            let refs: Vec<&dyn Array> = col_arrays.iter().map(|a| a.as_ref()).collect();
            let concatenated = arrow_select::concat::concat(&refs)
                .map_err(|e| EngineError::Internal(format!("concat error: {e}")))?;
            all_arrays.push(concatenated);
        }

        let result_batch = RecordBatch::try_new(right_schema, all_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Perform FULL OUTER JOIN - all rows from both tables (NULLs for non-matches on either side)
    fn full_outer_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use rustc_hash::FxHashMap;

        // Handle empty cases
        if left_batches.is_empty() && right_batches.is_empty() {
            return Ok(None);
        }
        if left_batches.is_empty() {
            return Self::right_join_with_empty_left(right_batches, right_col);
        }
        if right_batches.is_empty() {
            return Self::left_join_with_empty_right(left_batches, left_col);
        }

        let left_schema = left_batches[0].schema();
        let right_schema = right_batches[0].schema();

        // Build hash table from right side
        let right_row_count: usize = right_batches.iter().map(|b| b.num_rows()).sum();
        let mut hash_table: FxHashMap<u64, Vec<(u32, u32)>> =
            FxHashMap::with_capacity_and_hasher(right_row_count, Default::default());
        let mut right_matched: Vec<Vec<bool>> = right_batches
            .iter()
            .map(|b| vec![false; b.num_rows()])
            .collect();

        for (batch_idx, batch) in right_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{right_col}' not found in right table"
                ))
            })?;

            let col = batch.column(col_idx);
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                hash_table
                    .entry(key)
                    .or_insert_with(|| Vec::with_capacity(4))
                    .push((batch_idx as u32, row_idx as u32));
            }
        }

        // Build result schema (all columns nullable)
        let mut fields: Vec<arrow_schema::Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        for field in left_schema.fields() {
            fields.push(arrow_schema::Field::new(
                field.name(),
                field.data_type().clone(),
                true,
            ));
        }

        for field in right_schema.fields() {
            let name = if left_schema.field_with_name(field.name()).is_ok() {
                format!("r_{}", field.name())
            } else {
                field.name().to_string()
            };
            fields.push(arrow_schema::Field::new(
                name,
                field.data_type().clone(),
                true,
            ));
        }

        let result_schema = Arc::new(arrow_schema::Schema::new(fields));

        // Probe with left side
        let left_row_count: usize = left_batches.iter().map(|b| b.num_rows()).sum();
        let mut left_indices: Vec<Option<(u32, u32)>> =
            Vec::with_capacity(left_row_count + right_row_count);
        let mut right_indices: Vec<Option<(u32, u32)>> =
            Vec::with_capacity(left_row_count + right_row_count);

        for (left_batch_idx, left_batch) in left_batches.iter().enumerate() {
            let col_idx = left_batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{left_col}' not found in left table"))
            })?;

            let col = left_batch.column(col_idx);
            for row_idx in 0..left_batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                if let Some(matches) = hash_table.get(&key) {
                    for &(right_batch_idx, right_row_idx) in matches {
                        left_indices.push(Some((left_batch_idx as u32, row_idx as u32)));
                        right_indices.push(Some((right_batch_idx, right_row_idx)));
                        right_matched[right_batch_idx as usize][right_row_idx as usize] = true;
                    }
                } else {
                    left_indices.push(Some((left_batch_idx as u32, row_idx as u32)));
                    right_indices.push(None);
                }
            }
        }

        // Add unmatched right rows
        for (batch_idx, matched) in right_matched.iter().enumerate() {
            for (row_idx, &was_matched) in matched.iter().enumerate() {
                if !was_matched {
                    left_indices.push(None);
                    right_indices.push(Some((batch_idx as u32, row_idx as u32)));
                }
            }
        }

        if left_indices.is_empty() {
            return Ok(None);
        }

        // Build result arrays
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Left side columns
        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches_nullable(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        // Right side columns
        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches_nullable(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Take rows from multiple batches using optional indices (None = NULL)
    fn take_from_batches_nullable(
        batches: &[RecordBatch],
        col_idx: usize,
        indices: &[Option<(u32, u32)>],
    ) -> Result<ArrayRef, EngineError> {
        use arrow_array::NullArray;

        if batches.is_empty() || indices.is_empty() {
            // Return array of nulls
            return Ok(Arc::new(NullArray::new(indices.len())));
        }

        let sample_col = batches[0].column(col_idx);
        let data_type = sample_col.data_type();

        // Build array with nulls for None indices
        match data_type {
            DataType::Int64 => {
                let mut builder = Int64Builder::with_capacity(indices.len());
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::Int64Array>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            DataType::Int32 => {
                let mut builder = Int32Builder::with_capacity(indices.len());
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::Int32Array>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            DataType::UInt64 => {
                let mut builder = UInt64Builder::with_capacity(indices.len());
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::UInt64Array>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            DataType::Float64 => {
                let mut builder = Float64Builder::with_capacity(indices.len());
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::Float64Array>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            DataType::Boolean => {
                let mut builder = BooleanBuilder::with_capacity(indices.len());
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::BooleanArray>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            DataType::Utf8 => {
                let mut builder = StringBuilder::with_capacity(indices.len(), indices.len() * 32);
                for idx in indices {
                    if let Some((batch_idx, row_idx)) = idx {
                        let arr = batches[*batch_idx as usize]
                            .column(col_idx)
                            .as_any()
                            .downcast_ref::<arrow_array::StringArray>()
                            .ok_or_else(|| EngineError::Internal("type mismatch".into()))?;
                        if arr.is_null(*row_idx as usize) {
                            builder.append_null();
                        } else {
                            builder.append_value(arr.value(*row_idx as usize));
                        }
                    } else {
                        builder.append_null();
                    }
                }
                Ok(Arc::new(builder.finish()))
            }
            _ => {
                // Fallback for other types - create null array
                Ok(Arc::new(NullArray::new(indices.len())))
            }
        }
    }

    /// Perform SEMI or ANTI JOIN
    /// Semi-join returns left rows that have at least one match in right
    /// Anti-join returns left rows that have NO matches in right
    fn semi_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
        anti: bool,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use rustc_hash::FxHashSet;

        if left_batches.is_empty() {
            return Ok(None);
        }
        if right_batches.is_empty() {
            // No right rows: semi-join returns nothing, anti-join returns all left rows
            if anti {
                return Ok(Some(arrow_select::concat::concat_batches(
                    &left_batches[0].schema(),
                    left_batches,
                ).map_err(|e| EngineError::Internal(format!("concat failed: {e}")))?));
            } else {
                return Ok(None);
            }
        }

        // Build hash set from right side (just need to know if key exists)
        let right_row_count: usize = right_batches.iter().map(|b| b.num_rows()).sum();
        let mut hash_set: FxHashSet<u64> =
            FxHashSet::with_capacity_and_hasher(right_row_count, Default::default());

        for batch in right_batches {
            let col_idx = batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{right_col}' not found in right table"
                ))
            })?;

            let col = batch.column(col_idx);
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                hash_set.insert(key);
            }
        }

        // Probe with left side, collecting matching row indices
        let mut left_indices: Vec<(u32, u32)> = Vec::new();

        for (left_batch_idx, left_batch) in left_batches.iter().enumerate() {
            let col_idx = left_batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{left_col}' not found in left table"))
            })?;

            let col = left_batch.column(col_idx);
            for row_idx in 0..left_batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                let has_match = hash_set.contains(&key);

                // For semi-join: include if match exists
                // For anti-join: include if no match exists
                if has_match != anti {
                    left_indices.push((left_batch_idx as u32, row_idx as u32));
                }
            }
        }

        if left_indices.is_empty() {
            return Ok(None);
        }

        // Build result using only left table schema
        let left_schema = left_batches[0].schema();
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(left_schema.fields().len());

        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(left_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Perform ASOF JOIN - match each left row with the closest right row by timestamp
    /// Direction: Backward (<=), Forward (>=), or Nearest
    fn asof_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
        backward: bool, // true = match <= (backward), false = match >= (forward)
    ) -> Result<Option<RecordBatch>, EngineError> {
        use arrow_array::types::Int64Type;
        use arrow_ord::sort::{sort_to_indices, SortOptions};

        if left_batches.is_empty() || right_batches.is_empty() {
            return Ok(None);
        }

        let left_schema = left_batches[0].schema();
        let right_schema = right_batches[0].schema();

        // Collect all rows with their timestamps
        let mut left_rows: Vec<(i64, usize, usize)> = Vec::new(); // (timestamp, batch_idx, row_idx)
        let mut right_rows: Vec<(i64, usize, usize)> = Vec::new();

        // Extract left timestamps
        for (batch_idx, batch) in left_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{}' not found in left table", left_col))
            })?;
            let col = batch.column(col_idx);

            for row_idx in 0..batch.num_rows() {
                let ts = Self::extract_timestamp_value(col.as_ref(), row_idx)?;
                left_rows.push((ts, batch_idx, row_idx));
            }
        }

        // Extract right timestamps
        for (batch_idx, batch) in right_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{}' not found in right table", right_col))
            })?;
            let col = batch.column(col_idx);

            for row_idx in 0..batch.num_rows() {
                let ts = Self::extract_timestamp_value(col.as_ref(), row_idx)?;
                right_rows.push((ts, batch_idx, row_idx));
            }
        }

        // Sort both sides by timestamp
        left_rows.sort_by_key(|r| r.0);
        right_rows.sort_by_key(|r| r.0);

        // For each left row, find the best matching right row
        let mut left_indices: Vec<(u32, u32)> = Vec::new();
        let mut right_indices: Vec<(u32, u32)> = Vec::new();

        for &(left_ts, left_batch, left_row) in &left_rows {
            let best_match = if backward {
                // Find the largest right timestamp <= left timestamp
                right_rows.iter()
                    .filter(|r| r.0 <= left_ts)
                    .max_by_key(|r| r.0)
            } else {
                // Find the smallest right timestamp >= left timestamp
                right_rows.iter()
                    .filter(|r| r.0 >= left_ts)
                    .min_by_key(|r| r.0)
            };

            if let Some(&(_, right_batch, right_row)) = best_match {
                left_indices.push((left_batch as u32, left_row as u32));
                right_indices.push((right_batch as u32, right_row as u32));
            }
        }

        if left_indices.is_empty() {
            return Ok(None);
        }

        // Build result schema (all columns from both tables)
        let mut fields: Vec<arrow_schema::Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());
        fields.extend(left_schema.fields().iter().map(|f| f.as_ref().clone()));

        for field in right_schema.fields() {
            if left_schema.field_with_name(field.name()).is_ok() {
                fields.push(arrow_schema::Field::new(
                    format!("r_{}", field.name()),
                    field.data_type().clone(),
                    field.is_nullable(),
                ));
            } else {
                fields.push(field.as_ref().clone());
            }
        }

        let result_schema = Arc::new(arrow_schema::Schema::new(fields));

        // Build result arrays
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Left side columns
        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        // Right side columns
        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create ASOF join result: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Extract a timestamp/numeric value from an array for ASOF join comparison
    fn extract_timestamp_value(col: &dyn arrow_array::Array, row_idx: usize) -> Result<i64, EngineError> {
        use arrow_array::*;

        if col.is_null(row_idx) {
            return Ok(i64::MIN); // Treat nulls as minimum value
        }

        match col.data_type() {
            DataType::Int64 => {
                let arr = col.as_any().downcast_ref::<Int64Array>().unwrap();
                Ok(arr.value(row_idx))
            }
            DataType::Int32 => {
                let arr = col.as_any().downcast_ref::<Int32Array>().unwrap();
                Ok(arr.value(row_idx) as i64)
            }
            DataType::Timestamp(_, _) => {
                let arr = col.as_any().downcast_ref::<TimestampMicrosecondArray>()
                    .or_else(|| None);
                if let Some(ts_arr) = arr {
                    Ok(ts_arr.value(row_idx))
                } else {
                    // Try nanoseconds
                    if let Some(ts_arr) = col.as_any().downcast_ref::<TimestampNanosecondArray>() {
                        Ok(ts_arr.value(row_idx) / 1000) // Convert to micros
                    } else if let Some(ts_arr) = col.as_any().downcast_ref::<TimestampMillisecondArray>() {
                        Ok(ts_arr.value(row_idx) * 1000) // Convert to micros
                    } else if let Some(ts_arr) = col.as_any().downcast_ref::<TimestampSecondArray>() {
                        Ok(ts_arr.value(row_idx) * 1_000_000) // Convert to micros
                    } else {
                        Err(EngineError::InvalidArgument("unsupported timestamp type for ASOF join".into()))
                    }
                }
            }
            DataType::Date32 => {
                let arr = col.as_any().downcast_ref::<Date32Array>().unwrap();
                Ok(arr.value(row_idx) as i64 * 86400 * 1_000_000) // Days to micros
            }
            DataType::Float64 => {
                let arr = col.as_any().downcast_ref::<Float64Array>().unwrap();
                Ok(arr.value(row_idx) as i64)
            }
            _ => Err(EngineError::InvalidArgument(format!(
                "ASOF join requires numeric/timestamp column, got {:?}",
                col.data_type()
            ))),
        }
    }

    /// Execute a set operation query (UNION, INTERSECT, EXCEPT)
    fn execute_set_operation(
        &self,
        request: &QueryRequest,
        deadline: Option<std::time::Instant>,
        manifest_version: u64,
    ) -> Result<QueryResponse, EngineError> {
        use crate::sql::{parse_sql, SetOpType, SqlStatement};
        use arrow_ipc::writer::StreamWriter;

        let max_set_operation_bytes = self.cfg.set_operation_max_bytes;

        // Check timeout helper
        let check_timeout = || -> Result<(), EngineError> {
            if let Some(dl) = deadline {
                if std::time::Instant::now() > dl {
                    return Err(EngineError::Timeout(format!(
                        "query exceeded timeout of {}ms",
                        request.timeout_millis
                    )));
                }
            }
            Ok(())
        };

        // Parse the SQL to get set operation information
        let parsed = match parse_sql(&request.sql)? {
            SqlStatement::SetOperation(set_op) => set_op,
            _ => {
                return Err(EngineError::InvalidArgument(
                    "expected set operation query (UNION/INTERSECT/EXCEPT)".into(),
                ))
            }
        };

        // Execute left query
        let left_sql = match *parsed.left {
            SqlStatement::Query(q) => format!(
                "SELECT * FROM {}.{}",
                q.database.as_deref().unwrap_or("default"),
                q.table.as_deref().unwrap_or("dual")
            ),
            SqlStatement::SetOperation(_) => {
                return Err(EngineError::NotImplemented(
                    "nested set operations not yet supported".into(),
                ))
            }
            _ => {
                return Err(EngineError::InvalidArgument(
                    "invalid left side of set operation".into(),
                ))
            }
        };

        let left_request = QueryRequest {
            sql: left_sql,
            timeout_millis: request.timeout_millis,
            collect_stats: false,
            transaction_id: request.transaction_id, // Propagate transaction context
        };
        let left_response = self.query(left_request)?;
        check_timeout()?;

        // Execute right query
        let right_sql = match *parsed.right {
            SqlStatement::Query(q) => format!(
                "SELECT * FROM {}.{}",
                q.database.as_deref().unwrap_or("default"),
                q.table.as_deref().unwrap_or("dual")
            ),
            SqlStatement::SetOperation(_) => {
                return Err(EngineError::NotImplemented(
                    "nested set operations not yet supported".into(),
                ))
            }
            _ => {
                return Err(EngineError::InvalidArgument(
                    "invalid right side of set operation".into(),
                ))
            }
        };

        let right_request = QueryRequest {
            sql: right_sql,
            timeout_millis: request.timeout_millis,
            collect_stats: false,
            transaction_id: request.transaction_id, // Propagate transaction context
        };
        let right_response = self.query(right_request)?;
        check_timeout()?;

        let total_ipc_bytes = left_response.records_ipc.len() + right_response.records_ipc.len();
        if total_ipc_bytes > max_set_operation_bytes {
            return Err(EngineError::InvalidArgument(format!(
                "set operation inputs exceed size limit ({} bytes > {})",
                total_ipc_bytes, max_set_operation_bytes
            )));
        }

        // Decode both results
        let left_batches = Self::decode_ipc_batches(&left_response.records_ipc)?;
        let right_batches = Self::decode_ipc_batches(&right_response.records_ipc)?;

        // Combine based on operation type
        let result_batch = match parsed.op {
            SetOpType::UnionAll => {
                // Just concatenate all rows
                Self::concat_batches(&left_batches, &right_batches)?
            }
            SetOpType::Union => {
                // Concatenate and remove duplicates
                let combined = Self::concat_batches(&left_batches, &right_batches)?;
                if let Some(batch) = combined {
                    Some(Self::remove_duplicates(&batch)?)
                } else {
                    None
                }
            }
            SetOpType::IntersectAll => {
                // Keep rows that appear in both (with duplicates)
                Self::intersect_batches(&left_batches, &right_batches, true)?
            }
            SetOpType::Intersect => {
                // Keep rows that appear in both (no duplicates)
                Self::intersect_batches(&left_batches, &right_batches, false)?
            }
            SetOpType::ExceptAll => {
                // Keep rows from left that don't appear in right (with duplicates)
                Self::except_batches(&left_batches, &right_batches, true)?
            }
            SetOpType::Except => {
                // Keep rows from left that don't appear in right (no duplicates)
                Self::except_batches(&left_batches, &right_batches, false)?
            }
        };
        check_timeout()?;

        // Encode result to IPC
        let result_ipc = if let Some(batch) = result_batch {
            let mut ipc_data = Vec::new();
            {
                let mut writer = StreamWriter::try_new(&mut ipc_data, batch.schema().as_ref())
                    .map_err(|e| EngineError::Internal(format!("IPC writer error: {e}")))?;
                writer
                    .write(&batch)
                    .map_err(|e| EngineError::Internal(format!("IPC write error: {e}")))?;
                writer
                    .finish()
                    .map_err(|e| EngineError::Internal(format!("IPC finish error: {e}")))?;
            }
            ipc_data
        } else {
            Vec::new()
        };

        let response = QueryResponse {
            records_ipc: result_ipc,
            data_skipped_bytes: 0,
            segments_scanned: left_response.segments_scanned + right_response.segments_scanned,
            execution_stats: None,
        };

        // Cache the result
        let mut cache = self.query_cache.lock();
        // Use default database and table for cache invalidation
        cache.insert(
            &request.sql,
            response.clone(),
            manifest_version,
            "default",
            "default",
        );

        self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
        Ok(response)
    }

    /// Execute a query containing subqueries in WHERE clause (IN, EXISTS, scalar comparison)
    fn execute_subquery_query(
        &self,
        request: &QueryRequest,
        deadline: Option<std::time::Instant>,
        manifest_version: u64,
    ) -> Result<QueryResponse, EngineError> {
        use crate::sql::{parse_sql, SqlStatement};
        use arrow_ipc::writer::StreamWriter;

        // Check timeout helper
        let check_timeout = || -> Result<(), EngineError> {
            if let Some(dl) = deadline {
                if std::time::Instant::now() > dl {
                    return Err(EngineError::Timeout(format!(
                        "query exceeded timeout of {}ms",
                        request.timeout_millis
                    )));
                }
            }
            Ok(())
        };

        // Parse the SQL to get query with subquery filters
        let parsed = match parse_sql(&request.sql)? {
            SqlStatement::Query(q) => q,
            _ => return Err(EngineError::InvalidArgument("expected SELECT query".into())),
        };

        // Collect values from IN subqueries
        let mut in_values: HashMap<String, HashSet<String>> = HashMap::new();
        for (column, subquery_sql, negated) in &parsed.filter.in_subquery_filters {
            let subquery_request = QueryRequest {
                sql: subquery_sql.clone(),
                timeout_millis: request.timeout_millis,
                collect_stats: false,
                transaction_id: request.transaction_id, // Propagate transaction context
            };
            let subquery_response = self.query(subquery_request)?;
            check_timeout()?;

            // Extract values from subquery result (first column only)
            let batches = Self::decode_ipc_batches(&subquery_response.records_ipc)?;
            let mut values = HashSet::new();
            for batch in &batches {
                if batch.num_columns() > 0 {
                    let col = batch.column(0);
                    for row_idx in 0..batch.num_rows() {
                        let val = Self::extract_column_value_as_string(col, row_idx);
                        values.insert(val);
                    }
                }
            }

            // For NOT IN, we'll handle filtering differently
            if *negated {
                // Store with a special prefix to indicate negation
                in_values.insert(format!("NOT:{}", column), values);
            } else {
                in_values.insert(column.clone(), values);
            }
        }

        // Evaluate EXISTS subqueries
        let mut exists_results: Vec<(bool, bool)> = Vec::new(); // (has_rows, negated)
        for (subquery_sql, negated) in &parsed.filter.exists_subqueries {
            let subquery_request = QueryRequest {
                sql: subquery_sql.clone(),
                timeout_millis: request.timeout_millis,
                collect_stats: false,
                transaction_id: request.transaction_id, // Propagate transaction context
            };
            let subquery_response = self.query(subquery_request)?;
            check_timeout()?;

            let batches = Self::decode_ipc_batches(&subquery_response.records_ipc)?;
            let has_rows = batches.iter().any(|b| b.num_rows() > 0);
            exists_results.push((has_rows, *negated));
        }

        // Check if EXISTS conditions pass
        for (has_rows, negated) in &exists_results {
            let passes = if *negated { !*has_rows } else { *has_rows };
            if !passes {
                // EXISTS condition failed - return empty result
                return Ok(QueryResponse {
                    records_ipc: Vec::new(),
                    data_skipped_bytes: 0,
                    segments_scanned: 0,
                    execution_stats: None,
                });
            }
        }

        // Evaluate scalar subqueries
        let mut scalar_values: HashMap<String, (String, String)> = HashMap::new(); // column -> (op, value)
        for (column, op, subquery_sql) in &parsed.filter.scalar_subquery_filters {
            let subquery_request = QueryRequest {
                sql: subquery_sql.clone(),
                timeout_millis: request.timeout_millis,
                collect_stats: false,
                transaction_id: request.transaction_id, // Propagate transaction context
            };
            let subquery_response = self.query(subquery_request)?;
            check_timeout()?;

            let batches = Self::decode_ipc_batches(&subquery_response.records_ipc)?;
            // Scalar subquery must return exactly one row and one column
            let value = if let Some(batch) = batches.first() {
                if batch.num_rows() != 1 {
                    return Err(EngineError::InvalidArgument(format!(
                        "scalar subquery returned {} rows, expected 1",
                        batch.num_rows()
                    )));
                }
                if batch.num_columns() == 0 {
                    return Err(EngineError::InvalidArgument(
                        "scalar subquery returned no columns".into(),
                    ));
                }
                Self::extract_column_value_as_string(batch.column(0), 0)
            } else {
                return Err(EngineError::InvalidArgument(
                    "scalar subquery returned no results".into(),
                ));
            };

            scalar_values.insert(column.clone(), (op.clone(), value));
        }

        // Now execute the main query without subquery filters, then apply filters in memory
        // Build a simplified query without the subquery parts
        let main_sql = format!(
            "SELECT * FROM {}.{}",
            parsed.database.as_deref().unwrap_or("default"),
            parsed.table.as_deref().unwrap_or("dual")
        );
        let main_request = QueryRequest {
            sql: main_sql,
            timeout_millis: request.timeout_millis,
            collect_stats: false,
            transaction_id: None,
        };
        let main_response = self.query(main_request)?;
        check_timeout()?;

        // If no subquery filters need to be applied, return directly
        if in_values.is_empty() && scalar_values.is_empty() {
            return Ok(main_response);
        }

        // Apply subquery filters to the result
        let batches = Self::decode_ipc_batches(&main_response.records_ipc)?;
        let filtered_batch = Self::apply_subquery_filters(&batches, &in_values, &scalar_values)?;

        // Encode result to IPC
        let result_ipc = if let Some(batch) = filtered_batch {
            let mut ipc_data = Vec::new();
            {
                let mut writer = StreamWriter::try_new(&mut ipc_data, batch.schema().as_ref())
                    .map_err(|e| EngineError::Internal(format!("IPC writer error: {e}")))?;
                writer
                    .write(&batch)
                    .map_err(|e| EngineError::Internal(format!("IPC write error: {e}")))?;
                writer
                    .finish()
                    .map_err(|e| EngineError::Internal(format!("IPC finish error: {e}")))?;
            }
            ipc_data
        } else {
            Vec::new()
        };

        let response = QueryResponse {
            records_ipc: result_ipc,
            data_skipped_bytes: main_response.data_skipped_bytes,
            segments_scanned: main_response.segments_scanned,
            execution_stats: None,
        };

        // Cache the result
        let mut cache = self.query_cache.lock();
        cache.insert(
            &request.sql,
            response.clone(),
            manifest_version,
            parsed.database.as_deref().unwrap_or("default"),
            parsed.table.as_deref().unwrap_or("unknown"),
        );

        self.metrics.queries_total.fetch_add(1, Ordering::Relaxed);
        Ok(response)
    }

    /// Execute a query with CTEs (WITH clause)
    fn execute_cte_query(
        &self,
        request: &QueryRequest,
        _deadline: Option<std::time::Instant>,
        _manifest_version: u64,
    ) -> Result<QueryResponse, EngineError> {
        use crate::sql::{parse_sql, SqlStatement};

        // Parse the SQL to extract CTEs
        let parsed = match parse_sql(&request.sql)? {
            SqlStatement::Query(q) => q,
            _ => return Err(EngineError::InvalidArgument("expected SELECT query".into())),
        };

        // If no CTEs, execute normally
        if parsed.ctes.is_empty() {
            return self.query(QueryRequest {
                sql: request.sql.clone(),
                timeout_millis: request.timeout_millis,
                collect_stats: false,
                transaction_id: request.transaction_id, // Propagate transaction context
            });
        }

        // Execute query with CTEs
        execute_query_with_ctes(self, &request.sql, &parsed.ctes, request.timeout_millis)
    }

    /// Extract a column value as string for subquery comparison
    fn extract_column_value_as_string(col: &ArrayRef, row_idx: usize) -> String {
        use arrow_array::{Float32Array, Float64Array, Int32Array, Int64Array};

        if col.is_null(row_idx) {
            return "NULL".to_string();
        }

        if let Some(arr) = col.as_any().downcast_ref::<StringArray>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<Int32Array>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<Float64Array>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<Float32Array>() {
            return arr.value(row_idx).to_string();
        }
        if let Some(arr) = col.as_any().downcast_ref::<BooleanArray>() {
            return arr.value(row_idx).to_string();
        }

        // Fallback for other types
        format!("{:?}", col.slice(row_idx, 1))
    }

    /// Apply subquery filters (IN, NOT IN, scalar comparisons) to batches
    fn apply_subquery_filters(
        batches: &[RecordBatch],
        in_values: &HashMap<String, HashSet<String>>,
        scalar_values: &HashMap<String, (String, String)>,
    ) -> Result<Option<RecordBatch>, EngineError> {
        if batches.is_empty() {
            return Ok(None);
        }

        let schema = batches[0].schema();
        let mut all_indices: Vec<(usize, usize)> = Vec::new(); // (batch_idx, row_idx)

        // Build column index map
        let col_indices: HashMap<String, usize> = schema
            .fields()
            .iter()
            .enumerate()
            .map(|(i, f)| (f.name().to_lowercase(), i))
            .collect();

        for (batch_idx, batch) in batches.iter().enumerate() {
            for row_idx in 0..batch.num_rows() {
                let mut passes = true;

                // Check IN filters
                for (key, values) in in_values {
                    let (column, negated) = if let Some(col) = key.strip_prefix("NOT:") {
                        (col, true)
                    } else {
                        (key.as_str(), false)
                    };

                    if let Some(&col_idx) = col_indices.get(&column.to_lowercase()) {
                        let val =
                            Self::extract_column_value_as_string(batch.column(col_idx), row_idx);
                        let in_set = values.contains(&val);
                        if negated {
                            if in_set {
                                passes = false;
                                break;
                            }
                        } else if !in_set {
                            passes = false;
                            break;
                        }
                    }
                }

                if !passes {
                    continue;
                }

                // Check scalar comparison filters
                for (column, (op, expected_value)) in scalar_values {
                    if let Some(&col_idx) = col_indices.get(&column.to_lowercase()) {
                        let actual_value =
                            Self::extract_column_value_as_string(batch.column(col_idx), row_idx);
                        let cmp_result = Self::compare_string_values(&actual_value, expected_value);
                        let op_passes = match op.as_str() {
                            "=" => cmp_result == std::cmp::Ordering::Equal,
                            "!=" | "<>" => cmp_result != std::cmp::Ordering::Equal,
                            ">" => cmp_result == std::cmp::Ordering::Greater,
                            ">=" => cmp_result != std::cmp::Ordering::Less,
                            "<" => cmp_result == std::cmp::Ordering::Less,
                            "<=" => cmp_result != std::cmp::Ordering::Greater,
                            _ => true,
                        };
                        if !op_passes {
                            passes = false;
                            break;
                        }
                    }
                }

                if passes {
                    all_indices.push((batch_idx, row_idx));
                }
            }
        }

        if all_indices.is_empty() {
            return Ok(None);
        }

        // Build result batch from matching indices
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(schema.fields().len());
        for col_idx in 0..schema.fields().len() {
            let arrays: Vec<&dyn Array> =
                batches.iter().map(|b| b.column(col_idx).as_ref()).collect();

            // Build indices for arrow take operation
            let mut take_indices: Vec<u32> = Vec::with_capacity(all_indices.len());
            let mut row_offset = 0u32;
            let mut current_batch = 0usize;

            for (batch_idx, row_idx) in &all_indices {
                while current_batch < *batch_idx {
                    row_offset += batches[current_batch].num_rows() as u32;
                    current_batch += 1;
                }
                take_indices.push(row_offset + *row_idx as u32);
            }

            // Concatenate all arrays first
            let concatenated = arrow_select::concat::concat(&arrays)
                .map_err(|e| EngineError::Internal(format!("concat error: {e}")))?;

            // Take the matching rows
            let indices_array = arrow_array::UInt32Array::from(take_indices);
            let taken = arrow_select::take::take(&concatenated, &indices_array, None)
                .map_err(|e| EngineError::Internal(format!("take error: {e}")))?;
            result_arrays.push(taken);
        }

        let result_batch = RecordBatch::try_new(schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Compare two string values, attempting numeric comparison first
    fn compare_string_values(a: &str, b: &str) -> std::cmp::Ordering {
        // Try numeric comparison first
        if let (Ok(a_num), Ok(b_num)) = (a.parse::<f64>(), b.parse::<f64>()) {
            return a_num
                .partial_cmp(&b_num)
                .unwrap_or(std::cmp::Ordering::Equal);
        }
        // Fall back to string comparison
        a.cmp(b)
    }

    /// Concatenate batches from two sets
    fn concat_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
    ) -> Result<Option<RecordBatch>, EngineError> {
        if left_batches.is_empty() && right_batches.is_empty() {
            return Ok(None);
        }

        let schema = if !left_batches.is_empty() {
            left_batches[0].schema()
        } else {
            right_batches[0].schema()
        };

        let all_batches: Vec<&RecordBatch> =
            left_batches.iter().chain(right_batches.iter()).collect();

        if all_batches.is_empty() {
            return Ok(None);
        }

        // Concatenate all arrays for each column
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(schema.fields().len());
        for col_idx in 0..schema.fields().len() {
            let arrays: Vec<&dyn Array> = all_batches
                .iter()
                .map(|b| b.column(col_idx).as_ref())
                .collect();
            let concatenated = arrow_select::concat::concat(&arrays)
                .map_err(|e| EngineError::Internal(format!("concat error: {e}")))?;
            result_arrays.push(concatenated);
        }

        let result_batch = RecordBatch::try_new(schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Remove duplicate rows from a batch
    fn remove_duplicates(batch: &RecordBatch) -> Result<RecordBatch, EngineError> {
        use rustc_hash::FxHashSet;

        if batch.num_rows() == 0 {
            return Ok(batch.clone());
        }

        // Hash each row and keep only unique ones
        let mut seen: FxHashSet<u64> = FxHashSet::default();
        let mut keep_indices: Vec<u32> = Vec::new();

        for row_idx in 0..batch.num_rows() {
            let row_hash = Self::compute_row_hash(batch, row_idx);
            if seen.insert(row_hash) {
                keep_indices.push(row_idx as u32);
            }
        }

        // Take only the unique rows
        Self::take_rows(batch, &keep_indices)
    }

    /// Compute a hash for a row (all columns combined)
    fn compute_row_hash(batch: &RecordBatch, row_idx: usize) -> u64 {
        let mut hash: u64 = 0xcbf29ce484222325; // FNV-1a offset basis
        for col_idx in 0..batch.num_columns() {
            let col_hash = Self::compute_hash_key(batch.column(col_idx).as_ref(), row_idx);
            hash ^= col_hash;
            hash = hash.wrapping_mul(0x100000001b3);
        }
        hash
    }

    /// Take specific rows from a batch by indices
    fn take_rows(batch: &RecordBatch, indices: &[u32]) -> Result<RecordBatch, EngineError> {
        use arrow_array::UInt32Array;
        use arrow_select::take::take;

        let indices_array = UInt32Array::from(indices.to_vec());
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(batch.num_columns());

        for col_idx in 0..batch.num_columns() {
            let taken = take(batch.column(col_idx).as_ref(), &indices_array, None)
                .map_err(|e| EngineError::Internal(format!("take error: {e}")))?;
            result_arrays.push(taken);
        }

        RecordBatch::try_new(batch.schema(), result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))
    }

    /// Intersect two sets of batches
    fn intersect_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        keep_all: bool,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use rustc_hash::FxHashMap;

        if left_batches.is_empty() || right_batches.is_empty() {
            return Ok(None);
        }

        // Build hash table of right side rows
        let mut right_counts: FxHashMap<u64, usize> = FxHashMap::default();
        for batch in right_batches {
            for row_idx in 0..batch.num_rows() {
                let row_hash = Self::compute_row_hash(batch, row_idx);
                *right_counts.entry(row_hash).or_insert(0) += 1;
            }
        }

        // Find matching rows from left side
        let schema = left_batches[0].schema();
        let mut result_indices: Vec<(usize, usize)> = Vec::new(); // (batch_idx, row_idx)
        let mut seen: rustc_hash::FxHashSet<u64> = rustc_hash::FxHashSet::default();

        for (batch_idx, batch) in left_batches.iter().enumerate() {
            for row_idx in 0..batch.num_rows() {
                let row_hash = Self::compute_row_hash(batch, row_idx);
                if let Some(count) = right_counts.get_mut(&row_hash) {
                    if keep_all {
                        // Keep one for each match in right
                        if *count > 0 {
                            result_indices.push((batch_idx, row_idx));
                            *count -= 1;
                        }
                    } else {
                        // Keep only first occurrence
                        if seen.insert(row_hash) {
                            result_indices.push((batch_idx, row_idx));
                        }
                    }
                }
            }
        }

        if result_indices.is_empty() {
            return Ok(None);
        }

        // Build result batch
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(schema.fields().len());
        for col_idx in 0..schema.fields().len() {
            let indices: Vec<(u32, u32)> = result_indices
                .iter()
                .map(|(b, r)| (*b as u32, *r as u32))
                .collect();
            let array = Self::take_from_batches(left_batches, col_idx, &indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Except (difference) between two sets of batches
    fn except_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        keep_all: bool,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use rustc_hash::FxHashMap;

        if left_batches.is_empty() {
            return Ok(None);
        }

        // Build hash table of right side rows
        let mut right_counts: FxHashMap<u64, usize> = FxHashMap::default();
        for batch in right_batches {
            for row_idx in 0..batch.num_rows() {
                let row_hash = Self::compute_row_hash(batch, row_idx);
                *right_counts.entry(row_hash).or_insert(0) += 1;
            }
        }

        // Find non-matching rows from left side
        let schema = left_batches[0].schema();
        let mut result_indices: Vec<(usize, usize)> = Vec::new();
        let mut seen: rustc_hash::FxHashSet<u64> = rustc_hash::FxHashSet::default();

        for (batch_idx, batch) in left_batches.iter().enumerate() {
            for row_idx in 0..batch.num_rows() {
                let row_hash = Self::compute_row_hash(batch, row_idx);
                if let Some(count) = right_counts.get_mut(&row_hash) {
                    if keep_all && *count > 0 {
                        // Skip this row (it matches one in right)
                        *count -= 1;
                        continue;
                    } else if !keep_all {
                        // Skip all matching rows
                        continue;
                    }
                }
                // Row doesn't match right side
                if keep_all {
                    result_indices.push((batch_idx, row_idx));
                } else {
                    // Keep only first occurrence
                    if seen.insert(row_hash) {
                        result_indices.push((batch_idx, row_idx));
                    }
                }
            }
        }

        if result_indices.is_empty() {
            return Ok(None);
        }

        // Build result batch
        let mut result_arrays: Vec<ArrayRef> = Vec::with_capacity(schema.fields().len());
        for col_idx in 0..schema.fields().len() {
            let indices: Vec<(u32, u32)> = result_indices
                .iter()
                .map(|(b, r)| (*b as u32, *r as u32))
                .collect();
            let array = Self::take_from_batches(left_batches, col_idx, &indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Load all data from a table as decoded RecordBatches without concatenating IPC bytes.
    pub(crate) fn load_table_batches(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Vec<RecordBatch>, EngineError> {
        let matching = self.table_entries(database, table)?;
        if matching.is_empty() {
            return Ok(Vec::new());
        }

        let mut batches = Vec::new();
        for entry in &matching {
            let decoded = self.load_segment_batches_cached(entry)?;
            batches.extend(decoded.iter().cloned());
        }
        Ok(batches)
    }

    fn table_entries(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Vec<ManifestEntry>, EngineError> {
        self.table_entries_with_visibility(database, table, None)
    }

    /// Get table entries filtered by MVCC visibility
    fn table_entries_with_visibility(
        &self,
        database: &str,
        table: &str,
        snapshot: Option<&crate::mvcc::Snapshot>,
    ) -> Result<Vec<ManifestEntry>, EngineError> {
        use crate::mvcc::MvccVisibility;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let matching: Vec<_> = manifest
            .entries
            .iter()
            .filter(|e| {
                let entry_db = if e.database.is_empty() {
                    "default"
                } else {
                    &e.database
                };
                let entry_table = if e.table.is_empty() {
                    "default"
                } else {
                    &e.table
                };
                if entry_db != database || entry_table != table {
                    return false;
                }
                // Apply MVCC visibility filter if snapshot provided
                if let Some(snap) = snapshot {
                    if !e.is_visible_to(snap) {
                        return false;
                    }
                }
                true
            })
            .cloned()
            .collect();

        Ok(matching)
    }

    /// Get values from rows matching a filter for specific columns (used for FK cascade)
    fn get_rows_matching_filter(
        &self,
        database: &str,
        table: &str,
        filter: &QueryFilter,
        columns: &[String],
    ) -> Result<Vec<Vec<SqlValue>>, EngineError> {
        let batches = self.load_table_batches(database, table)?;
        let mut values: Vec<Vec<SqlValue>> = Vec::new();

        for batch in &batches {
            let schema = batch.schema();
            let col_indices: Vec<Option<usize>> = columns
                .iter()
                .map(|c| schema.index_of(c).ok())
                .collect();

            // Check if all columns exist
            if col_indices.iter().any(|i| i.is_none()) {
                continue; // Skip if columns don't exist in this batch
            }

            // Apply filter to batch
            let mask = apply_filter_to_batch(batch, filter)?;

            for row_idx in 0..batch.num_rows() {
                // Check if this row matches the filter
                if let Some(ref m) = mask {
                    if !m.value(row_idx) {
                        continue;
                    }
                }

                let mut row_values = Vec::new();
                for col_idx in &col_indices {
                    let array = batch.column(col_idx.unwrap());
                    let value = extract_sql_value_from_array(array, row_idx);
                    row_values.push(value);
                }
                values.push(row_values);
            }
        }

        Ok(values)
    }

    /// Get default values for columns in a table (used for FK SET DEFAULT)
    fn get_column_defaults(
        &self,
        database: &str,
        table: &str,
        columns: &[String],
    ) -> Result<Vec<SqlValue>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let table_meta = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound(format!("table {}.{} not found", database, table)))?;

        let defaults: Vec<SqlValue> = columns
            .iter()
            .map(|col| {
                // Look for column default in constraints or column definitions
                // For now, return NULL as the default (a production implementation
                // would look up actual default values from column definitions)
                SqlValue::Null
            })
            .collect();

        Ok(defaults)
    }

    fn entries_total_bytes(entries: &[ManifestEntry]) -> u64 {
        entries.iter().map(|e| e.size_bytes).sum()
    }

    fn partition_table_to_ipc(
        &self,
        entries: &[ManifestEntry],
        join_column: &str,
        partitions: usize,
        tmp_dir: &Path,
        prefix: &str,
        needed: Option<&[String]>,
        filter: Option<&QueryFilter>,
    ) -> Result<Vec<PathBuf>, EngineError> {
        use arrow_array::UInt32Array;

        let mut outputs: Vec<PartitionWriter> = Vec::with_capacity(partitions);
        for idx in 0..partitions {
            let path = tmp_dir.join(format!("{prefix}_{idx}.ipc"));
            let file = File::create(&path)
                .map_err(|e| EngineError::Io(format!("create join temp file failed: {e}")))?;
            outputs.push(PartitionWriter::new(path, file));
        }

        for entry in entries {
            let mut batches = self
                .load_segment_batches_cached(entry)?
                .iter()
                .cloned()
                .collect();
            if let Some(filter) = filter {
                batches = filter_batches_with_query_filter(batches, filter)?;
            }

            for batch in batches {
                let mut batch = batch;
                if let Some(needed) = needed {
                    batch = Self::project_batch_by_name(&batch, needed)?;
                }
                if batch.num_rows() == 0 {
                    continue;
                }
                let col_idx = batch.schema().index_of(join_column).map_err(|_| {
                    EngineError::InvalidArgument(format!(
                        "column '{join_column}' not found for JOIN partitioning"
                    ))
                })?;
                let col = batch.column(col_idx);

                let mut per_partition: Vec<Vec<u32>> = vec![Vec::new(); partitions];
                for row_idx in 0..batch.num_rows() {
                    let key = Self::compute_hash_key(col.as_ref(), row_idx);
                    let bucket = (key as usize) & (partitions - 1);
                    per_partition[bucket].push(row_idx as u32);
                }

                for (bucket, indices) in per_partition.iter().enumerate() {
                    if indices.is_empty() {
                        continue;
                    }
                    let idx_array = UInt32Array::from_iter_values(indices.iter().copied());
                    let subset = arrow_select::take::take_record_batch(&batch, &idx_array)
                        .map_err(|e| {
                            EngineError::Internal(format!("partition take failed: {e}"))
                        })?;
                    outputs[bucket].write(&subset)?;
                }
            }
        }

        let mut paths = Vec::with_capacity(partitions);
        for mut out in outputs {
            out.finish()?;
            paths.push(out.path);
        }
        Ok(paths)
    }

    fn partition_batches_to_ipc(
        batches: &[RecordBatch],
        join_column: &str,
        partitions: usize,
        tmp_dir: &Path,
        prefix: &str,
        needed: Option<&[String]>,
    ) -> Result<Vec<PathBuf>, EngineError> {
        use arrow_array::UInt32Array;

        let mut outputs: Vec<PartitionWriter> = Vec::with_capacity(partitions);
        for idx in 0..partitions {
            let path = tmp_dir.join(format!("{prefix}_{idx}.ipc"));
            let file = File::create(&path)
                .map_err(|e| EngineError::Io(format!("create join temp file failed: {e}")))?;
            outputs.push(PartitionWriter::new(path, file));
        }

        for batch in batches {
            let mut batch = batch.clone();
            if let Some(needed) = needed {
                batch = Self::project_batch_by_name(&batch, needed)?;
            }
            if batch.num_rows() == 0 {
                continue;
            }
            let col_idx = batch.schema().index_of(join_column).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{join_column}' not found for JOIN partitioning"
                ))
            })?;
            let col = batch.column(col_idx);

            let mut per_partition: Vec<Vec<u32>> = vec![Vec::new(); partitions];
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                let bucket = (key as usize) & (partitions - 1);
                per_partition[bucket].push(row_idx as u32);
            }

            for (bucket, indices) in per_partition.iter().enumerate() {
                if indices.is_empty() {
                    continue;
                }
                let idx_array = UInt32Array::from_iter_values(indices.iter().copied());
                let subset = arrow_select::take::take_record_batch(&batch, &idx_array)
                    .map_err(|e| EngineError::Internal(format!("partition take failed: {e}")))?;
                outputs[bucket].write(&subset)?;
            }
        }

        let mut paths = Vec::with_capacity(partitions);
        for mut out in outputs {
            out.finish()?;
            paths.push(out.path);
        }
        Ok(paths)
    }

    fn paths_total_bytes(paths: &[PathBuf]) -> Result<u64, EngineError> {
        let mut total = 0u64;
        for path in paths {
            let meta = fs::metadata(path)
                .map_err(|e| EngineError::Io(format!("stat join temp file failed: {e}")))?;
            total = total.saturating_add(meta.len());
        }
        Ok(total)
    }

    fn read_ipc_batches_from_paths(paths: &[PathBuf]) -> Result<Vec<RecordBatch>, EngineError> {
        let mut batches = Vec::new();
        for path in paths {
            batches.extend(Self::read_ipc_batches_from_file(path)?);
        }
        Ok(batches)
    }

    fn write_batches_to_ipc_file(batches: &[RecordBatch], path: &Path) -> Result<(), EngineError> {
        if batches.is_empty() {
            let _ = File::create(path)
                .map_err(|e| EngineError::Io(format!("create join spill file failed: {e}")))?;
            return Ok(());
        }
        let mut writer = StreamWriter::try_new(
            File::create(path)
                .map_err(|e| EngineError::Io(format!("create join spill file failed: {e}")))?,
            batches[0].schema().as_ref(),
        )
        .map_err(|e| EngineError::Internal(format!("IPC writer error: {e}")))?;
        for batch in batches {
            writer
                .write(batch)
                .map_err(|e| EngineError::Internal(format!("IPC write error: {e}")))?;
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("IPC finish error: {e}")))?;
        Ok(())
    }

    fn partition_ipc_paths_to_ipc(
        paths: &[PathBuf],
        join_column: &str,
        partitions: usize,
        tmp_dir: &Path,
        prefix: &str,
        needed: Option<&[String]>,
        filter: Option<&QueryFilter>,
    ) -> Result<Vec<PathBuf>, EngineError> {
        use arrow_array::UInt32Array;

        let mut outputs: Vec<PartitionWriter> = Vec::with_capacity(partitions);
        for idx in 0..partitions {
            let path = tmp_dir.join(format!("{prefix}_{idx}.ipc"));
            let file = File::create(&path)
                .map_err(|e| EngineError::Io(format!("create join temp file failed: {e}")))?;
            outputs.push(PartitionWriter::new(path, file));
        }

        for path in paths {
            let meta = fs::metadata(path)
                .map_err(|e| EngineError::Io(format!("stat join temp file failed: {e}")))?;
            if meta.len() == 0 {
                continue;
            }
            let file = File::open(path)
                .map_err(|e| EngineError::Io(format!("open join temp file failed: {e}")))?;
            let mut reader = StreamReader::try_new(file, None)
                .map_err(|e| EngineError::Internal(format!("IPC reader error: {e}")))?;
            while let Some(batch) = reader
                .next()
                .transpose()
                .map_err(|e| EngineError::Internal(format!("IPC batch read failed: {e}")))?
            {
                let mut batches = vec![batch];
                if let Some(needed) = needed {
                    batches = batches
                        .into_iter()
                        .map(|b| Self::project_batch_by_name(&b, needed))
                        .collect::<Result<Vec<_>, _>>()?;
                }
                if let Some(filter) = filter {
                    batches = filter_batches_with_query_filter(batches, filter)?;
                }
                for batch in batches {
                    if batch.num_rows() == 0 {
                        continue;
                    }
                    let col_idx = batch.schema().index_of(join_column).map_err(|_| {
                        EngineError::InvalidArgument(format!(
                            "join column not found in spilled data: {join_column}"
                        ))
                    })?;
                    let mut per_partition: Vec<Vec<u32>> =
                        (0..partitions).map(|_| Vec::new()).collect();
                    for row_idx in 0..batch.num_rows() {
                        let key = Self::compute_hash_key(batch.column(col_idx).as_ref(), row_idx);
                        let bucket = (key as usize) & (partitions - 1);
                        per_partition[bucket].push(row_idx as u32);
                    }
                    for (bucket, indices) in per_partition.iter().enumerate() {
                        if indices.is_empty() {
                            continue;
                        }
                        let idx_array = UInt32Array::from_iter_values(indices.iter().copied());
                        let subset = arrow_select::take::take_record_batch(&batch, &idx_array)
                            .map_err(|e| {
                                EngineError::Internal(format!("partition take failed: {e}"))
                            })?;
                        outputs[bucket].write(&subset)?;
                    }
                }
            }
        }

        let mut out_paths = Vec::with_capacity(partitions);
        for mut out in outputs {
            out.finish()?;
            out_paths.push(out.path);
        }
        Ok(out_paths)
    }

    fn read_ipc_batches_from_file(path: &Path) -> Result<Vec<RecordBatch>, EngineError> {
        let meta = fs::metadata(path)
            .map_err(|e| EngineError::Io(format!("stat join temp file failed: {e}")))?;
        if meta.len() == 0 {
            return Ok(Vec::new());
        }
        let file = File::open(path)
            .map_err(|e| EngineError::Io(format!("open join temp file failed: {e}")))?;
        let reader = StreamReader::try_new(file, None)
            .map_err(|e| EngineError::Internal(format!("IPC reader error: {e}")))?;
        let batches: Result<Vec<_>, _> = reader.collect();
        let mut batches =
            batches.map_err(|e| EngineError::Internal(format!("IPC decode error: {e}")))?;
        for idx in 0..batches.len() {
            let decoded = decode_record_batch_encodings(&batches[idx])?;
            batches[idx] = decoded;
        }
        Ok(batches)
    }

    fn project_batch_by_name(
        batch: &RecordBatch,
        needed: &[String],
    ) -> Result<RecordBatch, EngineError> {
        if needed.is_empty() {
            return Ok(batch.clone());
        }
        let schema = batch.schema();
        for name in needed {
            if schema.field_with_name(name).is_err() {
                return Err(EngineError::NotFound(format!("column not found: {name}")));
            }
        }
        let indices: Vec<usize> = schema
            .fields()
            .iter()
            .enumerate()
            .filter_map(|(idx, f)| {
                if needed.iter().any(|n| n == f.name()) {
                    Some(idx)
                } else {
                    None
                }
            })
            .collect();
        if indices.len() == schema.fields().len() {
            Ok(batch.clone())
        } else {
            batch
                .project(&indices)
                .map_err(|e| EngineError::Internal(format!("project failed: {e}")))
        }
    }

    fn estimate_batches_bytes(batches: &[RecordBatch]) -> u64 {
        batches
            .iter()
            .map(|b| b.get_array_memory_size() as u64)
            .sum()
    }

    fn first_batch_schema_from_entries(
        &self,
        entries: &[ManifestEntry],
    ) -> Result<Option<Arc<Schema>>, EngineError> {
        let entry = match entries.first() {
            Some(e) => e,
            None => return Ok(None),
        };
        if self.cfg.schema_cache_entries > 0 {
            if let Some(schema) = {
                let mut cache = self.schema_cache.lock();
                cache.get(&entry.segment_id).cloned()
            } {
                self.metrics
                    .schema_cache_hits
                    .fetch_add(1, Ordering::Relaxed);
                return Ok(Some(schema));
            }
            self.metrics
                .schema_cache_misses
                .fetch_add(1, Ordering::Relaxed);
        }
        let payload = self.load_segment_cached(entry)?;
        let cursor = Cursor::new(payload.as_ref());
        let mut reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("IPC reader error: {e}")))?;
        let batch = reader
            .next()
            .transpose()
            .map_err(|e| EngineError::Internal(format!("IPC batch read failed: {e}")))?;
        let schema = batch.map(|b| b.schema());
        if let Some(ref schema) = schema {
            let mut cache = self.schema_cache.lock();
            cache.put(entry.segment_id.clone(), schema.clone());
        }
        Ok(schema)
    }

    /// Decode IPC data to RecordBatches
    fn decode_ipc_batches(data: &[u8]) -> Result<Vec<RecordBatch>, EngineError> {
        use arrow_ipc::reader::StreamReader;
        use std::io::Cursor;

        if data.is_empty() {
            return Ok(Vec::new());
        }

        let cursor = Cursor::new(data);
        let mut reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("IPC reader error: {e}")))?;
        let mut batches = Vec::new();
        while let Some(batch) = reader
            .next()
            .transpose()
            .map_err(|e| EngineError::Internal(format!("IPC decode error: {e}")))?
        {
            batches.push(decode_record_batch_encodings(&batch)?);
        }
        Ok(batches)
    }

    fn project_batches_by_name(
        batches: &[RecordBatch],
        needed: &[String],
    ) -> Result<Vec<RecordBatch>, EngineError> {
        if needed.is_empty() {
            return Ok(batches.iter().cloned().collect());
        }
        let mut out = Vec::with_capacity(batches.len());
        for batch in batches {
            let schema = batch.schema();
            for name in needed {
                if schema.field_with_name(name).is_err() {
                    return Err(EngineError::NotFound(format!("column not found: {name}")));
                }
            }
            let indices: Vec<usize> = schema
                .fields()
                .iter()
                .enumerate()
                .filter_map(|(idx, f)| {
                    if needed.iter().any(|n| n == f.name()) {
                        Some(idx)
                    } else {
                        None
                    }
                })
                .collect();
            if indices.len() == schema.fields().len() {
                out.push(batch.clone());
            } else {
                out.push(
                    batch
                        .project(&indices)
                        .map_err(|e| EngineError::Internal(format!("project failed: {e}")))?,
                );
            }
        }
        Ok(out)
    }

    /// Perform hash join on two sets of record batches
    /// Uses efficient u64 hash keys and preserves original column types
    fn hash_join_batches(
        left_batches: &[RecordBatch],
        right_batches: &[RecordBatch],
        left_col: &str,
        right_col: &str,
    ) -> Result<Option<RecordBatch>, EngineError> {
        use arrow_array::ArrayRef;
        use arrow_schema::{Field, Schema};
        use rustc_hash::FxHashMap;

        if left_batches.is_empty() || right_batches.is_empty() {
            return Ok(None);
        }

        // Estimate result size for capacity pre-allocation
        let right_row_count: usize = right_batches.iter().map(|b| b.num_rows()).sum();
        let left_row_count: usize = left_batches.iter().map(|b| b.num_rows()).sum();

        // Build hash table from right side (use FxHashMap for speed)
        // Key: hash of join column value, Value: (batch_idx, row_idx) pairs
        let mut hash_table: FxHashMap<u64, Vec<(u32, u32)>> =
            FxHashMap::with_capacity_and_hasher(right_row_count, Default::default());

        for (batch_idx, batch) in right_batches.iter().enumerate() {
            let col_idx = batch.schema().index_of(right_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "column '{right_col}' not found in right table"
                ))
            })?;

            let col = batch.column(col_idx);
            for row_idx in 0..batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                hash_table
                    .entry(key)
                    .or_insert_with(|| Vec::with_capacity(4))
                    .push((batch_idx as u32, row_idx as u32));
            }
        }

        // Pre-allocate result indices with estimated capacity
        let estimated_matches = (left_row_count * right_row_count) / 100; // Conservative estimate
        let mut left_indices: Vec<(u32, u32)> = Vec::with_capacity(estimated_matches.max(1024));
        let mut right_indices: Vec<(u32, u32)> = Vec::with_capacity(estimated_matches.max(1024));

        // Probe with left side
        for (left_batch_idx, left_batch) in left_batches.iter().enumerate() {
            let col_idx = left_batch.schema().index_of(left_col).map_err(|_| {
                EngineError::InvalidArgument(format!("column '{left_col}' not found in left table"))
            })?;

            let col = left_batch.column(col_idx);
            for row_idx in 0..left_batch.num_rows() {
                let key = Self::compute_hash_key(col.as_ref(), row_idx);
                if let Some(matches) = hash_table.get(&key) {
                    for &(right_batch_idx, right_row_idx) in matches {
                        left_indices.push((left_batch_idx as u32, row_idx as u32));
                        right_indices.push((right_batch_idx, right_row_idx));
                    }
                }
            }
        }

        if left_indices.is_empty() {
            return Ok(None);
        }

        // Build result schema (all columns from both tables)
        let left_schema = left_batches[0].schema();
        let right_schema = right_batches[0].schema();

        let mut fields: Vec<Field> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());
        fields.extend(left_schema.fields().iter().map(|f| f.as_ref().clone()));

        for field in right_schema.fields() {
            // Prefix right table columns with "r_" to avoid name collisions
            if left_schema.field_with_name(field.name()).is_ok() {
                fields.push(Field::new(
                    format!("r_{}", field.name()),
                    field.data_type().clone(),
                    field.is_nullable(),
                ));
            } else {
                fields.push(field.as_ref().clone());
            }
        }

        let result_schema = Arc::new(Schema::new(fields));

        // Build result arrays using Arrow's take kernel (much faster than row-by-row)
        let mut result_arrays: Vec<ArrayRef> =
            Vec::with_capacity(left_schema.fields().len() + right_schema.fields().len());

        // Process left table columns
        for col_idx in 0..left_schema.fields().len() {
            let array = Self::take_from_batches(left_batches, col_idx, &left_indices)?;
            result_arrays.push(array);
        }

        // Process right table columns
        for col_idx in 0..right_schema.fields().len() {
            let array = Self::take_from_batches(right_batches, col_idx, &right_indices)?;
            result_arrays.push(array);
        }

        let result_batch = RecordBatch::try_new(result_schema, result_arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create result batch: {e}")))?;

        Ok(Some(result_batch))
    }

    /// Compute a hash key from an array value (uses FxHash-style fast hashing)
    #[inline]
    fn compute_hash_key(array: &dyn Array, idx: usize) -> u64 {
        use arrow_array::{BooleanArray, Float64Array, Int32Array, Int64Array, StringArray};

        if array.is_null(idx) {
            return 0; // NULL maps to 0
        }

        // Fast path for common types - avoid string conversion
        if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
            return arr.value(idx) as u64;
        }
        if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
            return arr.value(idx) as u64;
        }
        if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
            // FNV-1a hash for strings (fast and good distribution)
            let s = arr.value(idx);
            let mut hash: u64 = 0xcbf29ce484222325;
            for byte in s.bytes() {
                hash ^= byte as u64;
                hash = hash.wrapping_mul(0x100000001b3);
            }
            return hash;
        }
        if let Some(arr) = array.as_any().downcast_ref::<Float64Array>() {
            return arr.value(idx).to_bits();
        }
        if let Some(arr) = array.as_any().downcast_ref::<BooleanArray>() {
            return arr.value(idx) as u64;
        }

        // Fallback for other types - use a simple hash
        idx as u64
    }

    /// Take rows from multiple batches using indices (batch_idx, row_idx)
    fn take_from_batches(
        batches: &[RecordBatch],
        col_idx: usize,
        indices: &[(u32, u32)],
    ) -> Result<ArrayRef, EngineError> {
        use arrow_array::{Array, ArrayRef, UInt32Array};
        use arrow_select::concat::concat;
        use arrow_select::take::take;

        if indices.is_empty() {
            // Return empty array of the correct type
            let col = batches[0].column(col_idx);
            return Ok(col.slice(0, 0));
        }

        // Group indices by batch for efficient processing
        let mut batch_groups: Vec<Vec<u32>> = vec![Vec::new(); batches.len()];
        let mut output_positions: Vec<(usize, usize)> = Vec::with_capacity(indices.len());

        for (_, &(batch_idx, row_idx)) in indices.iter().enumerate() {
            let group_idx = batch_groups[batch_idx as usize].len();
            batch_groups[batch_idx as usize].push(row_idx);
            output_positions.push((batch_idx as usize, group_idx));
        }

        // Take from each batch and collect results
        let mut taken_arrays: Vec<ArrayRef> = Vec::with_capacity(batches.len());
        let mut taken_offsets: Vec<usize> = vec![0];
        let mut total_len = 0;

        for (batch_idx, group) in batch_groups.iter().enumerate() {
            if group.is_empty() {
                taken_arrays.push(batches[batch_idx].column(col_idx).slice(0, 0));
            } else {
                let indices_array = UInt32Array::from(group.clone());
                let col = batches[batch_idx].column(col_idx);
                let taken = take(col.as_ref(), &indices_array, None)
                    .map_err(|e| EngineError::Internal(format!("take error: {e}")))?;
                total_len += taken.len();
                taken_arrays.push(taken);
            }
            taken_offsets.push(total_len);
        }

        // If all from one batch, return directly (optimization)
        let non_empty: Vec<_> = taken_arrays.iter().filter(|a| a.len() > 0).collect();
        if non_empty.len() == 1 {
            // Clone the single non-empty array to return
            return Ok(non_empty[0].clone());
        }

        // Concatenate all taken arrays
        let array_refs: Vec<&dyn Array> = taken_arrays.iter().map(|a| a.as_ref()).collect();
        let concatenated =
            concat(&array_refs).map_err(|e| EngineError::Internal(format!("concat error: {e}")))?;

        // Reorder to match original output order
        let mut reorder_indices: Vec<u32> = vec![0; indices.len()];
        for (output_idx, (batch_idx, group_idx)) in output_positions.iter().enumerate() {
            let offset = taken_offsets[*batch_idx];
            reorder_indices[output_idx] = (offset + group_idx) as u32;
        }

        let reorder_array = UInt32Array::from(reorder_indices);
        take(concatenated.as_ref(), &reorder_array, None)
            .map_err(|e| EngineError::Internal(format!("reorder error: {e}")))
    }

    /// Explain query execution plan without executing the query
    pub fn explain(&self, sql: &str) -> Result<ExplainPlan, EngineError> {
        if sql.trim().is_empty() {
            return Err(EngineError::InvalidArgument("empty SQL".into()));
        }

        let agg = parse_agg(sql)?;
        let (db, table) = parse_table_target(sql)?;
        let projection = parse_projection(sql)?;
        let filter = parse_filters(sql)?;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Collect matching segments
        let matching: Vec<ManifestEntry> = manifest
            .entries
            .iter()
            .filter(|e| {
                let entry_db = e.database.as_str();
                let entry_table = e.table.as_str();
                let watermark_ok = filter
                    .watermark_ge
                    .map(|wm| e.watermark_micros >= wm)
                    .unwrap_or(true)
                    && filter
                        .watermark_le
                        .map(|wm| e.watermark_micros <= wm)
                        .unwrap_or(true);
                let event_time_ok = filter
                    .event_time_ge
                    .map(|et| e.event_time_max.unwrap_or(u64::MAX) >= et)
                    .unwrap_or(true)
                    && filter
                        .event_time_le
                        .map(|et| e.event_time_min.unwrap_or(0) <= et)
                        .unwrap_or(true);
                entry_db == db && entry_table == table && watermark_ok && event_time_ok
            })
            .cloned()
            .collect();

        let total_bytes: u64 = matching.iter().map(|e| e.size_bytes).sum();
        let uses_bloom = filter.tenant_id_eq.is_some() || filter.route_id_eq.is_some();

        // Build filter descriptions
        let mut filters = Vec::new();
        if let Some(v) = filter.watermark_ge {
            filters.push(format!("watermark_micros >= {}", v));
        }
        if let Some(v) = filter.watermark_le {
            filters.push(format!("watermark_micros <= {}", v));
        }
        if let Some(v) = filter.event_time_ge {
            filters.push(format!("event_time >= {}", v));
        }
        if let Some(v) = filter.event_time_le {
            filters.push(format!("event_time <= {}", v));
        }
        if let Some(v) = filter.tenant_id_eq {
            filters.push(format!("tenant_id = {} (bloom filter)", v));
        }
        if let Some(v) = filter.route_id_eq {
            filters.push(format!("route_id = {} (bloom filter)", v));
        }

        // Build order by descriptions
        let order_by = filter.order_by.as_ref().map(|ob| {
            ob.iter()
                .map(|(col, asc)| format!("{} {}", col, if *asc { "ASC" } else { "DESC" }))
                .collect()
        });

        // Calculate cost estimates using optimizer cost model
        let cost_params = crate::optimizer::CostModelParams::default();
        let num_pages = total_bytes as f64 / cost_params.page_size as f64;
        let io_cost = if uses_bloom {
            // Index scan - mostly random reads
            num_pages * cost_params.random_page_cost * 0.1 // Bloom filter reduces to ~10%
        } else {
            // Sequential scan
            num_pages * cost_params.seq_page_cost
        };

        // Estimate rows based on segment count and average rows per segment (assumed ~10K)
        let estimated_row_count = matching.len() as u64 * 10_000;
        let estimated_rows = Some(estimated_row_count);
        let cpu_cost = estimated_row_count as f64 * cost_params.cpu_tuple_cost;

        // Calculate selectivity based on filters
        let selectivity = if filters.is_empty() {
            Some(1.0)
        } else {
            // Rough estimate: each filter reduces selectivity by ~50%
            Some(0.5_f64.powi(filters.len() as i32))
        };

        let estimated_cost = Some(io_cost + cpu_cost);

        Ok(ExplainPlan {
            database: db.to_string(),
            table: table.to_string(),
            projection,
            filters,
            aggregation: agg.map(|a| format!("{:?}", a)),
            order_by,
            limit: filter.limit,
            offset: filter.offset,
            segments_to_scan: matching.len(),
            total_bytes,
            estimated_rows,
            uses_parallel_scan: matching.len() >= self.cfg.parallel_scan_threshold,
            uses_bloom_filter: uses_bloom,
            estimated_cost,
            cpu_cost: Some(cpu_cost),
            io_cost: Some(io_cost),
            selectivity,
            // ANALYZE fields - populated by explain_analyze()
            actual_rows: None,
            actual_time_ms: None,
            actual_segments_scanned: None,
            actual_bytes_read: None,
            cache_hits: None,
            cache_misses: None,
        })
    }

    /// Execute EXPLAIN ANALYZE - runs the query and captures actual execution stats
    pub fn explain_analyze(&self, sql: &str) -> Result<ExplainPlan, EngineError> {
        // Get the base explain plan
        let mut plan = self.explain(sql)?;

        // Capture cache stats before query
        let cache_hits_before = self.segment_cache.hits();
        let cache_misses_before = self.segment_cache.misses();

        // Execute the query and capture stats
        let start = std::time::Instant::now();

        // Execute the query with stats collection
        let request = QueryRequest {
            sql: sql.to_string(),
            timeout_millis: 30000,
            collect_stats: true,
            transaction_id: None,
        };

        match self.query(request) {
            Ok(response) => {
                let elapsed = start.elapsed();
                plan.actual_time_ms = Some(elapsed.as_secs_f64() * 1000.0);
                plan.actual_segments_scanned = Some(response.segments_scanned);
                plan.actual_bytes_read = Some(response.data_skipped_bytes);

                // Parse IPC to count actual rows
                if !response.records_ipc.is_empty() {
                    if let Ok(batches) = read_ipc_batches(&response.records_ipc) {
                        let total_rows: usize = batches.iter().map(|b| b.num_rows()).sum();
                        plan.actual_rows = Some(total_rows as u64);
                    }
                }

                // Calculate cache stats delta
                let cache_hits_after = self.segment_cache.hits();
                let cache_misses_after = self.segment_cache.misses();
                plan.cache_hits = Some(cache_hits_after.saturating_sub(cache_hits_before));
                plan.cache_misses = Some(cache_misses_after.saturating_sub(cache_misses_before));
            }
            Err(e) => {
                // Query failed but we can still return partial plan
                plan.actual_time_ms = Some(start.elapsed().as_secs_f64() * 1000.0);
                tracing::warn!("EXPLAIN ANALYZE query failed: {}", e);
            }
        }

        Ok(plan)
    }

    pub fn maintenance(&self) -> Result<(), EngineError> {
        self.prune_by_retention()?;
        self.apply_tiering_rules()?;
        if self.cfg.enable_compaction {
            self.run_compaction_pass()?;
        }
        Ok(())
    }

    // ==========================================================================
    // Query Optimizer Integration
    // ==========================================================================

    /// Update table statistics for the optimizer's cost model.
    /// Prefers ANALYZE-generated statistics (with histograms) over segment-level estimates.
    pub fn update_optimizer_stats(&self, database: &str, table: &str) -> Result<(), EngineError> {
        use crate::optimizer::{
            ColumnStatistics as OptimizerColStats, Histogram, HistogramBucket, StatValue,
            TableStats,
        };

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // First, check if we have ANALYZE-generated statistics (preferred - has histograms)
        let analyze_stats = manifest
            .table_stats
            .iter()
            .find(|s| s.database == database && s.table == table);

        if let Some(table_stats_meta) = analyze_stats {
            // Use ANALYZE-generated statistics with histograms
            let stats = Self::convert_analyze_stats_to_optimizer(table_stats_meta);

            // Update the optimizer context
            let mut optimizer_ctx = self.optimizer_context.write();
            optimizer_ctx.update_table_stats(database, table, stats);

            tracing::debug!(
                "Updated optimizer stats for {}.{} from ANALYZE (row_count={}, {} columns)",
                database,
                table,
                table_stats_meta.row_count,
                table_stats_meta.columns.len()
            );
            return Ok(());
        }

        // Fall back to segment-level statistics if no ANALYZE stats available
        let matching: Vec<&ManifestEntry> = manifest
            .entries
            .iter()
            .filter(|e| e.database == database && e.table == table)
            .collect();

        if matching.is_empty() {
            return Ok(());
        }

        let total_bytes: u64 = matching.iter().map(|e| e.size_bytes).sum();
        // Better row estimation: use segment row counts if available, else estimate
        let estimated_rows = matching
            .iter()
            .filter_map(|e| e.column_stats.as_ref())
            .flat_map(|cs| cs.values())
            .map(|cs| cs.row_count)
            .max()
            .unwrap_or(total_bytes / 100); // Fall back to 100 bytes/row estimate

        let mut stats = TableStats {
            row_count: estimated_rows,
            size_bytes: total_bytes,
            segment_count: matching.len() as u64,
            columns: std::collections::HashMap::new(),
            last_updated: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs(),
            correlations: std::collections::HashMap::new(), // Correlations require ANALYZE
        };

        // Helper function to convert PrimitiveValue to StatValue
        fn primitive_to_stat_value(
            pv: &crate::replication::PrimitiveValue,
        ) -> crate::optimizer::StatValue {
            use crate::optimizer::StatValue;
            use crate::replication::PrimitiveValue;
            match pv {
                PrimitiveValue::Int64(v) => StatValue::Int64(*v),
                PrimitiveValue::Int32(v) => StatValue::Int64(*v as i64),
                PrimitiveValue::UInt64(v) => StatValue::Int64(*v as i64),
                PrimitiveValue::UInt32(v) => StatValue::Int64(*v as i64),
                PrimitiveValue::Float64(v) => StatValue::Float64(*v),
                PrimitiveValue::Float32(v) => StatValue::Float64(*v as f64),
                PrimitiveValue::String(s) => StatValue::String(s.clone()),
                PrimitiveValue::Boolean(b) => StatValue::Bool(*b),
                PrimitiveValue::TimestampMicros(v) => StatValue::Int64(*v),
                PrimitiveValue::Date32(v) => StatValue::Int64(*v as i64),
            }
        }

        // Aggregate column statistics from segments with proper min/max tracking
        for entry in &matching {
            if let Some(ref col_stats_map) = entry.column_stats {
                for (col, col_stats) in col_stats_map {
                    let entry_stats = stats
                        .columns
                        .entry(col.clone())
                        .or_insert_with(OptimizerColStats::default);

                    // Update min value (take true minimum across segments)
                    if let Some(ref min) = col_stats.min {
                        let min_val = primitive_to_stat_value(min);
                        match (&entry_stats.min_value, &min_val) {
                            (None, _) => entry_stats.min_value = Some(min_val),
                            (Some(existing), new) if new < existing => {
                                entry_stats.min_value = Some(new.clone())
                            }
                            _ => {}
                        }
                    }

                    // Update max value (take true maximum across segments)
                    if let Some(ref max) = col_stats.max {
                        let max_val = primitive_to_stat_value(max);
                        match (&entry_stats.max_value, &max_val) {
                            (None, _) => entry_stats.max_value = Some(max_val),
                            (Some(existing), new) if new > existing => {
                                entry_stats.max_value = Some(new.clone())
                            }
                            _ => {}
                        }
                    }

                    // For distinct count, use HyperLogLog-style estimation (max of segments)
                    // since summing overestimates due to duplicates across segments
                    if let Some(distinct) = col_stats.distinct_count {
                        entry_stats.distinct_count =
                            entry_stats.distinct_count.max(distinct);
                    }

                    // Null count sums across segments
                    entry_stats.null_count += col_stats.null_count;
                }
            }
        }

        // Update the optimizer context
        let mut optimizer_ctx = self.optimizer_context.write();
        optimizer_ctx.update_table_stats(database, table, stats);

        tracing::debug!(
            "Updated optimizer stats for {}.{} from segments (estimated_rows={}, {} segments)",
            database,
            table,
            estimated_rows,
            matching.len()
        );

        Ok(())
    }

    /// Convert ANALYZE-generated TableStatsMeta to optimizer TableStats format
    fn convert_analyze_stats_to_optimizer(
        meta: &crate::replication::TableStatsMeta,
    ) -> crate::optimizer::TableStats {
        use crate::optimizer::{
            ColumnStatistics as OptimizerColStats, Histogram, HistogramBucket, McvEntry,
            MostCommonValues, StatValue, TableStats,
        };

        let mut columns = std::collections::HashMap::new();

        for (col_name, col_meta) in &meta.columns {
            let mut col_stats = OptimizerColStats {
                distinct_count: col_meta.distinct_count,
                null_count: col_meta.null_count,
                min_value: col_meta.min_value.as_ref().and_then(|s| parse_stat_value(s)),
                max_value: col_meta.max_value.as_ref().and_then(|s| parse_stat_value(s)),
                avg_length: col_meta.avg_length,
                histogram: None,
                most_common_values: None,
            };

            // Convert histogram if present
            if let Some(ref hist_meta) = col_meta.histogram {
                col_stats.histogram = Some(Self::convert_histogram_meta(hist_meta));
            }

            // Convert MCV if present
            if let Some(ref mcv_meta) = col_meta.most_common_values {
                col_stats.most_common_values = Some(Self::convert_mcv_meta(mcv_meta));
            }

            columns.insert(col_name.clone(), col_stats);
        }

        TableStats {
            row_count: meta.row_count,
            size_bytes: meta.size_bytes,
            segment_count: meta.segment_count,
            columns,
            last_updated: meta.last_updated / 1000, // Convert millis to secs
            correlations: meta.correlations.clone(),
        }
    }

    /// Convert McvMeta to optimizer MostCommonValues format
    fn convert_mcv_meta(meta: &crate::replication::McvMeta) -> crate::optimizer::MostCommonValues {
        use crate::optimizer::{McvEntry, MostCommonValues, StatValue};

        let total_rows_f64 = meta.total_rows.max(1) as f64;
        let values: Vec<McvEntry> = meta
            .values
            .iter()
            .zip(meta.counts.iter())
            .map(|(val_str, count)| {
                let value = parse_stat_value(val_str).unwrap_or(StatValue::String(val_str.clone()));
                let frequency = *count as f64 / total_rows_f64;
                McvEntry {
                    value,
                    count: *count,
                    frequency,
                }
            })
            .collect();

        // Use constructor which computes cached total_mcv_frequency
        MostCommonValues::new(values, meta.total_rows)
    }

    /// Convert HistogramMeta to optimizer Histogram format
    fn convert_histogram_meta(meta: &crate::replication::HistogramMeta) -> crate::optimizer::Histogram {
        use crate::optimizer::{Histogram, HistogramBucket, StatValue};

        let mut buckets = Vec::with_capacity(meta.num_buckets);

        // HistogramMeta stores boundaries as [b0, b1, b2, ...] where bucket i spans [bi, bi+1]
        for i in 0..meta.num_buckets {
            if i + 1 >= meta.boundaries.len() {
                break;
            }

            let lower = parse_stat_value(&meta.boundaries[i]).unwrap_or(StatValue::Null);
            let upper = parse_stat_value(&meta.boundaries[i + 1]).unwrap_or(StatValue::Null);
            let count = meta.counts.get(i).copied().unwrap_or(0);
            let distinct_count = meta.distinct_counts.get(i).copied().unwrap_or(1);

            buckets.push(HistogramBucket {
                lower_bound: lower,
                upper_bound: upper,
                count,
                distinct_count,
            });
        }

        Histogram { buckets }
    }

    /// Enable or disable the query optimizer
    pub fn set_optimizer_enabled(&self, enabled: bool) {
        let mut optimizer_ctx = self.optimizer_context.write();
        optimizer_ctx.enabled = enabled;
    }

    /// Check if the optimizer is enabled
    pub fn is_optimizer_enabled(&self) -> bool {
        let optimizer_ctx = self.optimizer_context.read();
        optimizer_ctx.enabled
    }

    /// Track rows changed for a table and trigger stats update if needed
    /// This is called after successful data ingestion
    fn track_rows_and_maybe_update_stats(
        &self,
        database: &str,
        table: &str,
        rows_ingested: u64,
    ) {
        if !self.cfg.auto_stats_enabled {
            return;
        }

        let table_key = format!("{}.{}", database, table);
        let now_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs())
            .unwrap_or(0);

        let should_update = {
            let mut tracker = self.stats_tracker.write();
            let state = tracker.tables.entry(table_key.clone()).or_insert(TableStatsState {
                rows_changed: 0,
                last_update_secs: 0,
                updating: false,
            });

            state.rows_changed += rows_ingested;

            // Check if we should trigger an update
            let rows_threshold_met = state.rows_changed >= self.cfg.auto_stats_min_rows_changed;
            let cooldown_elapsed =
                now_secs.saturating_sub(state.last_update_secs) >= self.cfg.auto_stats_cooldown_secs;

            // Prevent concurrent updates (race condition fix)
            if rows_threshold_met && cooldown_elapsed && !state.updating {
                // Mark as updating to prevent other threads from starting concurrent updates
                state.updating = true;
                state.rows_changed = 0;
                state.last_update_secs = now_secs;
                true
            } else {
                false
            }
        };

        if should_update {
            // Update optimizer stats from segment-level data
            // This is cheaper than a full ANALYZE
            let result = self.update_optimizer_stats(database, table);

            // Clear the updating flag
            {
                let mut tracker = self.stats_tracker.write();
                if let Some(state) = tracker.tables.get_mut(&table_key) {
                    state.updating = false;
                }
            }

            if let Err(e) = result {
                tracing::warn!(
                    "Auto-stats update failed for {}.{}: {}",
                    database,
                    table,
                    e
                );
            } else {
                tracing::debug!(
                    "Auto-stats updated for {}.{} (rows threshold reached)",
                    database,
                    table
                );
            }
        }
    }

    /// Force refresh statistics for a table from segment-level data
    /// This is faster than ANALYZE but less accurate (no histograms/MCV unless ANALYZE was run)
    pub fn refresh_stats(&self, database: &str, table: &str) -> Result<(), EngineError> {
        self.update_optimizer_stats(database, table)
    }

    /// Generate an optimized physical plan for a query
    pub fn optimize_query(
        &self,
        query: &crate::sql::ParsedQuery,
    ) -> Result<crate::optimizer::PhysicalPlan, EngineError> {
        let optimizer_ctx = self.optimizer_context.read();
        optimizer_ctx.optimize_query(query)
    }

    /// Execute a physical plan and return results
    pub fn execute_physical_plan(
        &self,
        plan: &crate::optimizer::PhysicalPlan,
    ) -> Result<Vec<arrow_array::RecordBatch>, EngineError> {
        let mut executor = crate::optimizer_integration::PhysicalPlanExecutor::new(self);
        executor.execute(plan)
    }

    fn prune_by_retention(&self) -> Result<(), EngineError> {
        if let Some(cutoff) = self.cfg.retention_watermark_micros {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let mut removed = Vec::new();
            manifest.entries.retain(|e| {
                let keep = e.watermark_micros >= cutoff || e.watermark_micros == 0;
                if !keep {
                    removed.push(e.segment_id.clone());
                }
                keep
            });
            if !removed.is_empty() {
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
                // Rebuild manifest index after entries removed
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
            drop(manifest);
            for seg in removed {
                self.remove_segment_file(&seg);
            }
        }
        Ok(())
    }

    fn apply_tiering_rules(&self) -> Result<(), EngineError> {
        let warm_after_micros = self.cfg.tier_warm_after_millis.saturating_mul(1_000);
        let cold_after_micros = self.cfg.tier_cold_after_millis.saturating_mul(1_000);
        let warm_compression = normalize_compression(self.cfg.tier_warm_compression.clone())?;
        let cold_compression = normalize_compression(self.cfg.tier_cold_compression.clone())?;

        if warm_after_micros == 0 && cold_after_micros == 0 {
            return Ok(());
        }

        let now = current_time_micros();
        let mut changed = false;
        let mut changed_tables: HashSet<(String, String)> = HashSet::new();
        let mut recompress_jobs: Vec<(ManifestEntry, Option<String>)> = Vec::new();
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            for entry in manifest.entries.iter_mut() {
                let Some(age) = segment_age_micros(entry, now) else {
                    continue;
                };
                let target_tier = if cold_after_micros > 0 && age >= cold_after_micros {
                    SegmentTier::Cold
                } else if warm_after_micros > 0 && age >= warm_after_micros {
                    SegmentTier::Warm
                } else {
                    entry.tier.clone()
                };
                let target_compression = match target_tier {
                    SegmentTier::Cold => cold_compression.clone(),
                    SegmentTier::Warm => warm_compression.clone(),
                    SegmentTier::Hot => None,
                };

                if target_tier != entry.tier {
                    entry.tier = target_tier;
                    changed = true;
                    changed_tables.insert((entry.database.clone(), entry.table.clone()));
                }
                if let Some(target) = target_compression {
                    if entry.compression.as_deref() != Some(target.as_str()) {
                        recompress_jobs.push((entry.clone(), Some(target.clone())));
                        changed_tables.insert((entry.database.clone(), entry.table.clone()));
                    }
                }
            }

            if changed {
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
        }

        if !recompress_jobs.is_empty() {
            let mut updates = Vec::with_capacity(recompress_jobs.len());
            for (entry, new_compression) in recompress_jobs {
                let raw = load_segment_raw(&self.storage, &entry)?;
                let decoded = decompress_payload(raw, entry.compression.as_deref())?;
                let stored = compress_payload(&decoded, new_compression.as_deref())?;
                persist_segment_ipc(&self.storage, &entry.segment_id, &stored)?;
                updates.push((
                    entry.segment_id.clone(),
                    stored.len() as u64,
                    compute_checksum(&stored),
                    new_compression,
                ));
            }

            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            for (segment_id, size_bytes, checksum, compression) in &updates {
                if let Some(entry) = manifest
                    .entries
                    .iter_mut()
                    .find(|e| e.segment_id == *segment_id)
                {
                    entry.size_bytes = *size_bytes;
                    entry.checksum = *checksum;
                    entry.compression = compression.clone();
                }
            }
            if !updates.is_empty() {
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }

            // Invalidate caches - both caches are sharded (each shard has independent lock)
            for (segment_id, _, _, _) in updates {
                self.segment_cache.invalidate(&segment_id);
                self.batch_cache.invalidate(&segment_id);
            }
            changed = true;
        }

        if changed {
            let mut cache = self.query_cache.lock();
            for (db, tbl) in changed_tables {
                cache.invalidate_table(&db, &tbl);
            }
        }

        Ok(())
    }

    fn run_compaction_pass(&self) -> Result<(), EngineError> {
        let target_bytes = self.cfg.compaction_target_bytes;
        let min_segments = self.cfg.compact_min_segments;
        if target_bytes == 0 || min_segments < 2 {
            return Ok(());
        }

        // Use configurable passes per cycle (default 32, higher when many segments)
        let passes = self.cfg.compaction_passes_per_cycle;
        for _ in 0..passes {
            let candidate = self.pick_compaction_candidate(target_bytes, min_segments, None)?;
            let Some((entries, table_meta)) = candidate else {
                break;
            };
            self.compact_entries(entries, table_meta)?;
        }
        Ok(())
    }

    fn pick_compaction_candidate(
        &self,
        target_bytes: u64,
        min_segments: usize,
        filter_table: Option<(String, String)>,
    ) -> Result<Option<(Vec<ManifestEntry>, Option<TableMeta>)>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut best: Option<(Vec<ManifestEntry>, Option<TableMeta>)> = None;
        let mut best_bytes = 0u64;

        // Group hot segments per table
        let mut grouped: HashMap<(String, String), Vec<ManifestEntry>> = HashMap::new();
        for entry in &manifest.entries {
            if let Some(ref filter) = filter_table {
                if &entry.database != &filter.0 || &entry.table != &filter.1 {
                    continue;
                }
            }
            if !matches!(entry.tier, SegmentTier::Hot) {
                continue;
            }
            grouped
                .entry((entry.database.clone(), entry.table.clone()))
                .or_default()
                .push(entry.clone());
        }

        let max_segments = self.cfg.max_segments_per_compaction;
        for ((db, tbl), mut entries) in grouped {
            entries.retain(|e| e.size_bytes < target_bytes);
            if entries.len() < min_segments {
                continue;
            }
            entries.sort_by_key(|e| e.size_bytes);
            let mut chunk = Vec::new();
            let mut bytes = 0u64;
            for entry in entries {
                // Stop if we've reached max segments or target bytes
                if chunk.len() >= max_segments {
                    break;
                }
                if bytes + entry.size_bytes > target_bytes && !chunk.is_empty() {
                    break;
                }
                bytes = bytes.saturating_add(entry.size_bytes);
                chunk.push(entry);
            }
            if chunk.len() < min_segments || bytes == 0 {
                continue;
            }
            if bytes <= target_bytes && bytes > best_bytes {
                best_bytes = bytes;
                let table_meta = manifest
                    .tables
                    .iter()
                    .find(|t| t.database == db && t.name == tbl)
                    .cloned();
                best = Some((chunk, table_meta));
            }
        }

        Ok(best)
    }

    pub fn compact_table(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Option<ManifestEntry>, EngineError> {
        self.require_writable()?;
        if !self.cfg.enable_compaction {
            return Ok(None);
        }

        let db_name = if database.is_empty() {
            "default"
        } else {
            database
        };
        let table_name = if table.is_empty() { "default" } else { table };
        let candidate = self.pick_compaction_candidate(
            self.cfg.compaction_target_bytes,
            self.cfg.compact_min_segments,
            Some((db_name.to_string(), table_name.to_string())),
        )?;

        if let Some((entries, table_meta)) = candidate {
            let new_entry = self.compact_entries(entries, table_meta)?;
            return Ok(Some(new_entry));
        }

        Ok(None)
    }

    /// Get the total number of segments in the manifest
    pub fn segment_count(&self) -> usize {
        self.manifest
            .read()
            .map(|m| m.entries.len())
            .unwrap_or(0)
    }

    /// Get segment counts per table
    pub fn segment_counts_per_table(&self) -> HashMap<(String, String), usize> {
        let manifest = match self.manifest.read() {
            Ok(m) => m,
            Err(_) => return HashMap::new(),
        };
        let mut counts: HashMap<(String, String), usize> = HashMap::new();
        for entry in manifest.entries.iter() {
            *counts.entry((entry.database.clone(), entry.table.clone())).or_insert(0) += 1;
        }
        counts
    }

    /// Check if segment count exceeds hard limit (should reject writes)
    pub fn is_segment_limit_exceeded(&self) -> bool {
        if self.cfg.max_segments_hard_limit == 0 {
            return false;
        }
        self.segment_count() >= self.cfg.max_segments_hard_limit
    }

    /// Check if emergency compaction should be triggered
    pub fn needs_emergency_compaction(&self) -> bool {
        if self.cfg.max_segments_emergency_threshold == 0 {
            return false;
        }
        let count = self.segment_count();
        if count >= self.cfg.max_segments_emergency_threshold {
            return true;
        }
        // Also check per-table limits
        if self.cfg.max_segments_per_table > 0 {
            let counts = self.segment_counts_per_table();
            for &table_count in counts.values() {
                if table_count >= self.cfg.max_segments_per_table {
                    return true;
                }
            }
        }
        false
    }

    /// Calculate adaptive backpressure delay based on segment count
    /// Returns delay in milliseconds (0 = no delay)
    pub fn calculate_backpressure_delay(&self) -> u64 {
        if !self.cfg.adaptive_backpressure_enabled || self.cfg.max_segments_emergency_threshold == 0 {
            return 0;
        }
        let count = self.segment_count();
        let start_threshold = (self.cfg.max_segments_emergency_threshold as u64
            * self.cfg.adaptive_backpressure_start_pct as u64) / 100;

        if count < start_threshold as usize {
            return 0;
        }

        // Linear interpolation from start_threshold to emergency_threshold
        let range = self.cfg.max_segments_emergency_threshold.saturating_sub(start_threshold as usize);
        if range == 0 {
            return self.cfg.adaptive_backpressure_max_delay_ms;
        }

        let progress = count.saturating_sub(start_threshold as usize);
        let ratio = (progress as f64 / range as f64).min(1.0);
        (ratio * self.cfg.adaptive_backpressure_max_delay_ms as f64) as u64
    }

    /// Run emergency compaction on tables exceeding segment limits
    /// Returns number of segments compacted
    /// Uses parallel compaction across tables for faster catch-up
    pub fn run_emergency_compaction(&self) -> Result<usize, EngineError> {
        self.require_writable()?;

        let total_segments = self.segment_count();
        let needs_emergency = self.needs_emergency_compaction();

        if !needs_emergency {
            return Ok(0);
        }

        tracing::warn!(
            total_segments = total_segments,
            emergency_threshold = self.cfg.max_segments_emergency_threshold,
            parallelism = self.cfg.emergency_compaction_parallelism,
            "EMERGENCY COMPACTION: segment count exceeds threshold, starting parallel compaction"
        );

        // Get tables sorted by segment count (highest first)
        let mut table_counts: Vec<((String, String), usize)> =
            self.segment_counts_per_table().into_iter().collect();
        table_counts.sort_by(|a, b| b.1.cmp(&a.1));

        let target = self.cfg.emergency_compaction_target_segments;
        let max_iterations = 20; // Increased for more aggressive compaction

        // Filter to tables needing compaction
        let tables_to_compact: Vec<_> = table_counts
            .into_iter()
            .filter(|(_, count)| *count > target)
            .collect();

        if tables_to_compact.is_empty() {
            return Ok(0);
        }

        tracing::info!(
            tables = tables_to_compact.len(),
            "Emergency compaction: processing tables in parallel"
        );

        // Use rayon for parallel compaction across tables
        use rayon::prelude::*;
        use std::sync::atomic::{AtomicUsize, Ordering as AtomicOrdering};

        let compacted = AtomicUsize::new(0);
        let parallelism = self.cfg.emergency_compaction_parallelism.max(1);

        // Build a thread pool with limited parallelism
        let pool = rayon::ThreadPoolBuilder::new()
            .num_threads(parallelism)
            .build()
            .unwrap_or_else(|_| rayon::ThreadPoolBuilder::new().build().unwrap());

        pool.install(|| {
            tables_to_compact.par_iter().for_each(|((database, table), initial_count)| {
                tracing::info!(
                    database = %database,
                    table = %table,
                    segments = initial_count,
                    target = target,
                    "Emergency compacting table (parallel)"
                );

                let mut iterations = 0;
                loop {
                    iterations += 1;
                    if iterations > max_iterations {
                        tracing::warn!(
                            database = %database,
                            table = %table,
                            iterations = iterations,
                            "Emergency compaction: max iterations reached"
                        );
                        break;
                    }

                    match self.compact_table(database, table) {
                        Ok(Some(_)) => {
                            compacted.fetch_add(1, AtomicOrdering::Relaxed);
                            // Check if we've reached target
                            let new_count = self.segment_counts_per_table()
                                .get(&(database.clone(), table.clone()))
                                .copied()
                                .unwrap_or(0);
                            if new_count <= target {
                                tracing::info!(
                                    database = %database,
                                    table = %table,
                                    new_count = new_count,
                                    iterations = iterations,
                                    "Emergency compaction: reached target"
                                );
                                break;
                            }
                        }
                        Ok(None) => {
                            // No more segments to compact
                            break;
                        }
                        Err(e) => {
                            tracing::error!(
                                database = %database,
                                table = %table,
                                error = %e,
                                "Emergency compaction failed"
                            );
                            break;
                        }
                    }
                }
            });
        });

        let total_compacted = compacted.load(AtomicOrdering::Relaxed);
        tracing::info!(
            compacted = total_compacted,
            remaining_segments = self.segment_count(),
            "Emergency compaction completed"
        );

        Ok(total_compacted)
    }

    /// Compact all tables in the database
    /// Returns the number of tables that were compacted
    pub fn compact_all(&self) -> Result<usize, EngineError> {
        self.require_writable()?;
        if !self.cfg.enable_compaction {
            return Ok(0);
        }

        // Get list of all unique database.table pairs
        let tables: Vec<(String, String)> = {
            let manifest = self.manifest.read().map_err(|_| {
                EngineError::Internal("manifest lock poisoned".into())
            })?;

            let mut tables = std::collections::HashSet::new();
            for entry in &manifest.entries {
                tables.insert((entry.database.clone(), entry.table.clone()));
            }
            tables.into_iter().collect()
        };

        let mut compacted = 0;
        for (database, table) in tables {
            // Try to compact each table, continue on error
            match self.compact_table(&database, &table) {
                Ok(Some(_)) => {
                    compacted += 1;
                    tracing::debug!(database = %database, table = %table, "compacted table");
                }
                Ok(None) => {
                    // No compaction needed for this table
                }
                Err(e) => {
                    tracing::warn!(
                        database = %database,
                        table = %table,
                        error = %e,
                        "failed to compact table"
                    );
                }
            }
        }

        Ok(compacted)
    }

    fn compact_entries(
        &self,
        entries: Vec<ManifestEntry>,
        table_meta: Option<TableMeta>,
    ) -> Result<ManifestEntry, EngineError> {
        if entries.is_empty() {
            return Err(EngineError::InvalidArgument(
                "no entries provided for compaction".into(),
            ));
        }

        let db_name = if entries[0].database.is_empty() {
            "default".to_string()
        } else {
            entries[0].database.clone()
        };
        let table_name = if entries[0].table.is_empty() {
            "default".to_string()
        } else {
            entries[0].table.clone()
        };

        // Validate all entries belong to the same table
        for e in &entries {
            if e.database != db_name || e.table != table_name {
                return Err(EngineError::InvalidArgument(
                    "compaction requires all entries to belong to the same table".into(),
                ));
            }
        }

        // Load segments - use parallel loading for multiple segments
        let batches: Vec<RecordBatch> = if self.cfg.parallel_merge_enabled
            && entries.len() >= self.cfg.parallel_merge_min_segments
        {
            // Parallel segment loading using rayon
            let results: Vec<Result<Arc<Vec<RecordBatch>>, EngineError>> = entries
                .par_iter()
                .map(|e| self.load_segment_batches_cached(e))
                .collect();

            let mut all_batches = Vec::new();
            for res in results {
                all_batches.extend(res?.iter().cloned());
            }
            all_batches
        } else {
            // Sequential loading for small number of segments
            let mut all_batches = Vec::new();
            for e in &entries {
                let decoded = self.load_segment_batches_cached(e)?;
                all_batches.extend(decoded.iter().cloned());
            }
            all_batches
        };

        if batches.is_empty() {
            return Err(EngineError::InvalidArgument(
                "no rows found for compaction".into(),
            ));
        }

        let schema = batches[0].schema();
        let merged_ipc = record_batches_to_ipc(schema.as_ref(), &batches)?;
        let sorted_ipc = sort_hot_payload(&merged_ipc, self.cfg.index_granularity_rows)?;
        let validated = validate_and_stats(&sorted_ipc, table_meta.as_ref())?;
        let max_watermark = entries
            .iter()
            .map(|e| e.watermark_micros)
            .max()
            .unwrap_or(0);
        let compression = normalize_compression(
            table_meta
                .as_ref()
                .and_then(|t| t.compression.clone())
                .or_else(|| entries.first().and_then(|e| e.compression.clone())),
        )?;
        let encodings = column_encodings_from_schema_json(
            table_meta.as_ref().and_then(|t| t.schema_json.as_ref()),
        )?;
        let encoded_payload = apply_column_encodings(&sorted_ipc, &encodings)?;
        let stored_payload = compress_payload(&encoded_payload, compression.as_deref())?;

        let seq = self.segment_seq.fetch_add(1, Ordering::SeqCst);
        let shard_id = (seq % (self.shards.len() as u64)) as usize;
        let segment_id = format!("cmp-{shard_id}-{seq}");
        let mut new_entry = ManifestEntry {
            segment_id: segment_id.clone(),
            shard_id: shard_id as u16,
            version_added: 0,
            size_bytes: stored_payload.len() as u64,
            checksum: compute_checksum(&stored_payload),
            tier: SegmentTier::Warm,
            database: db_name.clone(),
            table: table_name.clone(),
            compression: compression.clone(),
            watermark_micros: max_watermark,
            event_time_min: validated.stats.event_time_min,
            event_time_max: validated.stats.event_time_max,
            tenant_id_min: validated.stats.tenant_id_min,
            tenant_id_max: validated.stats.tenant_id_max,
            route_id_min: validated.stats.route_id_min,
            route_id_max: validated.stats.route_id_max,
            bloom_tenant: validated.stats.bloom_tenant,
            bloom_route: validated.stats.bloom_route,
            column_stats: if validated.stats.column_stats.is_empty() {
                None
            } else {
                Some(validated.stats.column_stats.clone())
            },
            schema_hash: Some(validated.schema_hash),
            created_txn: None,
            deleted_txn: None,
            deleted_version: None,
        };

        persist_segment_ipc(&self.storage, &segment_id, &stored_payload)?;
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = entries.iter().map(|e| e.segment_id.clone()).collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            new_entry.version_added = manifest.version;
            manifest.entries.push(new_entry.clone());
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            // Rebuild manifest index after compaction
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(&db_name, &table_name);
        }

        // delete old segment files best-effort
        for e in &entries {
            self.remove_segment_file(&e.segment_id);
        }

        // Record compaction metrics
        let original_bytes: u64 = entries.iter().map(|e| e.size_bytes).sum();
        self.metrics.compactions_total.fetch_add(1, Ordering::Relaxed);
        self.metrics.compactions_bytes.fetch_add(original_bytes, Ordering::Relaxed);

        Ok(new_entry)
    }

    pub fn plan_bundle(&self, request: BundleRequest) -> Result<BundlePlan, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if let Some(sv) = request.since_version {
            if sv > manifest.version {
                return Err(EngineError::InvalidArgument(format!(
                    "since_version {sv} exceeds manifest version {}",
                    manifest.version
                )));
            }
        }
        if let Some(max_bytes) = request.max_bytes {
            if max_bytes == 0 {
                return Err(EngineError::InvalidArgument(
                    "max_bytes must be greater than zero".into(),
                ));
            }
        }
        if let Some(max_entries) = request.max_entries {
            if max_entries == 0 {
                return Err(EngineError::InvalidArgument(
                    "max_entries must be greater than zero".into(),
                ));
            }
        }
        if let Some(bps) = request.target_bytes_per_sec {
            if bps == 0 {
                return Err(EngineError::InvalidArgument(
                    "target_bytes_per_sec must be greater than zero".into(),
                ));
            }
        }
        let planner = BundlePlanner::new();
        Ok(planner.plan(&manifest, request))
    }

    pub fn export_bundle(&self, request: BundleRequest) -> Result<BundlePayload, EngineError> {
        let plan = self.plan_bundle(request)?;
        let mut segments = Vec::with_capacity(plan.entries.len());
        for entry in &plan.entries {
            let data = load_segment_raw(&self.storage, entry)?;
            segments.push(BundleSegment {
                entry: entry.clone(),
                data,
            });
        }
        Ok(BundlePayload { plan, segments })
    }

    pub fn validate_bundle(&self, payload: &BundlePayload) -> Result<(), EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        self.validate_bundle_plan(payload, &manifest)?;
        for seg in &payload.segments {
            self.validate_bundle_segment(seg)?;
        }
        Ok(())
    }

    pub fn apply_bundle(&self, payload: BundlePayload) -> Result<(), EngineError> {
        {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            self.validate_bundle_plan(&payload, &manifest)?;
        }

        // Persist segments first, then manifest updates.
        for seg in &payload.segments {
            self.validate_bundle_segment(seg)?;
            persist_segment_ipc(&self.storage, &seg.entry.segment_id, &seg.data)?;
        }

        let entries: Vec<ManifestEntry> = payload
            .segments
            .iter()
            .map(|seg| seg.entry.clone())
            .collect();
        let _added = self.append_manifest_entries(entries)?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if manifest.version < payload.plan.manifest_version {
            manifest.version = payload.plan.manifest_version;
        }
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        if let Some(plan_hash) = payload.plan.plan_hash {
            let mut replay = self.recent_bundle_hashes.lock();
            replay.put(plan_hash, ());
        }
        Ok(())
    }

    fn validate_bundle_plan(
        &self,
        payload: &BundlePayload,
        manifest: &Manifest,
    ) -> Result<(), EngineError> {
        let plan_total: u64 = payload.plan.entries.iter().map(|e| e.size_bytes).sum();
        if payload.plan.total_bytes != plan_total {
            return Err(EngineError::InvalidArgument(format!(
                "bundle plan total_bytes {} does not match entries sum {}",
                payload.plan.total_bytes, plan_total
            )));
        }
        if let Some(plan_hash) = payload.plan.plan_hash {
            let expected = compute_bundle_plan_hash(
                payload.plan.manifest_version,
                payload.plan.since_version,
                &payload.plan.entries,
                payload.plan.total_bytes,
                payload.plan.throttle_millis,
            );
            if expected != plan_hash {
                return Err(EngineError::InvalidArgument(
                    "bundle plan hash mismatch".into(),
                ));
            }

            let replay = self.recent_bundle_hashes.lock();
            if replay.contains(&plan_hash) {
                return Err(EngineError::InvalidArgument(
                    "bundle already applied".into(),
                ));
            }
        }

        let mut plan_ids = HashSet::new();
        for entry in &payload.plan.entries {
            if !plan_ids.insert(entry.segment_id.clone()) {
                return Err(EngineError::InvalidArgument(format!(
                    "bundle plan has duplicate segment id {}",
                    entry.segment_id
                )));
            }
        }
        for seg in &payload.segments {
            if !plan_ids.contains(&seg.entry.segment_id) {
                return Err(EngineError::InvalidArgument(format!(
                    "bundle segment {} not present in plan entries",
                    seg.entry.segment_id
                )));
            }
        }
        if plan_ids.len() != payload.segments.len() {
            return Err(EngineError::InvalidArgument(
                "bundle segments do not match plan entries".into(),
            ));
        }

        if payload.plan.manifest_version < manifest.version {
            return Err(EngineError::InvalidArgument(format!(
                "bundle manifest version {} behind local {}",
                payload.plan.manifest_version, manifest.version
            )));
        }

        if let Some(since_version) = payload.plan.since_version {
            if since_version > payload.plan.manifest_version {
                return Err(EngineError::InvalidArgument(
                    "bundle since_version exceeds manifest_version".into(),
                ));
            }
            if manifest.version < since_version {
                return Err(EngineError::InvalidArgument(format!(
                    "bundle since_version {} ahead of local {}",
                    since_version, manifest.version
                )));
            }
        }

        for seg in &payload.segments {
            if let Some(existing) = manifest
                .entries
                .iter()
                .find(|e| e.segment_id == seg.entry.segment_id)
            {
                if existing.checksum != seg.entry.checksum
                    || existing.size_bytes != seg.entry.size_bytes
                    || existing.compression != seg.entry.compression
                    || existing.schema_hash != seg.entry.schema_hash
                {
                    return Err(EngineError::InvalidArgument(format!(
                        "bundle segment {} conflicts with existing manifest entry",
                        seg.entry.segment_id
                    )));
                }
            }
        }

        Ok(())
    }

    fn validate_bundle_segment(&self, seg: &BundleSegment) -> Result<(), EngineError> {
        let chk = compute_checksum(&seg.data);
        if chk != seg.entry.checksum {
            return Err(EngineError::InvalidArgument(format!(
                "bundle segment {} checksum mismatch",
                seg.entry.segment_id
            )));
        }
        if let Some(expected_schema_hash) = seg.entry.schema_hash {
            let actual_schema_hash =
                compute_schema_hash_from_payload(&seg.data, seg.entry.compression.as_deref())?;
            if actual_schema_hash != expected_schema_hash {
                return Err(EngineError::InvalidArgument(format!(
                    "bundle segment {} schema hash mismatch",
                    seg.entry.segment_id
                )));
            }
        }
        if seg.entry.database.trim().is_empty() || seg.entry.table.trim().is_empty() {
            return Err(EngineError::InvalidArgument(format!(
                "bundle segment {} missing database/table",
                seg.entry.segment_id
            )));
        }
        normalize_compression(seg.entry.compression.clone())?;
        let payload_len = seg.data.len() as u64;
        if seg.entry.size_bytes != payload_len {
            return Err(EngineError::InvalidArgument(format!(
                "bundle segment {} size mismatch (entry {} vs payload {payload_len})",
                seg.entry.segment_id, seg.entry.size_bytes
            )));
        }
        Ok(())
    }

    pub fn export_manifest(&self) -> Result<Vec<u8>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        serde_json::to_vec(&*manifest)
            .map_err(|e| EngineError::Internal(format!("manifest serialize failed: {e}")))
    }

    pub fn import_manifest(&self, payload: &[u8], overwrite: bool) -> Result<(), EngineError> {
        if !self.cfg.allow_manifest_import {
            return Err(EngineError::NotImplemented(
                "manifest import disabled; set allow_manifest_import".into(),
            ));
        }
        let new_manifest: Manifest = serde_json::from_slice(payload)
            .map_err(|e| EngineError::InvalidArgument(format!("invalid manifest: {e}")))?;
        validate_manifest(&new_manifest)?;
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if overwrite {
            *manifest = new_manifest;
        } else {
            for entry in new_manifest.entries {
                if !manifest
                    .entries
                    .iter()
                    .any(|e| e.segment_id == entry.segment_id)
                {
                    manifest.entries.push(entry);
                }
            }
            for dbm in new_manifest.databases {
                if !manifest.databases.iter().any(|d| d.name == dbm.name) {
                    manifest.databases.push(dbm);
                }
            }
            for tbl in new_manifest.tables {
                if !manifest
                    .tables
                    .iter()
                    .any(|t| t.database == tbl.database && t.name == tbl.name)
                {
                    manifest.tables.push(tbl);
                }
            }
            manifest.bump_version();
        }
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        // Rebuild manifest index after import
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        Ok(())
    }

    pub fn create_database(&self, name: &str) -> Result<(), EngineError> {
        self.require_writable()?;
        validate_identifier(name, "database")?;
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if manifest.databases.iter().any(|db| db.name == name) {
            return Ok(());
        }
        manifest.bump_version();
        manifest
            .databases
            .push(crate::replication::DatabaseMeta { name: name.into() });
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    pub fn create_table(
        &self,
        database: &str,
        table: &str,
        schema_json: Option<String>,
    ) -> Result<(), EngineError> {
        self.require_writable()?;
        validate_identifier(database, "database")?;
        validate_identifier(table, "table")?;
        let canonical_schema_json = match &schema_json {
            Some(schema) => Some(canonical_schema_from_json(schema)?.json),
            None => None,
        };
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if !manifest.databases.iter().any(|db| db.name == database) {
            return Err(EngineError::NotFound(format!(
                "database not found: {database}"
            )));
        }
        if manifest
            .tables
            .iter()
            .any(|t| t.database == database && t.name == table)
        {
            return Ok(());
        }
        manifest.bump_version();
        manifest.tables.push(crate::replication::TableMeta {
            database: database.to_string(),
            name: table.to_string(),
            schema_json: canonical_schema_json,
            compression: None,
            deduplication: None,
            constraints: Vec::new(),
            retention_policy: None,
            partition_config: None,
        });
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Create a new view in the database
    pub fn create_view(
        &self,
        database: &str,
        name: &str,
        query_sql: &str,
        or_replace: bool,
    ) -> Result<(), EngineError> {
        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and view name required".into(),
            ));
        }
        if query_sql.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "view query SQL required".into(),
            ));
        }
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if !manifest.databases.iter().any(|db| db.name == database) {
            return Err(EngineError::NotFound(format!(
                "database not found: {database}"
            )));
        }
        // Check if view already exists
        if let Some(idx) = manifest
            .views
            .iter()
            .position(|v| v.database == database && v.name == name)
        {
            if or_replace {
                manifest.views[idx].query_sql = query_sql.to_string();
            } else {
                return Err(EngineError::InvalidArgument(format!(
                    "view already exists: {database}.{name}"
                )));
            }
        } else {
            manifest.views.push(crate::replication::ViewMeta {
                database: database.to_string(),
                name: name.to_string(),
                query_sql: query_sql.to_string(),
            });
        }
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Drop a view from the database
    pub fn drop_view(
        &self,
        database: &str,
        name: &str,
        if_exists: bool,
    ) -> Result<(), EngineError> {
        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and view name required".into(),
            ));
        }
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        if let Some(idx) = manifest
            .views
            .iter()
            .position(|v| v.database == database && v.name == name)
        {
            manifest.views.remove(idx);
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            Ok(())
        } else if if_exists {
            Ok(())
        } else {
            Err(EngineError::NotFound(format!(
                "view not found: {database}.{name}"
            )))
        }
    }

    /// List all views in a database
    pub fn list_views(
        &self,
        database: Option<&str>,
    ) -> Result<Vec<(String, String, String)>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let views: Vec<(String, String, String)> = manifest
            .views
            .iter()
            .filter(|v| database.is_none() || database == Some(&v.database))
            .map(|v| (v.database.clone(), v.name.clone(), v.query_sql.clone()))
            .collect();
        Ok(views)
    }

    /// Get a view's query SQL by database and name
    pub fn get_view(&self, database: &str, name: &str) -> Result<Option<String>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        Ok(manifest
            .views
            .iter()
            .find(|v| v.database == database && v.name == name)
            .map(|v| v.query_sql.clone()))
    }

    /// Create a materialized view
    pub fn create_materialized_view(
        &self,
        database: &str,
        name: &str,
        query_sql: &str,
        or_replace: bool,
    ) -> Result<(), EngineError> {
        use crate::replication::MaterializedViewMeta;

        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and materialized view name required".into(),
            ));
        }
        if query_sql.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "materialized view query SQL required".into(),
            ));
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        if !manifest.databases.iter().any(|db| db.name == database) {
            return Err(EngineError::NotFound(format!(
                "database not found: {database}"
            )));
        }

        // Check if materialized view already exists
        if let Some(idx) = manifest
            .materialized_views
            .iter()
            .position(|v| v.database == database && v.name == name)
        {
            if or_replace {
                manifest.materialized_views[idx].query_sql = query_sql.to_string();
                manifest.materialized_views[idx].last_refresh_micros = 0; // Reset refresh time
                manifest.materialized_views[idx].data_segment_id = None; // Clear data
            } else {
                return Err(EngineError::InvalidArgument(format!(
                    "materialized view already exists: {database}.{name}"
                )));
            }
        } else {
            manifest.materialized_views.push(MaterializedViewMeta {
                database: database.to_string(),
                name: name.to_string(),
                query_sql: query_sql.to_string(),
                last_refresh_micros: 0,
                data_segment_id: None,
            });
        }

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Drop a materialized view
    pub fn drop_materialized_view(
        &self,
        database: &str,
        name: &str,
        if_exists: bool,
    ) -> Result<(), EngineError> {
        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and materialized view name required".into(),
            ));
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        if let Some(idx) = manifest
            .materialized_views
            .iter()
            .position(|v| v.database == database && v.name == name)
        {
            // Remove any data segment associated with this materialized view
            let segment_id_to_remove = manifest.materialized_views[idx].data_segment_id.clone();
            if let Some(segment_id) = segment_id_to_remove {
                manifest.entries.retain(|e| e.segment_id != segment_id);
            }
            manifest.materialized_views.remove(idx);
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            Ok(())
        } else if if_exists {
            Ok(())
        } else {
            Err(EngineError::NotFound(format!(
                "materialized view not found: {database}.{name}"
            )))
        }
    }

    /// Refresh a materialized view by re-executing its query and storing the results
    pub fn refresh_materialized_view(&self, database: &str, name: &str) -> Result<(), EngineError> {
        use std::time::{SystemTime, UNIX_EPOCH};

        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and materialized view name required".into(),
            ));
        }

        // Get the view's query
        let query_sql = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .materialized_views
                .iter()
                .find(|v| v.database == database && v.name == name)
                .map(|v| v.query_sql.clone())
                .ok_or_else(|| {
                    EngineError::NotFound(format!("materialized view not found: {database}.{name}"))
                })?
        };

        // Execute the query
        let response = self.query(QueryRequest {
            sql: query_sql,
            timeout_millis: 0,
            collect_stats: false,
            transaction_id: None,
        })?;

        // Create a unique segment ID for the materialized view data
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_micros() as u64;
        let segment_id = format!("mv-{}-{}-{}", database, name, now);

        // Store the result data as a segment
        if !response.records_ipc.is_empty() {
            // Write the IPC data to a segment file
            let segment_path = self.cfg.segments_dir.join(&segment_id);
            let payload = &response.records_ipc;
            fs::write(&segment_path, payload)
                .map_err(|e| EngineError::Io(format!("write mv segment failed: {e}")))?;

            // Update the manifest
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            // Find and update the materialized view
            if let Some(mv_idx) = manifest
                .materialized_views
                .iter()
                .position(|v| v.database == database && v.name == name)
            {
                // Remove old segment if exists
                let old_segment_id = manifest.materialized_views[mv_idx].data_segment_id.clone();
                if let Some(ref old_id) = old_segment_id {
                    manifest.entries.retain(|e| &e.segment_id != old_id);
                    // Also remove the old segment file
                    let old_path = self.cfg.segments_dir.join(old_id);
                    let _ = fs::remove_file(old_path);
                }

                // Update the view's metadata
                manifest.materialized_views[mv_idx].last_refresh_micros = now;
                manifest.materialized_views[mv_idx].data_segment_id = Some(segment_id.clone());

                // Compute version before push
                let version_added = manifest.version + 1;
                let checksum = {
                    let mut hasher = Crc32Hasher::new();
                    hasher.update(payload);
                    hasher.finalize() as u64
                };

                // Add a manifest entry for the new segment
                manifest.entries.push(crate::replication::ManifestEntry {
                    segment_id,
                    shard_id: 0,
                    version_added,
                    size_bytes: payload.len() as u64,
                    checksum,
                    tier: crate::replication::SegmentTier::Hot,
                    compression: None,
                    database: database.to_string(),
                    table: format!("__mv_{}", name),
                    watermark_micros: now,
                    event_time_min: None,
                    event_time_max: None,
                    tenant_id_min: None,
                    tenant_id_max: None,
                    route_id_min: None,
                    route_id_max: None,
                    bloom_tenant: None,
                    bloom_route: None,
                    column_stats: None,
                    schema_hash: None,
                    created_txn: None,
                    deleted_txn: None,
                    deleted_version: None,
                });
            }

            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
        }

        Ok(())
    }

    /// Incrementally refresh a materialized view
    ///
    /// This uses delta tracking to only process new data since last refresh,
    /// then merges with existing results for aggregate views.
    pub fn refresh_materialized_view_incremental(
        &self,
        database: &str,
        name: &str,
    ) -> Result<(), EngineError> {
        use std::time::{SystemTime, UNIX_EPOCH};

        if database.trim().is_empty() || name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and materialized view name required".into(),
            ));
        }

        // Get the view's query and last refresh timestamp
        let (query_sql, last_refresh_micros, old_segment_id) = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .materialized_views
                .iter()
                .find(|v| v.database == database && v.name == name)
                .map(|v| (v.query_sql.clone(), v.last_refresh_micros, v.data_segment_id.clone()))
                .ok_or_else(|| {
                    EngineError::NotFound(format!("materialized view not found: {database}.{name}"))
                })?
        };

        // Check if incremental refresh is possible for this query
        if !crate::incremental_mv::can_refresh_incrementally(&query_sql) {
            // Fall back to full refresh
            return self.refresh_materialized_view(database, name);
        }

        // If never refreshed before, do full refresh
        if last_refresh_micros == 0 {
            return self.refresh_materialized_view(database, name);
        }

        // Modify query to only fetch new data since last refresh
        // This works by adding a filter on the watermark column if present
        let delta_query = crate::incremental_mv::build_delta_query(&query_sql, last_refresh_micros);

        // Execute the delta query
        let delta_response = self.query(QueryRequest {
            sql: delta_query.clone(),
            timeout_millis: 0,
            collect_stats: false,
            transaction_id: None,
        })?;

        // If no new data, just update the refresh timestamp
        if delta_response.records_ipc.is_empty() {
            let now = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap_or_default()
                .as_micros() as u64;

            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            if let Some(mv_idx) = manifest
                .materialized_views
                .iter()
                .position(|v| v.database == database && v.name == name)
            {
                manifest.materialized_views[mv_idx].last_refresh_micros = now;
            }
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            return Ok(());
        }

        // Load existing materialized view data
        let existing_data = if let Some(ref seg_id) = old_segment_id {
            let seg_path = self.cfg.segments_dir.join(seg_id);
            if seg_path.exists() {
                Some(fs::read(&seg_path).map_err(|e| {
                    EngineError::Io(format!("read existing mv segment failed: {e}"))
                })?)
            } else {
                None
            }
        } else {
            None
        };

        // Merge existing data with delta results
        let merged_data = if let Some(existing) = existing_data {
            crate::incremental_mv::merge_ipc_data(
                &existing,
                &delta_response.records_ipc,
                &query_sql,
            )?
        } else {
            delta_response.records_ipc.clone()
        };

        // Create a unique segment ID
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_micros() as u64;
        let segment_id = format!("mv-{}-{}-{}", database, name, now);

        // Store the merged result
        if !merged_data.is_empty() {
            let segment_path = self.cfg.segments_dir.join(&segment_id);
            let payload = &merged_data;
            fs::write(&segment_path, payload)
                .map_err(|e| EngineError::Io(format!("write mv segment failed: {e}")))?;

            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            if let Some(mv_idx) = manifest
                .materialized_views
                .iter()
                .position(|v| v.database == database && v.name == name)
            {
                // Remove old segment
                if let Some(ref old_id) = old_segment_id {
                    manifest.entries.retain(|e| &e.segment_id != old_id);
                    let old_path = self.cfg.segments_dir.join(old_id);
                    let _ = fs::remove_file(old_path);
                }

                // Update metadata
                manifest.materialized_views[mv_idx].last_refresh_micros = now;
                manifest.materialized_views[mv_idx].data_segment_id = Some(segment_id.clone());

                // Compute version and checksum
                let version_added = manifest.version + 1;
                let checksum = {
                    let mut hasher = Crc32Hasher::new();
                    hasher.update(payload);
                    hasher.finalize() as u64
                };

                // Add manifest entry for new segment
                manifest.entries.push(crate::replication::ManifestEntry {
                    segment_id,
                    shard_id: 0,
                    version_added,
                    size_bytes: payload.len() as u64,
                    checksum,
                    tier: crate::replication::SegmentTier::Hot,
                    compression: None,
                    database: database.to_string(),
                    table: format!("__mv_{}", name),
                    watermark_micros: now,
                    event_time_min: None,
                    event_time_max: None,
                    tenant_id_min: None,
                    tenant_id_max: None,
                    route_id_min: None,
                    route_id_max: None,
                    bloom_tenant: None,
                    bloom_route: None,
                    column_stats: None,
                    schema_hash: None,
                    created_txn: None,
                    deleted_txn: None,
                    deleted_version: None,
                });
            }

            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
        }

        Ok(())
    }

    /// List all materialized views in a database
    /// Returns: Vec<(database, name, query_sql, last_refresh_micros)>
    pub fn list_materialized_views(
        &self,
        database: Option<&str>,
    ) -> Result<Vec<(String, String, String, u64)>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let views: Vec<(String, String, String, u64)> = manifest
            .materialized_views
            .iter()
            .filter(|v| database.is_none() || database == Some(&v.database))
            .map(|v| {
                (
                    v.database.clone(),
                    v.name.clone(),
                    v.query_sql.clone(),
                    v.last_refresh_micros,
                )
            })
            .collect();
        Ok(views)
    }

    /// Get a materialized view's data - returns the cached results if available
    pub fn get_materialized_view_data(
        &self,
        database: &str,
        name: &str,
    ) -> Result<Option<Vec<u8>>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mv = manifest
            .materialized_views
            .iter()
            .find(|v| v.database == database && v.name == name);

        match mv {
            Some(mv) => {
                if let Some(segment_id) = &mv.data_segment_id {
                    let segment_path = self.cfg.segments_dir.join(segment_id);
                    if segment_path.exists() {
                        let data = fs::read(&segment_path)
                            .map_err(|e| EngineError::Io(format!("read mv segment failed: {e}")))?;
                        return Ok(Some(data));
                    }
                }
                Ok(None)
            }
            None => Err(EngineError::NotFound(format!(
                "materialized view not found: {database}.{name}"
            ))),
        }
    }

    // ==================== Index Management ====================

    fn index_root(&self) -> PathBuf {
        self.cfg.data_dir.join("indexes")
    }

    fn index_dir(&self, database: &str, table: &str, index_name: &str) -> PathBuf {
        self.index_root()
            .join(database)
            .join(table)
            .join(index_name)
    }

    fn index_segment_path(&self, index: &IndexMeta, segment_id: &str) -> PathBuf {
        self.index_dir(&index.database, &index.table, &index.name)
            .join(format!("{segment_id}.idx"))
    }

    fn table_schema_map(
        &self,
        database: &str,
        table: &str,
    ) -> Result<HashMap<String, String>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let schema_json = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table)
            .and_then(|t| t.schema_json.clone())
            .ok_or_else(|| EngineError::NotFound("table schema not found".into()))?;
        let fields: Vec<TableFieldSpec> = serde_json::from_str(&schema_json)
            .map_err(|e| EngineError::InvalidArgument(format!("invalid schema json: {e}")))?;
        Ok(fields.into_iter().map(|f| (f.name, f.data_type)).collect())
    }

    fn hash_index_value(data_type: &str, value: &IndexValue) -> Option<u64> {
        use std::hash::Hasher;
        let mut hasher = DefaultHasher::new();
        match (data_type.to_ascii_lowercase().as_str(), value) {
            ("int64", IndexValue::Int(v))
            | ("int32", IndexValue::Int(v))
            | ("int16", IndexValue::Int(v))
            | ("int8", IndexValue::Int(v)) => {
                let val = i64::try_from(*v).ok()?;
                1u8.hash(&mut hasher);
                val.hash(&mut hasher);
            }
            ("uint64", IndexValue::UInt(v))
            | ("uint32", IndexValue::UInt(v))
            | ("uint16", IndexValue::UInt(v))
            | ("uint8", IndexValue::UInt(v)) => {
                1u8.hash(&mut hasher);
                v.hash(&mut hasher);
            }
            ("float64", IndexValue::Float(v)) => {
                1u8.hash(&mut hasher);
                v.to_bits().hash(&mut hasher);
            }
            ("float32", IndexValue::Float(v)) => {
                1u8.hash(&mut hasher);
                (*v as f32).to_bits().hash(&mut hasher);
            }
            ("bool", IndexValue::Bool(v)) | ("boolean", IndexValue::Bool(v)) => {
                1u8.hash(&mut hasher);
                v.hash(&mut hasher);
            }
            ("utf8", IndexValue::Str(v))
            | ("string", IndexValue::Str(v))
            | ("largestring", IndexValue::Str(v)) => {
                1u8.hash(&mut hasher);
                v.hash(&mut hasher);
            }
            ("uuid", IndexValue::Bytes(v))
            | ("binary", IndexValue::Bytes(v))
            | ("bytes", IndexValue::Bytes(v))
            | ("blob", IndexValue::Bytes(v))
            | ("largebinary", IndexValue::Bytes(v)) => {
                1u8.hash(&mut hasher);
                v.hash(&mut hasher);
            }
            _ => return None,
        }
        Some(hasher.finish())
    }

    fn index_filter_hashes(&self, filter: &QueryFilter, column: &str, data_type: &str) -> Vec<u64> {
        let mut values: Vec<IndexValue> = Vec::new();
        if column == "tenant_id" {
            if let Some(v) = filter.tenant_id_eq {
                values.push(IndexValue::UInt(v));
            }
            if let Some(vs) = &filter.tenant_id_in {
                values.extend(vs.iter().copied().map(IndexValue::UInt));
            }
        }
        if column == "route_id" {
            if let Some(v) = filter.route_id_eq {
                values.push(IndexValue::UInt(v));
            }
            if let Some(vs) = &filter.route_id_in {
                values.extend(vs.iter().copied().map(IndexValue::UInt));
            }
        }
        for (col, v) in &filter.numeric_eq_filters {
            if col == column {
                values.push(IndexValue::Int(*v));
            }
        }
        for (col, v) in &filter.float_eq_filters {
            if col == column {
                values.push(IndexValue::Float(*v));
            }
        }
        for (col, v) in &filter.bool_eq_filters {
            if col == column {
                values.push(IndexValue::Bool(*v));
            }
        }
        let data_type_lower = data_type.to_ascii_lowercase();
        let is_uuid = data_type_lower == "uuid";
        let is_binary = matches!(
            data_type_lower.as_str(),
            "binary" | "bytes" | "blob" | "largebinary"
        );
        for (col, v) in &filter.string_eq_filters {
            if col == column {
                if is_uuid {
                    if let Some(bytes) = parse_uuid_string(v) {
                        values.push(IndexValue::Bytes(bytes.to_vec()));
                    }
                } else if is_binary {
                    values.push(IndexValue::Bytes(decode_binary_literal(v)));
                } else {
                    values.push(IndexValue::Str(v.clone()));
                }
            }
        }
        for (col, vs) in &filter.string_in_filters {
            if col == column {
                if is_uuid {
                    values.extend(vs.iter().filter_map(|v| {
                        parse_uuid_string(v).map(|b| IndexValue::Bytes(b.to_vec()))
                    }));
                } else if is_binary {
                    values.extend(
                        vs.iter()
                            .map(|v| IndexValue::Bytes(decode_binary_literal(v))),
                    );
                } else {
                    values.extend(vs.iter().cloned().map(IndexValue::Str));
                }
            }
        }

        values
            .into_iter()
            .filter_map(|v| Self::hash_index_value(data_type, &v))
            .collect()
    }

    fn load_hash_index(path: &Path) -> Result<Vec<u64>, EngineError> {
        let bytes =
            fs::read(path).map_err(|e| EngineError::Io(format!("read hash index failed: {e}")))?;
        if bytes.len() < 8 {
            return Ok(Vec::new());
        }
        let count = u64::from_le_bytes(bytes[0..8].try_into().unwrap()) as usize;
        let mut values = Vec::with_capacity(count);
        let mut offset = 8;
        while offset + 8 <= bytes.len() {
            let val = u64::from_le_bytes(bytes[offset..offset + 8].try_into().unwrap());
            values.push(val);
            offset += 8;
        }
        values.sort_unstable();
        values.dedup();
        Ok(values)
    }

    fn entry_matches_index_filters(
        &self,
        entry: &ManifestEntry,
        filter: &QueryFilter,
        schema_map: &HashMap<String, String>,
        indexes: &[&IndexMeta],
    ) -> Result<bool, EngineError> {
        for &index in indexes {
            if index.state != IndexState::Ready {
                continue;
            }
            if index.columns.len() != 1 {
                continue;
            }
            let column = &index.columns[0];
            let path = self.index_segment_path(index, &entry.segment_id);
            if !path.exists() {
                continue;
            }

            // Handle fulltext indexes differently - check LIKE filters
            if index.index_type == crate::sql::IndexType::Fulltext {
                // Check if there are any LIKE filters for this column
                let like_patterns = self.get_like_patterns_for_column(filter, column);
                if like_patterns.is_empty() {
                    continue;
                }

                // Load the fulltext index and check if any pattern might match
                let bytes = fs::read(&path)
                    .map_err(|e| EngineError::Io(format!("read fulltext index failed: {e}")))?;
                let ft_index = crate::fts::load_fulltext_index(&bytes)?;

                // For each LIKE pattern, check if the segment might contain matches
                for (pattern, negate) in like_patterns {
                    if let Some(substring) = crate::fts::extract_like_substring(&pattern) {
                        let might_contain = ft_index.might_contain(&substring);
                        // If NOT LIKE and segment might contain, we can't prune
                        // If LIKE and segment doesn't contain, we can prune
                        if !negate && !might_contain {
                            return Ok(false); // Segment definitely has no matches
                        }
                    }
                }
                continue;
            }

            // For Bloom/Hash indexes, use hash-based filtering
            let data_type = match schema_map.get(column) {
                Some(t) => t,
                None => continue,
            };
            let hashes = self.index_filter_hashes(filter, column, data_type);
            if hashes.is_empty() {
                continue;
            }

            let matches = match index.index_type {
                crate::sql::IndexType::Bloom => {
                    let bytes = fs::read(&path)
                        .map_err(|e| EngineError::Io(format!("read bloom index failed: {e}")))?;
                    let bloom = crate::bloom_utils::deserialize_bloom_or_empty(&bytes, 1000);
                    hashes.iter().any(|h| bloom.check(h))
                }
                crate::sql::IndexType::Hash => {
                    let values = Self::load_hash_index(&path)?;
                    hashes.iter().any(|h| values.binary_search(h).is_ok())
                }
                _ => true,
            };
            if !matches {
                return Ok(false);
            }
        }
        Ok(true)
    }

    /// Extract LIKE patterns from the filter for a specific column
    /// Returns Vec<(pattern, negate)> where negate=true means NOT LIKE
    fn get_like_patterns_for_column(&self, filter: &QueryFilter, column: &str) -> Vec<(String, bool)> {
        filter.all_like_patterns_for_column(column)
    }

    fn build_index_for_segment(
        &self,
        index: &IndexMeta,
        entry: &ManifestEntry,
    ) -> Result<(), EngineError> {
        let batches = self.load_segment_batches_cached(entry)?;
        if batches.is_empty() {
            return Ok(());
        }
        let schema = batches[0].schema();
        let mut col_indices = Vec::with_capacity(index.columns.len());
        for col in &index.columns {
            let idx = schema.index_of(col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "index column '{col}' not found in segment schema"
                ))
            })?;
            col_indices.push(idx);
        }

        let total_rows: usize = batches.iter().map(|b| b.num_rows()).sum();
        let mut bloom = Bloom::new_for_fp_rate(total_rows.max(1), 0.01);
        let mut hash_values: HashSet<u64> = HashSet::new();

        // For fulltext indexes, we use a different approach - build an n-gram index
        let mut fulltext_builder = if index.index_type == crate::sql::IndexType::Fulltext {
            Some(crate::fts::FulltextIndexBuilder::new(
                crate::fts::FulltextConfig::default(),
            ))
        } else {
            None
        };

        let mut global_row_idx: u32 = 0;
        for batch in batches.iter() {
            for row_idx in 0..batch.num_rows() {
                match index.index_type {
                    crate::sql::IndexType::Fulltext => {
                        // For fulltext indexes, extract string values and add to the builder
                        if let Some(ref mut builder) = fulltext_builder {
                            // Only support single-column fulltext indexes for now
                            if col_indices.len() == 1 {
                                let col = batch.column(col_indices[0]);
                                let value = Self::extract_column_value_as_string(col, row_idx);
                                if !value.is_empty() && value != "NULL" {
                                    builder.add_value(global_row_idx, &value);
                                }
                            }
                        }
                    }
                    crate::sql::IndexType::Bloom | crate::sql::IndexType::Hash => {
                        let mut hasher = DefaultHasher::new();
                        for col_idx in &col_indices {
                            let col = batch.column(*col_idx);
                            hash_array_value(&mut hasher, col.as_ref(), row_idx);
                        }
                        let hash = hasher.finish();
                        match index.index_type {
                            crate::sql::IndexType::Bloom => {
                                bloom.set(&hash);
                            }
                            crate::sql::IndexType::Hash => {
                                hash_values.insert(hash);
                            }
                            _ => {}
                        }
                    }
                    _ => {}
                }
                global_row_idx += 1;
            }
        }

        let path = self.index_segment_path(index, &entry.segment_id);
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)
                .map_err(|e| EngineError::Io(format!("create index dir failed: {e}")))?;
        }

        match index.index_type {
            crate::sql::IndexType::Bloom => {
                let bytes = crate::bloom_utils::serialize_bloom(&bloom)?;
                fs::write(&path, bytes)
                    .map_err(|e| EngineError::Io(format!("write bloom index failed: {e}")))?;
            }
            crate::sql::IndexType::Hash => {
                let mut values: Vec<u64> = hash_values.into_iter().collect();
                values.sort_unstable();
                let mut out = Vec::with_capacity(8 + values.len() * 8);
                out.extend_from_slice(&(values.len() as u64).to_le_bytes());
                for v in values {
                    out.extend_from_slice(&v.to_le_bytes());
                }
                fs::write(&path, out)
                    .map_err(|e| EngineError::Io(format!("write hash index failed: {e}")))?;
            }
            crate::sql::IndexType::Fulltext => {
                if let Some(builder) = fulltext_builder {
                    let bytes = builder.build()?;
                    fs::write(&path, bytes)
                        .map_err(|e| EngineError::Io(format!("write fulltext index failed: {e}")))?;
                }
            }
            _ => {}
        }
        Ok(())
    }

    fn build_index_for_table(&self, index: &IndexMeta) -> Result<(), EngineError> {
        let entries = self.table_entries(&index.database, &index.table)?;
        for entry in &entries {
            let path = self.index_segment_path(index, &entry.segment_id);
            if path.exists() {
                continue;
            }
            if let Err(e) = self.build_index_for_segment(index, entry) {
                tracing::warn!(
                    database = %index.database,
                    table = %index.table,
                    index = %index.name,
                    error = %e,
                    "index build failed for segment"
                );
                return Err(e);
            }
        }
        Ok(())
    }

    fn update_index_state(
        &self,
        database: &str,
        table: &str,
        name: &str,
        state: IndexState,
    ) -> Result<(), EngineError> {
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_micros() as u64;
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let mut updated = false;
        for idx in &mut manifest.indexes {
            if idx.database == database && idx.table == table && idx.name == name {
                idx.state = state.clone();
                idx.last_built_micros = Some(now);
                updated = true;
                break;
            }
        }
        if updated {
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        }
        Ok(())
    }

    fn spawn_background_index_build(&self, index: IndexMeta) {
        let cfg = self.cfg.clone();
        std::thread::spawn(move || {
            // Try to open DB - use local-only storage if no tokio runtime is available
            // (common in test environments or when background threads are spawned outside async context)
            let db_result = {
                // First try normal open (for production use with S3)
                let storage_result = crate::storage::TieredStorage::new(&cfg);
                match storage_result {
                    Ok(storage) => Db::open_with_storage(cfg, std::sync::Arc::new(storage)),
                    Err(_) => {
                        // Fall back to local-only storage (no tokio runtime needed)
                        let storage =
                            crate::storage::TieredStorage::new_local_only(cfg.segments_dir.clone());
                        Db::open_with_storage(cfg, std::sync::Arc::new(storage))
                    }
                }
            };

            match db_result {
                Ok(db) => {
                    let result = db.build_index_for_table(&index);
                    let state = if result.is_ok() {
                        IndexState::Ready
                    } else {
                        IndexState::Failed
                    };
                    if let Err(e) =
                        db.update_index_state(&index.database, &index.table, &index.name, state)
                    {
                        tracing::warn!(error = %e, "failed to update index state");
                    }
                }
                Err(e) => {
                    tracing::warn!(error = %e, "failed to start background index build");
                }
            }
        });
    }

    fn spawn_background_index_build_for_segment(
        &self,
        database: &str,
        table: &str,
        segment_id: &str,
    ) {
        let cfg = self.cfg.clone();
        let db_name = database.to_string();
        let tbl_name = table.to_string();
        let seg_id = segment_id.to_string();
        let (entry, indexes) = {
            let manifest = match self.manifest.read() {
                Ok(m) => m,
                Err(_) => {
                    tracing::warn!("manifest lock poisoned");
                    return;
                }
            };
            let entry = manifest
                .entries
                .iter()
                .find(|e| e.segment_id == seg_id)
                .cloned();
            let indexes = manifest
                .indexes
                .iter()
                .filter(|idx| {
                    idx.database == db_name
                        && idx.table == tbl_name
                        && matches!(idx.state, IndexState::Ready | IndexState::Building)
                })
                .cloned()
                .collect::<Vec<_>>();
            (entry, indexes)
        };
        let Some(entry) = entry else {
            return;
        };
        if indexes.is_empty() {
            return;
        }
        std::thread::spawn(move || {
            // Try to open DB - use local-only storage if no tokio runtime is available
            let db_result = {
                let storage_result = crate::storage::TieredStorage::new(&cfg);
                match storage_result {
                    Ok(storage) => Db::open_with_storage(cfg, std::sync::Arc::new(storage)),
                    Err(_) => {
                        let storage =
                            crate::storage::TieredStorage::new_local_only(cfg.segments_dir.clone());
                        Db::open_with_storage(cfg, std::sync::Arc::new(storage))
                    }
                }
            };

            match db_result {
                Ok(db) => {
                    for index in &indexes {
                        if let Err(e) = db.build_index_for_segment(index, &entry) {
                            tracing::warn!(error = %e, "background index build failed");
                            break;
                        }
                    }
                }
                Err(e) => {
                    tracing::warn!(error = %e, "failed to start background index build");
                }
            }
        });
    }

    /// Create an index on a table
    pub fn create_index(
        &self,
        database: &str,
        table: &str,
        index_name: &str,
        columns: &[String],
        index_type: crate::sql::IndexType,
        if_not_exists: bool,
    ) -> Result<(), EngineError> {
        if columns.is_empty() {
            return Err(EngineError::InvalidArgument(
                "index must include at least one column".into(),
            ));
        }

        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_micros() as u64;

        let index_meta =
            {
                let mut manifest = self
                    .manifest
                    .write()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

                // Verify table exists
                let table_exists = manifest
                    .tables
                    .iter()
                    .any(|t| t.database == database && t.name == table);
                if !table_exists {
                    return Err(EngineError::NotFound(format!(
                        "table not found: {database}.{table}"
                    )));
                }

                if manifest.indexes.iter().any(|idx| {
                    idx.database == database && idx.table == table && idx.name == index_name
                }) {
                    if if_not_exists {
                        tracing::info!(
                            "Index {} already exists on {}.{}",
                            index_name,
                            database,
                            table
                        );
                        return Ok(());
                    }
                    return Err(EngineError::InvalidArgument(format!(
                        "index already exists: {database}.{table}.{index_name}"
                    )));
                }

                let index_meta = IndexMeta {
                    name: index_name.to_string(),
                    database: database.to_string(),
                    table: table.to_string(),
                    columns: columns.to_vec(),
                    index_type,
                    state: IndexState::Building,
                    created_micros: now,
                    last_built_micros: None,
                };
                manifest.indexes.push(index_meta.clone());
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
                index_meta
            };

        self.spawn_background_index_build(index_meta);
        Ok(())
    }

    /// Drop an index from a table
    pub fn drop_index(
        &self,
        database: &str,
        table: &str,
        index_name: &str,
        if_exists: bool,
    ) -> Result<(), EngineError> {
        let removed = {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let initial_len = manifest.indexes.len();
            manifest.indexes.retain(|idx| {
                idx.database != database || idx.table != table || idx.name != index_name
            });
            let removed = manifest.indexes.len() != initial_len;
            if !removed && !if_exists {
                return Err(EngineError::NotFound(format!(
                    "index not found: {database}.{table}.{index_name}"
                )));
            }
            if removed {
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            }
            removed
        };

        if removed {
            let path = self.index_dir(database, table, index_name);
            let _ = fs::remove_dir_all(&path);
            tracing::info!("Index {} dropped from {}.{}", index_name, database, table);
        }
        Ok(())
    }

    /// List indexes for a table
    /// Returns: Vec<(database, table, index_name, columns, index_type)>
    pub fn list_indexes(
        &self,
        database: Option<&str>,
        table: Option<&str>,
    ) -> Result<Vec<(String, String, String, Vec<String>, crate::sql::IndexType)>, EngineError>
    {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut out = Vec::new();
        for idx in &manifest.indexes {
            if database.map_or(true, |db| db == idx.database)
                && table.map_or(true, |t| t == idx.table)
            {
                out.push((
                    idx.database.clone(),
                    idx.table.clone(),
                    idx.name.clone(),
                    idx.columns.clone(),
                    idx.index_type.clone(),
                ));
            }
        }
        Ok(out)
    }

    // ==================== Table Maintenance ====================

    /// Analyze a table to collect statistics for query optimization
    /// Samples data to compute column statistics including min/max, distinct counts,
    /// null counts, and histograms for cardinality estimation.
    pub fn analyze_table(&self, database: &str, table: &str) -> Result<(), EngineError> {
        self.analyze_table_with_sample(database, table, 1.0) // Full scan by default
    }

    /// Analyze a table with a specified sample rate (0.0-1.0)
    /// Lower sample rates are faster but less accurate
    pub fn analyze_table_with_sample(
        &self,
        database: &str,
        table: &str,
        sample_rate: f64,
    ) -> Result<(), EngineError> {
        use arrow_array::{Array, ArrayRef};
        use std::collections::HashSet;

        let sample_rate = sample_rate.clamp(0.01, 1.0);
        let start_time = std::time::Instant::now();

        // Get segment entries for this table
        let entries: Vec<crate::replication::ManifestEntry> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            // Verify table exists
            let table_exists = manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table);
            if !table_exists {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }

            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect()
        };

        let segment_count = entries.len();
        if segment_count == 0 {
            tracing::info!("ANALYZE {}.{}: no segments to analyze", database, table);
            return Ok(());
        }

        // Determine which segments to sample
        let segments_to_sample = if sample_rate < 1.0 {
            let num_samples = ((segment_count as f64) * sample_rate).ceil() as usize;
            let step = segment_count / num_samples.max(1);
            entries
                .iter()
                .enumerate()
                .filter(|(i, _)| i % step.max(1) == 0)
                .map(|(_, e)| e.clone())
                .take(num_samples.max(1))
                .collect::<Vec<_>>()
        } else {
            entries.clone()
        };

        tracing::info!(
            "ANALYZE {}.{}: analyzing {}/{} segments (sample_rate={})",
            database,
            table,
            segments_to_sample.len(),
            segment_count,
            sample_rate
        );

        // Column statistics accumulators using HashSet for distinct counts
        // (HyperLogLog is overkill for most tables and adds complexity)
        struct ColumnAccum {
            null_count: u64,
            non_null_count: u64,
            min_i64: Option<i64>,
            max_i64: Option<i64>,
            min_f64: Option<f64>,
            max_f64: Option<f64>,
            min_str: Option<String>,
            max_str: Option<String>,
            total_str_len: u64,
            distinct_values: std::collections::HashSet<String>,
            is_numeric: bool,
            is_string: bool,
            histogram_values: Vec<f64>, // For building histogram
            value_counts: std::collections::HashMap<String, u64>, // For MCV tracking
        }

        // Memory limits for ANALYZE to prevent OOM on large tables
        const MAX_HISTOGRAM_SAMPLES: usize = 100_000;
        const MAX_DISTINCT_TRACK: usize = 50_000;
        const MAX_MCV_DISTINCT: usize = 10_000;

        impl ColumnAccum {
            fn new() -> Self {
                ColumnAccum {
                    null_count: 0,
                    non_null_count: 0,
                    min_i64: None,
                    max_i64: None,
                    min_f64: None,
                    max_f64: None,
                    min_str: None,
                    max_str: None,
                    total_str_len: 0,
                    distinct_values: std::collections::HashSet::new(),
                    is_numeric: false,
                    is_string: false,
                    histogram_values: Vec::new(),
                    value_counts: std::collections::HashMap::new(),
                }
            }

            // Track value for MCV - takes &str to avoid allocation, only clones when inserting new
            #[inline]
            fn track_value(&mut self, value: &str) {
                // Fast path: check if value exists first (no allocation)
                if let Some(count) = self.value_counts.get_mut(value) {
                    *count += 1;
                } else if self.value_counts.len() < MAX_MCV_DISTINCT {
                    // Only allocate String when inserting new value
                    self.value_counts.insert(value.to_owned(), 1);
                }
            }

            // Track histogram value with memory limit
            #[inline]
            fn track_histogram(&mut self, value: f64) {
                if self.histogram_values.len() < MAX_HISTOGRAM_SAMPLES {
                    self.histogram_values.push(value);
                }
            }

            // Track distinct value - takes &str, only allocates when inserting new
            #[inline]
            fn track_distinct(&mut self, value: &str) {
                if self.distinct_values.len() < MAX_DISTINCT_TRACK && !self.distinct_values.contains(value) {
                    self.distinct_values.insert(value.to_owned());
                }
            }

            // Combined tracking to minimize string operations
            #[inline]
            fn track_string_value(&mut self, value: &str) {
                // Single check for distinct, avoid double lookup
                let is_new = self.distinct_values.len() < MAX_DISTINCT_TRACK
                    && !self.distinct_values.contains(value);

                if is_new {
                    self.distinct_values.insert(value.to_owned());
                }

                // Track for MCV
                if let Some(count) = self.value_counts.get_mut(value) {
                    *count += 1;
                } else if self.value_counts.len() < MAX_MCV_DISTINCT {
                    self.value_counts.insert(value.to_owned(), 1);
                }
            }
        }

        let mut column_stats: std::collections::HashMap<String, ColumnAccum> =
            std::collections::HashMap::new();
        let mut total_rows: u64 = 0;
        let mut total_bytes: u64 = 0;

        // Process each sampled segment
        for entry in &segments_to_sample {
            total_bytes += entry.size_bytes;

            // Load segment data
            let payload = match self.load_segment_cached(entry) {
                Ok(p) => p,
                Err(e) => {
                    tracing::warn!("ANALYZE: failed to load segment {}: {}", entry.segment_id, e);
                    continue;
                }
            };

            let batches = match read_ipc_batches(&payload) {
                Ok(b) => b,
                Err(e) => {
                    tracing::warn!("ANALYZE: failed to read IPC {}: {}", entry.segment_id, e);
                    continue;
                }
            };

            for batch in batches {
                total_rows += batch.num_rows() as u64;
                let schema = batch.schema();

                for (col_idx, field) in schema.fields().iter().enumerate() {
                    let col_name = field.name().clone();
                    let col_array = batch.column(col_idx);

                    let accum = column_stats
                        .entry(col_name.clone())
                        .or_insert_with(ColumnAccum::new);

                    // Count nulls
                    let null_count = col_array.null_count() as u64;
                    accum.null_count += null_count;
                    accum.non_null_count += (col_array.len() as u64) - null_count;

                    // Process based on data type - inline for type safety
                    use arrow_array::*;
                    match col_array.data_type() {
                        arrow_schema::DataType::Int8 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Int8Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i) as i64;
                                        accum.min_i64 = Some(accum.min_i64.map_or(v, |m: i64| m.min(v)));
                                        accum.max_i64 = Some(accum.max_i64.map_or(v, |m: i64| m.max(v)));
                                        accum.track_histogram(v as f64);
                                        // Convert to string and track (single allocation path)
                                        accum.track_string_value(&v.to_string());
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Int16 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Int16Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i) as i64;
                                        accum.min_i64 = Some(accum.min_i64.map_or(v, |m: i64| m.min(v)));
                                        accum.max_i64 = Some(accum.max_i64.map_or(v, |m: i64| m.max(v)));
                                        accum.track_histogram(v as f64);
                                        // Convert to string and track (single allocation path)
                                        accum.track_string_value(&v.to_string());
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Int32 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Int32Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i) as i64;
                                        accum.min_i64 = Some(accum.min_i64.map_or(v, |m: i64| m.min(v)));
                                        accum.max_i64 = Some(accum.max_i64.map_or(v, |m: i64| m.max(v)));
                                        accum.track_histogram(v as f64);
                                        // Convert to string and track (single allocation path)
                                        accum.track_string_value(&v.to_string());
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Int64 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Int64Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i);
                                        accum.min_i64 = Some(accum.min_i64.map_or(v, |m: i64| m.min(v)));
                                        accum.max_i64 = Some(accum.max_i64.map_or(v, |m: i64| m.max(v)));
                                        accum.track_histogram(v as f64);
                                        // Convert to string and track (single allocation path)
                                        accum.track_string_value(&v.to_string());
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Float32 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Float32Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i) as f64;
                                        if v.is_finite() {
                                            accum.min_f64 = Some(accum.min_f64.map_or(v, |m: f64| m.min(v)));
                                            accum.max_f64 = Some(accum.max_f64.map_or(v, |m: f64| m.max(v)));
                                            accum.track_histogram(v);
                                            // Use ryu for fast float formatting if available, else format
                                            accum.track_string_value(&format!("{:.6}", v));
                                        }
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Float64 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<Float64Array>() {
                                accum.is_numeric = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i);
                                        if v.is_finite() {
                                            accum.min_f64 = Some(accum.min_f64.map_or(v, |m: f64| m.min(v)));
                                            accum.max_f64 = Some(accum.max_f64.map_or(v, |m: f64| m.max(v)));
                                            accum.track_histogram(v);
                                            // Use ryu for fast float formatting if available, else format
                                            accum.track_string_value(&format!("{:.6}", v));
                                        }
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Utf8 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<StringArray>() {
                                accum.is_string = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i);
                                        accum.total_str_len += v.len() as u64;
                                        // Use v directly - it's already &str, avoid allocation
                                        accum.track_string_value(v);
                                        // Only allocate for min/max when needed
                                        if accum.min_str.as_ref().map_or(true, |m| v < m.as_str()) {
                                            accum.min_str = Some(v.to_owned());
                                        }
                                        if accum.max_str.as_ref().map_or(true, |m| v > m.as_str()) {
                                            accum.max_str = Some(v.to_owned());
                                        }
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::LargeUtf8 => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<LargeStringArray>() {
                                accum.is_string = true;
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let v = arr.value(i);
                                        accum.total_str_len += v.len() as u64;
                                        // Use v directly - it's already &str, avoid allocation
                                        accum.track_string_value(v);
                                        // Only allocate for min/max when needed
                                        if accum.min_str.as_ref().map_or(true, |m| v < m.as_str()) {
                                            accum.min_str = Some(v.to_owned());
                                        }
                                        if accum.max_str.as_ref().map_or(true, |m| v > m.as_str()) {
                                            accum.max_str = Some(v.to_owned());
                                        }
                                    }
                                }
                            }
                        }
                        arrow_schema::DataType::Boolean => {
                            if let Some(arr) = col_array.as_any().downcast_ref::<BooleanArray>() {
                                // Booleans only have two values - use static strings
                                for i in 0..arr.len() {
                                    if !arr.is_null(i) {
                                        let vs = if arr.value(i) { "true" } else { "false" };
                                        accum.track_string_value(vs);
                                    }
                                }
                            }
                        }
                        _ => {
                            // For other types, just count as distinct
                        }
                    }
                }
            }
        }

        // Compute correlations between numeric columns before consuming column_stats
        let correlations = {
            let mut corrs = std::collections::HashMap::new();

            // Collect numeric columns with enough data
            let numeric_cols: Vec<(&String, &Vec<f64>)> = column_stats
                .iter()
                .filter(|(_, accum)| accum.is_numeric && accum.histogram_values.len() >= 10)
                .map(|(name, accum)| (name, &accum.histogram_values))
                .collect();

            // Sort by data availability and limit to top 10 columns
            let mut sorted_cols = numeric_cols;
            sorted_cols.sort_by(|a, b| b.1.len().cmp(&a.1.len()));
            let top_cols: Vec<_> = sorted_cols.into_iter().take(10).collect();

            // Compute pairwise correlations
            for i in 0..top_cols.len() {
                for j in (i + 1)..top_cols.len() {
                    let (col1_name, col1_vals) = top_cols[i];
                    let (col2_name, col2_vals) = top_cols[j];

                    let n = col1_vals.len().min(col2_vals.len()).min(1000);
                    if n < 10 {
                        continue;
                    }

                    // Use slices directly to avoid allocation
                    if let Some(corr) = Self::pearson_correlation(&col1_vals[..n], &col2_vals[..n]) {
                        if corr.abs() > 0.1 {
                            let key = if col1_name < col2_name {
                                format!("{}:{}", col1_name, col2_name)
                            } else {
                                format!("{}:{}", col2_name, col1_name)
                            };
                            corrs.insert(key, corr);
                        }
                    }
                }
            }
            corrs
        };

        // Build statistics metadata
        let mut col_stats_meta: std::collections::HashMap<String, crate::replication::ColumnStatsMeta> =
            std::collections::HashMap::new();

        let column_count = column_stats.len();
        for (col_name, mut accum) in column_stats {
            let distinct_count = accum.distinct_values.len() as u64;

            // Determine min/max values as JSON strings
            let min_value = if let Some(v) = accum.min_i64 {
                Some(v.to_string())
            } else if let Some(v) = accum.min_f64 {
                Some(v.to_string())
            } else {
                accum.min_str.clone()
            };

            let max_value = if let Some(v) = accum.max_i64 {
                Some(v.to_string())
            } else if let Some(v) = accum.max_f64 {
                Some(v.to_string())
            } else {
                accum.max_str.clone()
            };

            let avg_length = if accum.is_string && accum.non_null_count > 0 {
                Some(accum.total_str_len as f64 / accum.non_null_count as f64)
            } else {
                None
            };

            // Build histogram for numeric columns with enough data
            // Note: build_histogram sorts in place, but accum is consumed so that's fine
            let histogram = if accum.is_numeric && accum.histogram_values.len() >= 100 {
                Some(Self::build_histogram(&mut accum.histogram_values, 64))
            } else {
                None
            };

            // Build MCV (Most Common Values) for columns with skewed distribution
            // Only include MCV if there are repeated values (not all unique)
            let most_common_values = if accum.non_null_count > 0 {
                Self::build_mcv(&accum.value_counts, accum.non_null_count, 10)
            } else {
                None
            };

            col_stats_meta.insert(
                col_name,
                crate::replication::ColumnStatsMeta {
                    distinct_count,
                    null_count: accum.null_count,
                    non_null_count: accum.non_null_count,
                    min_value,
                    max_value,
                    avg_length,
                    histogram,
                    most_common_values,
                },
            );
        }

        // Create TableStatsMeta
        let now_millis = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_millis() as u64)
            .unwrap_or(0);

        // Extrapolate row count if we sampled
        let estimated_rows = if sample_rate < 1.0 {
            (total_rows as f64 / sample_rate) as u64
        } else {
            total_rows
        };

        let stats_meta = crate::replication::TableStatsMeta {
            database: database.to_string(),
            table: table.to_string(),
            row_count: estimated_rows,
            size_bytes: entries.iter().map(|e| e.size_bytes).sum(),
            segment_count: segment_count as u64,
            columns: col_stats_meta,
            last_updated: now_millis,
            sample_rate,
            correlations,
        };

        // Store statistics in manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            // Remove existing stats for this table
            manifest
                .table_stats
                .retain(|s| !(s.database == database && s.table == table));

            // Add new stats
            manifest.table_stats.push(stats_meta);
            manifest.version += 1;

            // Persist manifest
            drop(manifest);
        }
        self.maybe_persist_manifest()?;

        let elapsed = start_time.elapsed();
        tracing::info!(
            "ANALYZE {}.{}: completed in {:?} - {} rows, {} columns, {} segments",
            database,
            table,
            elapsed,
            estimated_rows,
            column_count,
            segment_count
        );

        Ok(())
    }

    /// Build equi-height histogram from sorted values
    fn build_histogram(values: &mut [f64], num_buckets: usize) -> crate::replication::HistogramMeta {
        values.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));

        let n = values.len();
        let bucket_size = (n / num_buckets).max(1);
        let actual_buckets = (n / bucket_size).min(num_buckets);

        let mut boundaries = Vec::with_capacity(actual_buckets + 1);
        let mut counts = Vec::with_capacity(actual_buckets);
        let mut distinct_counts = Vec::with_capacity(actual_buckets);

        for i in 0..actual_buckets {
            let start = i * bucket_size;
            let end = if i == actual_buckets - 1 {
                n
            } else {
                (i + 1) * bucket_size
            };

            if i == 0 {
                boundaries.push(values[start].to_string());
            }
            boundaries.push(values[end - 1].to_string());

            counts.push((end - start) as u64);

            // Count distinct in bucket using raw bits (avoids string allocation)
            let bucket_distinct: std::collections::HashSet<u64> = values[start..end]
                .iter()
                .map(|v| v.to_bits())
                .collect();
            distinct_counts.push(bucket_distinct.len() as u64);
        }

        crate::replication::HistogramMeta {
            num_buckets: actual_buckets,
            boundaries,
            counts,
            distinct_counts,
        }
    }

    /// Build Most Common Values (MCV) list from value counts
    /// Returns the top N most frequent values if they represent significant fraction of data
    fn build_mcv(
        value_counts: &std::collections::HashMap<String, u64>,
        total_rows: u64,
        max_values: usize,
    ) -> Option<crate::replication::McvMeta> {
        if value_counts.is_empty() || total_rows == 0 {
            return None;
        }

        // Sort by count descending
        let mut sorted: Vec<_> = value_counts.iter().collect();
        sorted.sort_by(|a, b| b.1.cmp(a.1));

        // Only include values that appear more than once (not all unique)
        // and represent at least 0.1% of the data
        let min_count = (total_rows / 1000).max(2);
        let top_values: Vec<_> = sorted
            .into_iter()
            .filter(|(_, count)| **count >= min_count)
            .take(max_values)
            .collect();

        if top_values.is_empty() {
            return None;
        }

        // Calculate total frequency of MCV values
        let mcv_total: u64 = top_values.iter().map(|(_, c)| **c).sum();
        let mcv_fraction = mcv_total as f64 / total_rows as f64;

        // Only create MCV if the top values represent at least 1% of data
        // This indicates skewed distribution where MCV is useful
        if mcv_fraction < 0.01 {
            return None;
        }

        let values: Vec<String> = top_values.iter().map(|(v, _)| (*v).clone()).collect();
        let counts: Vec<u64> = top_values.iter().map(|(_, c)| **c).collect();

        Some(crate::replication::McvMeta {
            values,
            counts,
            total_rows,
        })
    }

    /// Compute Pearson correlation coefficient between two vectors
    fn pearson_correlation(x: &[f64], y: &[f64]) -> Option<f64> {
        let n = x.len();
        if n != y.len() || n < 2 {
            return None;
        }

        let n_f64 = n as f64;

        // Compute means
        let mean_x: f64 = x.iter().sum::<f64>() / n_f64;
        let mean_y: f64 = y.iter().sum::<f64>() / n_f64;

        // Compute covariance and standard deviations
        let mut cov = 0.0;
        let mut var_x = 0.0;
        let mut var_y = 0.0;

        for i in 0..n {
            let dx = x[i] - mean_x;
            let dy = y[i] - mean_y;
            cov += dx * dy;
            var_x += dx * dx;
            var_y += dy * dy;
        }

        if var_x == 0.0 || var_y == 0.0 {
            return None; // Constant column, no correlation
        }

        let std_x = var_x.sqrt();
        let std_y = var_y.sqrt();

        let corr = cov / (std_x * std_y);

        // Clamp to [-1, 1] to handle floating point errors
        Some(corr.max(-1.0).min(1.0))
    }

    /// Get table statistics from manifest (for query optimizer)
    pub fn get_table_stats(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Option<crate::replication::TableStatsMeta>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        Ok(manifest
            .table_stats
            .iter()
            .find(|s| s.database == database && s.table == table)
            .cloned())
    }

    /// Vacuum a table to reclaim storage
    /// - Regular VACUUM: rewrites fragmented segments (< 50% of target size)
    /// - VACUUM FULL: merges all segments into optimal-sized chunks
    /// - VACUUM FORCE: skip missing/corrupted segments instead of failing
    pub fn vacuum(
        &self,
        database: &str,
        table: &str,
        full: bool,
    ) -> Result<VacuumResult, EngineError> {
        self.vacuum_with_options(database, table, full, false)
    }

    /// Vacuum with full options including force mode
    pub fn vacuum_with_options(
        &self,
        database: &str,
        table: &str,
        full: bool,
        force: bool,
    ) -> Result<VacuumResult, EngineError> {
        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            // Verify table exists
            let table_meta = manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned();
            if table_meta.is_none() {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }
            table_meta
        };

        let target_bytes = self.cfg.compaction_target_bytes;
        let fragmentation_threshold = target_bytes / 2; // 50% of target = fragmented

        // Collect segments for this table
        let segments_to_vacuum: Vec<ManifestEntry> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect()
        };

        if segments_to_vacuum.is_empty() {
            return Ok(VacuumResult {
                segments_processed: 0,
                segments_removed: 0,
                bytes_reclaimed: 0,
                new_segments: 0,
            });
        }

        let original_count = segments_to_vacuum.len();
        let original_bytes: u64 = segments_to_vacuum.iter().map(|e| e.size_bytes).sum();

        if full {
            tracing::info!(
                "VACUUM FULL {}.{}: merging {} segments ({} bytes)",
                database,
                table,
                original_count,
                original_bytes
            );

            // VACUUM FULL: merge ALL segments into optimal chunks
            let mut all_batches = Vec::new();
            let mut skipped_segments = 0usize;
            for entry in &segments_to_vacuum {
                match self.load_segment_batches_cached(entry) {
                    Ok(decoded) => {
                        all_batches.extend(decoded.iter().cloned());
                    }
                    Err(e) => {
                        if force {
                            tracing::warn!(
                                "VACUUM FORCE: skipping damaged segment {}: {}",
                                entry.segment_id, e
                            );
                            skipped_segments += 1;
                        } else {
                            return Err(e);
                        }
                    }
                }
            }
            if skipped_segments > 0 {
                tracing::info!(
                    "VACUUM FORCE: skipped {} damaged segments out of {}",
                    skipped_segments, original_count
                );
            }

            if all_batches.is_empty() {
                return Ok(VacuumResult {
                    segments_processed: original_count,
                    segments_removed: 0,
                    bytes_reclaimed: 0,
                    new_segments: 0,
                });
            }

            // Remove old segments from manifest
            {
                let mut manifest = self
                    .manifest
                    .write()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                let drop_set: std::collections::HashSet<String> = segments_to_vacuum
                    .iter()
                    .map(|e| e.segment_id.clone())
                    .collect();
                manifest
                    .entries
                    .retain(|e| !drop_set.contains(&e.segment_id));
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
            }

            // Delete old segment files
            for entry in &segments_to_vacuum {
                self.remove_segment_file(&entry.segment_id);
            }

            // Reingest all data as new optimally-sized segments
            let schema = all_batches[0].schema();
            let merged_ipc = record_batches_to_ipc(schema.as_ref(), &all_batches)?;

            let max_watermark = segments_to_vacuum
                .iter()
                .map(|e| e.watermark_micros)
                .max()
                .unwrap_or(0);

            self.ingest_ipc(IngestBatch {
                payload_ipc: merged_ipc,
                watermark_micros: max_watermark,
                shard_override: None,
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;

            let new_bytes: u64 = {
                let manifest = self
                    .manifest
                    .read()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest
                    .entries
                    .iter()
                    .filter(|e| e.database == database && e.table == table)
                    .map(|e| e.size_bytes)
                    .sum()
            };

            let new_count = {
                let manifest = self
                    .manifest
                    .read()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest
                    .entries
                    .iter()
                    .filter(|e| e.database == database && e.table == table)
                    .count()
            };

            // Invalidate query cache
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }

            tracing::info!(
                "VACUUM FULL complete: {} -> {} segments, {} -> {} bytes",
                original_count,
                new_count,
                original_bytes,
                new_bytes
            );

            Ok(VacuumResult {
                segments_processed: original_count,
                segments_removed: original_count,
                bytes_reclaimed: original_bytes.saturating_sub(new_bytes),
                new_segments: new_count,
            })
        } else {
            // Regular VACUUM: only rewrite fragmented segments (< 50% of target)
            let fragmented: Vec<ManifestEntry> = segments_to_vacuum
                .into_iter()
                .filter(|e| e.size_bytes < fragmentation_threshold)
                .collect();

            if fragmented.is_empty() {
                tracing::info!(
                    "VACUUM {}.{}: no fragmented segments found",
                    database,
                    table
                );
                return Ok(VacuumResult {
                    segments_processed: original_count,
                    segments_removed: 0,
                    bytes_reclaimed: 0,
                    new_segments: 0,
                });
            }

            tracing::info!(
                "VACUUM {}.{}: rewriting {} fragmented segments",
                database,
                table,
                fragmented.len()
            );

            // Group fragmented segments and compact them
            let fragmented_count = fragmented.len();
            let fragmented_bytes: u64 = fragmented.iter().map(|e| e.size_bytes).sum();

            // Use existing compaction logic
            if fragmented.len() >= 2 {
                self.compact_entries(fragmented, table_meta)?;
            }

            let new_bytes: u64 = {
                let manifest = self
                    .manifest
                    .read()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest
                    .entries
                    .iter()
                    .filter(|e| e.database == database && e.table == table)
                    .map(|e| e.size_bytes)
                    .sum()
            };

            // Invalidate query cache
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }

            Ok(VacuumResult {
                segments_processed: original_count,
                segments_removed: fragmented_count,
                bytes_reclaimed: fragmented_bytes
                    .saturating_sub(new_bytes.saturating_sub(original_bytes - fragmented_bytes)),
                new_segments: 1,
            })
        }
    }

    // ==================== Background Compaction ====================

    /// Get list of tables that are candidates for compaction, sorted by priority
    /// This helps implement intelligent background compaction that avoids merge storms
    pub fn get_compaction_candidates(&self) -> Result<Vec<CompactionCandidate>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let target_bytes = self.cfg.compaction_target_bytes;
        let min_segments = self.cfg.compact_min_segments;

        // Group segments by table
        let mut table_segments: std::collections::HashMap<(String, String), Vec<&ManifestEntry>> =
            std::collections::HashMap::new();
        for entry in &manifest.entries {
            if !matches!(entry.tier, SegmentTier::Hot) {
                continue;
            }
            let key = (entry.database.clone(), entry.table.clone());
            table_segments.entry(key).or_default().push(entry);
        }

        let mut candidates = Vec::new();
        for ((database, table), segments) in table_segments {
            // Skip if not enough segments
            if segments.len() < min_segments {
                continue;
            }

            // Skip if table is in cooldown
            if self.compaction_state.is_table_in_cooldown(
                &database,
                &table,
                self.cfg.compaction_cooldown_secs,
            ) {
                continue;
            }

            // Count small segments (< 50% of target)
            let fragmentation_threshold = target_bytes / 2;
            let small_segments: Vec<_> = segments
                .iter()
                .filter(|e| e.size_bytes < fragmentation_threshold)
                .collect();

            if small_segments.len() < min_segments {
                continue;
            }

            let total_bytes: u64 = segments.iter().map(|e| e.size_bytes).sum();
            let avg_size = total_bytes / segments.len() as u64;

            // Priority based on:
            // - More small segments = higher priority
            // - Smaller average size = higher priority
            // - More total segments = higher priority
            let priority = (small_segments.len() as u32 * 10)
                + ((target_bytes.saturating_sub(avg_size)) / (1024 * 1024)) as u32
                + segments.len() as u32;

            candidates.push(CompactionCandidate {
                database,
                table,
                segment_count: segments.len(),
                total_bytes,
                avg_segment_size: avg_size,
                priority,
            });
        }

        // Sort by priority (highest first)
        candidates.sort_by(|a, b| b.priority.cmp(&a.priority));
        Ok(candidates)
    }

    /// Get compaction candidates using leveled compaction strategy (ClickHouse MergeTree-style)
    /// Segments are organized into exponential size levels:
    /// - Level 0: < level_base_bytes (default 1MB)
    /// - Level N: level_base_bytes * level_multiplier^(N-1) to level_base_bytes * level_multiplier^N
    /// When a level has >= segments_per_level_trigger segments, they're merged to the next level
    pub fn get_leveled_compaction_candidates(&self) -> Result<Vec<LeveledCompactionCandidate>, EngineError> {
        if !self.cfg.leveled_compaction_enabled {
            return Ok(Vec::new());
        }

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let base_bytes = self.cfg.level_base_bytes;
        let multiplier = self.cfg.level_multiplier;
        let max_levels = self.cfg.max_levels;
        let trigger = self.cfg.segments_per_level_trigger;

        // Helper to determine level for a segment size
        let get_level = |size_bytes: u64| -> usize {
            if size_bytes < base_bytes {
                return 0;
            }
            let mut level = 1;
            let mut threshold = base_bytes * multiplier;
            while level < max_levels && size_bytes >= threshold {
                level += 1;
                threshold = threshold.saturating_mul(multiplier);
            }
            level.min(max_levels - 1)
        };

        // Group segments by (database, table, level)
        let mut table_levels: std::collections::HashMap<(String, String), Vec<Vec<&ManifestEntry>>> =
            std::collections::HashMap::new();

        for entry in &manifest.entries {
            // Only compact Hot tier segments
            if !matches!(entry.tier, SegmentTier::Hot) {
                continue;
            }

            let key = (entry.database.clone(), entry.table.clone());
            let level = get_level(entry.size_bytes);

            let levels = table_levels.entry(key).or_insert_with(|| vec![Vec::new(); max_levels]);
            if level < levels.len() {
                levels[level].push(entry);
            }
        }

        let mut candidates = Vec::new();

        for ((database, table), levels) in table_levels {
            // Skip tables in cooldown (unless we have many small segments)
            let in_cooldown = self.compaction_state.is_table_in_cooldown(
                &database,
                &table,
                self.cfg.compaction_cooldown_secs,
            );

            // Find levels that need compaction (have >= trigger segments)
            for (level, segments) in levels.iter().enumerate() {
                // Skip if not enough segments at this level
                if segments.len() < trigger {
                    continue;
                }

                // Skip if in cooldown and not level 0 (always prioritize tiny segment cleanup)
                if in_cooldown && level > 0 {
                    continue;
                }

                let total_bytes: u64 = segments.iter().map(|e| e.size_bytes).sum();
                let segment_ids: Vec<String> = segments.iter().map(|e| e.segment_id.clone()).collect();

                // Calculate target level after merge
                let merged_size = total_bytes;
                let target_level = get_level(merged_size);

                // Priority: lower levels get higher priority (clean up small segments first)
                // Also boost priority for levels with many segments
                let priority = ((max_levels - level) as u32 * 100) + (segments.len() as u32 * 10);

                candidates.push(LeveledCompactionCandidate {
                    database: database.clone(),
                    table: table.clone(),
                    level,
                    target_level,
                    segment_count: segments.len(),
                    total_bytes,
                    segment_ids,
                    priority,
                });
            }
        }

        // Sort by priority (highest first = lowest level first)
        candidates.sort_by(|a, b| b.priority.cmp(&a.priority));
        Ok(candidates)
    }

    /// Run a single round of background compaction
    /// Returns the number of tables compacted
    pub fn run_background_compaction(&self) -> Result<usize, EngineError> {
        if !self.cfg.enable_compaction {
            return Ok(0);
        }

        // Check for emergency compaction first (high priority, bypasses normal limits)
        if self.needs_emergency_compaction() {
            tracing::warn!(
                segments = self.segment_count(),
                threshold = self.cfg.max_segments_emergency_threshold,
                "EMERGENCY: Segment count exceeds threshold, running emergency compaction"
            );
            return self.run_emergency_compaction();
        }

        // Check if we can start more compactions
        if !self
            .compaction_state
            .can_start_compaction(self.cfg.max_concurrent_compactions)
        {
            tracing::debug!(
                "Skipping background compaction: {} active (max {})",
                self.compaction_state.active_count(),
                self.cfg.max_concurrent_compactions
            );
            return Ok(0);
        }

        // Try leveled compaction first (ClickHouse MergeTree-style)
        // This is more efficient at keeping segment count low
        if self.cfg.leveled_compaction_enabled {
            let leveled_count = self.run_leveled_compaction()?;
            if leveled_count > 0 {
                tracing::debug!("Leveled compaction merged {} segment groups", leveled_count);
                return Ok(leveled_count);
            }
        }

        // Fall back to traditional compaction for any remaining work
        let candidates = self.get_compaction_candidates()?;
        if candidates.is_empty() {
            return Ok(0);
        }

        let mut compacted = 0;
        for candidate in candidates {
            // Check again before each compaction
            if !self
                .compaction_state
                .can_start_compaction(self.cfg.max_concurrent_compactions)
            {
                break;
            }

            self.compaction_state
                .start_compaction(&candidate.database, &candidate.table);

            match self.vacuum(&candidate.database, &candidate.table, false) {
                Ok(result) => {
                    if result.segments_removed > 0 {
                        tracing::info!(
                            "Background compaction on {}.{}: {} segments -> {} bytes reclaimed",
                            candidate.database,
                            candidate.table,
                            result.segments_removed,
                            result.bytes_reclaimed
                        );
                        compacted += 1;
                    }
                }
                Err(e) => {
                    tracing::warn!(
                        "Background compaction failed on {}.{}: {}",
                        candidate.database,
                        candidate.table,
                        e
                    );
                }
            }

            self.compaction_state.finish_compaction();
        }

        Ok(compacted)
    }

    /// Run leveled compaction (ClickHouse MergeTree-style)
    /// Merges segments at each level when they exceed the trigger threshold
    /// Returns the number of merge operations performed
    pub fn run_leveled_compaction(&self) -> Result<usize, EngineError> {
        if !self.cfg.leveled_compaction_enabled {
            return Ok(0);
        }

        let candidates = self.get_leveled_compaction_candidates()?;
        if candidates.is_empty() {
            return Ok(0);
        }

        let mut merged = 0;
        let max_per_cycle = self.cfg.compaction_passes_per_cycle;

        for candidate in candidates.into_iter().take(max_per_cycle) {
            // Check concurrency limit
            if !self.compaction_state.can_start_compaction(self.cfg.max_concurrent_compactions) {
                break;
            }

            self.compaction_state.start_compaction(&candidate.database, &candidate.table);

            // Use merge_specific_segments to merge exactly the segments at this level
            match self.merge_segments_by_ids(
                &candidate.database,
                &candidate.table,
                &candidate.segment_ids,
            ) {
                Ok(new_segment_id) => {
                    tracing::info!(
                        "Leveled compaction L{} -> L{}: {}.{} merged {} segments ({} bytes) -> {}",
                        candidate.level,
                        candidate.target_level,
                        candidate.database,
                        candidate.table,
                        candidate.segment_count,
                        candidate.total_bytes,
                        new_segment_id.unwrap_or_else(|| "none".to_string())
                    );
                    merged += 1;
                }
                Err(e) => {
                    tracing::warn!(
                        "Leveled compaction failed for {}.{} L{}: {}",
                        candidate.database,
                        candidate.table,
                        candidate.level,
                        e
                    );
                }
            }

            self.compaction_state.finish_compaction();
        }

        Ok(merged)
    }

    /// Merge specific segments by their IDs
    /// Returns the new segment ID if segments were merged, None if no merge occurred
    fn merge_segments_by_ids(
        &self,
        database: &str,
        table: &str,
        segment_ids: &[String],
    ) -> Result<Option<String>, EngineError> {
        if segment_ids.is_empty() {
            return Ok(None);
        }

        // Load all segments to merge
        let manifest = self.manifest.read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let entries_to_merge: Vec<ManifestEntry> = segment_ids
            .iter()
            .filter_map(|id| {
                manifest.entries.iter()
                    .find(|e| &e.segment_id == id && e.database == database && e.table == table)
                    .cloned()
            })
            .collect();

        drop(manifest); // Release read lock

        if entries_to_merge.len() < 2 {
            return Ok(None); // Need at least 2 segments to merge
        }

        // Load and concatenate all batches
        let mut all_batches = Vec::new();
        for entry in &entries_to_merge {
            let payload = self.load_segment_cached(entry)?;
            let batches = read_ipc_batches(&payload)?;
            all_batches.extend(batches);
        }

        if all_batches.is_empty() {
            return Ok(None);
        }

        let schema = all_batches[0].schema();

        // Concatenate into single batch
        let concatenated = arrow_select::concat::concat_batches(&schema, &all_batches)
            .map_err(|e| EngineError::Internal(format!("concat batches failed: {e}")))?;

        // Sort by primary key if available
        let sorted = self.sort_batch_by_primary_key(&concatenated, database, table)?;

        // Get compression from table settings
        let compression = {
            let manifest = self.manifest.read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest.tables.iter()
                .find(|t| t.database == database && t.name == table)
                .and_then(|t| t.compression.clone())
                .or_else(|| self.cfg.tier_warm_compression.clone())
        };

        // Write merged segment
        let new_segment_id = format!(
            "{}_{}_{}_merged_{}",
            database,
            table,
            self.segment_seq.fetch_add(1, Ordering::Relaxed),
            chrono::Utc::now().timestamp_millis()
        );

        let ipc = record_batches_to_ipc(&schema, &[sorted.clone()])?;
        let compressed = compress_payload(&ipc, compression.as_deref())?;
        let checksum = compute_checksum(&compressed);
        let size_bytes = compressed.len() as u64;

        // Persist to disk
        let segment_path = self.cfg.segments_dir.join(format!("{}.ipc", new_segment_id));
        std::fs::write(&segment_path, &compressed)
            .map_err(|e| EngineError::Io(format!("write merged segment failed: {e}")))?;

        // Compute stats by merging stats from source entries
        // This avoids recomputing from the actual data
        let event_time_min = entries_to_merge.iter().filter_map(|e| e.event_time_min).min();
        let event_time_max = entries_to_merge.iter().filter_map(|e| e.event_time_max).max();
        let tenant_id_min = entries_to_merge.iter().filter_map(|e| e.tenant_id_min).min();
        let tenant_id_max = entries_to_merge.iter().filter_map(|e| e.tenant_id_max).max();
        let route_id_min = entries_to_merge.iter().filter_map(|e| e.route_id_min).min();
        let route_id_max = entries_to_merge.iter().filter_map(|e| e.route_id_max).max();
        let watermark_micros = entries_to_merge.iter().map(|e| e.watermark_micros).max().unwrap_or(0);

        // Compute schema hash from IPC
        let schema_hash = compute_schema_hash_from_payload(&ipc, None).ok();

        // Create new manifest entry (mark as Warm since it's compacted)
        let new_entry = ManifestEntry {
            segment_id: new_segment_id.clone(),
            shard_id: entries_to_merge[0].shard_id,
            version_added: 0, // Will be set by manifest update
            size_bytes,
            checksum,
            tier: SegmentTier::Warm,
            compression,
            database: database.to_string(),
            table: table.to_string(),
            watermark_micros,
            event_time_min,
            event_time_max,
            tenant_id_min,
            tenant_id_max,
            route_id_min,
            route_id_max,
            bloom_tenant: None, // Blooms rebuilt lazily on query
            bloom_route: None,
            column_stats: None, // Stats computed lazily
            schema_hash,
            created_txn: None,
            deleted_txn: None,
            deleted_version: None,
        };

        // Update manifest: remove old segments, add new
        {
            let mut manifest = self.manifest.write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            // Remove old segments
            let old_ids: std::collections::HashSet<_> = segment_ids.iter().collect();
            manifest.entries.retain(|e| !old_ids.contains(&e.segment_id));

            // Add new segment
            let mut entry_with_version = new_entry;
            entry_with_version.version_added = manifest.version + 1;
            manifest.entries.push(entry_with_version);
            manifest.bump_version();

            persist_manifest(&self.cfg.manifest_path, &manifest)?;

            // Update index
            let mut index = self.manifest_index.write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Delete old segment files
        for id in segment_ids {
            let old_path = self.cfg.segments_dir.join(format!("{}.ipc", id));
            if let Err(e) = std::fs::remove_file(&old_path) {
                tracing::warn!("Failed to delete old segment file {}: {}", id, e);
            }
        }

        // Note: Cache entries for merged segments will be evicted naturally by LRU.
        // The segments are no longer in the manifest, so they won't be accessed.

        Ok(Some(new_segment_id))
    }

    /// Sort a record batch by primary key columns if defined for the table
    fn sort_batch_by_primary_key(
        &self,
        batch: &RecordBatch,
        database: &str,
        table: &str,
    ) -> Result<RecordBatch, EngineError> {
        use arrow_ord::sort::{lexsort_to_indices, SortColumn};

        // Get primary key columns from table schema
        let manifest = self.manifest.read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let pk_cols: Vec<String> = manifest.tables.iter()
            .find(|t| t.database == database && t.name == table)
            .map(|t| {
                // Use common CDR columns as default sort key
                let mut cols = Vec::new();
                for col in ["event_time", "tenant_id", "route_id"] {
                    if batch.schema().field_with_name(col).is_ok() {
                        cols.push(col.to_string());
                    }
                }
                cols
            })
            .unwrap_or_default();

        drop(manifest);

        if pk_cols.is_empty() || batch.num_rows() == 0 {
            return Ok(batch.clone());
        }

        // Build sort columns
        let sort_cols: Vec<SortColumn> = pk_cols.iter()
            .filter_map(|name| {
                batch.column_by_name(name).map(|col| SortColumn {
                    values: col.clone(),
                    options: None,
                })
            })
            .collect();

        if sort_cols.is_empty() {
            return Ok(batch.clone());
        }

        // Sort
        let indices = lexsort_to_indices(&sort_cols, None)
            .map_err(|e| EngineError::Internal(format!("sort failed: {e}")))?;

        // Apply sort indices
        let sorted_columns: Vec<_> = batch.columns().iter()
            .map(|col| arrow_select::take::take(col.as_ref(), &indices, None))
            .collect::<Result<_, _>>()
            .map_err(|e| EngineError::Internal(format!("take failed: {e}")))?;

        RecordBatch::try_new(batch.schema(), sorted_columns)
            .map_err(|e| EngineError::Internal(format!("rebuild batch failed: {e}")))
    }

    /// Get the auto-compact interval from config (0 = disabled)
    pub fn auto_compact_interval_secs(&self) -> u64 {
        self.cfg.auto_compact_interval_secs
    }

    pub fn set_table_compression(
        &self,
        database: &str,
        table: &str,
        compression: Option<String>,
    ) -> Result<(), EngineError> {
        let comp = normalize_compression(compression)?;
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let tbl = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;
        tbl.compression = comp.clone();
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        Ok(())
    }

    // ==================== Deduplication ====================

    /// Set deduplication configuration for a table
    /// This enables automatic deduplication with merge-on-read semantics
    pub fn set_table_deduplication(
        &self,
        database: &str,
        table: &str,
        config: Option<crate::sql::DeduplicationConfig>,
    ) -> Result<(), EngineError> {
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let tbl = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;
        tbl.deduplication = config.clone();
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        if let Some(cfg) = config {
            tracing::info!(
                "Deduplication enabled on {}.{}: keys={:?}, version={:?}, mode={:?}",
                database,
                table,
                cfg.key_columns,
                cfg.version_column,
                cfg.mode
            );
        } else {
            tracing::info!("Deduplication disabled on {}.{}", database, table);
        }
        Ok(())
    }

    /// Get deduplication config for a table
    pub fn get_table_deduplication(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Option<crate::sql::DeduplicationConfig>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let tbl = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;
        Ok(tbl.deduplication.clone())
    }

    /// Add a constraint to a table
    pub fn add_constraint(
        &self,
        database: &str,
        table: &str,
        constraint: crate::sql::TableConstraint,
    ) -> Result<(), EngineError> {
        use crate::sql::TableConstraint;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // First, check if table exists and verify foreign key referenced table exists (before mutable borrow)
        let table_idx = manifest
            .tables
            .iter()
            .position(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;

        // For foreign keys, verify referenced table exists before we take mutable borrow
        if let TableConstraint::ForeignKey {
            referenced_table,
            columns,
            ..
        } = &constraint
        {
            if !manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == *referenced_table)
            {
                return Err(EngineError::NotFound(format!(
                    "Referenced table '{}' does not exist",
                    referenced_table
                )));
            }
            tracing::info!(
                "Adding foreign key on columns {:?} referencing {}.{}",
                columns,
                database,
                referenced_table
            );
        }

        let tbl = &mut manifest.tables[table_idx];

        // Validate constraint doesn't conflict with existing ones
        match &constraint {
            TableConstraint::PrimaryKey { name, .. } => {
                // Only one primary key allowed
                if tbl
                    .constraints
                    .iter()
                    .any(|c| matches!(c, TableConstraint::PrimaryKey { .. }))
                {
                    return Err(EngineError::InvalidArgument(
                        "table already has a primary key".into(),
                    ));
                }
                // Check for name conflict
                if let Some(n) = name {
                    if tbl.constraints.iter().any(|c| match c {
                        TableConstraint::PrimaryKey {
                            name: Some(existing),
                            ..
                        }
                        | TableConstraint::Unique {
                            name: Some(existing),
                            ..
                        }
                        | TableConstraint::Check {
                            name: Some(existing),
                            ..
                        } => existing == n,
                        _ => false,
                    }) {
                        return Err(EngineError::InvalidArgument(format!(
                            "constraint '{}' already exists",
                            n
                        )));
                    }
                }
            }
            TableConstraint::Unique { name, .. } | TableConstraint::Check { name, .. } => {
                if let Some(n) = name {
                    if tbl.constraints.iter().any(|c| match c {
                        TableConstraint::PrimaryKey {
                            name: Some(existing),
                            ..
                        }
                        | TableConstraint::Unique {
                            name: Some(existing),
                            ..
                        }
                        | TableConstraint::Check {
                            name: Some(existing),
                            ..
                        } => existing == n,
                        _ => false,
                    }) {
                        return Err(EngineError::InvalidArgument(format!(
                            "constraint '{}' already exists",
                            n
                        )));
                    }
                }
            }
            TableConstraint::NotNull { column } => {
                // Check for duplicate NOT NULL
                if tbl
                    .constraints
                    .iter()
                    .any(|c| matches!(c, TableConstraint::NotNull { column: col } if col == column))
                {
                    return Err(EngineError::InvalidArgument(format!(
                        "NOT NULL constraint already exists for column '{}'",
                        column
                    )));
                }
            }
            TableConstraint::Default { column, .. } => {
                // Check for duplicate DEFAULT
                if tbl.constraints.iter().any(
                    |c| matches!(c, TableConstraint::Default { column: col, .. } if col == column),
                ) {
                    return Err(EngineError::InvalidArgument(format!(
                        "DEFAULT constraint already exists for column '{}'",
                        column
                    )));
                }
            }
            TableConstraint::ForeignKey { name, .. } => {
                // Check for duplicate foreign key name
                if let Some(n) = name {
                    if tbl.constraints.iter().any(|c| match c {
                        TableConstraint::ForeignKey {
                            name: Some(existing),
                            ..
                        } => existing == n,
                        _ => false,
                    }) {
                        return Err(EngineError::InvalidArgument(format!(
                            "Foreign key constraint '{}' already exists",
                            n
                        )));
                    }
                }
                // Referenced table check already done above
            }
        }

        tbl.constraints.push(constraint.clone());
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        tracing::info!(
            "Added constraint to {}.{}: {:?}",
            database,
            table,
            constraint
        );
        Ok(())
    }

    /// Drop a constraint from a table by name
    pub fn drop_constraint(
        &self,
        database: &str,
        table: &str,
        constraint_name: &str,
    ) -> Result<(), EngineError> {
        use crate::sql::TableConstraint;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let tbl = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;

        let original_len = tbl.constraints.len();
        tbl.constraints.retain(|c| match c {
            TableConstraint::PrimaryKey { name: Some(n), .. }
            | TableConstraint::Unique { name: Some(n), .. }
            | TableConstraint::Check { name: Some(n), .. } => n != constraint_name,
            _ => true,
        });

        if tbl.constraints.len() == original_len {
            return Err(EngineError::NotFound(format!(
                "constraint '{}' not found",
                constraint_name
            )));
        }

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        tracing::info!(
            "Dropped constraint '{}' from {}.{}",
            constraint_name,
            database,
            table
        );
        Ok(())
    }

    /// Get all constraints for a table
    pub fn get_table_constraints(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Vec<crate::sql::TableConstraint>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let tbl = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound("table not found".into()))?;
        Ok(tbl.constraints.clone())
    }

    // =========================================================================
    // Sequence Management
    // =========================================================================

    /// Create a new sequence
    pub fn create_sequence(
        &self,
        database: &str,
        name: &str,
        start: i64,
        increment: i64,
        min_value: Option<i64>,
        max_value: Option<i64>,
        cycle: bool,
        if_not_exists: bool,
    ) -> Result<(), EngineError> {
        use crate::replication::SequenceMeta;

        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(name, "sequence")?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Check if database exists
        if !manifest.databases.iter().any(|db| db.name == database) {
            return Err(EngineError::NotFound(format!(
                "database '{}' not found",
                database
            )));
        }

        // Check if sequence already exists
        if manifest
            .sequences
            .iter()
            .any(|s| s.database == database && s.name == name)
        {
            if if_not_exists {
                return Ok(());
            }
            return Err(EngineError::InvalidArgument(format!(
                "sequence '{}' already exists in database '{}'",
                name, database
            )));
        }

        let now_micros = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);

        let seq = SequenceMeta {
            database: database.to_string(),
            name: name.to_string(),
            current_value: start - increment, // nextval will return start
            increment,
            min_value: min_value.unwrap_or(1),
            max_value: max_value.unwrap_or(i64::MAX),
            cycle,
            created_micros: now_micros,
        };

        manifest.sequences.push(seq);
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Drop a sequence
    pub fn drop_sequence(
        &self,
        database: &str,
        name: &str,
        if_exists: bool,
    ) -> Result<(), EngineError> {
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(name, "sequence")?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let idx = manifest
            .sequences
            .iter()
            .position(|s| s.database == database && s.name == name);

        match idx {
            Some(i) => {
                manifest.sequences.remove(i);
                manifest.bump_version();
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
                Ok(())
            }
            None => {
                if if_exists {
                    Ok(())
                } else {
                    Err(EngineError::NotFound(format!(
                        "sequence '{}' not found in database '{}'",
                        name, database
                    )))
                }
            }
        }
    }

    /// Alter a sequence (restart or change increment)
    pub fn alter_sequence(
        &self,
        database: &str,
        name: &str,
        restart_with: Option<i64>,
        increment: Option<i64>,
    ) -> Result<(), EngineError> {
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(name, "sequence")?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let seq = manifest
            .sequences
            .iter_mut()
            .find(|s| s.database == database && s.name == name)
            .ok_or_else(|| {
                EngineError::NotFound(format!(
                    "sequence '{}' not found in database '{}'",
                    name, database
                ))
            })?;

        if let Some(restart) = restart_with {
            seq.current_value = restart - seq.increment;
        }
        if let Some(inc) = increment {
            seq.increment = inc;
        }

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Get next value from sequence (NEXTVAL)
    pub fn nextval(&self, database: &str, name: &str) -> Result<i64, EngineError> {
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(name, "sequence")?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let seq = manifest
            .sequences
            .iter_mut()
            .find(|s| s.database == database && s.name == name)
            .ok_or_else(|| {
                EngineError::NotFound(format!(
                    "sequence '{}' not found in database '{}'",
                    name, database
                ))
            })?;

        let next = seq.current_value + seq.increment;

        // Check bounds
        if seq.increment > 0 && next > seq.max_value {
            if seq.cycle {
                seq.current_value = seq.min_value;
            } else {
                return Err(EngineError::InvalidArgument(format!(
                    "sequence '{}' reached maximum value {}",
                    name, seq.max_value
                )));
            }
        } else if seq.increment < 0 && next < seq.min_value {
            if seq.cycle {
                seq.current_value = seq.max_value;
            } else {
                return Err(EngineError::InvalidArgument(format!(
                    "sequence '{}' reached minimum value {}",
                    name, seq.min_value
                )));
            }
        } else {
            seq.current_value = next;
        }

        let result = seq.current_value;
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(result)
    }

    /// Get current value from sequence (CURRVAL) - only valid after NEXTVAL
    pub fn currval(&self, database: &str, name: &str) -> Result<i64, EngineError> {
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(name, "sequence")?;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let seq = manifest
            .sequences
            .iter()
            .find(|s| s.database == database && s.name == name)
            .ok_or_else(|| {
                EngineError::NotFound(format!(
                    "sequence '{}' not found in database '{}'",
                    name, database
                ))
            })?;

        Ok(seq.current_value)
    }

    /// Get all sequences in a database (for SHOW SEQUENCES)
    pub fn list_sequences(
        &self,
        database: &str,
    ) -> Result<Vec<crate::replication::SequenceMeta>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        Ok(manifest
            .sequences
            .iter()
            .filter(|s| s.database == database)
            .cloned()
            .collect())
    }

    // =========================================================================
    // User-Defined Functions (UDFs)
    // =========================================================================

    /// Create or replace a user-defined function
    pub fn create_function(
        &self,
        name: &str,
        parameters: Vec<crate::sql::FunctionParameter>,
        return_type: &str,
        body: crate::sql::FunctionBody,
        language: Option<String>,
        or_replace: bool,
    ) -> Result<(), EngineError> {
        self.validate_identifier(name, "function")?;

        let mut registry = self.udf_registry.write();

        // Check if function already exists
        if registry.get(name).is_some() && !or_replace {
            return Err(EngineError::InvalidArgument(format!(
                "function '{}' already exists (use CREATE OR REPLACE to overwrite)",
                name
            )));
        }

        let udf = UserDefinedFunction {
            name: name.to_string(),
            parameters,
            return_type: return_type.to_string(),
            body,
            language,
        };

        registry.register(udf);
        tracing::info!(function = %name, "UDF created");
        Ok(())
    }

    /// Drop a user-defined function
    pub fn drop_function(&self, name: &str, if_exists: bool) -> Result<(), EngineError> {
        self.validate_identifier(name, "function")?;

        let mut registry = self.udf_registry.write();

        if registry.unregister(name) {
            tracing::info!(function = %name, "UDF dropped");
            Ok(())
        } else if if_exists {
            Ok(())
        } else {
            Err(EngineError::NotFound(format!(
                "function '{}' not found",
                name
            )))
        }
    }

    /// List all user-defined functions
    pub fn list_functions(&self, pattern: Option<&str>) -> Vec<UserDefinedFunction> {
        let registry = self.udf_registry.read();
        registry.list_matching(pattern).into_iter().cloned().collect()
    }

    /// Get a specific user-defined function
    pub fn get_function(&self, name: &str) -> Option<UserDefinedFunction> {
        let registry = self.udf_registry.read();
        registry.get(name).cloned()
    }

    /// Execute a user-defined function with given arguments
    pub fn execute_udf(
        &self,
        name: &str,
        args: Vec<ScalarValue>,
    ) -> Result<ScalarValue, EngineError> {
        let udf = self.get_function(name).ok_or_else(|| {
            EngineError::NotFound(format!("function '{}' not found", name))
        })?;

        // Validate argument count
        let required_params: Vec<_> = udf.parameters.iter()
            .filter(|p| p.default_value.is_none())
            .collect();
        if args.len() < required_params.len() {
            return Err(EngineError::InvalidArgument(format!(
                "function '{}' requires at least {} arguments, got {}",
                name, required_params.len(), args.len()
            )));
        }
        if args.len() > udf.parameters.len() {
            return Err(EngineError::InvalidArgument(format!(
                "function '{}' accepts at most {} arguments, got {}",
                name, udf.parameters.len(), args.len()
            )));
        }

        // Build parameter bindings
        let mut bindings: HashMap<String, ScalarValue> = HashMap::new();
        for (i, param) in udf.parameters.iter().enumerate() {
            let value = if i < args.len() {
                args[i].clone()
            } else if let Some(ref default) = param.default_value {
                // Parse default value
                Self::parse_default_value(default)?
            } else {
                return Err(EngineError::InvalidArgument(format!(
                    "missing required argument '{}' for function '{}'",
                    param.name, name
                )));
            };
            bindings.insert(param.name.clone(), value);
        }

        // Execute based on function body type
        match &udf.body {
            crate::sql::FunctionBody::SqlExpression(expr) => {
                self.evaluate_udf_expression(expr, &bindings)
            }
            crate::sql::FunctionBody::SqlQuery(query) => {
                // For SQL queries, we'd execute and return first value
                // For now, just evaluate as expression
                self.evaluate_udf_expression(query, &bindings)
            }
            crate::sql::FunctionBody::External { library, symbol } => {
                Err(EngineError::NotImplemented(format!(
                    "external functions not yet supported: {}::{}",
                    library, symbol
                )))
            }
        }
    }

    /// Parse a default value string into ScalarValue
    fn parse_default_value(default: &str) -> Result<ScalarValue, EngineError> {
        let trimmed = default.trim();

        // Handle NULL
        if trimmed.eq_ignore_ascii_case("null") {
            return Ok(ScalarValue::Null);
        }

        // Handle quoted strings
        if (trimmed.starts_with('\'') && trimmed.ends_with('\''))
            || (trimmed.starts_with('"') && trimmed.ends_with('"'))
        {
            let inner = &trimmed[1..trimmed.len() - 1];
            return Ok(ScalarValue::Utf8(inner.to_string()));
        }

        // Handle booleans
        if trimmed.eq_ignore_ascii_case("true") {
            return Ok(ScalarValue::Bool(true));
        }
        if trimmed.eq_ignore_ascii_case("false") {
            return Ok(ScalarValue::Bool(false));
        }

        // Try parsing as integer
        if let Ok(i) = trimmed.parse::<i64>() {
            return Ok(ScalarValue::Int64(i));
        }

        // Try parsing as float
        if let Ok(f) = trimmed.parse::<f64>() {
            return Ok(ScalarValue::Float64(f));
        }

        // Return as string
        Ok(ScalarValue::Utf8(trimmed.to_string()))
    }

    /// Maximum recursion depth for UDF expression evaluation
    const UDF_MAX_RECURSION_DEPTH: usize = 100;

    /// Evaluate a UDF expression with parameter bindings
    fn evaluate_udf_expression(
        &self,
        expr: &str,
        bindings: &HashMap<String, ScalarValue>,
    ) -> Result<ScalarValue, EngineError> {
        self.evaluate_udf_expression_with_depth(expr, bindings, 0)
    }

    /// Internal recursive evaluator with depth tracking
    fn evaluate_udf_expression_with_depth(
        &self,
        expr: &str,
        bindings: &HashMap<String, ScalarValue>,
        depth: usize,
    ) -> Result<ScalarValue, EngineError> {
        // Prevent stack overflow from deeply nested or malicious expressions
        if depth > Self::UDF_MAX_RECURSION_DEPTH {
            return Err(EngineError::InvalidArgument(
                "UDF expression too deeply nested (max 100 levels)".into(),
            ));
        }

        let trimmed = expr.trim();

        // Check if it's just a parameter reference
        if let Some(value) = bindings.get(trimmed) {
            return Ok(value.clone());
        }

        // Handle simple arithmetic expressions
        // Support: +, -, *, /, %, ||
        if let Some(result) = self.evaluate_arithmetic_expr_with_depth(trimmed, bindings, depth)? {
            return Ok(result);
        }

        // Handle CONCAT function
        if trimmed.to_uppercase().starts_with("CONCAT(") && trimmed.ends_with(')') {
            let inner = &trimmed[7..trimmed.len() - 1];
            let parts: Vec<&str> = inner.split(',').collect();
            let mut result = String::new();
            for part in parts {
                let val = self.evaluate_udf_expression_with_depth(part.trim(), bindings, depth + 1)?;
                result.push_str(&val.to_string());
            }
            return Ok(ScalarValue::Utf8(result));
        }

        // Handle COALESCE function
        if trimmed.to_uppercase().starts_with("COALESCE(") && trimmed.ends_with(')') {
            let inner = &trimmed[9..trimmed.len() - 1];
            let parts: Vec<&str> = inner.split(',').collect();
            for part in parts {
                let val = self.evaluate_udf_expression_with_depth(part.trim(), bindings, depth + 1)?;
                if !matches!(val, ScalarValue::Null) {
                    return Ok(val);
                }
            }
            return Ok(ScalarValue::Null);
        }

        // Handle IF/CASE expressions
        if trimmed.to_uppercase().starts_with("IF(") && trimmed.ends_with(')') {
            let inner = &trimmed[3..trimmed.len() - 1];
            let parts: Vec<&str> = inner.splitn(3, ',').collect();
            if parts.len() == 3 {
                let condition = self.evaluate_udf_expression_with_depth(parts[0].trim(), bindings, depth + 1)?;
                let is_true = match condition {
                    ScalarValue::Bool(b) => b,
                    ScalarValue::Int64(i) => i != 0,
                    ScalarValue::Float64(f) => f != 0.0,
                    _ => false,
                };
                return if is_true {
                    self.evaluate_udf_expression_with_depth(parts[1].trim(), bindings, depth + 1)
                } else {
                    self.evaluate_udf_expression_with_depth(parts[2].trim(), bindings, depth + 1)
                };
            }
        }

        // Try parsing as literal
        Self::parse_default_value(trimmed)
    }

    /// Evaluate simple arithmetic expressions (internal, with depth tracking)
    fn evaluate_arithmetic_expr_with_depth(
        &self,
        expr: &str,
        bindings: &HashMap<String, ScalarValue>,
        depth: usize,
    ) -> Result<Option<ScalarValue>, EngineError> {
        // Handle binary operators: +, -, *, /, %, ||
        let operators = [("||", "concat"), ("+", "add"), ("-", "sub"), ("*", "mul"), ("/", "div"), ("%", "mod")];

        for (op, op_name) in operators {
            if let Some(pos) = expr.find(op) {
                // Don't split on operator inside parentheses or quotes
                let before = &expr[..pos];
                let after = &expr[pos + op.len()..];

                // Simple check for balanced parentheses
                if before.matches('(').count() != before.matches(')').count() {
                    continue;
                }

                let left = self.evaluate_udf_expression_with_depth(before.trim(), bindings, depth + 1)?;
                let right = self.evaluate_udf_expression_with_depth(after.trim(), bindings, depth + 1)?;

                let result = match op_name {
                    "concat" => {
                        ScalarValue::Utf8(format!("{}{}", left, right))
                    }
                    "add" => Self::numeric_op(left, right, |a, b| a + b, |a, b| a + b)?,
                    "sub" => Self::numeric_op(left, right, |a, b| a - b, |a, b| a - b)?,
                    "mul" => Self::numeric_op(left, right, |a, b| a * b, |a, b| a * b)?,
                    "div" => {
                        // Check for division by zero
                        let is_zero = match &right {
                            ScalarValue::Int64(0) => true,
                            ScalarValue::Float64(f) if *f == 0.0 => true,
                            _ => false,
                        };
                        if is_zero {
                            return Err(EngineError::InvalidArgument("division by zero".into()));
                        }
                        Self::numeric_op(left, right, |a, b| a / b, |a, b| a / b)?
                    }
                    "mod" => Self::numeric_op(left, right, |a, b| a % b, |a, b| a % b)?,
                    _ => return Ok(None),
                };

                return Ok(Some(result));
            }
        }

        Ok(None)
    }

    /// Helper for numeric operations
    fn numeric_op<F1, F2>(
        left: ScalarValue,
        right: ScalarValue,
        int_op: F1,
        float_op: F2,
    ) -> Result<ScalarValue, EngineError>
    where
        F1: Fn(i64, i64) -> i64,
        F2: Fn(f64, f64) -> f64,
    {
        match (left, right) {
            (ScalarValue::Int64(a), ScalarValue::Int64(b)) => Ok(ScalarValue::Int64(int_op(a, b))),
            (ScalarValue::Float64(a), ScalarValue::Float64(b)) => Ok(ScalarValue::Float64(float_op(a, b))),
            (ScalarValue::Int64(a), ScalarValue::Float64(b)) => Ok(ScalarValue::Float64(float_op(a as f64, b))),
            (ScalarValue::Float64(a), ScalarValue::Int64(b)) => Ok(ScalarValue::Float64(float_op(a, b as f64))),
            _ => Err(EngineError::InvalidArgument("invalid operand types for arithmetic".into())),
        }
    }

    // =========================================================================
    // Stream Management (Kafka/Pulsar Connectors)
    // =========================================================================

    /// Create a new stream connector
    pub fn create_stream(
        &self,
        name: &str,
        source_type: crate::sql::StreamSourceType,
        source_config: &str,
        target_database: &str,
        target_table: &str,
        format: Option<&str>,
    ) -> Result<(), EngineError> {
        self.validate_identifier(name, "stream")?;
        self.validate_identifier(target_database, "database")?;
        self.validate_identifier(target_table, "table")?;

        // Acquire stream registry lock first to prevent duplicate stream creation
        let mut registry = self.stream_registry.write();

        // Check if stream already exists
        if registry.get(name).is_some() {
            return Err(EngineError::InvalidArgument(format!(
                "stream '{}' already exists",
                name
            )));
        }

        // Verify target table exists while holding both locks to prevent TOCTOU race
        let manifest = self.manifest.read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let table_exists = manifest.tables.iter()
            .any(|t| t.database == target_database && t.name == target_table);

        if !table_exists {
            return Err(EngineError::NotFound(format!(
                "target table '{}.{}' does not exist",
                target_database, target_table
            )));
        }
        drop(manifest);

        let now_micros = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);

        let source_type_str = format!("{:?}", source_type);
        let stream = StreamDefinition {
            name: name.to_string(),
            source_type,
            source_config: source_config.to_string(),
            target_database: target_database.to_string(),
            target_table: target_table.to_string(),
            format: format.unwrap_or("json").to_string(),
            state: StreamState::Stopped,
            messages_consumed: 0,
            last_error: None,
            created_at: now_micros,
        };

        // Register is infallible now since we already checked for duplicates
        let _ = registry.register(stream);

        tracing::info!(stream = %name, source = %source_type_str, "Stream created");
        Ok(())
    }

    /// Drop a stream connector
    pub fn drop_stream(&self, name: &str, if_exists: bool) -> Result<(), EngineError> {
        self.validate_identifier(name, "stream")?;

        let mut registry = self.stream_registry.write();

        // Check if stream is running
        if let Some(stream) = registry.get(name) {
            if stream.state == StreamState::Running {
                return Err(EngineError::InvalidArgument(format!(
                    "stream '{}' is running, stop it first with STOP STREAM",
                    name
                )));
            }
        }

        if registry.unregister(name).is_some() {
            tracing::info!(stream = %name, "Stream dropped");
            Ok(())
        } else if if_exists {
            Ok(())
        } else {
            Err(EngineError::NotFound(format!("stream '{}' not found", name)))
        }
    }

    /// Start a stream connector (begin consuming)
    pub fn start_stream(&self, name: &str) -> Result<(), EngineError> {
        let mut registry = self.stream_registry.write();

        let stream = registry.get_mut(name)
            .ok_or_else(|| EngineError::NotFound(format!("stream '{}' not found", name)))?;

        if stream.state == StreamState::Running {
            return Err(EngineError::InvalidArgument(format!(
                "stream '{}' is already running",
                name
            )));
        }

        stream.state = StreamState::Running;
        stream.last_error = None;

        tracing::info!(stream = %name, "Stream started");
        Ok(())
    }

    /// Stop a stream connector
    pub fn stop_stream(&self, name: &str) -> Result<(), EngineError> {
        let mut registry = self.stream_registry.write();

        let stream = registry.get_mut(name)
            .ok_or_else(|| EngineError::NotFound(format!("stream '{}' not found", name)))?;

        if stream.state == StreamState::Stopped {
            return Err(EngineError::InvalidArgument(format!(
                "stream '{}' is not running",
                name
            )));
        }

        stream.state = StreamState::Stopped;

        tracing::info!(stream = %name, "Stream stopped");
        Ok(())
    }

    /// Get stream status
    pub fn get_stream_status(&self, name: &str) -> Result<StreamDefinition, EngineError> {
        let registry = self.stream_registry.read();
        registry.get(name)
            .cloned()
            .ok_or_else(|| EngineError::NotFound(format!("stream '{}' not found", name)))
    }

    /// List all streams
    pub fn list_streams(&self) -> Vec<StreamDefinition> {
        let registry = self.stream_registry.read();
        registry.list().into_iter().cloned().collect()
    }

    /// Handle information_schema queries (virtual system tables)
    /// Returns Some(QueryResponse) if the query is an information_schema query, None otherwise
    fn handle_information_schema_query(
        &self,
        sql: &str,
    ) -> Result<Option<QueryResponse>, EngineError> {
        let sql_lower = sql.to_lowercase();

        // Check if this is an information_schema query
        if !sql_lower.contains("information_schema") {
            return Ok(None);
        }

        // Parse to find which table is being queried
        if sql_lower.contains("information_schema.schemata")
            || sql_lower.contains("information_schema.\"schemata\"")
        {
            return Ok(Some(self.query_information_schema_schemata()?));
        } else if sql_lower.contains("information_schema.tables")
            || sql_lower.contains("information_schema.\"tables\"")
        {
            return Ok(Some(self.query_information_schema_tables()?));
        } else if sql_lower.contains("information_schema.columns")
            || sql_lower.contains("information_schema.\"columns\"")
        {
            return Ok(Some(self.query_information_schema_columns()?));
        } else if sql_lower.contains("information_schema.table_constraints")
            || sql_lower.contains("information_schema.\"table_constraints\"")
        {
            return Ok(Some(self.query_information_schema_table_constraints()?));
        } else if sql_lower.contains("information_schema.key_column_usage")
            || sql_lower.contains("information_schema.\"key_column_usage\"")
        {
            return Ok(Some(self.query_information_schema_key_column_usage()?));
        }

        // Unknown information_schema table
        Err(EngineError::NotFound(format!(
            "information_schema table not found in query: {}",
            sql
        )))
    }

    /// Query information_schema.schemata (list of databases)
    fn query_information_schema_schemata(&self) -> Result<QueryResponse, EngineError> {
        use arrow_array::builder::StringBuilder;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut catalog_name = StringBuilder::new();
        let mut schema_name = StringBuilder::new();
        let mut schema_owner = StringBuilder::new();
        let mut default_character_set_name = StringBuilder::new();

        for db in &manifest.databases {
            catalog_name.append_value("boyodb");
            schema_name.append_value(&db.name);
            schema_owner.append_value("admin");
            default_character_set_name.append_value("UTF8");
        }

        let schema = Schema::new(vec![
            Field::new("catalog_name", DataType::Utf8, true),
            Field::new("schema_name", DataType::Utf8, false),
            Field::new("schema_owner", DataType::Utf8, true),
            Field::new("default_character_set_name", DataType::Utf8, true),
        ]);

        let batch = RecordBatch::try_new(
            Arc::new(schema.clone()),
            vec![
                Arc::new(catalog_name.finish()),
                Arc::new(schema_name.finish()),
                Arc::new(schema_owner.finish()),
                Arc::new(default_character_set_name.finish()),
            ],
        )
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        let mut ipc = Vec::new();
        {
            let mut writer =
                StreamWriter::try_new(&mut ipc, batch.schema().as_ref()).map_err(|e| {
                    EngineError::Internal(format!("failed to create IPC writer: {}", e))
                })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }
        Ok(QueryResponse {
            records_ipc: ipc,
            data_skipped_bytes: 0,
            segments_scanned: 0,
            execution_stats: None,
        })
    }

    /// Query information_schema.tables (list of tables)
    fn query_information_schema_tables(&self) -> Result<QueryResponse, EngineError> {
        use arrow_array::builder::StringBuilder;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut table_catalog = StringBuilder::new();
        let mut table_schema = StringBuilder::new();
        let mut table_name = StringBuilder::new();
        let mut table_type = StringBuilder::new();

        for tbl in &manifest.tables {
            table_catalog.append_value("boyodb");
            table_schema.append_value(&tbl.database);
            table_name.append_value(&tbl.name);
            table_type.append_value("BASE TABLE");
        }

        // Also include views
        for view in &manifest.views {
            table_catalog.append_value("boyodb");
            table_schema.append_value(&view.database);
            table_name.append_value(&view.name);
            table_type.append_value("VIEW");
        }

        let schema = Schema::new(vec![
            Field::new("table_catalog", DataType::Utf8, true),
            Field::new("table_schema", DataType::Utf8, false),
            Field::new("table_name", DataType::Utf8, false),
            Field::new("table_type", DataType::Utf8, false),
        ]);

        let batch = RecordBatch::try_new(
            Arc::new(schema.clone()),
            vec![
                Arc::new(table_catalog.finish()),
                Arc::new(table_schema.finish()),
                Arc::new(table_name.finish()),
                Arc::new(table_type.finish()),
            ],
        )
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        let mut ipc = Vec::new();
        {
            let mut writer =
                StreamWriter::try_new(&mut ipc, batch.schema().as_ref()).map_err(|e| {
                    EngineError::Internal(format!("failed to create IPC writer: {}", e))
                })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }
        Ok(QueryResponse {
            records_ipc: ipc,
            data_skipped_bytes: 0,
            segments_scanned: 0,
            execution_stats: None,
        })
    }

    /// Query information_schema.columns (list of columns)
    fn query_information_schema_columns(&self) -> Result<QueryResponse, EngineError> {
        use arrow_array::builder::{Int64Builder, StringBuilder};

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut table_catalog = StringBuilder::new();
        let mut table_schema = StringBuilder::new();
        let mut table_name = StringBuilder::new();
        let mut column_name = StringBuilder::new();
        let mut ordinal_position = Int64Builder::new();
        let mut data_type = StringBuilder::new();
        let mut is_nullable = StringBuilder::new();

        for tbl in &manifest.tables {
            if let Some(schema_json) = &tbl.schema_json {
                // Parse schema JSON to extract columns
                if let Ok(fields) = serde_json::from_str::<Vec<serde_json::Value>>(schema_json) {
                    for (idx, field) in fields.iter().enumerate() {
                        table_catalog.append_value("boyodb");
                        table_schema.append_value(&tbl.database);
                        table_name.append_value(&tbl.name);

                        if let Some(name) = field.get("name").and_then(|v| v.as_str()) {
                            column_name.append_value(name);
                        } else {
                            column_name.append_value(&format!("column_{}", idx));
                        }

                        ordinal_position.append_value((idx + 1) as i64);

                        if let Some(dtype) = field
                            .get("type")
                            .and_then(|v| v.as_str())
                            .or_else(|| field.get("data_type").and_then(|v| v.as_str()))
                        {
                            data_type.append_value(dtype);
                        } else {
                            data_type.append_value("unknown");
                        }

                        // Check if nullable field exists
                        let nullable = field
                            .get("nullable")
                            .and_then(|v| v.as_bool())
                            .unwrap_or(true);
                        is_nullable.append_value(if nullable { "YES" } else { "NO" });
                    }
                }
            }
        }

        let schema = Schema::new(vec![
            Field::new("table_catalog", DataType::Utf8, true),
            Field::new("table_schema", DataType::Utf8, false),
            Field::new("table_name", DataType::Utf8, false),
            Field::new("column_name", DataType::Utf8, false),
            Field::new("ordinal_position", DataType::Int64, false),
            Field::new("data_type", DataType::Utf8, false),
            Field::new("is_nullable", DataType::Utf8, false),
        ]);

        let batch = RecordBatch::try_new(
            Arc::new(schema.clone()),
            vec![
                Arc::new(table_catalog.finish()),
                Arc::new(table_schema.finish()),
                Arc::new(table_name.finish()),
                Arc::new(column_name.finish()),
                Arc::new(ordinal_position.finish()),
                Arc::new(data_type.finish()),
                Arc::new(is_nullable.finish()),
            ],
        )
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        let mut ipc = Vec::new();
        {
            let mut writer =
                StreamWriter::try_new(&mut ipc, batch.schema().as_ref()).map_err(|e| {
                    EngineError::Internal(format!("failed to create IPC writer: {}", e))
                })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }
        Ok(QueryResponse {
            records_ipc: ipc,
            data_skipped_bytes: 0,
            segments_scanned: 0,
            execution_stats: None,
        })
    }

    /// Query information_schema.table_constraints
    fn query_information_schema_table_constraints(&self) -> Result<QueryResponse, EngineError> {
        use crate::sql::TableConstraint;
        use arrow_array::builder::StringBuilder;

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut constraint_catalog = StringBuilder::new();
        let mut constraint_schema = StringBuilder::new();
        let mut constraint_name = StringBuilder::new();
        let mut table_schema = StringBuilder::new();
        let mut table_name = StringBuilder::new();
        let mut constraint_type = StringBuilder::new();

        for tbl in &manifest.tables {
            for constraint in &tbl.constraints {
                constraint_catalog.append_value("boyodb");
                constraint_schema.append_value(&tbl.database);
                table_schema.append_value(&tbl.database);
                table_name.append_value(&tbl.name);

                match constraint {
                    TableConstraint::PrimaryKey { name, .. } => {
                        constraint_name.append_value(name.as_deref().unwrap_or("PRIMARY"));
                        constraint_type.append_value("PRIMARY KEY");
                    }
                    TableConstraint::Unique { name, .. } => {
                        constraint_name.append_value(name.as_deref().unwrap_or("UNIQUE"));
                        constraint_type.append_value("UNIQUE");
                    }
                    TableConstraint::Check { name, .. } => {
                        constraint_name.append_value(name.as_deref().unwrap_or("CHECK"));
                        constraint_type.append_value("CHECK");
                    }
                    TableConstraint::NotNull { column } => {
                        constraint_name.append_value(&format!("{}_not_null", column));
                        constraint_type.append_value("NOT NULL");
                    }
                    TableConstraint::Default { column, .. } => {
                        constraint_name.append_value(&format!("{}_default", column));
                        constraint_type.append_value("DEFAULT");
                    }
                    TableConstraint::ForeignKey { name, .. } => {
                        constraint_name.append_value(name.as_deref().unwrap_or("FOREIGN KEY"));
                        constraint_type.append_value("FOREIGN KEY");
                    }
                }
            }
        }

        let schema = Schema::new(vec![
            Field::new("constraint_catalog", DataType::Utf8, true),
            Field::new("constraint_schema", DataType::Utf8, false),
            Field::new("constraint_name", DataType::Utf8, false),
            Field::new("table_schema", DataType::Utf8, false),
            Field::new("table_name", DataType::Utf8, false),
            Field::new("constraint_type", DataType::Utf8, false),
        ]);

        let batch = RecordBatch::try_new(
            Arc::new(schema.clone()),
            vec![
                Arc::new(constraint_catalog.finish()),
                Arc::new(constraint_schema.finish()),
                Arc::new(constraint_name.finish()),
                Arc::new(table_schema.finish()),
                Arc::new(table_name.finish()),
                Arc::new(constraint_type.finish()),
            ],
        )
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        let mut ipc = Vec::new();
        {
            let mut writer =
                StreamWriter::try_new(&mut ipc, batch.schema().as_ref()).map_err(|e| {
                    EngineError::Internal(format!("failed to create IPC writer: {}", e))
                })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }
        Ok(QueryResponse {
            records_ipc: ipc,
            data_skipped_bytes: 0,
            segments_scanned: 0,
            execution_stats: None,
        })
    }

    /// Query information_schema.key_column_usage
    fn query_information_schema_key_column_usage(&self) -> Result<QueryResponse, EngineError> {
        use crate::sql::TableConstraint;
        use arrow_array::builder::{Int64Builder, StringBuilder};

        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut constraint_catalog = StringBuilder::new();
        let mut constraint_schema = StringBuilder::new();
        let mut constraint_name = StringBuilder::new();
        let mut table_schema = StringBuilder::new();
        let mut table_name = StringBuilder::new();
        let mut column_name = StringBuilder::new();
        let mut ordinal_position = Int64Builder::new();

        for tbl in &manifest.tables {
            for constraint in &tbl.constraints {
                let (name, columns) = match constraint {
                    TableConstraint::PrimaryKey { name, columns } => {
                        (name.as_deref().unwrap_or("PRIMARY"), columns.clone())
                    }
                    TableConstraint::Unique { name, columns } => {
                        (name.as_deref().unwrap_or("UNIQUE"), columns.clone())
                    }
                    _ => continue, // Only PK and UNIQUE have key columns
                };

                for (idx, col) in columns.iter().enumerate() {
                    constraint_catalog.append_value("boyodb");
                    constraint_schema.append_value(&tbl.database);
                    constraint_name.append_value(name);
                    table_schema.append_value(&tbl.database);
                    table_name.append_value(&tbl.name);
                    column_name.append_value(col);
                    ordinal_position.append_value((idx + 1) as i64);
                }
            }
        }

        let schema = Schema::new(vec![
            Field::new("constraint_catalog", DataType::Utf8, true),
            Field::new("constraint_schema", DataType::Utf8, false),
            Field::new("constraint_name", DataType::Utf8, false),
            Field::new("table_schema", DataType::Utf8, false),
            Field::new("table_name", DataType::Utf8, false),
            Field::new("column_name", DataType::Utf8, false),
            Field::new("ordinal_position", DataType::Int64, false),
        ]);

        let batch = RecordBatch::try_new(
            Arc::new(schema.clone()),
            vec![
                Arc::new(constraint_catalog.finish()),
                Arc::new(constraint_schema.finish()),
                Arc::new(constraint_name.finish()),
                Arc::new(table_schema.finish()),
                Arc::new(table_name.finish()),
                Arc::new(column_name.finish()),
                Arc::new(ordinal_position.finish()),
            ],
        )
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        let mut ipc = Vec::new();
        {
            let mut writer =
                StreamWriter::try_new(&mut ipc, batch.schema().as_ref()).map_err(|e| {
                    EngineError::Internal(format!("failed to create IPC writer: {}", e))
                })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }
        Ok(QueryResponse {
            records_ipc: ipc,
            data_skipped_bytes: 0,
            segments_scanned: 0,
            execution_stats: None,
        })
    }

    /// Deduplicate a RecordBatch based on key columns and optional version column
    /// Returns a new batch with duplicates removed (keeping latest version if version_column specified)
    pub fn deduplicate_batch(
        &self,
        batch: &RecordBatch,
        key_columns: &[String],
        version_column: Option<&str>,
    ) -> Result<RecordBatch, EngineError> {
        use std::collections::HashMap;

        if batch.num_rows() == 0 || key_columns.is_empty() {
            return Ok(batch.clone());
        }

        // Find key column indices
        let key_indices: Vec<usize> = key_columns
            .iter()
            .map(|name| {
                batch.schema().index_of(name).map_err(|_| {
                    EngineError::InvalidArgument(format!("dedup key column not found: {name}"))
                })
            })
            .collect::<Result<Vec<_>, _>>()?;

        // Find version column index if specified
        let version_idx = version_column
            .map(|name| {
                batch.schema().index_of(name).map_err(|_| {
                    EngineError::InvalidArgument(format!("version column not found: {name}"))
                })
            })
            .transpose()?;

        // Build a map of key -> (best_row_index, version)
        // We hash the key columns to create a composite key
        let mut key_map: HashMap<u64, (usize, i64)> = HashMap::new();

        for row_idx in 0..batch.num_rows() {
            // Compute composite key hash
            let mut hasher = std::collections::hash_map::DefaultHasher::new();
            for &col_idx in &key_indices {
                let col = batch.column(col_idx);
                // Hash the value at this row
                hash_array_value(&mut hasher, col, row_idx);
            }
            let key_hash = std::hash::Hasher::finish(&hasher);

            // Get version if available
            let version = if let Some(v_idx) = version_idx {
                get_version_value(batch.column(v_idx), row_idx)
            } else {
                row_idx as i64 // Use row index as implicit version (later = newer)
            };

            // Check if we should keep this row
            match key_map.get(&key_hash) {
                Some(&(_, existing_version)) if version <= existing_version => {
                    // Keep existing (higher or equal version)
                }
                _ => {
                    key_map.insert(key_hash, (row_idx, version));
                }
            }
        }

        // Collect row indices to keep
        let mut keep_indices: Vec<usize> = key_map.values().map(|(idx, _)| *idx).collect();
        keep_indices.sort_unstable(); // Preserve original order

        // Build filtered batch
        if keep_indices.len() == batch.num_rows() {
            return Ok(batch.clone()); // No duplicates found
        }

        let indices = arrow_array::UInt32Array::from(
            keep_indices.iter().map(|&i| i as u32).collect::<Vec<_>>(),
        );
        let columns: Vec<arrow_array::ArrayRef> = batch
            .columns()
            .iter()
            .map(|col| arrow_select::take::take(col.as_ref(), &indices, None))
            .collect::<Result<Vec<_>, _>>()
            .map_err(|e| EngineError::Internal(format!("dedup take failed: {e}")))?;

        RecordBatch::try_new(batch.schema(), columns)
            .map_err(|e| EngineError::Internal(format!("dedup batch creation failed: {e}")))
    }

    /// Run deduplication on a table's segments
    /// Returns number of duplicate rows removed
    pub fn deduplicate_table(&self, database: &str, table: &str) -> Result<usize, EngineError> {
        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
        };

        let table_meta = table_meta
            .ok_or_else(|| EngineError::NotFound(format!("table not found: {database}.{table}")))?;

        let dedup_config = table_meta.deduplication.ok_or_else(|| {
            EngineError::InvalidArgument(format!(
                "deduplication not configured for {database}.{table}"
            ))
        })?;

        // Get all segments for this table
        let segments: Vec<ManifestEntry> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect()
        };

        if segments.is_empty() {
            return Ok(0);
        }

        // Load all batches
        let mut all_batches = Vec::new();
        let mut total_rows_before = 0usize;
        for entry in &segments {
            let batches = self.load_segment_batches_cached(entry)?;
            for batch in batches.iter() {
                total_rows_before += batch.num_rows();
                all_batches.push(batch.clone());
            }
        }

        if all_batches.is_empty() {
            return Ok(0);
        }

        // Merge all batches and deduplicate
        let schema = all_batches[0].schema();
        let merged = arrow_select::concat::concat_batches(&schema, &all_batches)
            .map_err(|e| EngineError::Internal(format!("concat batches failed: {e}")))?;

        let deduped = self.deduplicate_batch(
            &merged,
            &dedup_config.key_columns,
            dedup_config.version_column.as_deref(),
        )?;

        let rows_removed = total_rows_before - deduped.num_rows();

        if rows_removed == 0 {
            tracing::info!(
                "Deduplication on {}.{}: no duplicates found",
                database,
                table
            );
            return Ok(0);
        }

        tracing::info!(
            "Deduplication on {}.{}: {} duplicates removed ({} -> {} rows)",
            database,
            table,
            rows_removed,
            total_rows_before,
            deduped.num_rows()
        );

        // Remove old segments
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = segments.iter().map(|e| e.segment_id.clone()).collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
        }

        // Delete old segment files
        for entry in &segments {
            self.remove_segment_file(&entry.segment_id);
        }

        // Reingest deduplicated data
        let max_watermark = segments
            .iter()
            .map(|e| e.watermark_micros)
            .max()
            .unwrap_or(0);

        let merged_ipc = record_batches_to_ipc(schema.as_ref(), &[deduped])?;
        self.ingest_ipc(IngestBatch {
            payload_ipc: merged_ipc,
            watermark_micros: max_watermark,
            shard_override: None,
            database: Some(database.to_string()),
            table: Some(table.to_string()),
        })?;

        // Invalidate cache
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        Ok(rows_removed)
    }

    /// Drop a database and all its tables and segments.
    /// If `if_exists` is true, no error is returned if the database doesn't exist.
    pub fn drop_database(&self, name: &str, if_exists: bool) -> Result<(), EngineError> {
        if name.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database name required".to_string(),
            ));
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Check if database exists
        if !manifest.databases.iter().any(|db| db.name == name) {
            if if_exists {
                return Ok(());
            }
            return Err(EngineError::NotFound(format!("database not found: {name}")));
        }

        // Collect segments to remove
        let segments_to_remove: Vec<String> = manifest
            .entries
            .iter()
            .filter(|e| e.database == name)
            .map(|e| e.segment_id.clone())
            .collect();

        // Remove all entries for this database
        manifest.entries.retain(|e| e.database != name);

        // Remove all tables for this database
        manifest.tables.retain(|t| t.database != name);

        // Remove the database itself
        manifest.databases.retain(|db| db.name != name);

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        // Rebuild manifest index and invalidate cache
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate();
        }

        // Drop the lock before file operations
        drop(manifest);

        // Remove segment files (best effort)
        for seg_id in segments_to_remove {
            self.remove_segment_file(&seg_id);
        }

        Ok(())
    }

    /// Drop a table and all its segments.
    /// If `if_exists` is true, no error is returned if the table doesn't exist.
    pub fn drop_table(
        &self,
        database: &str,
        table: &str,
        if_exists: bool,
    ) -> Result<(), EngineError> {
        self.require_writable()?;
        if database.trim().is_empty() || table.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and table name required".into(),
            ));
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Check if table exists
        let table_exists = manifest
            .tables
            .iter()
            .any(|t| t.database == database && t.name == table);

        if !table_exists {
            if if_exists {
                return Ok(());
            }
            return Err(EngineError::NotFound(format!(
                "table not found: {database}.{table}"
            )));
        }

        // Collect segments to remove
        let segments_to_remove: Vec<String> = manifest
            .entries
            .iter()
            .filter(|e| e.database == database && e.table == table)
            .map(|e| e.segment_id.clone())
            .collect();

        // Remove all entries for this table
        manifest
            .entries
            .retain(|e| !(e.database == database && e.table == table));

        // Remove the table
        manifest
            .tables
            .retain(|t| !(t.database == database && t.name == table));

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        // Clean up stats tracker to prevent memory leak
        {
            let table_key = format!("{}.{}", database, table);
            let mut tracker = self.stats_tracker.write();
            tracker.tables.remove(&table_key);
        }

        // Drop the lock before file operations
        drop(manifest);

        // Remove segment files (best effort)
        for seg_id in segments_to_remove {
            self.remove_segment_file(&seg_id);
        }

        Ok(())
    }

    /// Rename a table within a database
    pub fn rename_table(
        &self,
        database: &str,
        old_name: &str,
        new_name: &str,
    ) -> Result<(), EngineError> {
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(old_name, "table")?;
        self.validate_identifier(new_name, "table")?;

        if old_name == new_name {
            return Ok(()); // Nothing to do
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Check if source table exists
        let table_idx = manifest
            .tables
            .iter()
            .position(|t| t.database == database && t.name == old_name)
            .ok_or_else(|| {
                EngineError::NotFound(format!("table not found: {database}.{old_name}"))
            })?;

        // Check if target table name already exists
        if manifest
            .tables
            .iter()
            .any(|t| t.database == database && t.name == new_name)
        {
            return Err(EngineError::InvalidArgument(format!(
                "table already exists: {database}.{new_name}"
            )));
        }

        // Rename the table metadata
        manifest.tables[table_idx].name = new_name.to_string();

        // Update all segment entries to reference the new table name
        for entry in manifest.entries.iter_mut() {
            if entry.database == database && entry.table == old_name {
                entry.table = new_name.to_string();
            }
        }

        // Update any views that reference this table (in their query_sql)
        for view in manifest.views.iter_mut() {
            if view.database == database {
                // Simple replacement - may not handle all cases but covers most
                view.query_sql = view.query_sql.replace(
                    &format!("{}.{}", database, old_name),
                    &format!("{}.{}", database, new_name),
                );
            }
        }

        // Update indexes that reference this table
        for index in manifest.indexes.iter_mut() {
            if index.database == database && index.table == old_name {
                index.table = new_name.to_string();
            }
        }

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        // Rebuild manifest index
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Invalidate query cache for both old and new table names
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, old_name);
            cache.invalidate_table(database, new_name);
        }

        Ok(())
    }

    /// Create a new table from a SELECT query (CREATE TABLE AS SELECT)
    pub fn create_table_as(
        &self,
        database: &str,
        table: &str,
        query_sql: &str,
        if_not_exists: bool,
    ) -> Result<u64, EngineError> {
        self.require_writable()?;
        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(table, "table")?;

        // Check if table already exists
        {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            if manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table)
            {
                if if_not_exists {
                    return Ok(0);
                }
                return Err(EngineError::InvalidArgument(format!(
                    "table already exists: {database}.{table}"
                )));
            }

            // Check database exists
            if !manifest.databases.iter().any(|db| db.name == database) {
                return Err(EngineError::NotFound(format!(
                    "database not found: {database}"
                )));
            }
        }

        // Execute the query to get the schema and data
        let query_request = QueryRequest {
            sql: query_sql.to_string(),
            timeout_millis: 0,
            collect_stats: false,
            transaction_id: None,
        };
        let result = self.query(query_request)?;

        if result.records_ipc.is_empty() {
            // Empty result - create table with empty schema
            self.create_table(database, table, None)?;
            return Ok(0);
        }

        // Decode the IPC to get the schema
        use arrow_ipc::reader::StreamReader;
        let cursor = std::io::Cursor::new(&result.records_ipc);
        let reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("failed to read IPC: {}", e)))?;

        let schema = reader.schema();

        // Convert schema to JSON format for table creation
        let schema_fields: Vec<serde_json::Value> = schema
            .fields()
            .iter()
            .map(|f| {
                let type_str = match f.data_type() {
                    arrow_schema::DataType::Int8 => "int8",
                    arrow_schema::DataType::Int16 => "int16",
                    arrow_schema::DataType::Int32 => "int32",
                    arrow_schema::DataType::Int64 => "int64",
                    arrow_schema::DataType::UInt8 => "uint8",
                    arrow_schema::DataType::UInt16 => "uint16",
                    arrow_schema::DataType::UInt32 => "uint32",
                    arrow_schema::DataType::UInt64 => "uint64",
                    arrow_schema::DataType::Float32 => "float32",
                    arrow_schema::DataType::Float64 => "float64",
                    arrow_schema::DataType::Utf8 | arrow_schema::DataType::LargeUtf8 => "string",
                    arrow_schema::DataType::Boolean => "boolean",
                    arrow_schema::DataType::Date32 => "date32",
                    arrow_schema::DataType::Timestamp(_, _) => "timestamp_micros",
                    _ => "string", // Fallback to string for unknown types
                };
                serde_json::json!({
                    "name": f.name(),
                    "type": type_str,
                    "nullable": f.is_nullable()
                })
            })
            .collect();

        let schema_json = serde_json::to_string(&schema_fields)
            .map_err(|e| EngineError::Internal(format!("failed to serialize schema: {}", e)))?;

        // Create the table with the derived schema
        self.create_table(database, table, Some(schema_json))?;

        // Ingest the data into the new table
        let watermark = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);
        let batch = IngestBatch {
            payload_ipc: result.records_ipc,
            watermark_micros: watermark,
            shard_override: None,
            database: Some(database.to_string()),
            table: Some(table.to_string()),
        };
        self.ingest_ipc(batch)?;

        // Count rows from the IPC (approximate based on existence)
        Ok(1) // Return 1 to indicate success; actual row count would require decoding
    }

    /// Validate a SQL identifier (database name, table name, column name, etc.)
    /// to prevent SQL injection and path traversal attacks.
    fn validate_identifier(&self, name: &str, kind: &str) -> Result<(), EngineError> {
        if name.is_empty() {
            return Err(EngineError::InvalidArgument(format!(
                "{} name cannot be empty",
                kind
            )));
        }

        if name.len() > 128 {
            return Err(EngineError::InvalidArgument(format!(
                "{} name is too long (max 128 characters)",
                kind
            )));
        }

        // Check for invalid characters that could enable injection or path traversal
        let invalid_chars = [
            '\'', '"', '\\', '/', '\0', ';', '-', '*', '?', '`', '$', '!', '|', '&', '<', '>',
            '\n', '\r', '\t',
        ];
        for c in invalid_chars {
            if name.contains(c) {
                let char_display = match c {
                    '\0' => "null".to_string(),
                    '\n' => "newline".to_string(),
                    '\r' => "carriage return".to_string(),
                    '\t' => "tab".to_string(),
                    _ => c.to_string(),
                };
                return Err(EngineError::InvalidArgument(format!(
                    "{} name contains invalid character: '{}'",
                    kind, char_display
                )));
            }
        }

        // Check for path traversal patterns
        if name.contains("..") {
            return Err(EngineError::InvalidArgument(format!(
                "{} name contains invalid pattern '..'",
                kind
            )));
        }

        // Must start with a letter or underscore
        let first = name.chars().next().unwrap();
        if !first.is_ascii_alphabetic() && first != '_' {
            return Err(EngineError::InvalidArgument(format!(
                "{} name must start with a letter or underscore",
                kind
            )));
        }

        // Remaining characters must be alphanumeric, underscore, or period (for schema.table)
        for c in name.chars() {
            if !c.is_ascii_alphanumeric() && c != '_' && c != '.' {
                return Err(EngineError::InvalidArgument(format!(
                    "{} name contains invalid character: '{}'",
                    kind, c
                )));
            }
        }

        Ok(())
    }

    /// Validate and resolve a COPY file path for security.
    /// Paths must be within the data directory's 'copy' subdirectory to prevent path traversal attacks.
    fn validate_copy_path(
        &self,
        path: &str,
        for_write: bool,
    ) -> Result<std::path::PathBuf, EngineError> {
        use std::path::Path;

        // Create the allowed copy directory (data_dir/copy)
        let copy_dir = self.cfg.data_dir.join("copy");
        if !copy_dir.exists() {
            std::fs::create_dir_all(&copy_dir).map_err(|e| {
                EngineError::Internal(format!("failed to create copy directory: {}", e))
            })?;
        }

        // Parse the requested path
        let requested = Path::new(path);

        // If the path is absolute, it must be under copy_dir
        // If relative, resolve it relative to copy_dir
        let resolved = if requested.is_absolute() {
            requested.to_path_buf()
        } else {
            copy_dir.join(requested)
        };

        // Canonicalize the path to resolve .. and symlinks
        // For write operations, the file may not exist yet, so canonicalize the parent
        let canonical = if for_write {
            let parent = resolved.parent().unwrap_or(Path::new("."));
            if !parent.exists() {
                std::fs::create_dir_all(parent).map_err(|e| {
                    EngineError::Internal(format!("failed to create directory: {}", e))
                })?;
            }
            let canonical_parent = parent
                .canonicalize()
                .map_err(|e| EngineError::InvalidArgument(format!("invalid path: {}", e)))?;
            canonical_parent.join(resolved.file_name().unwrap_or_default())
        } else {
            resolved.canonicalize().map_err(|e| {
                EngineError::InvalidArgument(format!("file not found or invalid path: {}", e))
            })?
        };

        // Security check: ensure the canonical path is under copy_dir
        let canonical_copy_dir = copy_dir.canonicalize().unwrap_or_else(|_| copy_dir.clone());

        if !canonical.starts_with(&canonical_copy_dir) {
            return Err(EngineError::InvalidArgument(format!(
                "COPY path '{}' is outside the allowed directory. Files must be in '{}'",
                path,
                copy_dir.display()
            )));
        }

        // Additional security: reject paths with suspicious patterns
        let path_str = path.to_lowercase();
        if path_str.contains("..") || path_str.contains('\0') {
            return Err(EngineError::InvalidArgument(
                "COPY path contains invalid characters".into(),
            ));
        }

        Ok(canonical)
    }

    /// Copy data from a file into a table (COPY FROM)
    pub fn copy_from(
        &self,
        database: &str,
        table: &str,
        source: &crate::sql::CopySource,
        format: &crate::sql::CopyFormat,
        options: &crate::sql::CopyOptions,
    ) -> Result<u64, EngineError> {
        use crate::sql::{CopyFormat, CopySource};

        // Validate identifiers to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(table, "table")?;

        // Get and validate the file path
        let file_path = match source {
            CopySource::File(path) => self.validate_copy_path(path, false)?,
            CopySource::Stdin => {
                return Err(EngineError::InvalidArgument(
                    "COPY FROM STDIN is not supported in batch mode".into(),
                ));
            }
            CopySource::Program(cmd) => {
                return Err(EngineError::InvalidArgument(format!(
                    "COPY FROM PROGRAM '{}' is not supported for security reasons",
                    cmd
                )));
            }
        };

        // Read the file
        let file_content = std::fs::read(&file_path).map_err(|e| {
            EngineError::Internal(format!(
                "failed to read file '{}': {}",
                file_path.display(),
                e
            ))
        })?;

        match format {
            CopyFormat::Csv | CopyFormat::Text => {
                self.copy_from_csv(database, table, &file_content, format, options)
            }
            CopyFormat::Json => self.copy_from_json(database, table, &file_content, options),
            CopyFormat::Arrow => {
                // Direct Arrow IPC ingest
                let watermark = std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .map(|d| d.as_micros() as u64)
                    .unwrap_or(0);
                let batch = IngestBatch {
                    payload_ipc: file_content,
                    watermark_micros: watermark,
                    shard_override: None,
                    database: Some(database.to_string()),
                    table: Some(table.to_string()),
                };
                self.ingest_ipc(batch)?;
                Ok(1)
            }
            _ => Err(EngineError::InvalidArgument(format!(
                "COPY FROM format {:?} is not yet supported",
                format
            ))),
        }
    }

    /// Copy from CSV/Text format
    fn copy_from_csv(
        &self,
        database: &str,
        table: &str,
        content: &[u8],
        format: &crate::sql::CopyFormat,
        options: &crate::sql::CopyOptions,
    ) -> Result<u64, EngineError> {
        use arrow_array::builder::*;
        use arrow_schema::{DataType, Field, Schema};

        // Get table schema
        let table_desc = self.describe_table(database, table)?;
        let schema_json = table_desc
            .schema_json
            .ok_or_else(|| EngineError::InvalidArgument("table has no schema".into()))?;

        // Parse schema JSON
        let schema_fields: Vec<serde_json::Value> = serde_json::from_str(&schema_json)
            .map_err(|e| EngineError::Internal(format!("invalid schema JSON: {}", e)))?;

        // Determine delimiter
        let delimiter =
            options
                .delimiter
                .unwrap_or(if matches!(format, crate::sql::CopyFormat::Text) {
                    '\t'
                } else {
                    ','
                });

        // Parse content
        let content_str = std::str::from_utf8(content)
            .map_err(|e| EngineError::InvalidArgument(format!("invalid UTF-8: {}", e)))?;

        let lines: Vec<&str> = content_str.lines().collect();
        let start_line = if options.header { 1 } else { 0 };
        let data_lines = &lines[start_line..];

        if data_lines.is_empty() {
            return Ok(0);
        }

        // Build Arrow arrays for each column
        let null_str = options.null_string.as_deref().unwrap_or("");
        let mut builders: Vec<Box<dyn std::any::Any>> = Vec::new();
        let mut arrow_fields: Vec<Field> = Vec::new();

        for field in &schema_fields {
            let name = field["name"].as_str().unwrap_or("unknown");
            let type_str = field["type"]
                .as_str()
                .or_else(|| field["data_type"].as_str())
                .unwrap_or("string");
            let nullable = field
                .get("nullable")
                .and_then(|v| v.as_bool())
                .unwrap_or(true);

            let (arrow_type, builder): (DataType, Box<dyn std::any::Any>) = match type_str {
                "int64" | "bigint" => (DataType::Int64, Box::new(Int64Builder::new())),
                "int32" | "int" | "integer" => (DataType::Int32, Box::new(Int32Builder::new())),
                "float64" | "double" => (DataType::Float64, Box::new(Float64Builder::new())),
                "float32" | "float" => (DataType::Float32, Box::new(Float32Builder::new())),
                "boolean" | "bool" => (DataType::Boolean, Box::new(BooleanBuilder::new())),
                _ => (DataType::Utf8, Box::new(StringBuilder::new())),
            };

            arrow_fields.push(Field::new(name, arrow_type, nullable));
            builders.push(builder);
        }

        // Parse each line
        for line in data_lines {
            let values: Vec<&str> = line.split(delimiter).collect();

            for (i, field) in schema_fields.iter().enumerate() {
                let value = values.get(i).copied().unwrap_or("");
                let is_null = value == null_str || value.is_empty();
                let type_str = field["type"]
                    .as_str()
                    .or_else(|| field["data_type"].as_str())
                    .unwrap_or("string");

                match type_str {
                    "int64" | "bigint" => {
                        let builder = builders[i].downcast_mut::<Int64Builder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            builder.append_value(value.parse::<i64>().unwrap_or(0));
                        }
                    }
                    "int32" | "int" | "integer" => {
                        let builder = builders[i].downcast_mut::<Int32Builder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            builder.append_value(value.parse::<i32>().unwrap_or(0));
                        }
                    }
                    "float64" | "double" => {
                        let builder = builders[i].downcast_mut::<Float64Builder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            builder.append_value(value.parse::<f64>().unwrap_or(0.0));
                        }
                    }
                    "float32" | "float" => {
                        let builder = builders[i].downcast_mut::<Float32Builder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            builder.append_value(value.parse::<f32>().unwrap_or(0.0));
                        }
                    }
                    "boolean" | "bool" => {
                        let builder = builders[i].downcast_mut::<BooleanBuilder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            let b = matches!(
                                value.to_lowercase().as_str(),
                                "true" | "t" | "1" | "yes" | "y"
                            );
                            builder.append_value(b);
                        }
                    }
                    _ => {
                        let builder = builders[i].downcast_mut::<StringBuilder>().unwrap();
                        if is_null {
                            builder.append_null();
                        } else {
                            builder.append_value(value);
                        }
                    }
                }
            }
        }

        // Build arrays and create batch
        let mut arrays: Vec<ArrayRef> = Vec::new();
        for (i, field) in schema_fields.iter().enumerate() {
            let type_str = field["type"]
                .as_str()
                .or_else(|| field["data_type"].as_str())
                .unwrap_or("string");
            let array: ArrayRef = match type_str {
                "int64" | "bigint" => {
                    Arc::new(builders[i].downcast_mut::<Int64Builder>().unwrap().finish())
                }
                "int32" | "int" | "integer" => {
                    Arc::new(builders[i].downcast_mut::<Int32Builder>().unwrap().finish())
                }
                "float64" | "double" => Arc::new(
                    builders[i]
                        .downcast_mut::<Float64Builder>()
                        .unwrap()
                        .finish(),
                ),
                "float32" | "float" => Arc::new(
                    builders[i]
                        .downcast_mut::<Float32Builder>()
                        .unwrap()
                        .finish(),
                ),
                "boolean" | "bool" => Arc::new(
                    builders[i]
                        .downcast_mut::<BooleanBuilder>()
                        .unwrap()
                        .finish(),
                ),
                _ => Arc::new(
                    builders[i]
                        .downcast_mut::<StringBuilder>()
                        .unwrap()
                        .finish(),
                ),
            };
            arrays.push(array);
        }

        let schema = Arc::new(Schema::new(arrow_fields));
        let batch = RecordBatch::try_new(schema.clone(), arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        // Convert to IPC and ingest
        let mut ipc = Vec::new();
        {
            let mut writer = StreamWriter::try_new(&mut ipc, schema.as_ref()).map_err(|e| {
                EngineError::Internal(format!("failed to create IPC writer: {}", e))
            })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }

        let watermark = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);
        let ingest = IngestBatch {
            payload_ipc: ipc,
            watermark_micros: watermark,
            shard_override: None,
            database: Some(database.to_string()),
            table: Some(table.to_string()),
        };
        self.ingest_ipc(ingest)?;

        Ok(data_lines.len() as u64)
    }

    /// Copy from JSON lines format
    fn copy_from_json(
        &self,
        database: &str,
        table: &str,
        content: &[u8],
        _options: &crate::sql::CopyOptions,
    ) -> Result<u64, EngineError> {
        use arrow_array::builder::*;
        use arrow_schema::{DataType, Field, Schema};

        // Get table schema
        let table_desc = self.describe_table(database, table)?;
        let schema_json = table_desc
            .schema_json
            .ok_or_else(|| EngineError::InvalidArgument("table has no schema".into()))?;

        let schema_fields: Vec<serde_json::Value> = serde_json::from_str(&schema_json)
            .map_err(|e| EngineError::Internal(format!("invalid schema JSON: {}", e)))?;

        let content_str = std::str::from_utf8(content)
            .map_err(|e| EngineError::InvalidArgument(format!("invalid UTF-8: {}", e)))?;

        let lines: Vec<&str> = content_str
            .lines()
            .filter(|l| !l.trim().is_empty())
            .collect();
        if lines.is_empty() {
            return Ok(0);
        }

        // Build Arrow arrays
        let mut builders: Vec<Box<dyn std::any::Any>> = Vec::new();
        let mut arrow_fields: Vec<Field> = Vec::new();

        for field in &schema_fields {
            let name = field["name"].as_str().unwrap_or("unknown");
            let type_str = field["type"]
                .as_str()
                .or_else(|| field["data_type"].as_str())
                .unwrap_or("string");
            let nullable = field
                .get("nullable")
                .and_then(|v| v.as_bool())
                .unwrap_or(true);

            let (arrow_type, builder): (DataType, Box<dyn std::any::Any>) = match type_str {
                "int64" | "bigint" => (DataType::Int64, Box::new(Int64Builder::new())),
                "int32" | "int" | "integer" => (DataType::Int32, Box::new(Int32Builder::new())),
                "float64" | "double" => (DataType::Float64, Box::new(Float64Builder::new())),
                "float32" | "float" => (DataType::Float32, Box::new(Float32Builder::new())),
                "boolean" | "bool" => (DataType::Boolean, Box::new(BooleanBuilder::new())),
                _ => (DataType::Utf8, Box::new(StringBuilder::new())),
            };

            arrow_fields.push(Field::new(name, arrow_type, nullable));
            builders.push(builder);
        }

        // Parse each JSON line
        for line in &lines {
            let json: serde_json::Value = serde_json::from_str(line)
                .map_err(|e| EngineError::InvalidArgument(format!("invalid JSON: {}", e)))?;

            for (i, field) in schema_fields.iter().enumerate() {
                let name = field["name"].as_str().unwrap_or("unknown");
                let type_str = field["type"]
                    .as_str()
                    .or_else(|| field["data_type"].as_str())
                    .unwrap_or("string");
                let value = &json[name];

                match type_str {
                    "int64" | "bigint" => {
                        let builder = builders[i].downcast_mut::<Int64Builder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else {
                            builder.append_value(value.as_i64().unwrap_or(0));
                        }
                    }
                    "int32" | "int" | "integer" => {
                        let builder = builders[i].downcast_mut::<Int32Builder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else {
                            builder.append_value(value.as_i64().unwrap_or(0) as i32);
                        }
                    }
                    "float64" | "double" => {
                        let builder = builders[i].downcast_mut::<Float64Builder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else {
                            builder.append_value(value.as_f64().unwrap_or(0.0));
                        }
                    }
                    "float32" | "float" => {
                        let builder = builders[i].downcast_mut::<Float32Builder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else {
                            builder.append_value(value.as_f64().unwrap_or(0.0) as f32);
                        }
                    }
                    "boolean" | "bool" => {
                        let builder = builders[i].downcast_mut::<BooleanBuilder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else {
                            builder.append_value(value.as_bool().unwrap_or(false));
                        }
                    }
                    _ => {
                        let builder = builders[i].downcast_mut::<StringBuilder>().unwrap();
                        if value.is_null() {
                            builder.append_null();
                        } else if let Some(s) = value.as_str() {
                            builder.append_value(s);
                        } else {
                            builder.append_value(value.to_string());
                        }
                    }
                }
            }
        }

        // Build arrays and create batch
        let mut arrays: Vec<ArrayRef> = Vec::new();
        for (i, field) in schema_fields.iter().enumerate() {
            let type_str = field["type"]
                .as_str()
                .or_else(|| field["data_type"].as_str())
                .unwrap_or("string");
            let array: ArrayRef = match type_str {
                "int64" | "bigint" => {
                    Arc::new(builders[i].downcast_mut::<Int64Builder>().unwrap().finish())
                }
                "int32" | "int" | "integer" => {
                    Arc::new(builders[i].downcast_mut::<Int32Builder>().unwrap().finish())
                }
                "float64" | "double" => Arc::new(
                    builders[i]
                        .downcast_mut::<Float64Builder>()
                        .unwrap()
                        .finish(),
                ),
                "float32" | "float" => Arc::new(
                    builders[i]
                        .downcast_mut::<Float32Builder>()
                        .unwrap()
                        .finish(),
                ),
                "boolean" | "bool" => Arc::new(
                    builders[i]
                        .downcast_mut::<BooleanBuilder>()
                        .unwrap()
                        .finish(),
                ),
                _ => Arc::new(
                    builders[i]
                        .downcast_mut::<StringBuilder>()
                        .unwrap()
                        .finish(),
                ),
            };
            arrays.push(array);
        }

        let schema = Arc::new(Schema::new(arrow_fields));
        let batch = RecordBatch::try_new(schema.clone(), arrays)
            .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

        // Convert to IPC and ingest
        let mut ipc = Vec::new();
        {
            let mut writer = StreamWriter::try_new(&mut ipc, schema.as_ref()).map_err(|e| {
                EngineError::Internal(format!("failed to create IPC writer: {}", e))
            })?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish writer: {}", e)))?;
        }

        let watermark = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);
        let ingest = IngestBatch {
            payload_ipc: ipc,
            watermark_micros: watermark,
            shard_override: None,
            database: Some(database.to_string()),
            table: Some(table.to_string()),
        };
        self.ingest_ipc(ingest)?;

        Ok(lines.len() as u64)
    }

    /// Copy data to a file from a table (COPY TO)
    pub fn copy_to(
        &self,
        database: &str,
        table: &str,
        destination: &str,
        format: &crate::sql::CopyFormat,
        options: &crate::sql::CopyOptions,
    ) -> Result<u64, EngineError> {
        use crate::sql::CopyFormat;

        // Validate database and table names to prevent injection
        self.validate_identifier(database, "database")?;
        self.validate_identifier(table, "table")?;

        // Validate and resolve the destination path
        let dest_path = self.validate_copy_path(destination, true)?;

        // Query all data from the table using validated identifiers
        let query_request = QueryRequest {
            sql: format!("SELECT * FROM \"{}\".\"{}\"", database, table),
            timeout_millis: 0,
            collect_stats: false,
            transaction_id: None,
        };
        let result = self.query(query_request)?;

        if result.records_ipc.is_empty() {
            std::fs::write(&dest_path, "")
                .map_err(|e| EngineError::Internal(format!("failed to write file: {}", e)))?;
            return Ok(0);
        }

        // Decode the IPC
        use arrow_ipc::reader::StreamReader;
        let cursor = std::io::Cursor::new(&result.records_ipc);
        let mut reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("failed to read IPC: {}", e)))?;

        let mut output = String::new();
        let mut row_count = 0u64;

        // Get schema for header
        let schema = reader.schema();

        match format {
            CopyFormat::Csv | CopyFormat::Text => {
                let delimiter =
                    options
                        .delimiter
                        .unwrap_or(if matches!(format, CopyFormat::Text) {
                            '\t'
                        } else {
                            ','
                        });
                let null_str = options.null_string.as_deref().unwrap_or("");

                // Write header if requested
                if options.header {
                    let header: Vec<&str> =
                        schema.fields().iter().map(|f| f.name().as_str()).collect();
                    output.push_str(&header.join(&delimiter.to_string()));
                    output.push('\n');
                }

                // Write data rows
                while let Some(batch_result) = reader.next() {
                    let batch = batch_result.map_err(|e| {
                        EngineError::Internal(format!("failed to read batch: {}", e))
                    })?;

                    for row in 0..batch.num_rows() {
                        let values: Vec<String> = batch
                            .columns()
                            .iter()
                            .map(|col| {
                                if col.is_null(row) {
                                    null_str.to_string()
                                } else {
                                    self.array_value_to_string(col, row)
                                }
                            })
                            .collect();
                        output.push_str(&values.join(&delimiter.to_string()));
                        output.push('\n');
                        row_count += 1;
                    }
                }
            }
            CopyFormat::Json => {
                while let Some(batch_result) = reader.next() {
                    let batch = batch_result.map_err(|e| {
                        EngineError::Internal(format!("failed to read batch: {}", e))
                    })?;

                    for row in 0..batch.num_rows() {
                        let mut obj = serde_json::Map::new();
                        for (i, field) in schema.fields().iter().enumerate() {
                            let col = batch.column(i);
                            let value = if col.is_null(row) {
                                serde_json::Value::Null
                            } else {
                                self.array_value_to_json(col, row)
                            };
                            obj.insert(field.name().clone(), value);
                        }
                        output.push_str(&serde_json::to_string(&obj).unwrap_or_default());
                        output.push('\n');
                        row_count += 1;
                    }
                }
            }
            CopyFormat::Arrow => {
                // Write raw Arrow IPC
                std::fs::write(&dest_path, &result.records_ipc)
                    .map_err(|e| EngineError::Internal(format!("failed to write file: {}", e)))?;
                return Ok(row_count);
            }
            _ => {
                return Err(EngineError::InvalidArgument(format!(
                    "COPY TO format {:?} is not yet supported",
                    format
                )));
            }
        }

        std::fs::write(&dest_path, &output)
            .map_err(|e| EngineError::Internal(format!("failed to write file: {}", e)))?;

        Ok(row_count)
    }

    /// Convert an array value at a given row to a string
    fn array_value_to_string(&self, array: &ArrayRef, row: usize) -> String {
        use arrow_array::*;

        if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<Float64Array>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<Float32Array>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<BooleanArray>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<UInt64Array>() {
            return arr.value(row).to_string();
        }
        if let Some(arr) = array.as_any().downcast_ref::<UInt32Array>() {
            return arr.value(row).to_string();
        }
        String::new()
    }

    /// Convert an array value at a given row to a JSON value
    fn array_value_to_json(&self, array: &ArrayRef, row: usize) -> serde_json::Value {
        use arrow_array::*;

        if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
            return serde_json::Value::String(arr.value(row).to_string());
        }
        if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<Float64Array>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<Float32Array>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<BooleanArray>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<UInt64Array>() {
            return serde_json::json!(arr.value(row));
        }
        if let Some(arr) = array.as_any().downcast_ref::<UInt32Array>() {
            return serde_json::json!(arr.value(row));
        }
        serde_json::Value::Null
    }

    /// Truncate a table by removing all its segments but keeping the table definition.
    pub fn truncate_table(&self, database: &str, table: &str) -> Result<(), EngineError> {
        if database.trim().is_empty() || table.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "database and table name required".into(),
            ));
        }

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Check if table exists
        let table_exists = manifest
            .tables
            .iter()
            .any(|t| t.database == database && t.name == table);

        if !table_exists {
            return Err(EngineError::NotFound(format!(
                "table not found: {database}.{table}"
            )));
        }

        // Collect segments to remove
        let segments_to_remove: Vec<String> = manifest
            .entries
            .iter()
            .filter(|e| e.database == database && e.table == table)
            .map(|e| e.segment_id.clone())
            .collect();

        // Remove all entries for this table
        manifest
            .entries
            .retain(|e| !(e.database == database && e.table == table));

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;

        // Rebuild manifest index after entries changed
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Drop the lock before file operations
        drop(manifest);

        // Remove segment files (best effort)
        for seg_id in segments_to_remove {
            self.remove_segment_file(&seg_id);
        }

        Ok(())
    }

    /// Add a nullable column by rewriting segments and updating stored schema.
    pub fn alter_table_add_column(
        &self,
        database: &str,
        table: &str,
        column: &str,
        data_type: &str,
        nullable: bool,
    ) -> Result<(), EngineError> {
        if column.trim().is_empty() {
            return Err(EngineError::InvalidArgument("column name required".into()));
        }
        if !nullable {
            return Err(EngineError::InvalidArgument(
                "only nullable columns are supported for ALTER TABLE ADD COLUMN".into(),
            ));
        }
        let _arrow_type = arrow_type_from_str(data_type)?;

        // Get current schema
        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let tbl = manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
                .ok_or_else(|| {
                    EngineError::NotFound(format!("table not found: {database}.{table}"))
                })?;
            if tbl.schema_json.is_none() {
                return Err(EngineError::InvalidArgument(
                    "table schema is not defined; cannot alter".into(),
                ));
            }
            tbl
        };

        let mut fields: Vec<TableFieldSpec> = serde_json::from_str(
            table_meta
                .schema_json
                .as_ref()
                .ok_or_else(|| EngineError::InvalidArgument("table schema missing".into()))?,
        )
        .map_err(|e| EngineError::InvalidArgument(format!("invalid schema json: {e}")))?;

        if fields.iter().any(|f| f.name == column) {
            return Err(EngineError::InvalidArgument(format!(
                "column '{}' already exists",
                column
            )));
        }
        fields.push(TableFieldSpec {
            name: column.to_string(),
            data_type: data_type.to_string(),
            nullable,
            encoding: None,
        });
        let canonical_fields = canonicalize_schema_spec(&fields)?;
        let new_schema_json = serde_json::to_string(&canonical_fields)
            .map_err(|e| EngineError::Internal(format!("serialize schema failed: {e}")))?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        manifest.bump_version();
        if let Some(tbl) = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
        {
            tbl.schema_json = Some(new_schema_json.clone());
        }
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }
        self.spawn_background_schema_rewrite(database, table, &new_schema_json);
        Ok(())
    }

    /// Drop a column by rewriting segments and updating stored schema.
    pub fn alter_table_drop_column(
        &self,
        database: &str,
        table: &str,
        column: &str,
    ) -> Result<(), EngineError> {
        if column.trim().is_empty() {
            return Err(EngineError::InvalidArgument("column name required".into()));
        }

        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let tbl = manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
                .ok_or_else(|| {
                    EngineError::NotFound(format!("table not found: {database}.{table}"))
                })?;
            if tbl.schema_json.is_none() {
                return Err(EngineError::InvalidArgument(
                    "table schema is not defined; cannot alter".into(),
                ));
            }
            tbl
        };

        let mut fields: Vec<TableFieldSpec> = serde_json::from_str(
            table_meta
                .schema_json
                .as_ref()
                .ok_or_else(|| EngineError::InvalidArgument("table schema missing".into()))?,
        )
        .map_err(|e| EngineError::InvalidArgument(format!("invalid schema json: {e}")))?;

        let pos = fields
            .iter()
            .position(|f| f.name == column)
            .ok_or_else(|| EngineError::NotFound(format!("column '{}' not found", column)))?;
        fields.remove(pos);
        if fields.is_empty() {
            return Err(EngineError::InvalidArgument(
                "dropping the last column is not supported".into(),
            ));
        }
        let canonical_fields = canonicalize_schema_spec(&fields)?;
        let new_schema_json = serde_json::to_string(&canonical_fields)
            .map_err(|e| EngineError::Internal(format!("serialize schema failed: {e}")))?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        manifest.bump_version();
        if let Some(tbl) = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
        {
            tbl.schema_json = Some(new_schema_json.clone());
        }
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        self.spawn_background_schema_rewrite(database, table, &new_schema_json);
        Ok(())
    }

    /// Rename a column by updating the stored schema and rewriting segments.
    pub fn alter_table_rename_column(
        &self,
        database: &str,
        table: &str,
        old_column: &str,
        new_column: &str,
    ) -> Result<(), EngineError> {
        if old_column.trim().is_empty() || new_column.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "column name required".into(),
            ));
        }

        if old_column == new_column {
            return Ok(()); // Nothing to do
        }

        let table_meta = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let tbl = manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
                .ok_or_else(|| {
                    EngineError::NotFound(format!("table not found: {database}.{table}"))
                })?;
            if tbl.schema_json.is_none() {
                return Err(EngineError::InvalidArgument(
                    "table schema is not defined; cannot alter".into(),
                ));
            }
            tbl
        };

        let mut fields: Vec<TableFieldSpec> = serde_json::from_str(
            table_meta
                .schema_json
                .as_ref()
                .ok_or_else(|| EngineError::InvalidArgument("table schema missing".into()))?,
        )
        .map_err(|e| EngineError::InvalidArgument(format!("invalid schema json: {e}")))?;

        // Check if new column name already exists
        if fields.iter().any(|f| f.name == new_column) {
            return Err(EngineError::InvalidArgument(format!(
                "column '{}' already exists",
                new_column
            )));
        }

        // Find and rename the column
        let field = fields
            .iter_mut()
            .find(|f| f.name == old_column)
            .ok_or_else(|| {
                EngineError::NotFound(format!("column '{}' not found", old_column))
            })?;
        field.name = new_column.to_string();

        let canonical_fields = canonicalize_schema_spec(&fields)?;
        let new_schema_json = serde_json::to_string(&canonical_fields)
            .map_err(|e| EngineError::Internal(format!("serialize schema failed: {e}")))?;

        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        manifest.bump_version();
        if let Some(tbl) = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
        {
            tbl.schema_json = Some(new_schema_json.clone());
        }
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        {
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        self.spawn_background_column_rename(database, table, old_column, new_column);
        Ok(())
    }

    /// Background task to rename column in all segment files.
    fn spawn_background_column_rename(
        &self,
        database: &str,
        table: &str,
        old_column: &str,
        new_column: &str,
    ) {
        let cfg = self.cfg.clone();
        let db_name = database.to_string();
        let tbl_name = table.to_string();
        let old_col = old_column.to_string();
        let new_col = new_column.to_string();
        std::thread::spawn(move || match Db::open(cfg) {
            Ok(db) => {
                if let Err(e) = db.rewrite_segments_rename_column(&db_name, &tbl_name, &old_col, &new_col) {
                    tracing::warn!(
                        database = %db_name,
                        table = %tbl_name,
                        old_column = %old_col,
                        new_column = %new_col,
                        error = %e,
                        "background column rename failed"
                    );
                }
            }
            Err(e) => {
                tracing::warn!(
                    database = %db_name,
                    table = %tbl_name,
                    error = %e,
                    "failed to start background column rename"
                );
            }
        });
    }

    /// Rewrite all segments to rename a column.
    fn rewrite_segments_rename_column(
        &self,
        database: &str,
        table: &str,
        old_column: &str,
        new_column: &str,
    ) -> Result<(), EngineError> {
        let entries = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>()
        };

        for entry in entries {
            let data = load_segment(&self.storage, &entry)?;
            let batches = read_ipc_batches(&data)?;

            if batches.is_empty() {
                continue;
            }

            let original_schema = batches[0].schema();

            // Check if column exists in this segment
            if original_schema.index_of(old_column).is_err() {
                continue; // Column not in this segment, skip
            }

            // Build new schema with renamed column
            let new_fields: Vec<Field> = original_schema
                .fields()
                .iter()
                .map(|f| {
                    if f.name() == old_column {
                        Field::new(new_column, f.data_type().clone(), f.is_nullable())
                            .with_metadata(f.metadata().clone())
                    } else {
                        f.as_ref().clone()
                    }
                })
                .collect();
            let new_schema = Arc::new(Schema::new(new_fields));

            // Rebuild batches with new schema
            let mut new_batches = Vec::new();
            for batch in &batches {
                let new_batch = RecordBatch::try_new(
                    new_schema.clone(),
                    batch.columns().to_vec(),
                )
                .map_err(|e| EngineError::Internal(format!("failed to rename column: {e}")))?;
                new_batches.push(new_batch);
            }

            // Write new segment
            let ipc = record_batches_to_ipc(&new_schema, &new_batches)?;

            // Ingest new segment and clean up old
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: entry.watermark_micros,
                shard_override: Some(entry.shard_id as u64),
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;

            // Remove old segment
            {
                let mut manifest = self
                    .manifest
                    .write()
                    .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
                manifest.entries.retain(|e| e.segment_id != entry.segment_id);
                persist_manifest(&self.cfg.manifest_path, &manifest)?;
            }
            self.remove_segment_file(&entry.segment_id);
        }

        Ok(())
    }

    fn spawn_background_schema_rewrite(&self, database: &str, table: &str, schema_json: &str) {
        let cfg = self.cfg.clone();
        let db_name = database.to_string();
        let tbl_name = table.to_string();
        let schema_json = schema_json.to_string();
        std::thread::spawn(move || match Db::open(cfg) {
            Ok(db) => {
                if let Err(e) =
                    db.rewrite_table_segments_to_schema(&db_name, &tbl_name, &schema_json)
                {
                    tracing::warn!(
                        database = %db_name,
                        table = %tbl_name,
                        error = %e,
                        "background schema rewrite failed"
                    );
                }
            }
            Err(e) => {
                tracing::warn!(
                    database = %db_name,
                    table = %tbl_name,
                    error = %e,
                    "failed to start background schema rewrite"
                );
            }
        });
    }

    fn spawn_background_compaction_loop(&self) {
        if !self.cfg.enable_compaction {
            return;
        }

        // Spawn continuous compaction threads if enabled (ClickHouse-style)
        if self.cfg.continuous_compaction_enabled {
            self.spawn_continuous_compaction_threads();
        }

        // Also spawn the interval-based loop as a fallback/supplement
        if self.cfg.auto_compact_interval_secs == 0 {
            return;
        }

        let mut cfg = self.cfg.clone();
        let interval_secs = cfg.auto_compact_interval_secs;
        cfg.auto_compact_interval_secs = 0;
        cfg.continuous_compaction_enabled = false; // Don't spawn more continuous threads

        std::thread::spawn(move || {
            // Create a Tokio runtime for the background thread
            // This is needed because TieredStorage requires a Tokio runtime handle
            let rt = match tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
            {
                Ok(rt) => rt,
                Err(e) => {
                    tracing::warn!(error = %e, "failed to create tokio runtime for compaction loop");
                    return;
                }
            };

            let interval = std::time::Duration::from_secs(interval_secs);

            // Open the Db within the runtime context
            let db = match rt.block_on(async { Db::open(cfg) }) {
                Ok(db) => db,
                Err(e) => {
                    tracing::warn!(error = %e, "failed to start background compaction loop");
                    return;
                }
            };

            loop {
                std::thread::sleep(interval);
                if let Err(e) = db.run_background_compaction() {
                    tracing::warn!(error = %e, "background compaction loop failed");
                }
            }
        });
    }

    /// Spawn dedicated continuous compaction threads (ClickHouse-style)
    /// These threads run compaction constantly with minimal sleep when idle
    fn spawn_continuous_compaction_threads(&self) {
        let num_threads = self.cfg.compaction_threads.max(1);
        let idle_sleep_ms = self.cfg.compaction_idle_sleep_ms;

        tracing::info!(
            threads = num_threads,
            idle_sleep_ms = idle_sleep_ms,
            "Starting continuous compaction threads"
        );

        for thread_id in 0..num_threads {
            let mut cfg = self.cfg.clone();
            cfg.auto_compact_interval_secs = 0; // Disable interval-based in child
            cfg.continuous_compaction_enabled = false; // Don't spawn more threads

            std::thread::spawn(move || {
                // Create a Tokio runtime for the background thread
                let rt = match tokio::runtime::Builder::new_current_thread()
                    .enable_all()
                    .build()
                {
                    Ok(rt) => rt,
                    Err(e) => {
                        tracing::warn!(
                            thread_id = thread_id,
                            error = %e,
                            "failed to create tokio runtime for continuous compaction thread"
                        );
                        return;
                    }
                };

                // Open the Db within the runtime context
                let db = match rt.block_on(async { Db::open(cfg) }) {
                    Ok(db) => db,
                    Err(e) => {
                        tracing::warn!(
                            thread_id = thread_id,
                            error = %e,
                            "failed to open Db for continuous compaction thread"
                        );
                        return;
                    }
                };

                let idle_timeout = std::time::Duration::from_millis(idle_sleep_ms);

                loop {
                    // Try leveled compaction first
                    let leveled_work = if db.cfg.leveled_compaction_enabled {
                        db.run_leveled_compaction().unwrap_or(0)
                    } else {
                        0
                    };

                    // Then try traditional compaction
                    let traditional_work = db.run_background_compaction().unwrap_or(0);

                    // If no work was done, wait for notification instead of busy-polling
                    // This dramatically reduces CPU usage (60-80% reduction)
                    if leveled_work == 0 && traditional_work == 0 {
                        // Event-driven: wait for segment ingest to notify us
                        // Falls back to timeout-based check for safety
                        db.compaction_state.wait_for_work(idle_timeout);
                    }
                    // If work was done, immediately loop to check for more
                }
            });
        }
    }

    /// Spawn background thread to flush write buffer based on time interval
    fn spawn_write_buffer_flush_thread(&self) {
        if !self.cfg.write_buffer_enabled {
            return;
        }

        let flush_interval_ms = self.cfg.write_buffer_flush_interval_ms;
        if flush_interval_ms == 0 {
            return;
        }

        let mut cfg = self.cfg.clone();
        cfg.write_buffer_enabled = false; // Prevent recursive spawning

        tracing::info!(
            flush_interval_ms = flush_interval_ms,
            max_bytes = cfg.write_buffer_max_bytes,
            "Starting write buffer flush thread"
        );

        std::thread::spawn(move || {
            // Create a Tokio runtime for the background thread
            let rt = match tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
            {
                Ok(rt) => rt,
                Err(e) => {
                    tracing::warn!(error = %e, "failed to create tokio runtime for write buffer flush");
                    return;
                }
            };

            let db = match rt.block_on(async { Db::open(cfg) }) {
                Ok(db) => db,
                Err(e) => {
                    tracing::warn!(error = %e, "failed to open Db for write buffer flush thread");
                    return;
                }
            };

            let interval = std::time::Duration::from_millis(flush_interval_ms);

            loop {
                std::thread::sleep(interval);

                // Flush buffer if time threshold exceeded
                if let Err(e) = db.flush_write_buffer_if_needed() {
                    tracing::warn!(error = %e, "write buffer flush failed");
                }
            }
        });
    }

    /// Flush write buffer if time threshold exceeded
    fn flush_write_buffer_if_needed(&self) -> Result<(), EngineError> {
        if !self.cfg.write_buffer_enabled {
            return Ok(());
        }

        let should_flush = {
            let buffer = self.write_buffer.lock();
            buffer.should_flush_time(self.cfg.write_buffer_flush_interval_ms) && !buffer.is_empty()
        };

        if should_flush {
            self.flush_write_buffer()?;
        }

        Ok(())
    }

    /// Flush all buffered writes to segments
    pub fn flush_write_buffer(&self) -> Result<usize, EngineError> {
        let buffers = {
            let mut buffer = self.write_buffer.lock();
            buffer.take_all()
        };

        if buffers.is_empty() {
            return Ok(0);
        }

        let mut flushed = 0;
        for ((database, table), table_buffer) in buffers {
            if table_buffer.payloads.is_empty() {
                continue;
            }

            // Concatenate all buffered payloads into one large batch
            let combined = self.combine_buffered_payloads(&table_buffer)?;

            // Now ingest the combined payload as a single segment
            if !combined.is_empty() {
                // Create a batch from the combined payload
                let batch = IngestBatch {
                    database: Some(database.clone()),
                    table: Some(table.clone()),
                    shard_override: Some(table_buffer.shard_id as u64),
                    payload_ipc: combined,
                    watermark_micros: table_buffer.watermark_micros,
                };

                // Direct ingest bypassing buffer (since we're flushing)
                self.ingest_ipc_direct(batch)?;
                flushed += 1;
            }
        }

        if flushed > 0 {
            tracing::debug!(tables_flushed = flushed, "Flushed write buffer");
        }

        Ok(flushed)
    }

    /// Combine multiple IPC payloads into one
    fn combine_buffered_payloads(&self, buffer: &TableWriteBuffer) -> Result<Vec<u8>, EngineError> {
        if buffer.payloads.is_empty() {
            return Ok(Vec::new());
        }

        if buffer.payloads.len() == 1 {
            return Ok(buffer.payloads[0].clone());
        }

        // Read all batches from all payloads
        let mut all_batches = Vec::new();
        for payload in &buffer.payloads {
            let batches = read_ipc_batches(payload)?;
            all_batches.extend(batches);
        }

        if all_batches.is_empty() {
            return Ok(Vec::new());
        }

        let schema = all_batches[0].schema();

        // Concatenate all batches
        let concatenated = arrow_select::concat::concat_batches(&schema, &all_batches)
            .map_err(|e| EngineError::Internal(format!("concat buffered batches failed: {e}")))?;

        // Re-encode to IPC
        record_batches_to_ipc(&schema, &[concatenated])
    }

    fn rewrite_table_segments_to_schema(
        &self,
        database: &str,
        table: &str,
        schema_json: &str,
    ) -> Result<(), EngineError> {
        let expected_spec: Vec<TableFieldSpec> =
            serde_json::from_str(schema_json).map_err(|e| {
                EngineError::InvalidArgument(format!("invalid schema json for rewrite: {e}"))
            })?;
        let expected_fields: Vec<Field> = expected_spec
            .iter()
            .map(|s| {
                arrow_type_from_str(&s.data_type).map(|dt| Field::new(&s.name, dt, s.nullable))
            })
            .collect::<Result<_, _>>()?;

        let (table_meta, entries) = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let tbl = manifest
                .tables
                .iter()
                .find(|t| t.database == database && t.name == table)
                .cloned()
                .ok_or_else(|| {
                    EngineError::NotFound(format!("table not found: {database}.{table}"))
                })?;
            let entries = manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>();
            (tbl, entries)
        };

        if entries.is_empty() {
            return Ok(());
        }

        let compression = normalize_compression(table_meta.compression.clone())?;
        let mut rewritten: Vec<(String, Vec<u8>, u64, u64)> = Vec::new();
        for entry in &entries {
            let data = load_segment(&self.storage, entry)?;
            let batches = read_ipc_batches(&data)?;
            let mut new_batches = Vec::new();
            for batch in batches {
                let aligned = align_batch_to_fields(&expected_fields, &batch)?;
                new_batches.push(aligned);
            }
            if !new_batches.is_empty() {
                let ipc = record_batches_to_ipc(new_batches[0].schema().as_ref(), &new_batches)?;
                let stored = compress_payload(&ipc, compression.as_deref())?;
                let checksum = compute_checksum(&stored);
                let schema_hash =
                    compute_schema_hash_from_payload(&stored, compression.as_deref())?;
                rewritten.push((entry.segment_id.clone(), stored, checksum, schema_hash));
            }
        }

        for (segment_id, stored, _, _) in &rewritten {
            persist_segment_ipc(&self.storage, segment_id, stored)?;
            // Invalidate sharded segment cache (each shard locks independently)
            self.segment_cache.invalidate(segment_id);
        }

        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest.bump_version();
            for entry in manifest
                .entries
                .iter_mut()
                .filter(|e| e.database == database && e.table == table)
            {
                if let Some((_, stored, checksum, schema_hash)) = rewritten
                    .iter()
                    .find(|(id, _, _, _)| id == &entry.segment_id)
                {
                    entry.size_bytes = stored.len() as u64;
                    entry.checksum = *checksum;
                    entry.compression = compression.clone();
                    entry.schema_hash = Some(*schema_hash);
                }
            }
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
        }
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }
        Ok(())
    }

    /// Delete rows matching the filter from a table. Returns number of rows deleted.
    pub fn delete_rows(
        &self,
        database: &str,
        table: &str,
        where_clause: Option<&str>,
    ) -> Result<usize, EngineError> {
        use crate::sql::{ForeignKeyAction, TableConstraint};

        let filter = parse_where_filter(where_clause)?;
        if let Some(clause) = where_clause {
            if !clause.trim().is_empty() && filter_is_empty(&filter) {
                return Err(EngineError::InvalidArgument(
                    "unsupported WHERE clause for DELETE".into(),
                ));
            }
        }

        // Check for foreign key constraints that reference this table (ON DELETE RESTRICT)
        let referencing_tables: Vec<(String, String, TableConstraint)> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            manifest
                .tables
                .iter()
                .flat_map(|t| {
                    t.constraints
                        .iter()
                        .filter_map(|c| {
                            if let TableConstraint::ForeignKey {
                                referenced_table,
                                on_delete,
                                ..
                            } = c
                            {
                                // Check if this FK references our table
                                let ref_table_full = if referenced_table.contains('.') {
                                    referenced_table.clone()
                                } else {
                                    format!("{}.{}", t.database, referenced_table)
                                };
                                let target_full = format!("{}.{}", database, table);
                                if ref_table_full == target_full || *referenced_table == table {
                                    return Some((t.database.clone(), t.name.clone(), c.clone()));
                                }
                            }
                            None
                        })
                        .collect::<Vec<_>>()
                })
                .collect()
        };

        // Check ON DELETE RESTRICT constraints
        for (ref_db, ref_table, constraint) in &referencing_tables {
            if let TableConstraint::ForeignKey {
                columns,
                referenced_columns,
                on_delete,
                name,
                ..
            } = constraint
            {
                // Get rows that would be deleted to check FK violations
                let deleted_values = self.get_rows_matching_filter(database, table, &filter, referenced_columns)?;

                if deleted_values.is_empty() {
                    continue; // No rows being deleted, no FK action needed
                }

                match on_delete {
                    ForeignKeyAction::Restrict | ForeignKeyAction::NoAction => {
                        // Check if any rows in the referencing table point to rows we're deleting
                        let fk_clause = build_fk_where_clause(columns, &deleted_values);
                        if let Some(clause) = &fk_clause {
                            let ref_filter = parse_where_filter(Some(clause))?;
                            let matching = self.get_rows_matching_filter(ref_db, ref_table, &ref_filter, columns)?;
                            if !matching.is_empty() {
                                return Err(EngineError::ConstraintViolation(format!(
                                    "Cannot delete from {}.{}: foreign key constraint '{}' on {}.{} would be violated (ON DELETE {})",
                                    database,
                                    table,
                                    name.as_deref().unwrap_or("unnamed"),
                                    ref_db,
                                    ref_table,
                                    match on_delete {
                                        ForeignKeyAction::Restrict => "RESTRICT",
                                        _ => "NO ACTION",
                                    }
                                )));
                            }
                        }
                    }
                    ForeignKeyAction::Cascade => {
                        // ON DELETE CASCADE: recursively delete referencing rows
                        let fk_clause = build_fk_where_clause(columns, &deleted_values);
                        if let Some(clause) = fk_clause {
                            // Recursive delete on the referencing table
                            self.delete_rows(ref_db, ref_table, Some(&clause))?;
                        }
                    }
                    ForeignKeyAction::SetNull => {
                        // ON DELETE SET NULL: set FK columns to NULL in referencing rows
                        let fk_clause = build_fk_where_clause(columns, &deleted_values);
                        if let Some(clause) = fk_clause {
                            let assignments: Vec<(String, SqlValue)> = columns
                                .iter()
                                .map(|col| (col.clone(), SqlValue::Null))
                                .collect();
                            self.update_rows(ref_db, ref_table, &assignments, Some(&clause))?;
                        }
                    }
                    ForeignKeyAction::SetDefault => {
                        // ON DELETE SET DEFAULT: set FK columns to default values
                        // Get default values from table schema
                        let defaults = self.get_column_defaults(ref_db, ref_table, columns)?;
                        let fk_clause = build_fk_where_clause(columns, &deleted_values);
                        if let Some(clause) = fk_clause {
                            let assignments: Vec<(String, SqlValue)> = columns
                                .iter()
                                .zip(defaults.iter())
                                .map(|(col, def)| (col.clone(), def.clone()))
                                .collect();
                            self.update_rows(ref_db, ref_table, &assignments, Some(&clause))?;
                        }
                    }
                }
            }
        }

        let entries = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            if !manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table)
            {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>()
        };

        if entries.is_empty() {
            return Ok(0);
        }

        let mut new_segments: Vec<(u16, u64, Vec<u8>)> = Vec::new();
        let mut segments_to_drop: Vec<String> = Vec::new();
        let mut rows_deleted = 0usize;

        for entry in entries {
            let data = load_segment(&self.storage, &entry)?;
            let batches = read_ipc_batches(&data)?;
            let mut kept_batches = Vec::new();
            let mut segment_removed = 0usize;
            for batch in batches {
                let (kept, removed) = filter_batch_for_delete(&batch, &filter)?;
                rows_deleted += removed;
                segment_removed += removed;
                if let Some(b) = kept {
                    kept_batches.push(b);
                }
            }
            if segment_removed > 0 {
                if !kept_batches.is_empty() {
                    let ipc =
                        record_batches_to_ipc(kept_batches[0].schema().as_ref(), &kept_batches)?;
                    new_segments.push((entry.shard_id, entry.watermark_micros, ipc));
                }
                segments_to_drop.push(entry.segment_id.clone());
            }
        }

        if rows_deleted == 0 {
            return Ok(0);
        }

        // Remove affected segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = segments_to_drop.iter().cloned().collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }
        }

        // Drop old segment files (best effort)
        for seg_id in &segments_to_drop {
            self.remove_segment_file(seg_id);
        }

        for (shard, watermark, ipc) in new_segments {
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: watermark,
                shard_override: Some(shard as u64),
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;
        }
        Ok(rows_deleted)
    }

    /// Delete rows matching the filter and return them. Returns (deleted_count, deleted_batches).
    pub fn delete_rows_returning(
        &self,
        database: &str,
        table: &str,
        where_clause: Option<&str>,
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        let filter = parse_where_filter(where_clause)?;
        if let Some(clause) = where_clause {
            if !clause.trim().is_empty() && filter_is_empty(&filter) {
                return Err(EngineError::InvalidArgument(
                    "unsupported WHERE clause for DELETE".into(),
                ));
            }
        }

        let entries = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            if !manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table)
            {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>()
        };

        if entries.is_empty() {
            return Ok((0, Vec::new()));
        }

        let mut new_segments: Vec<(u16, u64, Vec<u8>)> = Vec::new();
        let mut segments_to_drop: Vec<String> = Vec::new();
        let mut rows_deleted = 0usize;
        let mut deleted_batches: Vec<RecordBatch> = Vec::new();

        for entry in entries {
            let data = load_segment(&self.storage, &entry)?;
            let batches = read_ipc_batches(&data)?;
            let mut kept_batches = Vec::new();
            let mut segment_removed = 0usize;
            for batch in batches {
                let (kept, deleted, removed) = filter_batch_for_delete_returning(&batch, &filter)?;
                rows_deleted += removed;
                segment_removed += removed;
                if let Some(d) = deleted {
                    deleted_batches.push(d);
                }
                if let Some(k) = kept {
                    kept_batches.push(k);
                }
            }
            if segment_removed > 0 {
                if !kept_batches.is_empty() {
                    let ipc =
                        record_batches_to_ipc(kept_batches[0].schema().as_ref(), &kept_batches)?;
                    new_segments.push((entry.shard_id, entry.watermark_micros, ipc));
                }
                segments_to_drop.push(entry.segment_id.clone());
            }
        }

        if rows_deleted == 0 {
            return Ok((0, Vec::new()));
        }

        // Remove affected segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = segments_to_drop.iter().cloned().collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }
        }

        // Drop old segment files (best effort)
        for seg_id in &segments_to_drop {
            self.remove_segment_file(seg_id);
        }

        for (shard, watermark, ipc) in new_segments {
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: watermark,
                shard_override: Some(shard as u64),
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;
        }
        Ok((rows_deleted, deleted_batches))
    }

    /// Update rows matching the filter by applying assignments. Returns number of rows updated.
    pub fn update_rows(
        &self,
        database: &str,
        table: &str,
        assignments: &[(String, SqlValue)],
        where_clause: Option<&str>,
    ) -> Result<usize, EngineError> {
        use crate::sql::{ForeignKeyAction, TableConstraint};

        if assignments.is_empty() {
            return Err(EngineError::InvalidArgument(
                "UPDATE requires at least one assignment".into(),
            ));
        }
        let filter = parse_where_filter(where_clause)?;
        if let Some(clause) = where_clause {
            if !clause.trim().is_empty() && filter_is_empty(&filter) {
                return Err(EngineError::InvalidArgument(
                    "unsupported WHERE clause for UPDATE".into(),
                ));
            }
        }

        // Get columns being updated
        let updated_columns: HashSet<String> = assignments
            .iter()
            .map(|(col, _)| col.to_lowercase())
            .collect();

        // Check for foreign key constraints that reference this table's updated columns (ON UPDATE RESTRICT)
        let referencing_tables: Vec<(String, String, TableConstraint)> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            manifest
                .tables
                .iter()
                .flat_map(|t| {
                    t.constraints
                        .iter()
                        .filter_map(|c| {
                            if let TableConstraint::ForeignKey {
                                referenced_table,
                                referenced_columns,
                                on_update,
                                ..
                            } = c
                            {
                                // Check if this FK references columns we're updating
                                let ref_table_full = if referenced_table.contains('.') {
                                    referenced_table.clone()
                                } else {
                                    format!("{}.{}", t.database, referenced_table)
                                };
                                let target_full = format!("{}.{}", database, table);

                                if ref_table_full == target_full || *referenced_table == table {
                                    // Check if any referenced column is being updated
                                    let refs_updated = referenced_columns
                                        .iter()
                                        .any(|c| updated_columns.contains(&c.to_lowercase()));
                                    if refs_updated {
                                        return Some((
                                            t.database.clone(),
                                            t.name.clone(),
                                            c.clone(),
                                        ));
                                    }
                                }
                            }
                            None
                        })
                        .collect::<Vec<_>>()
                })
                .collect()
        };

        // Check ON UPDATE RESTRICT constraints
        for (ref_db, ref_table, constraint) in &referencing_tables {
            if let TableConstraint::ForeignKey {
                on_update, name, ..
            } = constraint
            {
                // Get the referenced columns from the FK constraint
                let fk_referenced_columns = if let TableConstraint::ForeignKey {
                    referenced_columns: ref_cols,
                    columns: fk_cols,
                    ..
                } = constraint
                {
                    (ref_cols.clone(), fk_cols.clone())
                } else {
                    continue;
                };

                // Check if any of the updated columns are part of the referenced columns
                let updated_cols: HashSet<String> = assignments.iter().map(|(c, _)| c.to_lowercase()).collect();
                let ref_cols_set: HashSet<String> = fk_referenced_columns.0.iter().map(|c| c.to_lowercase()).collect();
                let affects_fk = updated_cols.intersection(&ref_cols_set).count() > 0;

                if !affects_fk {
                    continue; // This update doesn't affect FK columns, no action needed
                }

                // Get old values from rows being updated
                let old_values = self.get_rows_matching_filter(database, table, &filter, &fk_referenced_columns.0)?;

                if old_values.is_empty() {
                    continue; // No rows being updated, no FK action needed
                }

                match on_update {
                    ForeignKeyAction::Restrict | ForeignKeyAction::NoAction => {
                        // Check if any rows in the referencing table point to old values
                        let fk_clause = build_fk_where_clause(&fk_referenced_columns.1, &old_values);
                        if let Some(clause) = &fk_clause {
                            let ref_filter = parse_where_filter(Some(clause))?;
                            let matching = self.get_rows_matching_filter(ref_db, ref_table, &ref_filter, &fk_referenced_columns.1)?;
                            if !matching.is_empty() {
                                return Err(EngineError::ConstraintViolation(format!(
                                    "Cannot update {}.{}: foreign key constraint '{}' on {}.{} would be violated (ON UPDATE {})",
                                    database,
                                    table,
                                    name.as_deref().unwrap_or("unnamed"),
                                    ref_db,
                                    ref_table,
                                    match on_update {
                                        ForeignKeyAction::Restrict => "RESTRICT",
                                        _ => "NO ACTION",
                                    }
                                )));
                            }
                        }
                    }
                    ForeignKeyAction::Cascade => {
                        // ON UPDATE CASCADE: update referencing rows with new values
                        let fk_clause = build_fk_where_clause(&fk_referenced_columns.1, &old_values);
                        if let Some(clause) = fk_clause {
                            // Build new assignments from the update
                            let cascade_assignments: Vec<(String, SqlValue)> = fk_referenced_columns.0
                                .iter()
                                .zip(fk_referenced_columns.1.iter())
                                .filter_map(|(ref_col, fk_col)| {
                                    assignments.iter()
                                        .find(|(c, _)| c.eq_ignore_ascii_case(ref_col))
                                        .map(|(_, v)| (fk_col.clone(), v.clone()))
                                })
                                .collect();
                            if !cascade_assignments.is_empty() {
                                self.update_rows(ref_db, ref_table, &cascade_assignments, Some(&clause))?;
                            }
                        }
                    }
                    ForeignKeyAction::SetNull => {
                        // ON UPDATE SET NULL: set FK columns to NULL in referencing rows
                        let fk_clause = build_fk_where_clause(&fk_referenced_columns.1, &old_values);
                        if let Some(clause) = fk_clause {
                            let null_assignments: Vec<(String, SqlValue)> = fk_referenced_columns.1
                                .iter()
                                .map(|col| (col.clone(), SqlValue::Null))
                                .collect();
                            self.update_rows(ref_db, ref_table, &null_assignments, Some(&clause))?;
                        }
                    }
                    ForeignKeyAction::SetDefault => {
                        // ON UPDATE SET DEFAULT: set FK columns to default values
                        let defaults = self.get_column_defaults(ref_db, ref_table, &fk_referenced_columns.1)?;
                        let fk_clause = build_fk_where_clause(&fk_referenced_columns.1, &old_values);
                        if let Some(clause) = fk_clause {
                            let default_assignments: Vec<(String, SqlValue)> = fk_referenced_columns.1
                                .iter()
                                .zip(defaults.iter())
                                .map(|(col, def)| (col.clone(), def.clone()))
                                .collect();
                            self.update_rows(ref_db, ref_table, &default_assignments, Some(&clause))?;
                        }
                    }
                }
            }
        }

        let entries = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            if !manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table)
            {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>()
        };

        if entries.is_empty() {
            return Ok(0);
        }

        let mut new_segments: Vec<(u16, u64, Vec<u8>)> = Vec::new();
        let mut segments_to_drop: Vec<String> = Vec::new();
        let mut rows_updated = 0usize;

        for entry in entries {
            let data = load_segment(&self.storage, &entry)?;
            let batches = read_ipc_batches(&data)?;
            let mut updated_batches = Vec::new();
            let mut segment_changed = false;
            for batch in batches {
                let (updated, count) = apply_assignments_to_batch(&batch, &filter, assignments)?;
                if count > 0 {
                    segment_changed = true;
                }
                rows_updated += count;
                updated_batches.push(updated);
            }
            if segment_changed {
                let ipc =
                    record_batches_to_ipc(updated_batches[0].schema().as_ref(), &updated_batches)?;
                new_segments.push((entry.shard_id, entry.watermark_micros, ipc));
                segments_to_drop.push(entry.segment_id.clone());
            }
        }

        if rows_updated == 0 {
            return Ok(0);
        }

        // Remove affected segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = segments_to_drop.iter().cloned().collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }
        }

        for seg_id in &segments_to_drop {
            self.remove_segment_file(seg_id);
        }

        for (shard, watermark, ipc) in new_segments {
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: watermark,
                shard_override: Some(shard as u64),
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;
        }
        Ok(rows_updated)
    }

    /// Update rows matching the filter and return the updated rows (with new values).
    /// Returns (updated_count, updated_batches).
    pub fn update_rows_returning(
        &self,
        database: &str,
        table: &str,
        assignments: &[(String, SqlValue)],
        where_clause: Option<&str>,
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        if assignments.is_empty() {
            return Err(EngineError::InvalidArgument(
                "UPDATE requires at least one assignment".into(),
            ));
        }
        let filter = parse_where_filter(where_clause)?;
        if let Some(clause) = where_clause {
            if !clause.trim().is_empty() && filter_is_empty(&filter) {
                return Err(EngineError::InvalidArgument(
                    "unsupported WHERE clause for UPDATE".into(),
                ));
            }
        }

        let entries = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            if !manifest
                .tables
                .iter()
                .any(|t| t.database == database && t.name == table)
            {
                return Err(EngineError::NotFound(format!(
                    "table not found: {database}.{table}"
                )));
            }
            manifest
                .entries
                .iter()
                .filter(|e| e.database == database && e.table == table)
                .cloned()
                .collect::<Vec<_>>()
        };

        if entries.is_empty() {
            return Ok((0, Vec::new()));
        }

        let mut new_segments: Vec<(u16, u64, Vec<u8>)> = Vec::new();
        let mut segments_to_drop: Vec<String> = Vec::new();
        let mut rows_updated = 0usize;
        let mut updated_batches: Vec<RecordBatch> = Vec::new();

        for entry in entries {
            let data = load_segment(&self.storage, &entry)?;
            let batches = read_ipc_batches(&data)?;
            let mut all_updated_batches = Vec::new();
            let mut segment_changed = false;
            for batch in batches {
                let (updated, updated_rows, count) =
                    apply_assignments_to_batch_returning(&batch, &filter, assignments)?;
                if count > 0 {
                    segment_changed = true;
                    if let Some(rows) = updated_rows {
                        updated_batches.push(rows);
                    }
                }
                rows_updated += count;
                all_updated_batches.push(updated);
            }
            if segment_changed {
                let ipc = record_batches_to_ipc(
                    all_updated_batches[0].schema().as_ref(),
                    &all_updated_batches,
                )?;
                new_segments.push((entry.shard_id, entry.watermark_micros, ipc));
                segments_to_drop.push(entry.segment_id.clone());
            }
        }

        if rows_updated == 0 {
            return Ok((0, Vec::new()));
        }

        // Remove affected segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let drop_set: HashSet<String> = segments_to_drop.iter().cloned().collect();
            manifest
                .entries
                .retain(|e| !drop_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
            {
                let mut index = self
                    .manifest_index
                    .write()
                    .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
                *index = ManifestIndex::build(&manifest.entries);
            }
            {
                let mut cache = self.query_cache.lock();
                cache.invalidate_table(database, table);
            }
        }

        for seg_id in &segments_to_drop {
            self.remove_segment_file(seg_id);
        }

        for (shard, watermark, ipc) in new_segments {
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: watermark,
                shard_override: Some(shard as u64),
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;
        }
        Ok((rows_updated, updated_batches))
    }

    /// Execute a MERGE statement (UPSERT with WHEN MATCHED/NOT MATCHED).
    /// Returns (matched_count, inserted_count).
    pub fn merge_rows(
        &self,
        database: &str,
        table: &str,
        source_database: &str,
        source_table: &str,
        on_condition: &str,
        when_matched: &[crate::sql::MergeWhenMatched],
        when_not_matched: &[crate::sql::MergeWhenNotMatched],
    ) -> Result<(usize, usize), EngineError> {
        use crate::sql::{MergeWhenMatched, MergeWhenNotMatched};

        // Load source table data
        let source_batches = self.load_table_batches(source_database, source_table)?;
        if source_batches.is_empty() {
            return Ok((0, 0));
        }

        // Load target table data
        let target_batches = self.load_table_batches(database, table)?;

        // Parse ON condition to extract join columns
        // For now, we support simple "target.col = source.col" conditions
        let (target_col, source_col) = parse_merge_condition(on_condition)?;

        let mut matched_count = 0usize;
        let mut inserted_count = 0usize;

        // Build a set of values from target table for the join column
        let mut target_values: std::collections::HashSet<String> = std::collections::HashSet::new();
        for batch in &target_batches {
            if let Ok(idx) = batch.schema().index_of(&target_col) {
                let arr = batch.column(idx);
                for i in 0..arr.len() {
                    if let Some(val) = merge_array_value_to_string(arr.as_ref(), i) {
                        target_values.insert(val);
                    }
                }
            }
        }

        // Process source rows
        for src_batch in &source_batches {
            let src_schema = src_batch.schema();
            let src_col_idx = src_schema.index_of(&source_col).map_err(|_| {
                EngineError::InvalidArgument(format!(
                    "source column '{}' not found in MERGE ON condition",
                    source_col
                ))
            })?;

            let src_arr = src_batch.column(src_col_idx);

            for row_idx in 0..src_batch.num_rows() {
                let src_val = merge_array_value_to_string(src_arr.as_ref(), row_idx);
                let is_matched = src_val.as_ref().map(|v| target_values.contains(v)).unwrap_or(false);

                if is_matched {
                    // WHEN MATCHED - apply update/delete actions
                    for action in when_matched {
                        match action {
                            MergeWhenMatched::Update { assignments, condition } => {
                                // Build WHERE clause for this specific row
                                if let Some(key_val) = &src_val {
                                    let where_clause = format!("{} = '{}'", target_col, key_val);
                                    // Check condition if specified
                                    let should_update = condition.is_none() ||
                                        evaluate_simple_condition(condition.as_ref(), src_batch, row_idx);
                                    if should_update {
                                        self.update_rows(database, table, assignments, Some(&where_clause))?;
                                        matched_count += 1;
                                    }
                                }
                            }
                            MergeWhenMatched::Delete { condition } => {
                                if let Some(key_val) = &src_val {
                                    let where_clause = format!("{} = '{}'", target_col, key_val);
                                    let should_delete = condition.is_none() ||
                                        evaluate_simple_condition(condition.as_ref(), src_batch, row_idx);
                                    if should_delete {
                                        self.delete_rows(database, table, Some(&where_clause))?;
                                        matched_count += 1;
                                    }
                                }
                            }
                        }
                    }
                } else {
                    // WHEN NOT MATCHED - apply insert actions
                    for action in when_not_matched {
                        let MergeWhenNotMatched { columns, values, condition } = action;

                        let should_insert = condition.is_none() ||
                            evaluate_simple_condition(condition.as_ref(), src_batch, row_idx);

                        if should_insert && !values.is_empty() {
                            // Build INSERT for this row
                            // For now, use the literal values from the MERGE statement
                            let insert_batch = crate::sql::InsertCommand {
                                database: database.to_string(),
                                table: table.to_string(),
                                columns: Some(columns.clone()),
                                values: vec![values.clone()],
                                on_conflict: None,
                                returning: None,
                            };

                            // Convert InsertCommand to IPC and ingest
                            if let Ok(ipc) = build_insert_ipc(&insert_batch, self, database, table) {
                                if let Ok(_) = self.ingest_ipc(IngestBatch {
                                    payload_ipc: ipc,
                                    watermark_micros: std::time::SystemTime::now()
                                        .duration_since(std::time::UNIX_EPOCH)
                                        .unwrap_or_default()
                                        .as_micros() as u64,
                                    shard_override: None,
                                    database: Some(database.to_string()),
                                    table: Some(table.to_string()),
                                }) {
                                    inserted_count += 1;
                                }
                            }
                        }
                    }
                }
            }
        }

        Ok((matched_count, inserted_count))
    }

    /// Delete rows from target table that match a join with USING tables.
    /// This implements PostgreSQL-style DELETE ... USING syntax.
    /// Returns (deleted_count, deleted_batches).
    pub fn delete_rows_with_using(
        &self,
        database: &str,
        table: &str,
        table_alias: Option<&str>,
        using_tables: &[crate::sql::JoinTable],
        where_clause: Option<&str>,
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        // Load all using tables into memory
        let mut using_data: Vec<(String, String, Option<String>, Vec<RecordBatch>)> = Vec::new();
        for ut in using_tables {
            let batches = self.load_table_batches(&ut.database, &ut.table)?;
            using_data.push((ut.database.clone(), ut.table.clone(), ut.alias.clone(), batches));
        }

        // Parse WHERE clause to identify join conditions
        let where_str = where_clause.unwrap_or("");

        // Build a set of matching row IDs from the target table by evaluating the join
        // Strategy: For each row in target, check if it matches any row in using tables
        // based on the WHERE clause predicates

        // Load target table batches
        let target_batches = self.load_table_batches(database, table)?;
        if target_batches.is_empty() {
            return Ok((0, Vec::new()));
        }

        // Extract matching row indices based on the join condition
        let matching_indices =
            self.evaluate_join_condition(&target_batches, table_alias, &using_data, where_str)?;

        if matching_indices.is_empty() {
            return Ok((0, Vec::new()));
        }

        // Build a WHERE clause that filters by the matching indices
        // For simplicity, we'll collect the rows to delete based on the matching indices
        // and delete them by reconstructing the table without those rows
        self.delete_rows_by_indices(database, table, &target_batches, &matching_indices)
    }

    /// Update rows in target table that match a join with FROM tables.
    /// This implements PostgreSQL-style UPDATE ... FROM syntax.
    /// Returns (updated_count, updated_batches).
    pub fn update_rows_with_from(
        &self,
        database: &str,
        table: &str,
        table_alias: Option<&str>,
        assignments: &[(String, SqlValue)],
        from_tables: &[crate::sql::JoinTable],
        where_clause: Option<&str>,
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        if assignments.is_empty() {
            return Err(EngineError::InvalidArgument(
                "UPDATE requires at least one assignment".into(),
            ));
        }

        // Load all from tables into memory
        let mut from_data: Vec<(String, String, Option<String>, Vec<RecordBatch>)> = Vec::new();
        for ft in from_tables {
            let batches = self.load_table_batches(&ft.database, &ft.table)?;
            from_data.push((ft.database.clone(), ft.table.clone(), ft.alias.clone(), batches));
        }

        // Parse WHERE clause to identify join conditions
        let where_str = where_clause.unwrap_or("");

        // Load target table batches
        let target_batches = self.load_table_batches(database, table)?;
        if target_batches.is_empty() {
            return Ok((0, Vec::new()));
        }

        // Extract matching row indices based on the join condition
        let matching_indices =
            self.evaluate_join_condition(&target_batches, table_alias, &from_data, where_str)?;

        if matching_indices.is_empty() {
            return Ok((0, Vec::new()));
        }

        // Update the matching rows
        self.update_rows_by_indices(database, table, assignments, &target_batches, &matching_indices)
    }

    /// Evaluate a join condition between target table and join tables.
    /// Returns a set of (batch_index, row_index) tuples for matching target rows.
    fn evaluate_join_condition(
        &self,
        target_batches: &[RecordBatch],
        target_alias: Option<&str>,
        join_tables: &[(String, String, Option<String>, Vec<RecordBatch>)],
        where_clause: &str,
    ) -> Result<Vec<(usize, usize)>, EngineError> {
        use std::collections::HashSet;

        if where_clause.trim().is_empty() || join_tables.is_empty() {
            // No WHERE clause or no join tables - match all rows
            let mut all_indices = Vec::new();
            for (batch_idx, batch) in target_batches.iter().enumerate() {
                for row_idx in 0..batch.num_rows() {
                    all_indices.push((batch_idx, row_idx));
                }
            }
            return Ok(all_indices);
        }

        // Parse the WHERE clause to extract join predicates
        // We look for patterns like "target.col = join.col" or "alias.col = alias2.col"
        let predicates = parse_join_predicates(where_clause, target_alias, join_tables)?;

        if predicates.is_empty() {
            // No recognizable join predicates - fall back to matching all rows
            let mut all_indices = Vec::new();
            for (batch_idx, batch) in target_batches.iter().enumerate() {
                for row_idx in 0..batch.num_rows() {
                    all_indices.push((batch_idx, row_idx));
                }
            }
            return Ok(all_indices);
        }

        // Build hash sets of values from join tables for each predicate
        let mut join_value_sets: Vec<HashSet<String>> = Vec::new();
        for pred in &predicates {
            let mut value_set = HashSet::new();
            for (_, _, alias, batches) in join_tables {
                // Check if this join table matches the predicate's join table reference
                let matches = pred.join_table_name.is_none()
                    || alias.as_deref() == pred.join_table_name.as_deref()
                    || join_tables
                        .iter()
                        .any(|(_, t, _, _)| Some(t.as_str()) == pred.join_table_name.as_deref());

                if matches {
                    for batch in batches {
                        if let Ok(col_idx) = batch.schema().index_of(&pred.join_column) {
                            let col = batch.column(col_idx);
                            for i in 0..col.len() {
                                if let Some(val) = array_value_to_string_for_join(col.as_ref(), i) {
                                    value_set.insert(val);
                                }
                            }
                        }
                    }
                }
            }
            join_value_sets.push(value_set);
        }

        // Find matching rows in target table
        let mut matching_indices = Vec::new();
        for (batch_idx, batch) in target_batches.iter().enumerate() {
            // Check each predicate
            let mut predicate_columns: Vec<Option<&dyn arrow_array::Array>> = Vec::new();
            for pred in &predicates {
                let col = batch
                    .schema()
                    .index_of(&pred.target_column)
                    .ok()
                    .map(|idx| batch.column(idx).as_ref());
                predicate_columns.push(col);
            }

            for row_idx in 0..batch.num_rows() {
                let mut all_match = true;
                for (i, col_opt) in predicate_columns.iter().enumerate() {
                    if let Some(col) = col_opt {
                        if let Some(val) = array_value_to_string_for_join(*col, row_idx) {
                            if !join_value_sets[i].contains(&val) {
                                all_match = false;
                                break;
                            }
                        } else {
                            all_match = false;
                            break;
                        }
                    } else {
                        all_match = false;
                        break;
                    }
                }
                if all_match {
                    matching_indices.push((batch_idx, row_idx));
                }
            }
        }

        Ok(matching_indices)
    }

    /// Delete rows from a table based on (batch_index, row_index) tuples.
    fn delete_rows_by_indices(
        &self,
        database: &str,
        table: &str,
        batches: &[RecordBatch],
        indices_to_delete: &[(usize, usize)],
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        use std::collections::HashSet;

        let delete_set: HashSet<(usize, usize)> = indices_to_delete.iter().copied().collect();
        let mut deleted_rows = Vec::new();
        let mut remaining_batches = Vec::new();
        let deleted_count = indices_to_delete.len();

        for (batch_idx, batch) in batches.iter().enumerate() {
            let mut keep_indices = Vec::new();
            let mut delete_indices = Vec::new();

            for row_idx in 0..batch.num_rows() {
                if delete_set.contains(&(batch_idx, row_idx)) {
                    delete_indices.push(row_idx);
                } else {
                    keep_indices.push(row_idx);
                }
            }

            // Collect deleted rows for RETURNING
            if !delete_indices.is_empty() {
                let deleted_batch = filter_batch_by_indices(batch, &delete_indices)?;
                deleted_rows.push(deleted_batch);
            }

            // Keep remaining rows
            if !keep_indices.is_empty() {
                let remaining_batch = filter_batch_by_indices(batch, &keep_indices)?;
                remaining_batches.push(remaining_batch);
            }
        }

        // Rewrite the table with remaining data
        self.rewrite_table_with_batches(database, table, &remaining_batches)?;

        Ok((deleted_count, deleted_rows))
    }

    /// Update rows from a table based on (batch_index, row_index) tuples.
    fn update_rows_by_indices(
        &self,
        database: &str,
        table: &str,
        assignments: &[(String, SqlValue)],
        batches: &[RecordBatch],
        indices_to_update: &[(usize, usize)],
    ) -> Result<(usize, Vec<RecordBatch>), EngineError> {
        use std::collections::HashSet;

        let update_set: HashSet<(usize, usize)> = indices_to_update.iter().copied().collect();
        let mut updated_rows = Vec::new();
        let mut result_batches = Vec::new();
        let updated_count = indices_to_update.len();

        for (batch_idx, batch) in batches.iter().enumerate() {
            let schema = batch.schema();
            let mut new_columns: Vec<Arc<dyn arrow_array::Array>> = Vec::new();

            for col_idx in 0..batch.num_columns() {
                let col_name = schema.field(col_idx).name().to_lowercase();
                let original_col = batch.column(col_idx);

                // Check if this column needs updating
                let assignment = assignments
                    .iter()
                    .find(|(name, _)| name.to_lowercase() == col_name);

                if let Some((_, new_value)) = assignment {
                    // Apply updates to matching rows
                    let updated_col =
                        apply_update_to_column(original_col, &update_set, batch_idx, new_value)?;
                    new_columns.push(updated_col);
                } else {
                    new_columns.push(original_col.clone());
                }
            }

            let new_batch = RecordBatch::try_new(schema.clone(), new_columns)
                .map_err(|e| EngineError::Internal(format!("failed to create batch: {}", e)))?;

            // Collect updated rows for RETURNING
            let mut update_indices = Vec::new();
            for row_idx in 0..batch.num_rows() {
                if update_set.contains(&(batch_idx, row_idx)) {
                    update_indices.push(row_idx);
                }
            }
            if !update_indices.is_empty() {
                let updated_batch = filter_batch_by_indices(&new_batch, &update_indices)?;
                updated_rows.push(updated_batch);
            }

            result_batches.push(new_batch);
        }

        // Rewrite the table with updated data
        self.rewrite_table_with_batches(database, table, &result_batches)?;

        Ok((updated_count, updated_rows))
    }

    /// Rewrite a table with new batches, removing old segments and creating new ones.
    fn rewrite_table_with_batches(
        &self,
        database: &str,
        table: &str,
        batches: &[RecordBatch],
    ) -> Result<(), EngineError> {
        // Get old segments to remove
        let old_entries = self.table_entries(database, table)?;
        let old_segment_ids: Vec<String> = old_entries.iter().map(|e| e.segment_id.clone()).collect();

        // Remove old segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest
                .entries
                .retain(|e| !old_segment_ids.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;
            snapshot_manifest(&self.cfg.manifest_snapshot_path, &self.cfg.manifest_path)?;
        }

        // Remove old segment files
        for seg_id in &old_segment_ids {
            self.remove_segment_file(seg_id);
        }

        // Invalidate cache
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        // Ingest new batches
        for batch in batches {
            if batch.num_rows() == 0 {
                continue;
            }
            let ipc = batch_to_ipc(batch)?;
            self.ingest_ipc(IngestBatch {
                payload_ipc: ipc,
                watermark_micros: std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_micros() as u64,
                shard_override: None,
                database: Some(database.to_string()),
                table: Some(table.to_string()),
            })?;
        }

        // Rebuild manifest index
        {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        Ok(())
    }

    pub fn health_check(&self) -> Result<(), EngineError> {
        // Lightweight health check: ensure manifest is readable and segments dir exists.
        // Note: We no longer fail on missing/corrupted segments - queries will skip them.
        let manifest = load_manifest(&self.cfg.manifest_path)?;
        if !self.cfg.segments_dir.exists() {
            return Err(EngineError::Internal(
                "segments directory missing".to_string(),
            ));
        }
        // Just log missing segments as warnings, don't fail the health check
        // This allows the server to start and queries to proceed (skipping bad segments)
        let mut missing_count = 0;
        for entry in &manifest.entries {
            let path = self
                .cfg
                .segments_dir
                .join(format!("{}.ipc", entry.segment_id));
            if !path.exists() {
                missing_count += 1;
                tracing::warn!(
                    "Segment missing on disk: {} (table: {}.{})",
                    entry.segment_id, entry.database, entry.table
                );
            }
        }
        if missing_count > 0 {
            tracing::warn!(
                "{} segments missing from disk. Run CHECK MANIFEST for details, REPAIR ALL SEGMENTS to fix.",
                missing_count
            );
        }
        Ok(())
    }

    /// Detailed health check returning comprehensive status information
    pub fn health_status(&self) -> HealthStatus {
        let mut errors = Vec::new();

        // Check manifest readability
        let manifest_result = load_manifest(&self.cfg.manifest_path);
        let manifest_readable = manifest_result.is_ok();
        if !manifest_readable {
            errors.push("Failed to read manifest".to_string());
        }

        // Check directories
        let segments_dir_exists = self.cfg.segments_dir.exists();
        if !segments_dir_exists {
            errors.push("Segments directory does not exist".to_string());
        }

        let wal_dir_exists = self.cfg.wal_dir.exists();
        if !wal_dir_exists {
            errors.push("WAL directory does not exist".to_string());
        }

        // Get manifest info
        let (
            total_segments,
            missing_segments,
            total_size_bytes,
            manifest_version,
            total_databases,
            total_tables,
        ) = if let Ok(manifest) = manifest_result {
            let mut missing = Vec::new();
            let mut total_size = 0u64;

            for entry in &manifest.entries {
                total_size += entry.size_bytes;
                if segments_dir_exists {
                    let path = self
                        .cfg
                        .segments_dir
                        .join(format!("{}.ipc", entry.segment_id));
                    if !path.exists() {
                        missing.push(entry.segment_id.clone());
                    }
                }
            }

            if !missing.is_empty() {
                errors.push(format!("{} segment(s) missing on disk", missing.len()));
            }

            (
                manifest.entries.len(),
                missing,
                total_size,
                manifest.version,
                manifest.databases.len(),
                manifest.tables.len(),
            )
        } else {
            (0, Vec::new(), 0, 0, 0, 0)
        };

        // Get cache info
        let cache_entries = self.query_cache.lock().len();

        // Calculate uptime
        let uptime_seconds = Some(self.start_time.elapsed().as_secs());

        // Determine overall health
        let is_healthy = errors.is_empty()
            && manifest_readable
            && segments_dir_exists
            && wal_dir_exists
            && missing_segments.is_empty();

        HealthStatus {
            is_healthy,
            manifest_readable,
            segments_dir_exists,
            wal_dir_exists,
            total_segments,
            missing_segments,
            total_databases,
            total_tables,
            total_size_bytes,
            manifest_version,
            uptime_seconds,
            cache_entries,
            errors,
        }
    }

    pub fn list_databases(&self) -> Result<Vec<String>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        Ok(manifest.databases.iter().map(|d| d.name.clone()).collect())
    }

    pub fn list_tables(
        &self,
        database: Option<&str>,
    ) -> Result<Vec<crate::replication::TableMeta>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        let tables = manifest
            .tables
            .iter()
            .filter(|t| {
                if let Some(db) = database {
                    t.database == db
                } else {
                    true
                }
            })
            .cloned()
            .collect();
        Ok(tables)
    }

    /// Get the current/default database name.
    /// Returns the first database if one exists, otherwise "boyodb".
    pub fn current_database(&self) -> Option<String> {
        let manifest = self.manifest.read().ok()?;
        manifest.databases.first().map(|d| d.name.clone())
    }

    /// Get the current manifest version.
    pub fn get_manifest_version(&self) -> Result<u64, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        Ok(manifest.version)
    }

    /// Get the current manifest version (convenience method).
    pub fn manifest_version(&self) -> u64 {
        self.manifest
            .read()
            .map(|m| m.version)
            .unwrap_or(0)
    }

    /// Reload manifest from storage (for read replicas).
    /// Returns (bytes_loaded, segments_added, new_version).
    pub fn reload_manifest_from_storage(&self) -> Result<(u64, u64, u64), EngineError> {
        // Load manifest from disk/S3
        let new_manifest = load_manifest(&self.cfg.manifest_path)?;
        let new_version = new_manifest.version;

        // Get current manifest to compare
        let (segments_added, bytes_loaded) = {
            let current_manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            if new_manifest.version <= current_manifest.version {
                // No new data
                return Ok((0, 0, current_manifest.version));
            }

            // Count new segments
            let current_ids: std::collections::HashSet<_> = current_manifest
                .entries
                .iter()
                .map(|e| e.segment_id.as_str())
                .collect();

            let new_entries: Vec<_> = new_manifest
                .entries
                .iter()
                .filter(|e| !current_ids.contains(e.segment_id.as_str()))
                .collect();

            let segments_added = new_entries.len() as u64;
            let bytes_loaded: u64 = new_entries.iter().map(|e| e.size_bytes).sum();

            (segments_added, bytes_loaded)
        };

        // Update manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            *manifest = new_manifest;

            // Rebuild index
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Invalidate caches since data changed
        self.invalidate_all_caches();

        Ok((bytes_loaded, segments_added, new_version))
    }

    /// Invalidate all caches (query cache, plan cache, batch cache).
    /// Used when manifest is updated externally (e.g., replica sync).
    pub fn invalidate_all_caches(&self) {
        // Clear query cache
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate();
        }

        // Clear plan cache
        {
            let mut cache = self.plan_cache.lock();
            cache.clear();
        }

        // Clear batch cache (all shards)
        self.batch_cache.clear();

        // Clear segment cache
        self.segment_cache.clear();

        // Clear bloom filter cache
        self.bloom_cache.clear();
    }

    /// Get the current WAL LSN (Log Sequence Number).
    /// Returns 0 if WAL is not available or empty.
    pub fn wal_lsn(&self) -> u64 {
        self.wal
            .lock()
            .ok()
            .map(|wal| wal.current_lsn())
            .unwrap_or(0)
    }

    /// Get server information including version and statistics
    pub fn get_server_info(&self) -> Result<ServerInfo, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
        Ok(ServerInfo {
            version: env!("CARGO_PKG_VERSION").to_string(),
            database_count: manifest.databases.len(),
            table_count: manifest.tables.len(),
            segment_count: manifest.entries.len(),
            manifest_version: manifest.version,
            wal_lsn: self.wal_lsn(),
        })
    }

    /// Find segments that are in the manifest but missing from disk
    pub fn find_missing_segments(
        &self,
        database: Option<&str>,
        table: Option<&str>,
    ) -> Result<Vec<MissingSegment>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut missing = Vec::new();
        for entry in &manifest.entries {
            // Filter by database/table if specified
            if let Some(db) = database {
                if entry.database != db {
                    continue;
                }
            }
            if let Some(tbl) = table {
                if entry.table != tbl {
                    continue;
                }
            }

            // Check if file exists
            let path = self.cfg.segments_dir.join(format!("{}.ipc", entry.segment_id));
            if !path.exists() {
                missing.push(MissingSegment {
                    segment_id: entry.segment_id.clone(),
                    database: entry.database.clone(),
                    table: entry.table.clone(),
                    size_bytes: entry.size_bytes,
                });
            }
        }
        Ok(missing)
    }

    /// Find segments that exist on disk but have checksum mismatches
    pub fn find_corrupted_segments(
        &self,
        database: Option<&str>,
        table: Option<&str>,
    ) -> Result<Vec<CorruptedSegment>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let mut corrupted = Vec::new();
        for entry in &manifest.entries {
            // Filter by database/table if specified
            if let Some(db) = database {
                if entry.database != db {
                    continue;
                }
            }
            if let Some(tbl) = table {
                if entry.table != tbl {
                    continue;
                }
            }

            // Check if file exists
            let path = self.cfg.segments_dir.join(format!("{}.ipc", entry.segment_id));
            if path.exists() {
                // Read and verify checksum (supports both xxHash64 and legacy CRC32)
                match std::fs::read(&path) {
                    Ok(data) => {
                        // Try xxHash64 first, then CRC32 for backward compatibility
                        let xxhash = compute_checksum(&data);
                        let crc32 = compute_checksum_crc32(&data);

                        // If neither matches, segment is corrupted
                        if xxhash != entry.checksum && crc32 != entry.checksum {
                            corrupted.push(CorruptedSegment {
                                segment_id: entry.segment_id.clone(),
                                database: entry.database.clone(),
                                table: entry.table.clone(),
                                size_bytes: entry.size_bytes,
                                expected_checksum: entry.checksum,
                                actual_checksum: xxhash, // Report xxHash64 as actual
                            });
                        }
                    }
                    Err(_) => {
                        // If we can't read it, treat it as corrupted with checksum 0
                        corrupted.push(CorruptedSegment {
                            segment_id: entry.segment_id.clone(),
                            database: entry.database.clone(),
                            table: entry.table.clone(),
                            size_bytes: entry.size_bytes,
                            expected_checksum: entry.checksum,
                            actual_checksum: 0,
                        });
                    }
                }
            }
        }
        Ok(corrupted)
    }

    /// Find all damaged segments (both missing and corrupted)
    pub fn find_damaged_segments(
        &self,
        database: Option<&str>,
        table: Option<&str>,
    ) -> Result<Vec<DamagedSegment>, EngineError> {
        let missing = self.find_missing_segments(database, table)?;
        let corrupted = self.find_corrupted_segments(database, table)?;

        let mut damaged: Vec<DamagedSegment> = missing
            .into_iter()
            .map(DamagedSegment::Missing)
            .collect();
        damaged.extend(corrupted.into_iter().map(DamagedSegment::Corrupted));

        Ok(damaged)
    }

    /// Repair segments by removing missing and corrupted segment entries from the manifest
    /// Also deletes corrupted segment files from disk
    ///
    /// - database=None, table=None: repair all segments in all databases
    /// - database=Some(db), table=None: repair all segments in a specific database
    /// - database=Some(db), table=Some(tbl): repair segments for a specific table
    pub fn repair_segments(
        &self,
        database: Option<&str>,
        table: Option<&str>,
    ) -> Result<Vec<String>, EngineError> {
        let missing = self.find_missing_segments(database, table)?;
        let corrupted = self.find_corrupted_segments(database, table)?;

        if missing.is_empty() && corrupted.is_empty() {
            return Ok(Vec::new());
        }

        // Collect all segment IDs to remove
        let mut removed_ids: Vec<String> = missing.iter().map(|m| m.segment_id.clone()).collect();
        removed_ids.extend(corrupted.iter().map(|c| c.segment_id.clone()));

        let remove_set: std::collections::HashSet<String> =
            removed_ids.iter().cloned().collect();

        // Delete corrupted segment files from disk
        for seg in &corrupted {
            let path = self.cfg.segments_dir.join(format!("{}.ipc", seg.segment_id));
            if path.exists() {
                if let Err(e) = std::fs::remove_file(&path) {
                    tracing::warn!(
                        "Failed to delete corrupted segment file {}: {}",
                        seg.segment_id,
                        e
                    );
                }
            }
        }

        // Remove from manifest and rebuild index
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;
            manifest.entries.retain(|e| !remove_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;

            // Rebuild the entire index since entry indices have changed
            let mut index = self.manifest_index.write().map_err(|_| {
                EngineError::Internal("manifest_index lock poisoned".into())
            })?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Record segments repaired metric
        self.metrics.segments_repaired.fetch_add(removed_ids.len() as u64, Ordering::Relaxed);

        Ok(removed_ids)
    }

    /// Check manifest integrity and return a summary of issues
    pub fn check_manifest(&self) -> Result<ManifestCheckResult, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let missing = self.find_missing_segments(None, None)?;
        let corrupted = self.find_corrupted_segments(None, None)?;

        // Find orphaned files (files on disk not in manifest)
        let mut orphaned_files = Vec::new();
        if let Ok(entries) = std::fs::read_dir(&self.cfg.segments_dir) {
            let manifest_segment_ids: std::collections::HashSet<String> = manifest
                .entries
                .iter()
                .map(|e| e.segment_id.clone())
                .collect();

            for entry in entries.flatten() {
                let path = entry.path();
                if path.extension().map_or(false, |ext| ext == "ipc") {
                    if let Some(stem) = path.file_stem() {
                        let segment_id = stem.to_string_lossy().to_string();
                        if !manifest_segment_ids.contains(&segment_id) {
                            let size = std::fs::metadata(&path).map(|m| m.len()).unwrap_or(0);
                            orphaned_files.push(OrphanedFile {
                                path: path.to_string_lossy().to_string(),
                                size_bytes: size,
                            });
                        }
                    }
                }
            }
        }

        Ok(ManifestCheckResult {
            total_segments: manifest.entries.len(),
            total_databases: manifest.databases.len(),
            total_tables: manifest.tables.len(),
            missing_segments: missing,
            corrupted_segments: corrupted,
            orphaned_files,
            manifest_version: manifest.version,
        })
    }

    /// Get current repair statistics (for SHOW REPAIR STATUS)
    /// Note: This is a snapshot; actual stats are maintained by the auto-repair task
    pub fn get_repair_stats(&self) -> AutoRepairStats {
        // Get count of currently damaged segments
        let pending_count = self
            .find_damaged_segments(None, None)
            .map(|v| v.len())
            .unwrap_or(0);

        AutoRepairStats {
            enabled: false, // Will be set by server with actual auto-repair state
            last_scan_timestamp: None,
            total_repaired: 0,
            pending_count,
            scan_interval_secs: 300,
            max_repairs_per_scan: 100,
        }
    }

    /// Set retention policy for a table
    pub fn set_retention_policy(
        &self,
        database: &str,
        table: &str,
        retention_seconds: u64,
        time_column: Option<String>,
    ) -> Result<(), EngineError> {
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Find the table
        let table_meta = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound(format!("table {}.{}", database, table)))?;

        // Set retention policy
        table_meta.retention_policy = Some(crate::replication::RetentionPolicy {
            retention_seconds,
            time_column,
            enabled: true,
        });

        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Remove retention policy from a table
    pub fn remove_retention_policy(&self, database: &str, table: &str) -> Result<(), EngineError> {
        let mut manifest = self
            .manifest
            .write()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let table_meta = manifest
            .tables
            .iter_mut()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound(format!("table {}.{}", database, table)))?;

        table_meta.retention_policy = None;
        manifest.bump_version();
        persist_manifest(&self.cfg.manifest_path, &manifest)?;
        Ok(())
    }

    /// Get retention policy for a table
    pub fn get_retention_policy(
        &self,
        database: &str,
        table: &str,
    ) -> Result<Option<crate::replication::RetentionPolicy>, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        let table_meta = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table);

        Ok(table_meta.and_then(|t| t.retention_policy.clone()))
    }

    /// Enforce retention policy for a specific table
    /// Returns the number of segments deleted and bytes reclaimed
    pub fn enforce_retention(
        &self,
        database: &str,
        table: &str,
        max_deletes: usize,
    ) -> Result<RetentionResult, EngineError> {
        let manifest = self
            .manifest
            .read()
            .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

        // Get retention policy
        let table_meta = manifest
            .tables
            .iter()
            .find(|t| t.database == database && t.name == table)
            .ok_or_else(|| EngineError::NotFound(format!("table {}.{}", database, table)))?;

        let policy = table_meta
            .retention_policy
            .as_ref()
            .ok_or_else(|| {
                EngineError::InvalidArgument(format!(
                    "no retention policy for {}.{}",
                    database, table
                ))
            })?;

        if !policy.enabled {
            return Ok(RetentionResult {
                database: database.to_string(),
                table: table.to_string(),
                segments_deleted: 0,
                bytes_reclaimed: 0,
                cutoff_time_micros: 0,
            });
        }

        // Calculate cutoff time
        let now_micros = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_micros() as u64)
            .unwrap_or(0);
        let retention_micros = policy.retention_seconds * 1_000_000;
        let cutoff_micros = now_micros.saturating_sub(retention_micros);

        // Find segments to delete (those with event_time_max < cutoff)
        let mut segments_to_delete: Vec<(String, u64)> = Vec::new();
        for entry in &manifest.entries {
            if entry.database == database && entry.table == table {
                if let Some(max_time) = entry.event_time_max {
                    if max_time < cutoff_micros {
                        segments_to_delete.push((entry.segment_id.clone(), entry.size_bytes));
                        if segments_to_delete.len() >= max_deletes {
                            break;
                        }
                    }
                }
            }
        }

        drop(manifest);

        if segments_to_delete.is_empty() {
            return Ok(RetentionResult {
                database: database.to_string(),
                table: table.to_string(),
                segments_deleted: 0,
                bytes_reclaimed: 0,
                cutoff_time_micros: cutoff_micros,
            });
        }

        let segment_ids: Vec<String> = segments_to_delete.iter().map(|(id, _)| id.clone()).collect();
        let bytes_reclaimed: u64 = segments_to_delete.iter().map(|(_, sz)| *sz).sum();
        let segment_count = segment_ids.len();

        // Delete segments from manifest
        {
            let mut manifest = self
                .manifest
                .write()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            let id_set: std::collections::HashSet<String> = segment_ids.iter().cloned().collect();
            manifest.entries.retain(|e| !id_set.contains(&e.segment_id));
            manifest.bump_version();
            persist_manifest(&self.cfg.manifest_path, &manifest)?;

            // Rebuild index
            let mut index = self
                .manifest_index
                .write()
                .map_err(|_| EngineError::Internal("manifest_index lock poisoned".into()))?;
            *index = ManifestIndex::build(&manifest.entries);
        }

        // Delete segment files
        for segment_id in &segment_ids {
            self.remove_segment_file(segment_id);
        }

        // Invalidate query cache for this table
        {
            let mut cache = self.query_cache.lock();
            cache.invalidate_table(database, table);
        }

        Ok(RetentionResult {
            database: database.to_string(),
            table: table.to_string(),
            segments_deleted: segment_count,
            bytes_reclaimed,
            cutoff_time_micros: cutoff_micros,
        })
    }

    /// Enforce retention policies for all tables that have them configured
    pub fn enforce_all_retention_policies(
        &self,
        max_deletes_per_table: usize,
    ) -> Result<Vec<RetentionResult>, EngineError> {
        let tables_with_retention: Vec<(String, String)> = {
            let manifest = self
                .manifest
                .read()
                .map_err(|_| EngineError::Internal("manifest lock poisoned".into()))?;

            manifest
                .tables
                .iter()
                .filter(|t| {
                    t.retention_policy
                        .as_ref()
                        .map(|p| p.enabled)
                        .unwrap_or(false)
                })
                .map(|t| (t.database.clone(), t.name.clone()))
                .collect()
        };

        let mut results = Vec::new();
        for (database, table) in tables_with_retention {
            match self.enforce_retention(&database, &table, max_deletes_per_table) {
                Ok(result) => {
                    if result.segments_deleted > 0 {
                        results.push(result);
                    }
                }
                Err(e) => {
                    tracing::warn!(
                        database = %database,
                        table = %table,
                        error = %e,
                        "Failed to enforce retention policy"
                    );
                }
            }
        }

        Ok(results)
    }

