#[allow(dead_code)]
fn mix64(mut x: u64) -> u64 {
    // Simple mixer to spread shard hints; not cryptographic.
    x ^= x >> 33;
    x = x.wrapping_mul(0xff51afd7ed558ccd);
    x ^= x >> 33;
    x = x.wrapping_mul(0xc4ceb9fe1a85ec53);
    x ^= x >> 33;
    x
}

pub(crate) fn load_manifest(path: &Path) -> Result<Manifest, EngineError> {
    // Try binary format first (.bincode), then fall back to JSON (.json)
    let binary_path = path.with_extension("bincode");
    let json_path = path;

    // Try binary format first
    if binary_path.exists() {
        let bytes = fs::read(&binary_path)
            .map_err(|e| EngineError::Internal(format!("read binary manifest failed: {e}")))?;

        if crate::replication::is_binary_manifest(&bytes) {
            match crate::replication::deserialize_manifest_binary(&bytes) {
                Ok(manifest) => return Ok(manifest),
                Err(e) => {
                    // Binary format failed - try JSON fallback
                    eprintln!(
                        "WARNING: Binary manifest parse failed ({}), trying JSON fallback...",
                        e
                    );
                }
            }
        }
    }

    // Fall back to JSON format
    if !json_path.exists() {
        // Neither binary nor JSON exists - check if we have a bincode that failed
        if binary_path.exists() {
            // Binary exists but failed to parse - this is a real error
            return Err(EngineError::Internal(
                "binary manifest exists but failed to parse, and no JSON fallback available".into(),
            ));
        }
        return Ok(Manifest::empty());
    }

    let bytes = fs::read(json_path)
        .map_err(|e| EngineError::Internal(format!("read manifest failed: {e}")))?;

    // Check if it's actually binary format saved with .json extension (shouldn't happen but be safe)
    if crate::replication::is_binary_manifest(&bytes) {
        match crate::replication::deserialize_manifest_binary(&bytes) {
            Ok(manifest) => return Ok(manifest),
            Err(e) => {
                return Err(EngineError::Internal(format!(
                    "parse binary manifest failed: {e}"
                )));
            }
        }
    }

    let mut manifest: Manifest = serde_json::from_slice(&bytes)
        .map_err(|e| EngineError::Internal(format!("parse manifest failed: {e}")))?;

    if manifest.migrate_if_needed() {
        // Migrate to binary format
        persist_manifest(path, &manifest)?;
    }

    Ok(manifest)
}

pub(crate) fn persist_manifest(path: &Path, manifest: &Manifest) -> Result<(), EngineError> {
    // Use binary format for 3x smaller files and 5x faster parsing
    let binary_path = path.with_extension("bincode");
    let tmp = binary_path.with_extension("bincode.tmp");

    let bytes = crate::replication::serialize_manifest_binary(manifest)
        .map_err(|e| EngineError::Internal(format!("serialize manifest failed: {e}")))?;

    // Ensure parent directory exists for both original and binary paths
    if let Some(parent) = binary_path.parent() {
        fs::create_dir_all(parent)
            .map_err(|e| EngineError::Io(format!("create manifest dir failed: {e}")))?;
    }

    {
        let mut file = OpenOptions::new()
            .create(true)
            .write(true)
            .truncate(true)
            .open(&tmp)
            .map_err(|e| EngineError::Io(format!("open manifest tmp failed: {e}")))?;
        file.write_all(&bytes)
            .map_err(|e| EngineError::Io(format!("write manifest tmp failed: {e}")))?;
        file.sync_all()
            .map_err(|e| EngineError::Io(format!("fsync manifest tmp failed: {e}")))?;
    }

    // Atomic rename - NEVER fall back to truncating live manifest
    // The old fallback could corrupt the manifest during concurrent writes
    fs::rename(&tmp, &binary_path).map_err(|e| {
        // Clean up temp file on failure
        let _ = fs::remove_file(&tmp);
        EngineError::Io(format!(
            "atomic manifest rename failed (tmp={}, target={}): {}",
            tmp.display(),
            binary_path.display(),
            e
        ))
    })?;

    // Also write JSON for backward compatibility and debugging (can be disabled for production)
    #[cfg(debug_assertions)]
    {
        let json_bytes = serde_json::to_vec(manifest)
            .map_err(|e| EngineError::Internal(format!("serialize manifest json failed: {e}")))?;
        let _ = fs::write(path, &json_bytes); // Best effort, ignore errors
    }

    if let Some(parent) = path.parent() {
        sync_dir(parent)?;
    }

    Ok(())
}

fn snapshot_manifest(snapshot_path: &Path, manifest_path: &Path) -> Result<(), EngineError> {
    if let Some(parent) = snapshot_path.parent() {
        fs::create_dir_all(parent)
            .map_err(|e| EngineError::Io(format!("create snapshot dir failed: {e}")))?;
    }
    // Copy binary manifest (.bincode) to snapshot, or fall back to JSON
    let binary_manifest_path = manifest_path.with_extension("bincode");
    let binary_snapshot_path = snapshot_path.with_extension("bincode");
    if binary_manifest_path.exists() {
        fs::copy(&binary_manifest_path, &binary_snapshot_path)
            .map_err(|e| EngineError::Io(format!("copy binary manifest snapshot failed: {e}")))?;
    } else if manifest_path.exists() {
        fs::copy(manifest_path, snapshot_path)
            .map_err(|e| EngineError::Io(format!("copy manifest snapshot failed: {e}")))?;
    }
    // If neither exists, it's a fresh database - no snapshot needed
    Ok(())
}

fn validate_manifest(manifest: &Manifest) -> Result<(), EngineError> {
    // Check for duplicate segment IDs (corruption indicator)
    let mut seen_segments: HashSet<&str> = HashSet::new();

    for db in &manifest.databases {
        if !is_valid_ident(&db.name) {
            return Err(EngineError::InvalidArgument(
                "invalid database name in manifest".into(),
            ));
        }
    }
    for tbl in &manifest.tables {
        if !is_valid_ident(&tbl.database) || !is_valid_ident(&tbl.name) {
            return Err(EngineError::InvalidArgument(
                "invalid table name in manifest".into(),
            ));
        }
    }
    for entry in &manifest.entries {
        if entry.segment_id.trim().is_empty() {
            return Err(EngineError::InvalidArgument(
                "manifest entry missing segment_id".into(),
            ));
        }
        // Check for duplicate segment IDs
        if !seen_segments.insert(&entry.segment_id) {
            return Err(EngineError::InvalidArgument(format!(
                "manifest contains duplicate segment_id: {} (corruption detected)",
                entry.segment_id
            )));
        }
        if entry.size_bytes == 0 {
            return Err(EngineError::InvalidArgument(
                "manifest entry has zero size_bytes".into(),
            ));
        }
        if entry.checksum == 0 {
            return Err(EngineError::InvalidArgument(
                "manifest entry has zero checksum".into(),
            ));
        }
        if !is_valid_ident(&entry.database) || !is_valid_ident(&entry.table) {
            return Err(EngineError::InvalidArgument(
                "manifest entry invalid database/table name".into(),
            ));
        }
        if let Some(c) = &entry.compression {
            if c != "zstd" && c != "lz4" && c != "snappy" {
                return Err(EngineError::InvalidArgument(format!(
                    "manifest entry has unsupported compression: {} (supported: zstd, lz4, snappy)",
                    c
                )));
            }
        }
        // Validate size is reasonable (< 10GB per segment)
        if entry.size_bytes > 10_000_000_000 {
            tracing::warn!(
                "manifest entry {} has suspiciously large size: {} bytes (possible corruption)",
                entry.segment_id, entry.size_bytes
            );
        }
    }

    // Validate manifest version is reasonable
    if manifest.version > 1_000_000_000 {
        tracing::warn!(
            "manifest version {} is suspiciously high (possible corruption)",
            manifest.version
        );
    }

    Ok(())
}

/// Parse a string value (from ANALYZE stats) into an optimizer StatValue
fn parse_stat_value(s: &str) -> Option<crate::optimizer::StatValue> {
    use crate::optimizer::StatValue;

    // Try parsing as integer first
    if let Ok(v) = s.parse::<i64>() {
        return Some(StatValue::Int64(v));
    }

    // Try parsing as float
    if let Ok(v) = s.parse::<f64>() {
        return Some(StatValue::Float64(v));
    }

    // Try parsing as boolean
    match s.to_lowercase().as_str() {
        "true" => return Some(StatValue::Bool(true)),
        "false" => return Some(StatValue::Bool(false)),
        _ => {}
    }

    // Treat as string
    if !s.is_empty() {
        Some(StatValue::String(s.to_string()))
    } else {
        None
    }
}

fn normalize_compression(opt: Option<String>) -> Result<Option<String>, EngineError> {
    match opt.as_deref() {
        Some("zstd") => Ok(Some("zstd".to_string())),
        Some("lz4") => Ok(Some("lz4".to_string())),
        Some("snappy") => Ok(Some("snappy".to_string())),
        Some("none") | None => Ok(None),
        Some(other) => Err(EngineError::InvalidArgument(format!(
            "unsupported compression: {other} (supported: zstd, lz4, snappy, none)"
        ))),
    }
}

/// Compress payload using the specified codec with adaptive optimization.
///
/// Compression speed and ratio comparison:
/// - LZ4: Fastest compression/decompression, ~2-3x compression ratio
/// - Snappy: Very fast, ~2x compression ratio
/// - ZSTD: Best compression ratio (~4-5x), slower but still fast decompression
///
/// For OLAP workloads:
/// - Use LZ4 for hot data (fastest reads)
/// - Use ZSTD for cold/archived data (best compression)
///
/// Optimizations:
/// - Skips compression for payloads below skip_threshold (default: 4KB)
/// - Uses adaptive ZSTD levels: level 1 for <1MB, level 3 for >=1MB
fn compress_payload(payload: &[u8], compression: Option<&str>) -> Result<Vec<u8>, EngineError> {
    compress_payload_adaptive(payload, compression, 4 * 1024, true)
}

/// Compress payload with configurable skip threshold and adaptive levels.
fn compress_payload_adaptive(
    payload: &[u8],
    compression: Option<&str>,
    _skip_threshold: usize,
    adaptive_levels: bool,
) -> Result<Vec<u8>, EngineError> {
    // Note: Skip threshold is disabled for now because skipping compression
    // would require metadata changes to track whether compression was applied.
    // The adaptive compression levels still provide optimization benefit.

    match compression {
        Some("zstd") => {
            // Adaptive ZSTD levels based on payload size:
            // - Level 1: Fast compression for hot data (<1MB)
            // - Level 3: Better ratio for larger segments (>=1MB)
            // - Level 5: Best ratio for cold tier (>=64MB)
            let level = if !adaptive_levels {
                1
            } else if payload.len() >= 64 * 1024 * 1024 {
                5 // Cold tier: best compression
            } else if payload.len() >= 1024 * 1024 {
                3 // Large segments: balanced
            } else {
                1 // Small segments: fast
            };
            zstd_encode_all(Cursor::new(payload), level)
                .map_err(|e| EngineError::Internal(format!("zstd encode failed: {e}")))
        }
        Some("lz4") => Ok(lz4_compress(payload)),
        Some("snappy") => {
            let mut encoder = SnappyEncoder::new(Vec::new());
            std::io::copy(&mut Cursor::new(payload), &mut encoder)
                .map_err(|e| EngineError::Internal(format!("snappy encode failed: {e}")))?;
            encoder
                .into_inner()
                .map_err(|e| EngineError::Internal(format!("snappy finalize failed: {e}")))
        }
        Some(other) => Err(EngineError::InvalidArgument(format!(
            "unsupported compression: {other}"
        ))),
        None => Ok(payload.to_vec()),
    }
}

fn decompress_payload(payload: Vec<u8>, compression: Option<&str>) -> Result<Vec<u8>, EngineError> {
    match compression {
        Some("zstd") => zstd_decode_all(Cursor::new(payload))
            .map_err(|e| EngineError::InvalidArgument(format!("zstd decode failed: {e}"))),
        Some("lz4") => lz4_decompress(&payload)
            .map_err(|e| EngineError::InvalidArgument(format!("lz4 decode failed: {e}"))),
        Some("snappy") => {
            let mut decoder = SnappyDecoder::new(Cursor::new(payload));
            let mut decompressed = Vec::new();
            std::io::Read::read_to_end(&mut decoder, &mut decompressed)
                .map_err(|e| EngineError::InvalidArgument(format!("snappy decode failed: {e}")))?;
            Ok(decompressed)
        }
        Some(other) => Err(EngineError::InvalidArgument(format!(
            "unsupported compression: {other}"
        ))),
        None => Ok(payload),
    }
}

fn sync_dir(path: &Path) -> Result<(), EngineError> {
    let dir = OpenOptions::new()
        .read(true)
        .open(path)
        .map_err(|e| EngineError::Io(format!("open dir for fsync failed: {e}")))?;
    dir.sync_all()
        .map_err(|e| EngineError::Io(format!("fsync dir failed: {e}")))
}

/// Get available disk space in bytes for the given path
fn get_available_disk_space(path: &Path) -> Result<u64, EngineError> {
    #[cfg(unix)]
    {
        use std::os::unix::fs::MetadataExt;

        // Find the mount point by traversing up until we find a different device
        let path_metadata = std::fs::metadata(path)
            .map_err(|e| EngineError::Io(format!("stat path failed: {}", e)))?;

        // Use statvfs on Unix
        let c_path = std::ffi::CString::new(path.to_string_lossy().as_bytes())
            .map_err(|e| EngineError::Io(format!("path conversion failed: {}", e)))?;

        let mut stat: libc::statvfs = unsafe { std::mem::zeroed() };
        let result = unsafe { libc::statvfs(c_path.as_ptr(), &mut stat) };

        if result != 0 {
            return Err(EngineError::Io(format!(
                "statvfs failed: {}",
                std::io::Error::last_os_error()
            )));
        }

        // Available space = f_bavail * f_frsize
        Ok(stat.f_bavail as u64 * stat.f_frsize as u64)
    }

    #[cfg(windows)]
    {
        use std::os::windows::ffi::OsStrExt;
        use winapi::um::fileapi::GetDiskFreeSpaceExW;

        let wide_path: Vec<u16> = path.as_os_str().encode_wide().chain(Some(0)).collect();
        let mut free_bytes_available: u64 = 0;

        let result = unsafe {
            GetDiskFreeSpaceExW(
                wide_path.as_ptr(),
                &mut free_bytes_available as *mut _,
                std::ptr::null_mut(),
                std::ptr::null_mut(),
            )
        };

        if result == 0 {
            return Err(EngineError::Io("GetDiskFreeSpaceExW failed".into()));
        }

        Ok(free_bytes_available)
    }

    #[cfg(not(any(unix, windows)))]
    {
        // Fallback: return a large value to allow writes
        Ok(u64::MAX)
    }
}

pub(crate) fn persist_segment_ipc(
    storage: &crate::storage::TieredStorage,
    segment_id: &str,
    payload: &[u8],
) -> Result<(), EngineError> {
    storage.persist_segment_local(segment_id, payload)
}

/// Hash an array value at a specific row index for deduplication key computation
fn hash_array_value(
    hasher: &mut impl std::hash::Hasher,
    array: &dyn arrow_array::Array,
    row_idx: usize,
) {
    use arrow_array::*;
    use std::hash::Hash;

    if array.is_null(row_idx) {
        // Hash a sentinel for null
        0u8.hash(hasher);
        return;
    }

    // Mark as non-null
    1u8.hash(hasher);

    match array.data_type() {
        arrow_schema::DataType::Boolean => {
            if let Some(arr) = array.as_any().downcast_ref::<BooleanArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Int8 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int8Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Int16 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int16Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Int32 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Int64 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::UInt8 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt8Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::UInt16 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt16Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::UInt32 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt32Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::UInt64 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt64Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Float32 => {
            if let Some(arr) = array.as_any().downcast_ref::<Float32Array>() {
                arr.value(row_idx).to_bits().hash(hasher);
            }
        }
        arrow_schema::DataType::Float64 => {
            if let Some(arr) = array.as_any().downcast_ref::<Float64Array>() {
                arr.value(row_idx).to_bits().hash(hasher);
            }
        }
        arrow_schema::DataType::Utf8 => {
            if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::LargeUtf8 => {
            if let Some(arr) = array.as_any().downcast_ref::<LargeStringArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Binary => {
            if let Some(arr) = array.as_any().downcast_ref::<BinaryArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::LargeBinary => {
            if let Some(arr) = array.as_any().downcast_ref::<LargeBinaryArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::FixedSizeBinary(_) => {
            if let Some(arr) = array.as_any().downcast_ref::<FixedSizeBinaryArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Timestamp(_, _) => {
            if let Some(arr) = array.as_any().downcast_ref::<TimestampMicrosecondArray>() {
                arr.value(row_idx).hash(hasher);
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampNanosecondArray>() {
                arr.value(row_idx).hash(hasher);
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampMillisecondArray>() {
                arr.value(row_idx).hash(hasher);
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampSecondArray>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Date32 => {
            if let Some(arr) = array.as_any().downcast_ref::<Date32Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        arrow_schema::DataType::Date64 => {
            if let Some(arr) = array.as_any().downcast_ref::<Date64Array>() {
                arr.value(row_idx).hash(hasher);
            }
        }
        _ => {
            // For unsupported types, hash the row index as a fallback
            // This ensures deterministic behavior but may cause false matches
            row_idx.hash(hasher);
        }
    }
}

/// Extract a version value from a column for deduplication ordering
fn get_version_value(array: &dyn arrow_array::Array, row_idx: usize) -> i64 {
    use arrow_array::*;

    if array.is_null(row_idx) {
        return i64::MIN;
    }

    match array.data_type() {
        arrow_schema::DataType::Int8 => array
            .as_any()
            .downcast_ref::<Int8Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::Int16 => array
            .as_any()
            .downcast_ref::<Int16Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::Int32 => array
            .as_any()
            .downcast_ref::<Int32Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::Int64 => array
            .as_any()
            .downcast_ref::<Int64Array>()
            .map(|a| a.value(row_idx))
            .unwrap_or(0),
        arrow_schema::DataType::UInt8 => array
            .as_any()
            .downcast_ref::<UInt8Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::UInt16 => array
            .as_any()
            .downcast_ref::<UInt16Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::UInt32 => array
            .as_any()
            .downcast_ref::<UInt32Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::UInt64 => array
            .as_any()
            .downcast_ref::<UInt64Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::Timestamp(_, _) => {
            if let Some(arr) = array.as_any().downcast_ref::<TimestampMicrosecondArray>() {
                arr.value(row_idx)
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampNanosecondArray>() {
                arr.value(row_idx)
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampMillisecondArray>() {
                arr.value(row_idx)
            } else if let Some(arr) = array.as_any().downcast_ref::<TimestampSecondArray>() {
                arr.value(row_idx)
            } else {
                0
            }
        }
        arrow_schema::DataType::Date32 => array
            .as_any()
            .downcast_ref::<Date32Array>()
            .map(|a| a.value(row_idx) as i64)
            .unwrap_or(0),
        arrow_schema::DataType::Date64 => array
            .as_any()
            .downcast_ref::<Date64Array>()
            .map(|a| a.value(row_idx))
            .unwrap_or(0),
        _ => row_idx as i64, // Fallback: use row index
    }
}

/// Verify segment checksum with backward compatibility.
/// Tries xxHash64 first (new format), then CRC32 (legacy format).
fn verify_segment_checksum(data: &[u8], expected: u64, segment_id: &str) -> Result<(), EngineError> {
    // Try xxHash64 first (new format)
    let xxhash = compute_checksum(data);
    if xxhash == expected {
        return Ok(());
    }

    // Fall back to CRC32 for backward compatibility with older segments
    let crc32 = compute_checksum_crc32(data);
    if crc32 == expected {
        return Ok(());
    }

    // Neither matched - corruption detected
    Err(EngineError::Io(format!(
        "checksum mismatch for segment {} expected={:016x} actual_xxh64={:016x} actual_crc32={:016x} - CORRUPTION DETECTED",
        segment_id, expected, xxhash, crc32
    )))
}

fn load_segment(
    storage: &crate::storage::TieredStorage,
    entry: &ManifestEntry,
) -> Result<Vec<u8>, EngineError> {
    let data = storage.load_segment(entry)?;
    verify_segment_checksum(&data, entry.checksum, &entry.segment_id)?;
    decompress_payload(data, entry.compression.as_deref())
}

/// Load segment with retry logic for transient errors
fn load_segment_with_retry(
    storage: &crate::storage::TieredStorage,
    entry: &ManifestEntry,
    max_retries: usize,
    retry_delay_ms: u64,
) -> Result<Vec<u8>, EngineError> {
    let mut last_error = None;

    for attempt in 0..=max_retries {
        match load_segment(storage, entry) {
            Ok(data) => return Ok(data),
            Err(e) => {
                last_error = Some(e);
                if attempt < max_retries {
                    tracing::warn!(
                        "Segment {} load attempt {} failed, retrying in {}ms",
                        entry.segment_id,
                        attempt + 1,
                        retry_delay_ms
                    );
                    std::thread::sleep(std::time::Duration::from_millis(retry_delay_ms));
                }
            }
        }
    }

    Err(last_error.unwrap_or_else(|| {
        EngineError::Internal("load_segment_with_retry: no error captured".into())
    }))
}

/// Load and validate segment with comprehensive integrity checks
fn load_segment_validated(
    storage: &crate::storage::TieredStorage,
    entry: &ManifestEntry,
    validate_schema: bool,
    validate_ipc: bool,
) -> Result<Vec<u8>, EngineError> {
    let data = storage.load_segment(entry)?;

    // Verify checksum first
    verify_segment_checksum(&data, entry.checksum, &entry.segment_id)?;

    // Decompress
    let decompressed = decompress_payload(data, entry.compression.as_deref())?;

    // Validate IPC format if enabled
    if validate_ipc {
        if !validate_ipc_format(&decompressed)? {
            return Err(EngineError::Io(format!(
                "segment {} has invalid IPC format - CORRUPTION DETECTED",
                entry.segment_id
            )));
        }
    }

    // Validate schema hash if enabled and hash is available
    if validate_schema {
        if let Some(expected_schema_hash) = entry.schema_hash {
            let actual_schema_hash = compute_schema_hash_from_payload(&decompressed, None)?;
            if actual_schema_hash != expected_schema_hash {
                return Err(EngineError::Io(format!(
                    "segment {} schema hash mismatch: expected {:016x}, got {:016x} - SCHEMA CORRUPTION",
                    entry.segment_id, expected_schema_hash, actual_schema_hash
                )));
            }
        }
    }

    Ok(decompressed)
}

fn load_segment_raw(
    storage: &crate::storage::TieredStorage,
    entry: &ManifestEntry,
) -> Result<Vec<u8>, EngineError> {
    let data = storage.load_segment(entry)?;
    verify_segment_checksum(&data, entry.checksum, &entry.segment_id)?;
    Ok(data)
}

/// Validate compression type matches the actual data format
fn validate_compression_type(data: &[u8], compression: Option<&str>) -> bool {
    match compression {
        Some("zstd") => {
            // ZSTD magic number: 0x28B52FFD (little-endian)
            data.len() >= 4 && data[0..4] == [0x28, 0xB5, 0x2F, 0xFD]
        }
        Some("lz4") => {
            // LZ4 frame magic: 0x184D2204 (little-endian) or size-prefixed
            if data.len() < 4 {
                return false;
            }
            // lz4_flex uses size-prefixed format, first 4 bytes are uncompressed size
            // We can't easily validate without trying to decompress
            true
        }
        Some("snappy") => {
            // Snappy framing format starts with stream identifier
            data.len() >= 4 && data[0] == 0xFF
        }
        None => {
            // No compression - should start with Arrow IPC magic or valid data
            // Arrow IPC stream starts with schema message
            true
        }
        _ => true, // Unknown compression, allow it
    }
}

/// Sort a hot ingest payload by event_time, tenant_id, route_id when present.
fn sort_hot_payload(ipc_data: &[u8], granularity_rows: usize) -> Result<Vec<u8>, EngineError> {
    use arrow_ord::sort::{lexsort_to_indices, SortColumn};

    let batches = read_ipc_batches(ipc_data)?;
    if batches.is_empty() {
        return Ok(ipc_data.to_vec());
    }
    let schema = batches[0].schema();
    let concatenated = if batches.len() == 1 {
        batches.into_iter().next().unwrap()
    } else {
        arrow_select::concat::concat_batches(&schema, &batches).map_err(|e| {
            EngineError::Internal(format!("concat batches for hot sort failed: {e}"))
        })?
    };
    if concatenated.num_rows() == 0 {
        return Ok(ipc_data.to_vec());
    }

    let mut sort_columns = Vec::new();
    for col_name in ["event_time", "tenant_id", "route_id"] {
        if let Some((idx, _)) = schema.column_with_name(col_name) {
            sort_columns.push(SortColumn {
                values: concatenated.column(idx).clone(),
                options: Some(arrow_ord::sort::SortOptions {
                    descending: false,
                    nulls_first: false,
                }),
            });
        }
    }
    if sort_columns.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let indices = lexsort_to_indices(&sort_columns, None)
        .map_err(|e| EngineError::Internal(format!("hot sort failed: {e}")))?;
    let sorted_batch = arrow_select::take::take_record_batch(&concatenated, &indices)
        .map_err(|e| EngineError::Internal(format!("hot sort take failed: {e}")))?;

    let mut output = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output, schema.as_ref())
            .map_err(|e| EngineError::Internal(format!("hot sort ipc writer failed: {e}")))?;
        if granularity_rows == 0 || sorted_batch.num_rows() <= granularity_rows {
            writer
                .write(&sorted_batch)
                .map_err(|e| EngineError::Internal(format!("hot sort ipc write failed: {e}")))?;
        } else {
            let mut offset = 0;
            while offset < sorted_batch.num_rows() {
                let len = (granularity_rows).min(sorted_batch.num_rows() - offset);
                let slice = sorted_batch.slice(offset, len);
                writer.write(&slice).map_err(|e| {
                    EngineError::Internal(format!("hot sort ipc write failed: {e}"))
                })?;
                offset += len;
            }
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("hot sort ipc finish failed: {e}")))?;
    }
    Ok(output)
}

/// Apply ORDER BY sorting to IPC record batches
fn apply_order_by(ipc_data: &[u8], filter: &QueryFilter) -> Result<Vec<u8>, EngineError> {
    use arrow_ord::sort::{lexsort_to_indices, SortColumn};

    let order_by = match &filter.order_by {
        Some(ob) => ob,
        None => return Ok(ipc_data.to_vec()),
    };

    // Parse IPC to get record batches
    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("read IPC for sorting failed: {e}")))?;

    let mut batches = Vec::new();
    while let Some(batch) = reader
        .next()
        .transpose()
        .map_err(|e| EngineError::Internal(format!("read batch for sorting failed: {e}")))?
    {
        batches.push(batch);
    }

    if batches.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    // Concatenate all batches into a single record batch for sorting
    let schema = batches[0].schema();
    let total_rows: usize = batches.iter().map(|b| b.num_rows()).sum();
    if total_rows == 0 {
        return Ok(ipc_data.to_vec());
    }
    let concatenated = arrow_select::concat::concat_batches(&schema, &batches)
        .map_err(|e| EngineError::Internal(format!("concat batches for sort failed: {e}")))?;

    // Build sort columns
    let mut sort_columns = Vec::new();
    for (col_name, ascending) in order_by {
        if let Some((idx, _)) = schema.column_with_name(col_name) {
            sort_columns.push(SortColumn {
                values: concatenated.column(idx).clone(),
                options: Some(arrow_ord::sort::SortOptions {
                    descending: !ascending,
                    nulls_first: true,
                }),
            });
        }
    }

    if sort_columns.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let sort_limit = match (filter.limit, filter.offset) {
        (Some(limit), Some(offset)) => Some(limit.saturating_add(offset)),
        (Some(limit), None) => Some(limit),
        _ => None,
    };
    if matches!(sort_limit, Some(0)) {
        let mut output = Vec::new();
        {
            let mut writer = StreamWriter::try_new(&mut output, schema.as_ref())
                .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
        }
        return Ok(output);
    }

    // Get sorted indices (optionally limited for top-K)
    let indices = lexsort_to_indices(&sort_columns, sort_limit)
        .map_err(|e| EngineError::Internal(format!("lexsort failed: {e}")))?;

    let sorted_batch = arrow_select::take::take_record_batch(&concatenated, &indices)
        .map_err(|e| EngineError::Internal(format!("take batch failed: {e}")))?;

    // Write back to IPC
    let mut output = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output, schema.as_ref())
            .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
        writer
            .write(&sorted_batch)
            .map_err(|e| EngineError::Internal(format!("write sorted batch failed: {e}")))?;
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
    }

    Ok(output)
}

/// Apply OFFSET to IPC record batches
fn apply_offset(ipc_data: &[u8], offset: usize) -> Result<Vec<u8>, EngineError> {
    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("read IPC for offset failed: {e}")))?;

    let mut remaining_offset = offset;
    let mut batches_to_write: Vec<RecordBatch> = Vec::new();
    let mut schema: Option<Arc<Schema>> = None;
    let mut saw_batch = false;

    while let Some(batch) = reader
        .next()
        .transpose()
        .map_err(|e| EngineError::Internal(format!("read batch for offset failed: {e}")))?
    {
        saw_batch = true;
        if schema.is_none() {
            schema = Some(batch.schema());
        }

        let batch_rows = batch.num_rows();
        if remaining_offset > 0 {
            if batch_rows <= remaining_offset {
                remaining_offset -= batch_rows;
                continue;
            }
            let kept = batch.slice(remaining_offset, batch_rows - remaining_offset);
            remaining_offset = 0;
            batches_to_write.push(kept);
            continue;
        }

        batches_to_write.push(batch);
    }

    // Write collected batches
    if !batches_to_write.is_empty() {
        let mut output = Vec::new();
        {
            let first_schema = batches_to_write[0].schema();
            let mut writer = StreamWriter::try_new(&mut output, first_schema.as_ref())
                .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
            for batch in &batches_to_write {
                writer
                    .write(batch)
                    .map_err(|e| EngineError::Internal(format!("write batch failed: {e}")))?;
            }
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
        }
        return Ok(output);
    }

    if !saw_batch {
        return Ok(ipc_data.to_vec());
    }

    // Return empty result with schema
    if let Some(schema) = schema {
        let mut empty = Vec::new();
        {
            let mut w = StreamWriter::try_new(&mut empty, schema.as_ref())
                .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
            w.finish()
                .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
        }
        return Ok(empty);
    }

    Ok(Vec::new())
}

fn apply_offset_limit_to_batches(
    batches: Vec<RecordBatch>,
    remaining_offset: &mut usize,
    remaining_limit: &mut usize,
) -> Vec<RecordBatch> {
    if *remaining_offset == 0 && *remaining_limit == usize::MAX {
        return batches;
    }
    let mut out = Vec::new();
    for batch in batches {
        if *remaining_limit == 0 {
            break;
        }
        let rows = batch.num_rows();
        if *remaining_offset > 0 {
            if rows <= *remaining_offset {
                *remaining_offset -= rows;
                continue;
            }
        }
        let start = *remaining_offset;
        let mut len = rows.saturating_sub(start);
        *remaining_offset = 0;
        if len == 0 {
            continue;
        }
        if len > *remaining_limit {
            len = *remaining_limit;
        }
        out.push(batch.slice(start, len));
        *remaining_limit = remaining_limit.saturating_sub(len);
    }
    out
}

/// Apply column projection to IPC record batches (select specific columns)
fn apply_projection(ipc_data: &[u8], columns: &[String]) -> Result<Vec<u8>, EngineError> {
    apply_projection_with_schema(ipc_data, columns, None)
}

/// Apply projection with optional expected schema for handling missing columns (e.g. from ALTER TABLE ADD COLUMN)
fn apply_projection_with_schema(
    ipc_data: &[u8],
    columns: &[String],
    expected_schema: Option<&Schema>,
) -> Result<Vec<u8>, EngineError> {
    if columns.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("read IPC for projection failed: {e}")))?;

    let mut batches = Vec::new();
    while let Some(batch) = reader
        .next()
        .transpose()
        .map_err(|e| EngineError::Internal(format!("read batch for projection failed: {e}")))?
    {
        batches.push(batch);
    }

    if batches.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let schema = batches[0].schema();
    let num_rows = batches.iter().map(|b| b.num_rows()).sum::<usize>();

    // Build projection info - handle missing columns with NULLs
    enum ColSource {
        Existing(usize),   // Index in source batch
        NullFilled(Field), // Generate NULL column with this field
    }

    let mut sources: Vec<ColSource> = Vec::with_capacity(columns.len());
    let mut new_fields = Vec::with_capacity(columns.len());

    for col_name in columns {
        if let Some((idx, field)) = schema.column_with_name(col_name) {
            sources.push(ColSource::Existing(idx));
            new_fields.push(field.clone());
        } else {
            // Column not in batch - check expected schema for type info
            let field = if let Some(exp_schema) = expected_schema {
                if let Some((_, exp_field)) = exp_schema.column_with_name(col_name) {
                    // Use field from expected schema, ensure nullable
                    Field::new(col_name, exp_field.data_type().clone(), true)
                } else {
                    // Not found even in expected schema - default to nullable Int64
                    Field::new(col_name, DataType::Int64, true)
                }
            } else {
                // No expected schema - default to nullable Int64
                Field::new(col_name, DataType::Int64, true)
            };
            sources.push(ColSource::NullFilled(field.clone()));
            new_fields.push(field);
        }
    }

    let new_schema = Arc::new(Schema::new(new_fields));

    // Project each batch
    let mut projected_batches = Vec::with_capacity(batches.len());
    for batch in &batches {
        let batch_rows = batch.num_rows();
        let projected_columns: Vec<ArrayRef> = sources
            .iter()
            .map(|src| {
                match src {
                    ColSource::Existing(idx) => batch.column(*idx).clone(),
                    ColSource::NullFilled(field) => {
                        // Create a NULL-filled array of the appropriate type
                        create_null_array(field.data_type(), batch_rows)
                    }
                }
            })
            .collect();
        let projected = RecordBatch::try_new(new_schema.clone(), projected_columns)
            .map_err(|e| EngineError::Internal(format!("create projected batch failed: {e}")))?;
        projected_batches.push(projected);
    }

    // Write back to IPC
    let mut output = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output, new_schema.as_ref()).map_err(|e| {
            EngineError::Internal(format!("create IPC writer for projection failed: {e}"))
        })?;
        for batch in &projected_batches {
            writer
                .write(batch)
                .map_err(|e| EngineError::Internal(format!("write projected batch failed: {e}")))?;
        }
        writer.finish().map_err(|e| {
            EngineError::Internal(format!("finish IPC writer for projection failed: {e}"))
        })?;
    }

    Ok(output)
}

/// Create a NULL-filled array of the specified type
fn create_null_array(data_type: &DataType, len: usize) -> ArrayRef {
    use arrow_array::builder::*;
    match data_type {
        DataType::Int8 => {
            let mut builder = Int8Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Int16 => {
            let mut builder = Int16Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Int32 => {
            let mut builder = Int32Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Int64 => {
            let mut builder = Int64Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::UInt8 => {
            let mut builder = UInt8Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::UInt16 => {
            let mut builder = UInt16Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::UInt32 => {
            let mut builder = UInt32Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::UInt64 => {
            let mut builder = UInt64Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Float32 => {
            let mut builder = Float32Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Float64 => {
            let mut builder = Float64Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Boolean => {
            let mut builder = BooleanBuilder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::Utf8 => {
            let mut builder = StringBuilder::with_capacity(len, 0);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        DataType::LargeUtf8 => {
            let mut builder = LargeStringBuilder::with_capacity(len, 0);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
        _ => {
            // Default fallback to nullable Int64
            let mut builder = Int64Builder::with_capacity(len);
            for _ in 0..len {
                builder.append_null();
            }
            Arc::new(builder.finish())
        }
    }
}

/// Apply DISTINCT to remove duplicate rows from IPC record batches
fn apply_distinct(ipc_data: &[u8]) -> Result<Vec<u8>, EngineError> {
    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("read IPC for distinct failed: {e}")))?;

    let mut batches = Vec::new();
    while let Some(batch) = reader
        .next()
        .transpose()
        .map_err(|e| EngineError::Internal(format!("read batch for distinct failed: {e}")))?
    {
        batches.push(batch);
    }

    if batches.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let schema = batches[0].schema();
    let total_rows: usize = batches.iter().map(|b| b.num_rows()).sum();

    if total_rows == 0 {
        return Ok(ipc_data.to_vec());
    }

    // Concatenate all batches
    let mut all_columns = Vec::new();
    for col_idx in 0..schema.fields().len() {
        let arrays: Vec<_> = batches.iter().map(|b| b.column(col_idx).clone()).collect();
        let refs: Vec<_> = arrays.iter().map(|a| a.as_ref()).collect();
        let concatenated = arrow_select::concat::concat(&refs)
            .map_err(|e| EngineError::Internal(format!("concat for distinct failed: {e}")))?;
        all_columns.push(concatenated);
    }

    // Build a set of seen row hashes to identify duplicates
    use std::collections::hash_map::DefaultHasher;
    use std::collections::HashSet;
    use std::hash::{Hash, Hasher};

    let mut seen: HashSet<u64> = HashSet::new();
    let mut keep_indices: Vec<usize> = Vec::new();

    for row_idx in 0..total_rows {
        let mut hasher = DefaultHasher::new();
        for col in &all_columns {
            // Hash the raw bytes for this row in each column
            // We use the debug representation as a proxy for value equality
            // This is a simplification - ideally we'd compare actual values
            let array = col.as_ref();
            if array.is_null(row_idx) {
                0u8.hash(&mut hasher);
            } else {
                1u8.hash(&mut hasher);
                // Hash based on data type
                use arrow::datatypes::DataType;
                match array.data_type() {
                    DataType::UInt64 => {
                        let arr = array.as_any().downcast_ref::<UInt64Array>();
                        if let Some(a) = arr {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Int64 => {
                        let arr = array.as_any().downcast_ref::<arrow_array::Int64Array>();
                        if let Some(a) = arr {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Utf8 => {
                        let arr = array.as_any().downcast_ref::<arrow_array::StringArray>();
                        if let Some(a) = arr {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Float64 => {
                        let arr = array.as_any().downcast_ref::<arrow_array::Float64Array>();
                        if let Some(a) = arr {
                            a.value(row_idx).to_bits().hash(&mut hasher);
                        }
                    }
                    DataType::Boolean => {
                        let arr = array.as_any().downcast_ref::<arrow_array::BooleanArray>();
                        if let Some(a) = arr {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    _ => {
                        // For other types, use row index (no dedup)
                        row_idx.hash(&mut hasher);
                    }
                }
            }
        }
        let row_hash = hasher.finish();
        if seen.insert(row_hash) {
            keep_indices.push(row_idx);
        }
    }

    // If no duplicates, return original
    if keep_indices.len() == total_rows {
        return Ok(ipc_data.to_vec());
    }

    // Build indices array for selection
    let indices_u32 =
        arrow_array::UInt32Array::from(keep_indices.iter().map(|&i| i as u32).collect::<Vec<_>>());

    // Select only unique rows
    use arrow_select::take::take;
    let mut distinct_columns = Vec::new();
    for col in &all_columns {
        let selected = take(col.as_ref(), &indices_u32, None)
            .map_err(|e| EngineError::Internal(format!("take for distinct failed: {e}")))?;
        distinct_columns.push(selected);
    }

    let distinct_batch = RecordBatch::try_new(schema.clone(), distinct_columns)
        .map_err(|e| EngineError::Internal(format!("create distinct batch failed: {e}")))?;

    // Write back to IPC
    let mut output = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output, schema.as_ref())
            .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
        writer
            .write(&distinct_batch)
            .map_err(|e| EngineError::Internal(format!("write distinct batch failed: {e}")))?;
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
    }

    Ok(output)
}

/// Apply DISTINCT ON (columns) to keep first row for each unique combination
/// of the specified columns. Data should already be sorted by ORDER BY clause.
fn apply_distinct_on(ipc_data: &[u8], columns: &[String]) -> Result<Vec<u8>, EngineError> {
    if columns.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("read IPC for distinct on failed: {e}")))?;

    let mut batches = Vec::new();
    while let Some(batch) = reader
        .next()
        .transpose()
        .map_err(|e| EngineError::Internal(format!("read batch for distinct on failed: {e}")))?
    {
        batches.push(batch);
    }

    if batches.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    let schema = batches[0].schema();
    let total_rows: usize = batches.iter().map(|b| b.num_rows()).sum();

    if total_rows == 0 {
        return Ok(ipc_data.to_vec());
    }

    // Find column indices for DISTINCT ON columns
    let col_indices: Vec<usize> = columns
        .iter()
        .filter_map(|name| schema.index_of(name).ok())
        .collect();

    if col_indices.is_empty() {
        return Err(EngineError::InvalidArgument(
            format!("DISTINCT ON columns not found in result: {:?}", columns)
        ));
    }

    // Concatenate all batches
    let mut all_columns = Vec::new();
    for col_idx in 0..schema.fields().len() {
        let arrays: Vec<_> = batches.iter().map(|b| b.column(col_idx).clone()).collect();
        let refs: Vec<_> = arrays.iter().map(|a| a.as_ref()).collect();
        let concatenated = arrow_select::concat::concat(&refs)
            .map_err(|e| EngineError::Internal(format!("concat for distinct on failed: {e}")))?;
        all_columns.push(concatenated);
    }

    // Build a set of seen row hashes for DISTINCT ON columns only
    use std::collections::hash_map::DefaultHasher;
    use std::collections::HashSet;
    use std::hash::{Hash, Hasher};

    let mut seen: HashSet<u64> = HashSet::new();
    let mut keep_indices: Vec<usize> = Vec::new();

    for row_idx in 0..total_rows {
        let mut hasher = DefaultHasher::new();
        // Only hash the DISTINCT ON columns
        for &col_idx in &col_indices {
            let col = &all_columns[col_idx];
            let array = col.as_ref();
            if array.is_null(row_idx) {
                0u8.hash(&mut hasher);
            } else {
                1u8.hash(&mut hasher);
                use arrow::datatypes::DataType;
                match array.data_type() {
                    DataType::UInt64 => {
                        if let Some(a) = array.as_any().downcast_ref::<UInt64Array>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Int64 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::Int64Array>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Int32 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::Int32Array>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Utf8 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::StringArray>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::LargeUtf8 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::LargeStringArray>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Float64 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::Float64Array>() {
                            a.value(row_idx).to_bits().hash(&mut hasher);
                        }
                    }
                    DataType::Float32 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::Float32Array>() {
                            a.value(row_idx).to_bits().hash(&mut hasher);
                        }
                    }
                    DataType::Boolean => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::BooleanArray>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Date32 => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::Date32Array>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    DataType::Timestamp(_, _) => {
                        if let Some(a) = array.as_any().downcast_ref::<arrow_array::TimestampMicrosecondArray>() {
                            a.value(row_idx).hash(&mut hasher);
                        }
                    }
                    _ => {
                        // For other types, use row index (no dedup for this column)
                        row_idx.hash(&mut hasher);
                    }
                }
            }
        }
        let row_hash = hasher.finish();
        // Keep only the first occurrence of each unique combination
        if seen.insert(row_hash) {
            keep_indices.push(row_idx);
        }
    }

    // If no duplicates, return original
    if keep_indices.len() == total_rows {
        return Ok(ipc_data.to_vec());
    }

    // Build indices array for selection
    let indices_u32 =
        arrow_array::UInt32Array::from(keep_indices.iter().map(|&i| i as u32).collect::<Vec<_>>());

    // Select only unique rows
    use arrow_select::take::take;
    let mut distinct_columns = Vec::new();
    for col in &all_columns {
        let selected = take(col.as_ref(), &indices_u32, None)
            .map_err(|e| EngineError::Internal(format!("take for distinct on failed: {e}")))?;
        distinct_columns.push(selected);
    }

    let distinct_batch = RecordBatch::try_new(schema.clone(), distinct_columns)
        .map_err(|e| EngineError::Internal(format!("create distinct on batch failed: {e}")))?;

    // Write back to IPC
    let mut output = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output, schema.as_ref())
            .map_err(|e| EngineError::Internal(format!("create IPC writer failed: {e}")))?;
        writer
            .write(&distinct_batch)
            .map_err(|e| EngineError::Internal(format!("write distinct on batch failed: {e}")))?;
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("finish IPC writer failed: {e}")))?;
    }

    Ok(output)
}

fn parse_table_target(sql: &str) -> Result<(String, String), EngineError> {
    let mut tokens = sql.split_whitespace().peekable();
    while let Some(tok) = tokens.next() {
        if tok.eq_ignore_ascii_case("from") {
            if let Some(target) = tokens.next() {
                let cleaned = target.trim_end_matches(';');
                if let Some((db, tbl)) = cleaned.split_once('.') {
                    let db = if db.is_empty() { "default" } else { db };
                    let tbl = if tbl.is_empty() { "default" } else { tbl };
                    if !is_valid_ident(db) || !is_valid_ident(tbl) {
                        return Err(EngineError::InvalidArgument(
                            "invalid database or table identifier".into(),
                        ));
                    }
                    return Ok((db.to_string(), tbl.to_string()));
                } else {
                    let tbl = if cleaned.is_empty() {
                        "default"
                    } else {
                        cleaned
                    };
                    if !is_valid_ident(tbl) {
                        return Err(EngineError::InvalidArgument(
                            "invalid table identifier".into(),
                        ));
                    }
                    return Ok(("default".to_string(), tbl.to_string()));
                }
            } else {
                break;
            }
        }
    }

    // If no FROM clause is found, we assume it's a scalar query (e.g. SELECT 1)
    // We return empty strings for database and table to indicate this.
    Ok(("".to_string(), "".to_string()))
}

#[derive(Default, Clone, Debug, Serialize, Deserialize)]
pub struct QueryFilter {
    watermark_ge: Option<u64>,
    watermark_le: Option<u64>,
    limit: Option<usize>,
    offset: Option<usize>,
    event_time_ge: Option<u64>,
    event_time_le: Option<u64>,
    pub tenant_id_eq: Option<u64>,
    pub route_id_eq: Option<u64>,
    pub tenant_id_in: Option<Vec<u64>>,
    pub route_id_in: Option<Vec<u64>>,
    order_by: Option<Vec<(String, bool)>>, // (column, ascending)
    distinct: bool,
    /// DISTINCT ON (columns) - PostgreSQL-style first row per group
    #[serde(default)]
    distinct_on: Option<Vec<String>>,
    /// Generic numeric equality filters (integer-only)
    numeric_eq_filters: Vec<(String, i128)>,
    /// Generic floating-point equality filters
    float_eq_filters: Vec<(String, f64)>,
    /// Generic boolean equality filters
    bool_eq_filters: Vec<(String, bool)>,
    /// LIKE patterns: Vec<(column, pattern, negate)>
    /// negate=true means NOT LIKE
    like_filters: Vec<(String, String, bool)>,
    /// ILIKE patterns (case-insensitive): Vec<(column, pattern, negate)>
    #[serde(default)]
    ilike_filters: Vec<(String, String, bool)>,
    /// IS NULL checks: Vec<(column, is_null)>
    /// is_null=true means IS NULL, is_null=false means IS NOT NULL
    null_filters: Vec<(String, bool)>,
    /// Generic string equality filters: Vec<(column, value)>
    string_eq_filters: Vec<(String, String)>,
    /// Generic string IN filters: Vec<(column, values)>
    string_in_filters: Vec<(String, Vec<String>)>,
    /// Numeric range filters for segment pruning using column stats
    #[serde(default)]
    numeric_range_filters: Vec<crate::sql::NumericFilter>,
}

impl QueryFilter {
    /// Get LIKE patterns for a column
    /// Returns Vec<(pattern, negate)> where negate=true means NOT LIKE
    pub fn like_patterns_for_column(&self, column: &str) -> Vec<(String, bool)> {
        self.like_filters
            .iter()
            .filter(|(col, _, _)| col == column)
            .map(|(_, pattern, negate)| (pattern.clone(), *negate))
            .collect()
    }

    /// Get ILIKE patterns for a column (case-insensitive LIKE)
    /// Returns Vec<(pattern, negate)> where negate=true means NOT ILIKE
    pub fn ilike_patterns_for_column(&self, column: &str) -> Vec<(String, bool)> {
        self.ilike_filters
            .iter()
            .filter(|(col, _, _)| col == column)
            .map(|(_, pattern, negate)| (pattern.clone(), *negate))
            .collect()
    }

    /// Get all LIKE and ILIKE patterns for a column
    /// Returns Vec<(pattern, negate)>
    pub fn all_like_patterns_for_column(&self, column: &str) -> Vec<(String, bool)> {
        let mut patterns = self.like_patterns_for_column(column);
        patterns.extend(self.ilike_patterns_for_column(column));
        patterns
    }
}

// --- RESTORED HELPER TYPES ---

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct TableFieldSpec {
    pub name: String,
    pub data_type: String, // Use string representation of arrow data type
    pub nullable: bool,
    pub encoding: Option<String>,
}

/// Aggregate expression with optional alias and FILTER clause for result column naming
#[derive(Debug, Clone, PartialEq, serde::Serialize, serde::Deserialize)]
pub struct AggregateExpr {
    pub kind: AggKind,
    pub alias: Option<String>,
    /// Optional FILTER clause: only include rows where this condition is true
    /// Example: COUNT(*) FILTER (WHERE status = 'active')
    #[serde(default)]
    pub filter: Option<crate::sql::AggregateFilter>,
}

impl AggregateExpr {
    pub fn new(kind: AggKind) -> Self {
        Self { kind, alias: None, filter: None }
    }

    pub fn with_alias(kind: AggKind, alias: String) -> Self {
        Self {
            kind,
            alias: Some(alias),
            filter: None,
        }
    }

    /// Get the output column name for this aggregate
    pub fn output_name(&self) -> String {
        if let Some(ref alias) = self.alias {
            return alias.clone();
        }
        // Default names based on aggregate type
        match &self.kind {
            AggKind::CountStar => "count".to_string(),
            AggKind::CountDistinct { column } => format!("count_distinct_{}", column),
            AggKind::Sum { column } => format!("sum_{}", column),
            AggKind::Avg { column } => format!("avg_{}", column),
            AggKind::Min { column } => format!("min_{}", column),
            AggKind::Max { column } => format!("max_{}", column),
            AggKind::StddevSamp { column } => format!("stddev_samp_{}", column),
            AggKind::StddevPop { column } => format!("stddev_pop_{}", column),
            AggKind::VarianceSamp { column } => format!("var_samp_{}", column),
            AggKind::VariancePop { column } => format!("var_pop_{}", column),
            AggKind::ApproxCountDistinct { column } => format!("approx_count_distinct_{}", column),
            AggKind::Median { column } => format!("median_{}", column),
            AggKind::PercentileCont { column, percentile } => {
                format!("percentile_cont_{}_{}", (percentile * 100.0) as i32, column)
            }
            AggKind::PercentileDisc { column, percentile } => {
                format!("percentile_disc_{}_{}", (percentile * 100.0) as i32, column)
            }
            AggKind::ArrayAgg { column, .. } => format!("array_agg_{}", column),
            AggKind::StringAgg { column, .. } => format!("string_agg_{}", column),
            AggKind::Mode { column } => format!("mode_{}", column),
            AggKind::StringAggOrdered { column, .. } => format!("string_agg_ordered_{}", column),
            AggKind::ArrayAggOrdered { column, .. } => format!("array_agg_ordered_{}", column),
            AggKind::NthValue { column, n } => format!("nth_value_{}_{}", n, column),
            AggKind::FirstValue { column } => format!("first_value_{}", column),
            AggKind::LastValue { column } => format!("last_value_{}", column),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Default, serde::Serialize, serde::Deserialize)]
pub struct AggPlan {
    pub group_by: GroupBy,
    pub aggs: Vec<AggregateExpr>,
    pub having: Vec<HavingCondition>,
}

#[derive(Debug, Clone, PartialEq, serde::Serialize, serde::Deserialize)]
pub enum AggKind {
    CountStar,
    CountDistinct { column: String },
    Sum { column: String },
    Avg { column: String },
    Min { column: String },
    Max { column: String },
    StddevSamp { column: String },
    StddevPop { column: String },
    VarianceSamp { column: String },
    VariancePop { column: String },
    ApproxCountDistinct { column: String },
    Median { column: String },
    PercentileCont { column: String, percentile: f64 },
    PercentileDisc { column: String, percentile: f64 },
    ArrayAgg { column: String, distinct: bool },
    StringAgg { column: String, delimiter: String, distinct: bool },
    /// MODE - most frequent value
    Mode { column: String },
    /// STRING_AGG with WITHIN GROUP ordering
    StringAggOrdered { column: String, delimiter: String, order_by: String, order_desc: bool },
    /// ARRAY_AGG with WITHIN GROUP ordering
    ArrayAggOrdered { column: String, order_by: String, order_desc: bool },
    /// NTH_VALUE - get nth value in ordered group
    NthValue { column: String, n: usize },
    /// FIRST_VALUE - first value in ordered group
    FirstValue { column: String },
    /// LAST_VALUE - last value in ordered group
    LastValue { column: String },
}

#[derive(Debug, Clone, PartialEq, serde::Serialize, serde::Deserialize)]
pub struct HavingCondition {
    pub agg: AggKind,
    pub op: HavingOp,
    pub value: f64,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub enum HavingOp {
    Eq,
    Ne,
    Gt,
    Ge,
    Lt,
    Le,
}

#[derive(Debug, Clone, PartialEq, Eq, Default, serde::Serialize, serde::Deserialize)]
pub enum GroupBy {
    #[default]
    None,
    Tenant,
    Route,
    Columns(Vec<GroupByColumn>),
    /// GROUP BY ALL - infer from non-aggregate columns
    All,
    /// GROUPING SETS - explicit list of grouping combinations
    GroupingSets(Vec<Vec<GroupByColumn>>),
    /// ROLLUP - hierarchical grouping with progressive subtotals
    Rollup(Vec<GroupByColumn>),
    /// CUBE - all possible grouping combinations
    Cube(Vec<GroupByColumn>),
}

#[derive(Debug, Clone, PartialEq, Eq, Hash, serde::Serialize, serde::Deserialize)]
pub enum GroupByColumn {
    TenantId,
    RouteId,
    Named(String),
}

// Keep legacy GroupByColumn for backward compatibility
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, serde::Serialize, serde::Deserialize)]
pub enum LegacyGroupByColumn {
    TenantId,
    RouteId,
}

// --- CONVERSION HELPERS ---

fn agg_kind_from_sql(kind: crate::sql::AggKind) -> AggKind {
    match kind {
        crate::sql::AggKind::CountStar => AggKind::CountStar,
        crate::sql::AggKind::CountDistinct { column } => AggKind::CountDistinct { column },
        crate::sql::AggKind::Sum { column } => AggKind::Sum { column },
        crate::sql::AggKind::Avg { column } => AggKind::Avg { column },
        crate::sql::AggKind::Min { column } => AggKind::Min { column },
        crate::sql::AggKind::Max { column } => AggKind::Max { column },
        crate::sql::AggKind::StddevSamp { column } => AggKind::StddevSamp { column },
        crate::sql::AggKind::StddevPop { column } => AggKind::StddevPop { column },
        crate::sql::AggKind::VarianceSamp { column } => AggKind::VarianceSamp { column },
        crate::sql::AggKind::VariancePop { column } => AggKind::VariancePop { column },
        crate::sql::AggKind::ApproxCountDistinct { column } => {
            AggKind::ApproxCountDistinct { column }
        }
        crate::sql::AggKind::Median { column } => AggKind::Median { column },
        crate::sql::AggKind::PercentileCont { column, percentile } => {
            AggKind::PercentileCont { column, percentile }
        }
        crate::sql::AggKind::PercentileDisc { column, percentile } => {
            AggKind::PercentileDisc { column, percentile }
        }
        crate::sql::AggKind::ArrayAgg { column, distinct } => {
            AggKind::ArrayAgg { column, distinct }
        }
        crate::sql::AggKind::StringAgg { column, delimiter, distinct } => {
            AggKind::StringAgg { column, delimiter, distinct }
        }
        crate::sql::AggKind::Mode { column } => AggKind::Mode { column },
        crate::sql::AggKind::StringAggOrdered { column, delimiter, order_by, order_desc } => {
            AggKind::StringAggOrdered { column, delimiter, order_by, order_desc }
        }
        crate::sql::AggKind::ArrayAggOrdered { column, order_by, order_desc } => {
            AggKind::ArrayAggOrdered { column, order_by, order_desc }
        }
        crate::sql::AggKind::NthValue { column, n } => AggKind::NthValue { column, n },
        crate::sql::AggKind::FirstValue { column } => AggKind::FirstValue { column },
        crate::sql::AggKind::LastValue { column } => AggKind::LastValue { column },
    }
}

fn agg_expr_from_sql(expr: crate::sql::AggregateExpr) -> AggregateExpr {
    AggregateExpr {
        kind: agg_kind_from_sql(expr.kind),
        alias: expr.alias,
        filter: expr.filter,
    }
}

fn having_condition_from_sql(cond: crate::sql::HavingCondition) -> HavingCondition {
    HavingCondition {
        agg: agg_kind_from_sql(cond.agg),
        op: match cond.op {
            crate::sql::HavingOp::Eq => HavingOp::Eq,
            crate::sql::HavingOp::Ne => HavingOp::Ne,
            crate::sql::HavingOp::Gt => HavingOp::Gt,
            crate::sql::HavingOp::Ge => HavingOp::Ge,
            crate::sql::HavingOp::Lt => HavingOp::Lt,
            crate::sql::HavingOp::Le => HavingOp::Le,
        },
        value: cond.value,
    }
}

fn agg_plan_from_sql(plan: crate::sql::AggPlan) -> AggPlan {
    AggPlan {
        group_by: match plan.group_by {
            crate::sql::GroupBy::None => GroupBy::None,
            crate::sql::GroupBy::Tenant => GroupBy::Tenant,
            crate::sql::GroupBy::Route => GroupBy::Route,
            crate::sql::GroupBy::Columns(cols) => GroupBy::Columns(
                cols.into_iter()
                    .filter_map(|c| match c {
                        crate::sql::GroupByColumn::TenantId => Some(GroupByColumn::TenantId),
                        crate::sql::GroupByColumn::RouteId => Some(GroupByColumn::RouteId),
                        crate::sql::GroupByColumn::Named(_) => None, // Named columns handled at SQL layer
                    })
                    .collect(),
            ),
            // Advanced GROUP BY features - fall back to None for this internal API
            // The full GROUPING SETS/CUBE/ROLLUP support is handled at the SQL execution layer
            crate::sql::GroupBy::All
            | crate::sql::GroupBy::GroupingSets(_)
            | crate::sql::GroupBy::Rollup(_)
            | crate::sql::GroupBy::Cube(_) => GroupBy::None,
        },
        aggs: plan.aggs.into_iter().map(agg_expr_from_sql).collect(),
        having: plan
            .having
            .into_iter()
            .map(having_condition_from_sql)
            .collect(),
    }
}

fn query_filter_from_sql(filter: &crate::sql::QueryFilter) -> QueryFilter {
    // Basic mapping. Missing fields are defaulted or ignored for now.
    QueryFilter {
        watermark_ge: filter.watermark_ge,
        watermark_le: filter.watermark_le,
        limit: filter.limit,
        offset: filter.offset,
        event_time_ge: filter.event_time_ge,
        event_time_le: filter.event_time_le,
        tenant_id_eq: filter.tenant_id_eq,
        route_id_eq: filter.route_id_eq,
        tenant_id_in: filter.tenant_id_in.clone(),
        route_id_in: filter.route_id_in.clone(),
        order_by: None,  // Handle at call site or improve mapping
        distinct: false, // Handle at call site
        distinct_on: filter.distinct_on.clone(),
        numeric_eq_filters: Vec::new(),
        float_eq_filters: Vec::new(),
        bool_eq_filters: Vec::new(),
        like_filters: filter.like_filters.clone(),
        ilike_filters: filter.ilike_filters.clone(),
        null_filters: filter.null_filters.clone(),
        string_eq_filters: filter.string_eq_filters.clone(),
        string_in_filters: filter.string_in_filters.clone(),
        numeric_range_filters: filter.numeric_range_filters.clone(),
    }
}

fn build_query_plan(sql: &str) -> Result<CachedPlan, EngineError> {
    use crate::sql::{parse_sql, SqlStatement};
    let sql_upper = sql.to_uppercase();
    if sql_upper.contains(" JOIN ") {
        return Ok(CachedPlan {
            kind: PlanKind::Join,
        });
    }
    if sql_upper.contains(" UNION ")
        || sql_upper.contains(" INTERSECT ")
        || sql_upper.contains(" EXCEPT ")
    {
        return Ok(CachedPlan {
            kind: PlanKind::SetOperation,
        });
    }
    if sql_upper.contains(" IN (SELECT")
        || sql_upper.contains(" IN(SELECT")
        || sql_upper.contains("EXISTS (SELECT")
        || sql_upper.contains("EXISTS(SELECT")
        || sql_upper.contains("= (SELECT")
        || sql_upper.contains("=(SELECT")
    {
        return Ok(CachedPlan {
            kind: PlanKind::Subquery,
        });
    }
    if sql_upper.trim_start().starts_with("WITH ") {
        return Ok(CachedPlan {
            kind: PlanKind::Cte,
        });
    }
    match parse_sql(sql)? {
        SqlStatement::Transaction(cmd) => Ok(CachedPlan {
            kind: PlanKind::Transaction(cmd),
        }),
        SqlStatement::Query(parsed) => {
            let mut filter = query_filter_from_sql(&parsed.filter);
            // Map extra fields
            if let Some(order_by) = parsed.order_by {
                filter.order_by = Some(
                    order_by
                        .into_iter()
                        .map(|o| (o.column, o.ascending))
                        .collect(),
                );
            }
            filter.distinct = parsed.distinct;
            filter.distinct_on = parsed.distinct_on;

            Ok(CachedPlan {
                kind: PlanKind::Simple {
                    agg: parsed.aggregation.map(agg_plan_from_sql),
                    db: parsed.database,
                    table: parsed.table,
                    projection: parsed.projection,
                    filter,
                    computed_columns: parsed.computed_columns,
                },
            })
        }
        _ => Err(EngineError::NotImplemented(
            "unsupported statement type".into(),
        )),
    }
}

// --- CTE SUPPORT ---

#[derive(Default)]
pub struct CteContext {
    results: std::collections::HashMap<String, Vec<u8>>,
}

impl CteContext {
    pub fn new() -> Self {
        Self::default()
    }
    pub fn add_result(&mut self, name: String, data: Vec<u8>) {
        self.results.insert(name, data);
    }
    pub fn get_result(&self, name: &str) -> Option<&Vec<u8>> {
        self.results.get(name)
    }
    /// Check if a CTE with the given name exists
    pub fn has_cte(&self, name: &str) -> bool {
        self.results.contains_key(name)
    }
}

/// Extract the main SELECT portion from a CTE query (after WITH...AS clauses)
fn extract_main_query_from_cte(sql: &str) -> String {
    let sql_upper = sql.to_uppercase();

    // Find the position after the last CTE definition
    // CTEs have the form: WITH name AS (...), name2 AS (...) SELECT ...
    // We need to find the final SELECT that's not inside a CTE

    let mut depth = 0;
    let mut last_close_paren_after_as = 0;
    let mut in_as_block = false;
    let chars: Vec<char> = sql.chars().collect();
    let mut i = 0;

    while i < chars.len() {
        let c = chars[i];

        // Check for 'AS' followed by '('
        if !in_as_block && depth == 0 && i + 3 < chars.len() {
            let slice: String = chars[i..i + 2].iter().collect();
            if slice.to_uppercase() == "AS" {
                // Check if followed by whitespace and '('
                let mut j = i + 2;
                while j < chars.len() && chars[j].is_whitespace() {
                    j += 1;
                }
                if j < chars.len() && chars[j] == '(' {
                    in_as_block = true;
                    i = j;
                    depth = 1;
                    i += 1;
                    continue;
                }
            }
        }

        if in_as_block {
            if c == '(' {
                depth += 1;
            } else if c == ')' {
                depth -= 1;
                if depth == 0 {
                    in_as_block = false;
                    last_close_paren_after_as = i;
                }
            }
        }

        i += 1;
    }

    // Find the SELECT after the last CTE definition
    if last_close_paren_after_as > 0 {
        let remainder = &sql[last_close_paren_after_as + 1..];
        // Skip any comma (for multiple CTEs) and find SELECT
        let remainder_upper = remainder.to_uppercase();
        if let Some(select_pos) = remainder_upper.find("SELECT") {
            // Check it's not another CTE (no AS ( before it at same level)
            let before_select = &remainder_upper[..select_pos];
            if !before_select.contains(" AS ") && !before_select.contains(" AS(") {
                return remainder[select_pos..].to_string();
            }
        }
    }

    // Fallback: find first SELECT not inside WITH
    // Simple heuristic: skip "WITH" and find top-level "SELECT"
    if let Some(with_pos) = sql_upper.find("WITH") {
        let after_with = &sql[with_pos..];
        let after_with_upper = after_with.to_uppercase();

        // Find balanced parens to skip CTE definitions
        let mut depth = 0;
        let chars: Vec<char> = after_with.chars().collect();
        for (i, c) in chars.iter().enumerate() {
            if *c == '(' {
                depth += 1;
            } else if *c == ')' {
                depth -= 1;
            }

            // When at depth 0, check for SELECT
            if depth == 0 && i + 6 < chars.len() {
                let slice: String = chars[i..i + 6].iter().collect();
                if slice.to_uppercase() == "SELECT" {
                    return after_with[i..].to_string();
                }
            }
        }
    }

    // Ultimate fallback: return as-is (will likely fail but won't recurse infinitely)
    sql.to_string()
}

pub fn execute_query_with_ctes(
    db: &Db,
    sql: &str,
    ctes: &[crate::sql::CteDefinition],
    timeout_millis: u32,
) -> Result<QueryResponse, EngineError> {
    let mut cte_context = CteContext::new();

    for cte in ctes {
        if cte.recursive {
            let result = execute_recursive_cte(db, cte, &cte_context, timeout_millis)?;
            cte_context.add_result(cte.name.clone(), result);
        } else {
            let cte_sql = cte.raw_sql.clone();

            let result = db.query(QueryRequest {
                sql: cte_sql,
                timeout_millis,
                collect_stats: false,
                transaction_id: None,
            })?;

            // Store the result in the CTE context
            cte_context.add_result(cte.name.clone(), result.records_ipc);
        }
    }

    // Extract just the main SELECT portion without the WITH clause
    // to avoid infinite recursion through CTE detection
    let main_query = extract_main_query_from_cte(sql);

    db.query(QueryRequest {
        sql: main_query,
        timeout_millis,
        collect_stats: false,
        transaction_id: None,
    })
}

// --- RESTORED COMPUTED VALUE STUBS ---

#[derive(Debug, Clone, PartialEq)]
pub enum ComputedValue {
    Null,
    Boolean(bool),
    Integer(i64),
    Float(f64),
    String(String),
    Binary(Vec<u8>),
    Timestamp(i64),
    Date(i32),
    Decimal {
        value: i128,
        precision: u8,
        scale: i8,
    },
    Uuid([u8; 16]),
    Json(String),
}

impl ComputedValue {
    pub fn to_string_value(&self) -> String {
        match self {
            ComputedValue::String(s) => s.clone(),
            ComputedValue::Integer(i) => i.to_string(),
            ComputedValue::Float(f) => f.to_string(),
            ComputedValue::Boolean(b) => b.to_string(),
            ComputedValue::Null => "NULL".to_string(),
            ComputedValue::Uuid(bytes) => {
                // Format as standard UUID: xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx
                format!(
                    "{:02x}{:02x}{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}{:02x}{:02x}{:02x}{:02x}",
                    bytes[0], bytes[1], bytes[2], bytes[3],
                    bytes[4], bytes[5],
                    bytes[6], bytes[7],
                    bytes[8], bytes[9],
                    bytes[10], bytes[11], bytes[12], bytes[13], bytes[14], bytes[15]
                )
            }
            ComputedValue::Json(s) => s.clone(),
            ComputedValue::Date(days) => {
                // Days since Unix epoch to date string
                let epoch = chrono::NaiveDate::from_ymd_opt(1970, 1, 1).unwrap();
                if let Some(date) = epoch.checked_add_signed(chrono::Duration::days(*days as i64)) {
                    date.format("%Y-%m-%d").to_string()
                } else {
                    format!("Date({})", days)
                }
            }
            ComputedValue::Timestamp(micros) => {
                // Microseconds since Unix epoch to datetime string
                let secs = micros / 1_000_000;
                let nsecs = ((micros % 1_000_000) * 1000) as u32;
                if let Some(dt) = chrono::DateTime::from_timestamp(secs, nsecs) {
                    dt.format("%Y-%m-%d %H:%M:%S%.6f").to_string()
                } else {
                    format!("Timestamp({})", micros)
                }
            }
            ComputedValue::Decimal {
                value,
                precision: _,
                scale,
            } => {
                if *scale == 0 {
                    value.to_string()
                } else {
                    let divisor = 10i128.pow(*scale as u32);
                    let int_part = value / divisor;
                    let frac_part = (value % divisor).abs();
                    format!(
                        "{}.{:0>width$}",
                        int_part,
                        frac_part,
                        width = *scale as usize
                    )
                }
            }
            ComputedValue::Binary(bytes) => {
                // Hex representation for binary data
                let hex: String = bytes.iter().map(|b| format!("{:02x}", b)).collect();
                format!("\\x{}", hex)
            }
        }
    }

    pub fn as_f64(&self) -> Option<f64> {
        match self {
            ComputedValue::Float(f) => Some(*f),
            ComputedValue::Integer(i) => Some(*i as f64),
            ComputedValue::Decimal { value, scale, .. } => {
                let divisor = 10f64.powi(*scale as i32);
                Some(*value as f64 / divisor)
            }
            _ => None,
        }
    }
    pub fn as_i64(&self) -> Option<i64> {
        match self {
            ComputedValue::Integer(i) => Some(*i),
            ComputedValue::Float(f) => Some(*f as i64),
            ComputedValue::Decimal { value, scale, .. } => {
                let divisor = 10i128.pow(*scale as u32);
                Some((*value / divisor) as i64)
            }
            _ => None,
        }
    }

    pub fn is_null(&self) -> bool {
        matches!(self, ComputedValue::Null)
    }

    /// Get the UUID bytes if this is a Uuid variant
    pub fn as_uuid(&self) -> Option<&[u8; 16]> {
        match self {
            ComputedValue::Uuid(bytes) => Some(bytes),
            _ => None,
        }
    }

    /// Get the JSON string if this is a Json variant
    pub fn as_json(&self) -> Option<&str> {
        match self {
            ComputedValue::Json(s) => Some(s),
            _ => None,
        }
    }

    /// Get as boolean
    pub fn as_bool(&self) -> Option<bool> {
        match self {
            ComputedValue::Boolean(b) => Some(*b),
            _ => None,
        }
    }

    /// Get as string reference
    pub fn as_str(&self) -> Option<&str> {
        match self {
            ComputedValue::String(s) => Some(s),
            ComputedValue::Json(s) => Some(s),
            _ => None,
        }
    }
}

pub fn compare_values(_a: &ComputedValue, _b: &ComputedValue) -> i32 {
    0
}

pub struct EvalContext<'a> {
    pub row: &'a std::collections::HashMap<String, ComputedValue>,
}

impl<'a> EvalContext<'a> {
    pub fn new(row: &'a std::collections::HashMap<String, ComputedValue>) -> Self {
        Self { row }
    }
}

pub fn evaluate_expr(
    expr: &crate::sql::SelectExpr,
    ctx: &EvalContext,
) -> Result<ComputedValue, EngineError> {
    use crate::sql::{LiteralValue, SelectExpr};

    match expr {
        SelectExpr::Column(name) => {
            ctx.row.get(name).cloned().ok_or_else(|| {
                EngineError::Internal(format!("column not found in context: {}", name))
            })
        }

        SelectExpr::QualifiedColumn { table: _, column } => {
            // For now, just look up the column name ignoring table qualifier
            ctx.row.get(column).cloned().ok_or_else(|| {
                EngineError::Internal(format!("column not found in context: {}", column))
            })
        }

        SelectExpr::Literal(lit) => Ok(match lit {
            LiteralValue::Integer(i) => ComputedValue::Integer(*i),
            LiteralValue::Float(f) => ComputedValue::Float(*f),
            LiteralValue::String(s) => ComputedValue::String(s.clone()),
            LiteralValue::Boolean(b) => ComputedValue::Boolean(*b),
            LiteralValue::Null => ComputedValue::Null,
        }),

        SelectExpr::Null => Ok(ComputedValue::Null),

        SelectExpr::BinaryOp { left, op, right } => {
            let left_val = evaluate_expr(left, ctx)?;
            let right_val = evaluate_expr(right, ctx)?;
            apply_binary_op(&left_val, op, &right_val)
        }

        SelectExpr::UnaryOp { op, expr: inner } => {
            let val = evaluate_expr(inner, ctx)?;
            apply_unary_op(op, &val)
        }

        SelectExpr::Function(func) => evaluate_scalar_function(func, ctx),

        SelectExpr::Aggregate(_) => {
            // Aggregates are handled separately in the aggregation engine
            Ok(ComputedValue::Null)
        }

        SelectExpr::Window { .. } => {
            // Window functions are handled separately
            Ok(ComputedValue::Null)
        }

        SelectExpr::Case {
            operand,
            when_clauses,
            else_result,
        } => evaluate_case_expr(operand, when_clauses, else_result, ctx),

        SelectExpr::Subquery(_) => {
            // Subqueries not supported in expression evaluation context
            Err(EngineError::Internal(
                "subqueries not supported in expression evaluation".into(),
            ))
        }
    }
}

fn apply_binary_op(
    left: &ComputedValue,
    op: &str,
    right: &ComputedValue,
) -> Result<ComputedValue, EngineError> {
    // Handle NULL propagation for most operations
    if matches!(left, ComputedValue::Null) || matches!(right, ComputedValue::Null) {
        return Ok(ComputedValue::Null);
    }

    match op {
        "+" => match (left, right) {
            (ComputedValue::Integer(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Integer(a + b))
            }
            (ComputedValue::Float(a), ComputedValue::Float(b)) => Ok(ComputedValue::Float(a + b)),
            (ComputedValue::Integer(a), ComputedValue::Float(b)) => {
                Ok(ComputedValue::Float(*a as f64 + b))
            }
            (ComputedValue::Float(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Float(a + *b as f64))
            }
            (ComputedValue::String(a), ComputedValue::String(b)) => {
                Ok(ComputedValue::String(format!("{}{}", a, b)))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for +: {:?} and {:?}",
                left, right
            ))),
        },
        "-" => match (left, right) {
            (ComputedValue::Integer(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Integer(a - b))
            }
            (ComputedValue::Float(a), ComputedValue::Float(b)) => Ok(ComputedValue::Float(a - b)),
            (ComputedValue::Integer(a), ComputedValue::Float(b)) => {
                Ok(ComputedValue::Float(*a as f64 - b))
            }
            (ComputedValue::Float(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Float(a - *b as f64))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for -: {:?} and {:?}",
                left, right
            ))),
        },
        "*" => match (left, right) {
            (ComputedValue::Integer(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Integer(a * b))
            }
            (ComputedValue::Float(a), ComputedValue::Float(b)) => Ok(ComputedValue::Float(a * b)),
            (ComputedValue::Integer(a), ComputedValue::Float(b)) => {
                Ok(ComputedValue::Float(*a as f64 * b))
            }
            (ComputedValue::Float(a), ComputedValue::Integer(b)) => {
                Ok(ComputedValue::Float(a * *b as f64))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for *: {:?} and {:?}",
                left, right
            ))),
        },
        "/" => match (left, right) {
            (ComputedValue::Integer(a), ComputedValue::Integer(b)) => {
                if *b == 0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Integer(a / b))
            }
            (ComputedValue::Float(a), ComputedValue::Float(b)) => {
                if *b == 0.0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Float(a / b))
            }
            (ComputedValue::Integer(a), ComputedValue::Float(b)) => {
                if *b == 0.0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Float(*a as f64 / b))
            }
            (ComputedValue::Float(a), ComputedValue::Integer(b)) => {
                if *b == 0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Float(a / *b as f64))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for /: {:?} and {:?}",
                left, right
            ))),
        },
        "%" => match (left, right) {
            (ComputedValue::Integer(a), ComputedValue::Integer(b)) => {
                if *b == 0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Integer(a % b))
            }
            (ComputedValue::Float(a), ComputedValue::Float(b)) => {
                if *b == 0.0 {
                    return Ok(ComputedValue::Null);
                }
                Ok(ComputedValue::Float(a % b))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for %: {:?} and {:?}",
                left, right
            ))),
        },
        "||" => {
            // String concatenation
            Ok(ComputedValue::String(format!(
                "{}{}",
                left.to_string_value(),
                right.to_string_value()
            )))
        }
        "AND" | "and" => match (left, right) {
            (ComputedValue::Boolean(a), ComputedValue::Boolean(b)) => {
                Ok(ComputedValue::Boolean(*a && *b))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for AND: {:?} and {:?}",
                left, right
            ))),
        },
        "OR" | "or" => match (left, right) {
            (ComputedValue::Boolean(a), ComputedValue::Boolean(b)) => {
                Ok(ComputedValue::Boolean(*a || *b))
            }
            _ => Err(EngineError::Internal(format!(
                "invalid operands for OR: {:?} and {:?}",
                left, right
            ))),
        },
        "=" | "==" => Ok(ComputedValue::Boolean(computed_values_equal(left, right))),
        "!=" | "<>" => Ok(ComputedValue::Boolean(!computed_values_equal(left, right))),
        "<" => Ok(ComputedValue::Boolean(
            computed_values_cmp(left, right) == std::cmp::Ordering::Less,
        )),
        "<=" => {
            let cmp = computed_values_cmp(left, right);
            Ok(ComputedValue::Boolean(
                cmp == std::cmp::Ordering::Less || cmp == std::cmp::Ordering::Equal,
            ))
        }
        ">" => Ok(ComputedValue::Boolean(
            computed_values_cmp(left, right) == std::cmp::Ordering::Greater,
        )),
        ">=" => {
            let cmp = computed_values_cmp(left, right);
            Ok(ComputedValue::Boolean(
                cmp == std::cmp::Ordering::Greater || cmp == std::cmp::Ordering::Equal,
            ))
        }
        _ => Err(EngineError::Internal(format!(
            "unsupported binary operator: {}",
            op
        ))),
    }
}

fn computed_values_equal(a: &ComputedValue, b: &ComputedValue) -> bool {
    match (a, b) {
        (ComputedValue::Integer(x), ComputedValue::Integer(y)) => x == y,
        (ComputedValue::Float(x), ComputedValue::Float(y)) => (x - y).abs() < f64::EPSILON,
        (ComputedValue::Integer(x), ComputedValue::Float(y)) => {
            (*x as f64 - y).abs() < f64::EPSILON
        }
        (ComputedValue::Float(x), ComputedValue::Integer(y)) => {
            (x - *y as f64).abs() < f64::EPSILON
        }
        (ComputedValue::String(x), ComputedValue::String(y)) => x == y,
        (ComputedValue::Boolean(x), ComputedValue::Boolean(y)) => x == y,
        (ComputedValue::Null, ComputedValue::Null) => true,
        _ => false,
    }
}

fn computed_values_cmp(a: &ComputedValue, b: &ComputedValue) -> std::cmp::Ordering {
    use std::cmp::Ordering;
    match (a, b) {
        (ComputedValue::Integer(x), ComputedValue::Integer(y)) => x.cmp(y),
        (ComputedValue::Float(x), ComputedValue::Float(y)) => {
            x.partial_cmp(y).unwrap_or(Ordering::Equal)
        }
        (ComputedValue::Integer(x), ComputedValue::Float(y)) => {
            (*x as f64).partial_cmp(y).unwrap_or(Ordering::Equal)
        }
        (ComputedValue::Float(x), ComputedValue::Integer(y)) => {
            x.partial_cmp(&(*y as f64)).unwrap_or(Ordering::Equal)
        }
        (ComputedValue::String(x), ComputedValue::String(y)) => x.cmp(y),
        _ => Ordering::Equal,
    }
}

fn apply_unary_op(op: &str, val: &ComputedValue) -> Result<ComputedValue, EngineError> {
    match op {
        "-" => match val {
            ComputedValue::Integer(i) => Ok(ComputedValue::Integer(-i)),
            ComputedValue::Float(f) => Ok(ComputedValue::Float(-f)),
            ComputedValue::Null => Ok(ComputedValue::Null),
            _ => Err(EngineError::Internal(format!(
                "invalid operand for unary -: {:?}",
                val
            ))),
        },
        "NOT" | "not" | "!" => match val {
            ComputedValue::Boolean(b) => Ok(ComputedValue::Boolean(!b)),
            ComputedValue::Null => Ok(ComputedValue::Null),
            _ => Err(EngineError::Internal(format!(
                "invalid operand for NOT: {:?}",
                val
            ))),
        },
        _ => Err(EngineError::Internal(format!(
            "unsupported unary operator: {}",
            op
        ))),
    }
}

fn evaluate_scalar_function(
    func: &crate::sql::ScalarFunction,
    ctx: &EvalContext,
) -> Result<ComputedValue, EngineError> {
    use crate::sql::ScalarFunction;

    match func {
        // String functions
        ScalarFunction::Upper(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.to_uppercase())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::String(val.to_string_value().to_uppercase())),
            }
        }
        ScalarFunction::Lower(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.to_lowercase())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::String(val.to_string_value().to_lowercase())),
            }
        }
        ScalarFunction::Length(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::Integer(s.len() as i64)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Integer(val.to_string_value().len() as i64)),
            }
        }
        ScalarFunction::Trim(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.trim().to_string())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::String(
                    val.to_string_value().trim().to_string(),
                )),
            }
        }
        ScalarFunction::LTrim(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.trim_start().to_string())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::String(
                    val.to_string_value().trim_start().to_string(),
                )),
            }
        }
        ScalarFunction::RTrim(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.trim_end().to_string())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::String(
                    val.to_string_value().trim_end().to_string(),
                )),
            }
        }
        ScalarFunction::Concat(exprs) => {
            let mut result = String::new();
            for e in exprs {
                let val = evaluate_expr(e, ctx)?;
                if matches!(val, ComputedValue::Null) {
                    continue; // Skip nulls in CONCAT
                }
                result.push_str(&val.to_string_value());
            }
            Ok(ComputedValue::String(result))
        }
        ScalarFunction::Substring {
            expr,
            start,
            length,
        } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    let start_idx = (*start as usize).saturating_sub(1); // SQL is 1-indexed
                    let chars: Vec<char> = s.chars().collect();
                    if start_idx >= chars.len() {
                        return Ok(ComputedValue::String(String::new()));
                    }
                    let end_idx = if let Some(len) = length {
                        (start_idx + *len as usize).min(chars.len())
                    } else {
                        chars.len()
                    };
                    let substr: String = chars[start_idx..end_idx].iter().collect();
                    Ok(ComputedValue::String(substr))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Replace { expr, from, to } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.replace(from, to))),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Left { expr, count } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    let chars: Vec<char> = s.chars().collect();
                    let end = (*count as usize).min(chars.len());
                    Ok(ComputedValue::String(chars[..end].iter().collect()))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Right { expr, count } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    let chars: Vec<char> = s.chars().collect();
                    let start = chars.len().saturating_sub(*count as usize);
                    Ok(ComputedValue::String(chars[start..].iter().collect()))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Reverse(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => Ok(ComputedValue::String(s.chars().rev().collect())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Coalesce(exprs) => {
            for e in exprs {
                let val = evaluate_expr(e, ctx)?;
                if !matches!(val, ComputedValue::Null) {
                    return Ok(val);
                }
            }
            Ok(ComputedValue::Null)
        }

        // Regex functions
        ScalarFunction::RegexpReplace { expr, pattern, replacement, flags } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    let case_insensitive = flags.as_ref().map(|f| f.contains('i')).unwrap_or(false);
                    let global = flags.as_ref().map(|f| f.contains('g')).unwrap_or(true);

                    let re = if case_insensitive {
                        regex::RegexBuilder::new(pattern)
                            .case_insensitive(true)
                            .build()
                    } else {
                        regex::Regex::new(pattern)
                    };

                    match re {
                        Ok(re) => {
                            let result = if global {
                                re.replace_all(&s, replacement.as_str()).to_string()
                            } else {
                                re.replace(&s, replacement.as_str()).to_string()
                            };
                            Ok(ComputedValue::String(result))
                        }
                        Err(e) => Err(EngineError::InvalidArgument(
                            format!("Invalid regex pattern: {}", e),
                        )),
                    }
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::RegexpMatch { expr, pattern, flags } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    let case_insensitive = flags.as_ref().map(|f| f.contains('i')).unwrap_or(false);

                    let re = if case_insensitive {
                        regex::RegexBuilder::new(pattern)
                            .case_insensitive(true)
                            .build()
                    } else {
                        regex::Regex::new(pattern)
                    };

                    match re {
                        Ok(re) => {
                            // Return true/false as integer (1/0) for SQL compatibility
                            let matches = re.is_match(&s);
                            Ok(ComputedValue::Integer(if matches { 1 } else { 0 }))
                        }
                        Err(e) => Err(EngineError::InvalidArgument(
                            format!("Invalid regex pattern: {}", e),
                        )),
                    }
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::RegexpExtract { expr, pattern, group_index } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::String(s) => {
                    match regex::Regex::new(pattern) {
                        Ok(re) => {
                            if let Some(caps) = re.captures(&s) {
                                let idx = group_index.unwrap_or(0) as usize;
                                if let Some(m) = caps.get(idx) {
                                    Ok(ComputedValue::String(m.as_str().to_string()))
                                } else {
                                    Ok(ComputedValue::Null)
                                }
                            } else {
                                Ok(ComputedValue::Null)
                            }
                        }
                        Err(e) => Err(EngineError::InvalidArgument(
                            format!("Invalid regex pattern: {}", e),
                        )),
                    }
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }

        // Math functions
        ScalarFunction::Abs(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Integer(i) => Ok(ComputedValue::Integer(i.abs())),
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.abs())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "ABS requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Round { expr, precision } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => {
                    let prec = precision.unwrap_or(0);
                    let multiplier = 10f64.powi(prec);
                    Ok(ComputedValue::Float((f * multiplier).round() / multiplier))
                }
                ComputedValue::Integer(i) => Ok(ComputedValue::Integer(i)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "ROUND requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Ceil(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.ceil())),
                ComputedValue::Integer(i) => Ok(ComputedValue::Integer(i)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "CEIL requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Floor(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.floor())),
                ComputedValue::Integer(i) => Ok(ComputedValue::Integer(i)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "FLOOR requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Mod { dividend, divisor } => {
            let left = evaluate_expr(dividend, ctx)?;
            let right = evaluate_expr(divisor, ctx)?;
            apply_binary_op(&left, "%", &right)
        }
        ScalarFunction::Power { base, exponent } => {
            let base_val = evaluate_expr(base, ctx)?;
            let exp_val = evaluate_expr(exponent, ctx)?;
            match (&base_val, &exp_val) {
                (ComputedValue::Float(b), ComputedValue::Float(e)) => {
                    Ok(ComputedValue::Float(b.powf(*e)))
                }
                (ComputedValue::Integer(b), ComputedValue::Integer(e)) => {
                    if *e >= 0 {
                        Ok(ComputedValue::Integer(b.pow(*e as u32)))
                    } else {
                        Ok(ComputedValue::Float((*b as f64).powf(*e as f64)))
                    }
                }
                (ComputedValue::Integer(b), ComputedValue::Float(e)) => {
                    Ok(ComputedValue::Float((*b as f64).powf(*e)))
                }
                (ComputedValue::Float(b), ComputedValue::Integer(e)) => {
                    Ok(ComputedValue::Float(b.powf(*e as f64)))
                }
                (ComputedValue::Null, _) | (_, ComputedValue::Null) => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "POWER requires numeric arguments".into(),
                )),
            }
        }
        ScalarFunction::Sqrt(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.sqrt())),
                ComputedValue::Integer(i) => Ok(ComputedValue::Float((i as f64).sqrt())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "SQRT requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Log { expr, base } => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => {
                    let result = if let Some(b) = base {
                        f.log(*b)
                    } else {
                        f.log10()
                    };
                    Ok(ComputedValue::Float(result))
                }
                ComputedValue::Integer(i) => {
                    let f = i as f64;
                    let result = if let Some(b) = base {
                        f.log(*b)
                    } else {
                        f.log10()
                    };
                    Ok(ComputedValue::Float(result))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "LOG requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Ln(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.ln())),
                ComputedValue::Integer(i) => Ok(ComputedValue::Float((i as f64).ln())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal("LN requires numeric argument".into())),
            }
        }
        ScalarFunction::Exp(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Float(f.exp())),
                ComputedValue::Integer(i) => Ok(ComputedValue::Float((i as f64).exp())),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "EXP requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Sign(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Float(f) => Ok(ComputedValue::Integer(if f > 0.0 {
                    1
                } else if f < 0.0 {
                    -1
                } else {
                    0
                })),
                ComputedValue::Integer(i) => Ok(ComputedValue::Integer(if i > 0 {
                    1
                } else if i < 0 {
                    -1
                } else {
                    0
                })),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Err(EngineError::Internal(
                    "SIGN requires numeric argument".into(),
                )),
            }
        }
        ScalarFunction::Greatest(exprs) => {
            let mut max: Option<ComputedValue> = None;
            for e in exprs {
                let val = evaluate_expr(e, ctx)?;
                if matches!(val, ComputedValue::Null) {
                    continue;
                }
                match &max {
                    None => max = Some(val),
                    Some(current) => {
                        if computed_values_cmp(&val, current) == std::cmp::Ordering::Greater {
                            max = Some(val);
                        }
                    }
                }
            }
            Ok(max.unwrap_or(ComputedValue::Null))
        }
        ScalarFunction::Least(exprs) => {
            let mut min: Option<ComputedValue> = None;
            for e in exprs {
                let val = evaluate_expr(e, ctx)?;
                if matches!(val, ComputedValue::Null) {
                    continue;
                }
                match &min {
                    None => min = Some(val),
                    Some(current) => {
                        if computed_values_cmp(&val, current) == std::cmp::Ordering::Less {
                            min = Some(val);
                        }
                    }
                }
            }
            Ok(min.unwrap_or(ComputedValue::Null))
        }

        // Date/Time functions
        ScalarFunction::Now | ScalarFunction::CurrentTimestamp => {
            let now = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .map(|d| d.as_micros() as i64)
                .unwrap_or(0);
            Ok(ComputedValue::Timestamp(now))
        }
        ScalarFunction::CurrentDate => {
            let now = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .map(|d| (d.as_secs() / 86400) as i32)
                .unwrap_or(0);
            Ok(ComputedValue::Date(now))
        }
        ScalarFunction::DateAdd { expr, interval, unit } => {
            let val = evaluate_expr(expr, ctx)?;
            let micros = interval_to_micros(*interval, unit);
            match val {
                ComputedValue::Timestamp(ts) => Ok(ComputedValue::Timestamp(ts + micros)),
                ComputedValue::Date(days) => {
                    // Convert interval to days for date arithmetic
                    let interval_days = (micros / (86400 * 1_000_000)) as i32;
                    Ok(ComputedValue::Date(days + interval_days))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::DateSub { expr, interval, unit } => {
            let val = evaluate_expr(expr, ctx)?;
            let micros = interval_to_micros(*interval, unit);
            match val {
                ComputedValue::Timestamp(ts) => Ok(ComputedValue::Timestamp(ts - micros)),
                ComputedValue::Date(days) => {
                    let interval_days = (micros / (86400 * 1_000_000)) as i32;
                    Ok(ComputedValue::Date(days - interval_days))
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::DateDiff { unit, start, end } => {
            let start_val = evaluate_expr(start, ctx)?;
            let end_val = evaluate_expr(end, ctx)?;

            let (start_micros, end_micros) = match (&start_val, &end_val) {
                (ComputedValue::Timestamp(s), ComputedValue::Timestamp(e)) => (*s, *e),
                (ComputedValue::Date(s), ComputedValue::Date(e)) => {
                    ((*s as i64) * 86400 * 1_000_000, (*e as i64) * 86400 * 1_000_000)
                }
                (ComputedValue::Null, _) | (_, ComputedValue::Null) => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };

            let diff_micros = end_micros - start_micros;
            let result = match unit.to_lowercase().as_str() {
                "microsecond" | "microseconds" => diff_micros,
                "millisecond" | "milliseconds" => diff_micros / 1_000,
                "second" | "seconds" => diff_micros / 1_000_000,
                "minute" | "minutes" => diff_micros / (60 * 1_000_000),
                "hour" | "hours" => diff_micros / (3600 * 1_000_000),
                "day" | "days" => diff_micros / (86400 * 1_000_000),
                "week" | "weeks" => diff_micros / (7 * 86400 * 1_000_000),
                _ => diff_micros / (86400 * 1_000_000), // Default to days
            };
            Ok(ComputedValue::Integer(result))
        }
        ScalarFunction::Date(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Timestamp(ts) => {
                    // Convert microseconds timestamp to days since epoch
                    let days = (ts / (86400 * 1_000_000)) as i32;
                    Ok(ComputedValue::Date(days))
                }
                ComputedValue::Date(d) => Ok(ComputedValue::Date(d)),
                ComputedValue::String(s) => {
                    // Try to parse date string YYYY-MM-DD
                    if let Some(days) = parse_date_to_days(&s) {
                        Ok(ComputedValue::Date(days))
                    } else {
                        Ok(ComputedValue::Null)
                    }
                }
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::Extract { field, expr } => {
            let val = evaluate_expr(expr, ctx)?;
            let timestamp_micros = match val {
                ComputedValue::Timestamp(ts) => ts,
                ComputedValue::Date(days) => (days as i64) * 86400 * 1_000_000,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };

            // Convert to seconds and compute datetime components
            let total_secs = timestamp_micros / 1_000_000;
            let micros_remainder = (timestamp_micros % 1_000_000) as i64;

            // Days since epoch (1970-01-01)
            let days_since_epoch = total_secs / 86400;
            let secs_in_day = total_secs % 86400;

            let hour = secs_in_day / 3600;
            let minute = (secs_in_day % 3600) / 60;
            let second = secs_in_day % 60;

            // Calculate year, month, day from days since epoch
            let (year, month, day) = days_to_ymd(days_since_epoch as i32);

            let result = match field.to_lowercase().as_str() {
                "year" => year as i64,
                "month" => month as i64,
                "day" => day as i64,
                "hour" => hour,
                "minute" => minute,
                "second" => second,
                "microsecond" => micros_remainder,
                "millisecond" => micros_remainder / 1000,
                "dow" | "dayofweek" => {
                    // 0 = Sunday, 1 = Monday, etc. (epoch was Thursday = 4)
                    ((days_since_epoch + 4) % 7) as i64
                }
                "doy" | "dayofyear" => {
                    // Day of year (1-366)
                    day_of_year(year, month as u32, day as u32) as i64
                }
                "week" => {
                    // ISO week number
                    iso_week_number(year, month as u32, day as u32) as i64
                }
                "quarter" => ((month - 1) / 3 + 1) as i64,
                "epoch" => total_secs,
                _ => return Ok(ComputedValue::Null),
            };
            Ok(ComputedValue::Integer(result))
        }
        ScalarFunction::ToTimestamp(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Integer(i) => Ok(ComputedValue::Timestamp(i * 1_000_000)), // seconds to micros
                ComputedValue::Float(f) => Ok(ComputedValue::Timestamp((f * 1_000_000.0) as i64)),
                ComputedValue::String(s) => {
                    // Try to parse as Unix timestamp
                    if let Ok(ts) = s.parse::<i64>() {
                        Ok(ComputedValue::Timestamp(ts * 1_000_000))
                    } else {
                        Ok(ComputedValue::Null)
                    }
                }
                ComputedValue::Timestamp(ts) => Ok(ComputedValue::Timestamp(ts)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::FromUnixtime(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Integer(i) => Ok(ComputedValue::Timestamp(i * 1_000_000)),
                ComputedValue::Float(f) => Ok(ComputedValue::Timestamp((f * 1_000_000.0) as i64)),
                ComputedValue::Null => Ok(ComputedValue::Null),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::ToString(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            match val {
                ComputedValue::Null => Ok(ComputedValue::Null),
                ComputedValue::Timestamp(ts) => {
                    // Format timestamp as ISO 8601 string
                    let secs = ts / 1_000_000;
                    let micros = (ts % 1_000_000) as u32;
                    let days = secs / 86400;
                    let time_secs = secs % 86400;
                    let (year, month, day) = days_to_ymd(days as i32);
                    let hour = time_secs / 3600;
                    let minute = (time_secs % 3600) / 60;
                    let second = time_secs % 60;
                    Ok(ComputedValue::String(format!(
                        "{:04}-{:02}-{:02} {:02}:{:02}:{:02}.{:06}",
                        year, month, day, hour, minute, second, micros
                    )))
                }
                ComputedValue::Date(days) => {
                    let (year, month, day) = days_to_ymd(days);
                    Ok(ComputedValue::String(format!("{:04}-{:02}-{:02}", year, month, day)))
                }
                _ => Ok(ComputedValue::String(val.to_string_value())),
            }
        }

        // JSON functions
        ScalarFunction::JsonExtract { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match json_extract(&json_str, path) {
                Some(v) => Ok(ComputedValue::String(v)),
                None => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonExtractScalar { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match json_extract_scalar(&json_str, path) {
                Some(v) => Ok(ComputedValue::String(v)),
                None => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonExtractAll { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match json_extract_all(&json_str, path) {
                Some(v) => Ok(ComputedValue::String(v)),
                None => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonArray(exprs) => {
            let mut values = Vec::new();
            for e in exprs {
                let val = evaluate_expr(e, ctx)?;
                values.push(computed_value_to_json_value(&val));
            }
            Ok(ComputedValue::String(
                serde_json::to_string(&values).unwrap_or_else(|_| "[]".to_string()),
            ))
        }
        ScalarFunction::JsonObject(pairs) => {
            let mut map = serde_json::Map::new();
            for (key, expr) in pairs {
                let val = evaluate_expr(expr, ctx)?;
                map.insert(key.clone(), computed_value_to_json_value(&val));
            }
            Ok(ComputedValue::String(
                serde_json::to_string(&map).unwrap_or_else(|_| "{}".to_string()),
            ))
        }
        ScalarFunction::JsonType(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::String("NULL".to_string())),
                _ => return Ok(ComputedValue::Null),
            };
            let type_str = match serde_json::from_str::<serde_json::Value>(&json_str) {
                Ok(serde_json::Value::Null) => "NULL",
                Ok(serde_json::Value::Bool(_)) => "BOOLEAN",
                Ok(serde_json::Value::Number(_)) => "NUMBER",
                Ok(serde_json::Value::String(_)) => "STRING",
                Ok(serde_json::Value::Array(_)) => "ARRAY",
                Ok(serde_json::Value::Object(_)) => "OBJECT",
                Err(_) => "INVALID",
            };
            Ok(ComputedValue::String(type_str.to_string()))
        }
        ScalarFunction::JsonContainsPath { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Boolean(false)),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let exists = json_path_exists(&json_str, path);
            Ok(ComputedValue::Boolean(exists))
        }
        ScalarFunction::JsonArrayLength(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match serde_json::from_str::<serde_json::Value>(&json_str) {
                Ok(serde_json::Value::Array(arr)) => Ok(ComputedValue::Integer(arr.len() as i64)),
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonKeys(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match serde_json::from_str::<serde_json::Value>(&json_str) {
                Ok(serde_json::Value::Object(obj)) => {
                    let keys: Vec<serde_json::Value> =
                        obj.keys().map(|k| serde_json::Value::String(k.clone())).collect();
                    Ok(ComputedValue::String(
                        serde_json::to_string(&keys).unwrap_or_else(|_| "[]".to_string()),
                    ))
                }
                _ => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonValid(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Boolean(false)),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let is_valid = serde_json::from_str::<serde_json::Value>(&json_str).is_ok();
            Ok(ComputedValue::Boolean(is_valid))
        }
        ScalarFunction::JsonPretty(expr) => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match serde_json::from_str::<serde_json::Value>(&json_str) {
                Ok(v) => Ok(ComputedValue::String(
                    serde_json::to_string_pretty(&v).unwrap_or(json_str),
                )),
                Err(_) => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonContains { left, right } => {
            let left_val = evaluate_expr(left, ctx)?;
            let right_val = evaluate_expr(right, ctx)?;
            let left_str = match left_val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let right_str = match right_val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let contains = json_contains(&left_str, &right_str);
            Ok(ComputedValue::Boolean(contains))
        }
        ScalarFunction::JsonRemove { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Null),
            };
            match json_remove(&json_str, path) {
                Some(v) => Ok(ComputedValue::String(v)),
                None => Ok(ComputedValue::Null),
            }
        }
        ScalarFunction::JsonPathExists { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let path_val = evaluate_expr(path, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let path_str = match path_val {
                ComputedValue::String(s) => s,
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let exists = json_path_exists(&json_str, &path_str);
            Ok(ComputedValue::Boolean(exists))
        }
        ScalarFunction::JsonPathMatch { expr, path } => {
            let val = evaluate_expr(expr, ctx)?;
            let path_val = evaluate_expr(path, ctx)?;
            let json_str = match val {
                ComputedValue::String(s) => s,
                ComputedValue::Null => return Ok(ComputedValue::Null),
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            let path_str = match path_val {
                ComputedValue::String(s) => s,
                _ => return Ok(ComputedValue::Boolean(false)),
            };
            // For path match, we check if the path returns a truthy result
            let result = json_path_match(&json_str, &path_str);
            Ok(ComputedValue::Boolean(result))
        }

        // Default for unhandled functions
        _ => Ok(ComputedValue::Null),
    }
}

fn evaluate_case_expr(
    operand: &Option<Box<crate::sql::SelectExpr>>,
    when_clauses: &[(crate::sql::SelectExpr, crate::sql::SelectExpr)],
    else_result: &Option<Box<crate::sql::SelectExpr>>,
    ctx: &EvalContext,
) -> Result<ComputedValue, EngineError> {
    // If there's an operand, this is a simple CASE (CASE x WHEN y THEN z)
    if let Some(op_expr) = operand {
        let op_val = evaluate_expr(op_expr, ctx)?;
        for (when_expr, then_expr) in when_clauses {
            let when_val = evaluate_expr(when_expr, ctx)?;
            if computed_values_equal(&op_val, &when_val) {
                return evaluate_expr(then_expr, ctx);
            }
        }
    } else {
        // Searched CASE (CASE WHEN condition THEN result)
        for (when_expr, then_expr) in when_clauses {
            let when_val = evaluate_expr(when_expr, ctx)?;
            match when_val {
                ComputedValue::Boolean(true) => return evaluate_expr(then_expr, ctx),
                _ => continue,
            }
        }
    }

    // No match - return ELSE or NULL
    if let Some(else_expr) = else_result {
        evaluate_expr(else_expr, ctx)
    } else {
        Ok(ComputedValue::Null)
    }
}

// --- JSON Helper Functions ---

/// Convert a ComputedValue to a serde_json::Value
fn computed_value_to_json_value(val: &ComputedValue) -> serde_json::Value {
    match val {
        ComputedValue::Null => serde_json::Value::Null,
        ComputedValue::Boolean(b) => serde_json::Value::Bool(*b),
        ComputedValue::Integer(i) => serde_json::Value::Number((*i).into()),
        ComputedValue::Float(f) => {
            serde_json::Number::from_f64(*f)
                .map(serde_json::Value::Number)
                .unwrap_or(serde_json::Value::Null)
        }
        ComputedValue::String(s) => serde_json::Value::String(s.clone()),
        ComputedValue::Timestamp(ts) => serde_json::Value::Number((*ts).into()),
        ComputedValue::Date(d) => serde_json::Value::Number((*d as i64).into()),
        ComputedValue::Binary(b) => {
            // Encode binary as base64 string
            use base64::Engine;
            serde_json::Value::String(base64::engine::general_purpose::STANDARD.encode(b))
        }
        ComputedValue::Uuid(u) => {
            // Format UUID as hex string
            serde_json::Value::String(hex::encode(u))
        }
        ComputedValue::Decimal { value, scale, .. } => {
            // Convert decimal to float for JSON
            let divisor = 10_i128.pow(*scale as u32);
            let float_val = *value as f64 / divisor as f64;
            serde_json::Number::from_f64(float_val)
                .map(serde_json::Value::Number)
                .unwrap_or(serde_json::Value::Null)
        }
        ComputedValue::Json(s) => {
            // Parse the JSON string and return it directly
            serde_json::from_str(s).unwrap_or(serde_json::Value::String(s.clone()))
        }
    }
}

/// Extract a value from JSON using a JSONPath-like path
/// Supports paths like $.key, $.key.subkey, $[0], $.array[0].field
fn json_extract(json_str: &str, path: &str) -> Option<String> {
    let value: serde_json::Value = serde_json::from_str(json_str).ok()?;
    let result = navigate_json_path(&value, path)?;
    Some(result.to_string())
}

/// Extract a scalar value from JSON (returns unquoted string for strings)
fn json_extract_scalar(json_str: &str, path: &str) -> Option<String> {
    let value: serde_json::Value = serde_json::from_str(json_str).ok()?;
    let result = navigate_json_path(&value, path)?;
    match result {
        serde_json::Value::String(s) => Some(s.clone()),
        serde_json::Value::Null => None,
        v => Some(v.to_string()),
    }
}

/// Navigate a JSON value using a simple path (no wildcards/recursion)
/// Returns borrowed reference for efficiency
fn navigate_json_path<'a>(value: &'a serde_json::Value, path: &str) -> Option<&'a serde_json::Value> {
    let path = path.trim();
    if path.is_empty() || path == "$" {
        return Some(value);
    }

    // Remove leading $ if present
    let path = if path.starts_with("$.") {
        &path[2..]
    } else if path.starts_with('$') {
        &path[1..]
    } else {
        path
    };

    let mut current = value;
    let mut remaining = path;

    while !remaining.is_empty() {
        // Skip leading dots
        if remaining.starts_with('.') {
            remaining = &remaining[1..];
        }

        if remaining.starts_with('[') {
            // Array index
            let end = remaining.find(']')?;
            let index_str = &remaining[1..end];
            // Simple numeric index only
            let index: usize = index_str.parse().ok()?;
            current = current.get(index)?;
            remaining = &remaining[end + 1..];
        } else {
            // Object key
            let end = remaining.find(|c| c == '.' || c == '[').unwrap_or(remaining.len());
            let key = &remaining[..end];
            if key.is_empty() {
                break;
            }
            current = current.get(key)?;
            remaining = &remaining[end..];
        }
    }

    Some(current)
}

/// Navigate JSON with advanced JSONPath support
/// Returns multiple values for wildcards, slices, and recursive descent
fn navigate_json_path_multi(value: &serde_json::Value, path: &str) -> Vec<serde_json::Value> {
    let path = path.trim();
    if path.is_empty() || path == "$" {
        return vec![value.clone()];
    }

    // Remove leading $ if present
    let path = if path.starts_with("$.") {
        &path[2..]
    } else if path.starts_with('$') {
        &path[1..]
    } else {
        path
    };

    navigate_path_impl(value, path)
}

/// Internal implementation of path navigation
fn navigate_path_impl(value: &serde_json::Value, path: &str) -> Vec<serde_json::Value> {
    if path.is_empty() {
        return vec![value.clone()];
    }

    let mut remaining = path;

    // Skip leading dots
    while remaining.starts_with('.') && !remaining.starts_with("..") {
        remaining = &remaining[1..];
    }

    if remaining.is_empty() {
        return vec![value.clone()];
    }

    // Handle recursive descent (..)
    if remaining.starts_with("..") {
        remaining = &remaining[2..];
        let mut results = Vec::new();

        // Find next path component
        let next_end = remaining.find(|c| c == '.' || c == '[').unwrap_or(remaining.len());
        let next_key = &remaining[..next_end];
        let rest = &remaining[next_end..];

        // Recursive descent: search all levels
        collect_recursive_descent(value, next_key, rest, &mut results);
        return results;
    }

    // Handle array access
    if remaining.starts_with('[') {
        let end = match remaining.find(']') {
            Some(e) => e,
            None => return vec![],
        };
        let bracket_content = &remaining[1..end];
        let rest = &remaining[end + 1..];

        // Wildcard [*]
        if bracket_content == "*" {
            if let serde_json::Value::Array(arr) = value {
                let mut results = Vec::new();
                for elem in arr {
                    results.extend(navigate_path_impl(elem, rest));
                }
                return results;
            }
            return vec![];
        }

        // Array slice [start:end] or [start:end:step]
        if bracket_content.contains(':') {
            if let serde_json::Value::Array(arr) = value {
                let slice_results = parse_and_apply_slice(arr, bracket_content);
                let mut results = Vec::new();
                for elem in slice_results {
                    results.extend(navigate_path_impl(&elem, rest));
                }
                return results;
            }
            return vec![];
        }

        // Filter expression [?(@.field > value)]
        if bracket_content.starts_with("?(") && bracket_content.ends_with(')') {
            if let serde_json::Value::Array(arr) = value {
                let filter_expr = &bracket_content[2..bracket_content.len() - 1];
                let filtered: Vec<_> = arr
                    .iter()
                    .filter(|elem| evaluate_json_filter(elem, filter_expr))
                    .cloned()
                    .collect();
                let mut results = Vec::new();
                for elem in filtered {
                    results.extend(navigate_path_impl(&elem, rest));
                }
                return results;
            }
            return vec![];
        }

        // Negative index (last element)
        if bracket_content.starts_with('-') {
            if let serde_json::Value::Array(arr) = value {
                if let Ok(neg_idx) = bracket_content.parse::<i64>() {
                    let idx = (arr.len() as i64 + neg_idx) as usize;
                    if idx < arr.len() {
                        return navigate_path_impl(&arr[idx], rest);
                    }
                }
            }
            return vec![];
        }

        // Simple numeric index
        if let Ok(index) = bracket_content.parse::<usize>() {
            if let Some(elem) = value.get(index) {
                return navigate_path_impl(elem, rest);
            }
        }

        return vec![];
    }

    // Object key access
    let end = remaining.find(|c| c == '.' || c == '[').unwrap_or(remaining.len());
    let key = &remaining[..end];
    let rest = &remaining[end..];

    if key.is_empty() {
        return vec![value.clone()];
    }

    // Wildcard key access (*)
    if key == "*" {
        let mut results = Vec::new();
        match value {
            serde_json::Value::Object(map) => {
                for v in map.values() {
                    results.extend(navigate_path_impl(v, rest));
                }
            }
            serde_json::Value::Array(arr) => {
                for v in arr {
                    results.extend(navigate_path_impl(v, rest));
                }
            }
            _ => {}
        }
        return results;
    }

    // Regular key access
    if let Some(v) = value.get(key) {
        return navigate_path_impl(v, rest);
    }

    vec![]
}

/// Collect values using recursive descent
fn collect_recursive_descent(
    value: &serde_json::Value,
    target_key: &str,
    rest: &str,
    results: &mut Vec<serde_json::Value>,
) {
    // Check if current value matches
    if let Some(v) = value.get(target_key) {
        results.extend(navigate_path_impl(v, rest));
    }

    // Recursively search children
    match value {
        serde_json::Value::Object(map) => {
            for v in map.values() {
                collect_recursive_descent(v, target_key, rest, results);
            }
        }
        serde_json::Value::Array(arr) => {
            for elem in arr {
                collect_recursive_descent(elem, target_key, rest, results);
            }
        }
        _ => {}
    }
}

/// Parse and apply array slice [start:end] or [start:end:step]
fn parse_and_apply_slice(arr: &[serde_json::Value], slice_expr: &str) -> Vec<serde_json::Value> {
    let parts: Vec<&str> = slice_expr.split(':').collect();
    let len = arr.len() as i64;

    let start = if parts.is_empty() || parts[0].is_empty() {
        0i64
    } else {
        parts[0].parse::<i64>().unwrap_or(0)
    };

    let end = if parts.len() < 2 || parts[1].is_empty() {
        len
    } else {
        parts[1].parse::<i64>().unwrap_or(len)
    };

    let step = if parts.len() < 3 || parts[2].is_empty() {
        1i64
    } else {
        parts[2].parse::<i64>().unwrap_or(1).max(1)
    };

    // Normalize negative indices
    let start = if start < 0 { (len + start).max(0) } else { start.min(len) } as usize;
    let end = if end < 0 { (len + end).max(0) } else { end.min(len) } as usize;

    if start >= end || step <= 0 {
        return vec![];
    }

    let mut result = Vec::new();
    let mut i = start;
    while i < end {
        if i < arr.len() {
            result.push(arr[i].clone());
        }
        i += step as usize;
    }
    result
}

/// Evaluate a JSONPath filter expression
fn evaluate_json_filter(value: &serde_json::Value, filter_expr: &str) -> bool {
    let expr = filter_expr.trim();

    // Parse simple comparisons: @.field op value
    if let Some((lhs, rest)) = expr.split_once(|c| c == '=' || c == '>' || c == '<' || c == '!') {
        let lhs = lhs.trim();
        let (op, rhs) = if rest.starts_with('=') {
            let rhs = rest[1..].trim();
            if filter_expr.contains("!=") {
                ("!=", rhs)
            } else if filter_expr.contains(">=") {
                (">=", rhs)
            } else if filter_expr.contains("<=") {
                ("<=", rhs)
            } else {
                ("==", rhs)
            }
        } else {
            let rhs = rest.trim();
            if filter_expr.contains('>') && !filter_expr.contains(">=") {
                (">", rhs)
            } else if filter_expr.contains('<') && !filter_expr.contains("<=") {
                ("<", rhs)
            } else {
                return false;
            }
        };

        // Get value from @ path
        let lhs_value = if lhs.starts_with("@.") {
            let path = &lhs[2..];
            value.get(path)
        } else if lhs == "@" {
            Some(value)
        } else {
            None
        };

        let lhs_value = match lhs_value {
            Some(v) => v,
            None => return false,
        };

        // Parse right-hand side
        let rhs = rhs.trim_matches(|c| c == '\'' || c == '"');

        match op {
            "==" => compare_json_values(lhs_value, rhs, |a, b| a == b, |a, b| a == b),
            "!=" => compare_json_values(lhs_value, rhs, |a, b| a != b, |a, b| a != b),
            ">" => compare_json_values(lhs_value, rhs, |a, b| a > b, |a, b| a > b),
            ">=" => compare_json_values(lhs_value, rhs, |a, b| a >= b, |a, b| a >= b),
            "<" => compare_json_values(lhs_value, rhs, |a, b| a < b, |a, b| a < b),
            "<=" => compare_json_values(lhs_value, rhs, |a, b| a <= b, |a, b| a <= b),
            _ => false,
        }
    } else {
        // Check for existence: @.field
        if expr.starts_with("@.") {
            let path = &expr[2..];
            value.get(path).is_some()
        } else {
            false
        }
    }
}

/// Compare JSON value against string literal
fn compare_json_values<F1, F2>(json_val: &serde_json::Value, rhs: &str, num_cmp: F1, str_cmp: F2) -> bool
where
    F1: Fn(f64, f64) -> bool,
    F2: Fn(&str, &str) -> bool,
{
    match json_val {
        serde_json::Value::Number(n) => {
            if let Ok(rhs_num) = rhs.parse::<f64>() {
                if let Some(lhs_num) = n.as_f64() {
                    return num_cmp(lhs_num, rhs_num);
                }
            }
            false
        }
        serde_json::Value::String(s) => str_cmp(s.as_str(), rhs),
        serde_json::Value::Bool(b) => {
            let rhs_bool = rhs == "true";
            str_cmp(&b.to_string(), &rhs_bool.to_string())
        }
        serde_json::Value::Null => rhs == "null",
        _ => false,
    }
}

/// Extract multiple values as a JSON array (for [*] and .. paths)
fn json_extract_all(json_str: &str, path: &str) -> Option<String> {
    let value: serde_json::Value = serde_json::from_str(json_str).ok()?;
    let results = navigate_json_path_multi(&value, path);
    if results.is_empty() {
        None
    } else if results.len() == 1 {
        Some(results[0].to_string())
    } else {
        Some(serde_json::Value::Array(results).to_string())
    }
}

/// Check if a path exists in JSON
fn json_path_exists(json_str: &str, path: &str) -> bool {
    let value: serde_json::Value = match serde_json::from_str(json_str) {
        Ok(v) => v,
        Err(_) => return false,
    };
    navigate_json_path(&value, path).is_some()
}

/// Check if left JSON contains right JSON (PostgreSQL @> semantics)
fn json_contains(left_str: &str, right_str: &str) -> bool {
    let left: serde_json::Value = match serde_json::from_str(left_str) {
        Ok(v) => v,
        Err(_) => return false,
    };
    let right: serde_json::Value = match serde_json::from_str(right_str) {
        Ok(v) => v,
        Err(_) => return false,
    };
    json_value_contains(&left, &right)
}

/// Recursively check if left contains right
fn json_value_contains(left: &serde_json::Value, right: &serde_json::Value) -> bool {
    match (left, right) {
        // Arrays: left must contain all elements of right
        (serde_json::Value::Array(l_arr), serde_json::Value::Array(r_arr)) => {
            r_arr.iter().all(|r_elem| {
                l_arr.iter().any(|l_elem| json_value_contains(l_elem, r_elem))
            })
        }
        // Objects: left must have all keys from right with matching values
        (serde_json::Value::Object(l_obj), serde_json::Value::Object(r_obj)) => {
            r_obj.iter().all(|(k, r_val)| {
                l_obj.get(k).map(|l_val| json_value_contains(l_val, r_val)).unwrap_or(false)
            })
        }
        // Scalars: must be equal
        _ => left == right,
    }
}

/// Remove a path from JSON
fn json_remove(json_str: &str, path: &str) -> Option<String> {
    let mut value: serde_json::Value = serde_json::from_str(json_str).ok()?;

    let path = path.trim();
    let path = if path.starts_with("$.") {
        &path[2..]
    } else if path.starts_with('$') {
        &path[1..]
    } else {
        path
    };

    // Parse path into components
    let mut components = Vec::new();
    let mut remaining = path;
    while !remaining.is_empty() {
        if remaining.starts_with('.') {
            remaining = &remaining[1..];
        }
        if remaining.starts_with('[') {
            let end = remaining.find(']')?;
            let index_str = &remaining[1..end];
            components.push(PathComponent::Index(index_str.parse().ok()?));
            remaining = &remaining[end + 1..];
        } else {
            let end = remaining.find(|c| c == '.' || c == '[').unwrap_or(remaining.len());
            let key = &remaining[..end];
            if !key.is_empty() {
                components.push(PathComponent::Key(key.to_string()));
            }
            remaining = &remaining[end..];
        }
    }

    if components.is_empty() {
        return None;
    }

    // Navigate to parent and remove the last component
    let last = components.pop()?;
    let mut current = &mut value;

    for comp in &components {
        current = match comp {
            PathComponent::Key(k) => current.get_mut(k)?,
            PathComponent::Index(i) => current.get_mut(*i)?,
        };
    }

    match last {
        PathComponent::Key(k) => {
            if let serde_json::Value::Object(obj) = current {
                obj.remove(&k);
            }
        }
        PathComponent::Index(i) => {
            if let serde_json::Value::Array(arr) = current {
                if i < arr.len() {
                    arr.remove(i);
                }
            }
        }
    }

    serde_json::to_string(&value).ok()
}

#[derive(Debug)]
enum PathComponent {
    Key(String),
    Index(usize),
}

/// JSON path match (simplified implementation)
fn json_path_match(json_str: &str, path_str: &str) -> bool {
    // This is a simplified implementation that checks if the path expression
    // returns a truthy value. A full implementation would need a JSONPath parser.
    let value: serde_json::Value = match serde_json::from_str(json_str) {
        Ok(v) => v,
        Err(_) => return false,
    };

    // Simple path matching: just check if the path exists and has a truthy value
    if let Some(result) = navigate_json_path(&value, path_str) {
        match result {
            serde_json::Value::Null => false,
            serde_json::Value::Bool(b) => *b,
            serde_json::Value::Number(n) => n.as_f64().map(|f| f != 0.0).unwrap_or(false),
            serde_json::Value::String(s) => !s.is_empty(),
            serde_json::Value::Array(a) => !a.is_empty(),
            serde_json::Value::Object(o) => !o.is_empty(),
        }
    } else {
        false
    }
}

// --- Date/Time Helper Functions ---

/// Convert interval value and unit to microseconds
fn interval_to_micros(interval: i64, unit: &str) -> i64 {
    match unit.to_lowercase().as_str() {
        "microsecond" | "microseconds" => interval,
        "millisecond" | "milliseconds" => interval * 1_000,
        "second" | "seconds" => interval * 1_000_000,
        "minute" | "minutes" => interval * 60 * 1_000_000,
        "hour" | "hours" => interval * 3600 * 1_000_000,
        "day" | "days" => interval * 86400 * 1_000_000,
        "week" | "weeks" => interval * 7 * 86400 * 1_000_000,
        "month" | "months" => interval * 30 * 86400 * 1_000_000, // Approximation
        "year" | "years" => interval * 365 * 86400 * 1_000_000,  // Approximation
        _ => interval * 86400 * 1_000_000, // Default to days
    }
}

/// Parse a date string (YYYY-MM-DD) to days since Unix epoch
fn parse_date_to_days(s: &str) -> Option<i32> {
    let parts: Vec<&str> = s.split('-').collect();
    if parts.len() != 3 {
        return None;
    }
    let year: i32 = parts[0].parse().ok()?;
    let month: u32 = parts[1].parse().ok()?;
    let day: u32 = parts[2].parse().ok()?;

    if month < 1 || month > 12 || day < 1 || day > 31 {
        return None;
    }

    Some(ymd_to_days(year, month, day))
}

/// Convert days since Unix epoch to (year, month, day)
fn days_to_ymd(days: i32) -> (i32, i32, i32) {
    // Algorithm based on Howard Hinnant's date algorithms
    // http://howardhinnant.github.io/date_algorithms.html
    let z = days + 719468;
    let era = if z >= 0 { z } else { z - 146096 } / 146097;
    let doe = (z - era * 146097) as u32; // day of era
    let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146096) / 365; // year of era
    let y = yoe as i32 + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100); // day of year
    let mp = (5 * doy + 2) / 153;
    let d = doy - (153 * mp + 2) / 5 + 1;
    let m = if mp < 10 { mp + 3 } else { mp - 9 };
    let year = if m <= 2 { y + 1 } else { y };
    (year, m as i32, d as i32)
}

/// Convert (year, month, day) to days since Unix epoch
fn ymd_to_days(year: i32, month: u32, day: u32) -> i32 {
    let y = if month <= 2 { year - 1 } else { year };
    let era = if y >= 0 { y } else { y - 399 } / 400;
    let yoe = (y - era * 400) as u32;
    let m = month;
    let doy = (153 * (if m > 2 { m - 3 } else { m + 9 }) + 2) / 5 + day - 1;
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
    era * 146097 + doe as i32 - 719468
}

/// Calculate day of year (1-366)
fn day_of_year(year: i32, month: u32, day: u32) -> u32 {
    let is_leap = (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0);
    let days_before_month = [0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334];
    let mut doy = days_before_month[(month - 1) as usize] + day;
    if is_leap && month > 2 {
        doy += 1;
    }
    doy
}

/// Calculate ISO week number
fn iso_week_number(year: i32, month: u32, day: u32) -> u32 {
    let days = ymd_to_days(year, month, day);
    let dow = ((days + 4) % 7) as u32; // 0 = Sunday
    let dow_monday = if dow == 0 { 6 } else { dow - 1 }; // Convert to 0 = Monday

    // Find the Thursday of this week
    let thursday = days + (3 - dow_monday as i32);
    let (thu_year, _, _) = days_to_ymd(thursday);

    // Find January 4th of that year (always in week 1)
    let jan4 = ymd_to_days(thu_year, 1, 4);
    let jan4_dow = ((jan4 + 4) % 7) as i32;
    let jan4_monday = if jan4_dow == 0 { 6 } else { jan4_dow - 1 };
    let week1_monday = jan4 - jan4_monday;

    // Calculate week number
    ((thursday - week1_monday) / 7 + 1) as u32
}

// --- RESTORED UTILITIES ---

/// Result of deep segment scrubbing
#[derive(Debug, Default)]
pub struct DeepScrubResult {
    /// Number of segments that passed all validation checks
    pub valid_count: usize,
    /// Segments that are missing from disk
    pub missing: Vec<String>,
    /// Segments with checksum mismatch
    pub checksum_mismatch: Vec<String>,
    /// Segments with invalid IPC format
    pub ipc_invalid: Vec<String>,
    /// Segments with schema hash mismatch
    pub schema_mismatch: Vec<String>,
    /// Segments where decompression failed
    pub decompression_failed: Vec<String>,
    /// Segments with compression type mismatch
    pub compression_mismatch: Vec<String>,
    /// Segments with read errors
    pub read_errors: Vec<String>,
}

impl DeepScrubResult {
    /// Total number of issues found
    pub fn total_issues(&self) -> usize {
        self.missing.len()
            + self.checksum_mismatch.len()
            + self.ipc_invalid.len()
            + self.schema_mismatch.len()
            + self.decompression_failed.len()
            + self.compression_mismatch.len()
            + self.read_errors.len()
    }

    /// Get all corrupted segment IDs
    pub fn all_corrupted(&self) -> Vec<String> {
        let mut all = Vec::new();
        all.extend(self.missing.clone());
        all.extend(self.checksum_mismatch.clone());
        all.extend(self.ipc_invalid.clone());
        all.extend(self.schema_mismatch.clone());
        all.extend(self.decompression_failed.clone());
        all.extend(self.compression_mismatch.clone());
        all.extend(self.read_errors.clone());
        all
    }

    /// Check if any issues were found
    pub fn has_issues(&self) -> bool {
        self.total_issues() > 0
    }
}

