pub struct SchemaWrapper {
    pub json: String,
    pub hash: u64,
}

pub fn is_valid_ident(s: &str) -> bool {
    s.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') && !s.is_empty()
}

/// Compute checksum for data integrity verification using xxHash64.
/// xxHash64 provides better collision resistance than CRC32 while maintaining high speed.
pub fn compute_checksum(data: &[u8]) -> u64 {
    xxhash_rust::xxh64::xxh64(data, 0)
}

/// Legacy CRC32 checksum for backward compatibility with older segments.
/// Used only for reading old segments; new segments use xxHash64.
pub fn compute_checksum_crc32(data: &[u8]) -> u64 {
    let mut hasher = Crc32Hasher::new();
    hasher.update(data);
    hasher.finalize() as u64
}

pub fn compute_schema_hash_from_payload(
    data: &[u8],
    compression: Option<&str>,
) -> Result<u64, EngineError> {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};

    // Decompress if needed
    let decompressed = decompress_payload(data.to_vec(), compression)?;

    // Parse IPC to get schema
    let batches = read_ipc_batches(&decompressed)?;
    if batches.is_empty() {
        return Ok(0);
    }

    let schema = batches[0].schema();

    // Build same JSON format as validate_and_stats (TableFieldSpec format)
    let schema_json = serde_json::to_string(
        &schema
            .fields()
            .iter()
            .map(|f| {
                let data_type_str = match f.data_type() {
                    DataType::Int8 => "int8",
                    DataType::Int16 => "int16",
                    DataType::Int32 => "int32",
                    DataType::Int64 => "int64",
                    DataType::UInt8 => "uint8",
                    DataType::UInt16 => "uint16",
                    DataType::UInt32 => "uint32",
                    DataType::UInt64 => "uint64",
                    DataType::Float32 => "float32",
                    DataType::Float64 => "float64",
                    DataType::Boolean => "bool",
                    DataType::Utf8 => "string",
                    DataType::LargeUtf8 => "string",
                    DataType::Binary => "binary",
                    DataType::LargeBinary => "binary",
                    DataType::Date32 => "date",
                    DataType::Date64 => "date",
                    DataType::Timestamp(_, _) => "timestamp",
                    _ => "string",
                };
                serde_json::json!({
                    "name": f.name(),
                    "data_type": data_type_str,
                    "nullable": f.is_nullable()
                })
            })
            .collect::<Vec<_>>(),
    )
    .unwrap_or_default();

    // Compute hash
    let mut hasher = DefaultHasher::new();
    schema_json.hash(&mut hasher);
    Ok(hasher.finish())
}

pub fn read_ipc_batches(ipc: &[u8]) -> Result<Vec<RecordBatch>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use std::io::Cursor;
    let cursor = Cursor::new(ipc);
    let mut reader =
        StreamReader::try_new(cursor, None).map_err(|e| EngineError::Internal(format!("{e}")))?;
    let mut batches = Vec::new();
    while let Some(b) = reader.next() {
        batches.push(b.map_err(|e| EngineError::Internal(format!("{e}")))?);
    }
    Ok(batches)
}

/// Read IPC batches with column projection - only reads specified columns from disk
/// This provides significant I/O and memory savings when only a subset of columns is needed.
/// Returns all columns if projection is None or empty.
pub fn read_ipc_batches_with_projection(
    ipc: &[u8],
    projection: Option<&[String]>,
) -> Result<Vec<RecordBatch>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use std::io::Cursor;

    let cursor = Cursor::new(ipc);
    let reader_result =
        StreamReader::try_new(cursor, None).map_err(|e| EngineError::Internal(format!("{e}")))?;

    // If no projection or empty projection, read all columns
    let projection_cols = match projection {
        Some(cols) if !cols.is_empty() => cols,
        _ => return read_ipc_batches(ipc), // Fall back to full read
    };

    // Get schema to build projection mask
    let schema = reader_result.schema();
    let projection_indices: Vec<usize> = projection_cols
        .iter()
        .filter_map(|col| schema.index_of(col).ok())
        .collect();

    // If no valid columns found, return empty result
    if projection_indices.is_empty() {
        return Ok(Vec::new());
    }

    // Re-create reader with projection mask
    let cursor = Cursor::new(ipc);
    let mut reader = StreamReader::try_new(cursor, Some(projection_indices))
        .map_err(|e| EngineError::Internal(format!("{e}")))?;

    let mut batches = Vec::new();
    while let Some(b) = reader.next() {
        batches.push(b.map_err(|e| EngineError::Internal(format!("{e}")))?);
    }
    Ok(batches)
}

/// Validate IPC format integrity without fully parsing
/// Returns true if the IPC data appears valid
pub fn validate_ipc_format(ipc: &[u8]) -> Result<bool, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use std::io::Cursor;

    if ipc.is_empty() {
        return Ok(false);
    }

    // Try to create a reader - this validates the header
    let cursor = Cursor::new(ipc);
    match StreamReader::try_new(cursor, None) {
        Ok(mut reader) => {
            // Try to read at least one batch to validate structure
            match reader.next() {
                Some(Ok(_)) => Ok(true),
                Some(Err(e)) => {
                    tracing::warn!("IPC validation failed: {}", e);
                    Ok(false)
                }
                None => Ok(true), // Empty but valid IPC
            }
        }
        Err(e) => {
            tracing::warn!("IPC header validation failed: {}", e);
            Ok(false)
        }
    }
}

/// Segment checksum journal entry
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ChecksumJournalEntry {
    pub segment_id: String,
    pub checksum: u64,
    pub schema_hash: u64,
    pub size_bytes: u64,
    pub timestamp_secs: u64,
    pub compression: Option<String>,
}

/// Segment checksum journal for redundant integrity tracking
#[derive(Debug)]
pub struct SegmentChecksumJournal {
    path: PathBuf,
    entries: parking_lot::RwLock<HashMap<String, ChecksumJournalEntry>>,
}

impl SegmentChecksumJournal {
    pub fn new(path: PathBuf) -> Result<Self, EngineError> {
        let entries = if path.exists() {
            match std::fs::read_to_string(&path) {
                Ok(content) => {
                    let mut map = HashMap::new();
                    for line in content.lines() {
                        if let Ok(entry) = serde_json::from_str::<ChecksumJournalEntry>(line) {
                            map.insert(entry.segment_id.clone(), entry);
                        }
                    }
                    map
                }
                Err(_) => HashMap::new(),
            }
        } else {
            HashMap::new()
        };

        Ok(Self {
            path,
            entries: parking_lot::RwLock::new(entries),
        })
    }

    /// Record a segment's checksum in the journal
    pub fn record(
        &self,
        segment_id: &str,
        checksum: u64,
        schema_hash: u64,
        size_bytes: u64,
        compression: Option<&str>,
    ) -> Result<(), EngineError> {
        let entry = ChecksumJournalEntry {
            segment_id: segment_id.to_string(),
            checksum,
            schema_hash,
            size_bytes,
            timestamp_secs: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .map(|d| d.as_secs())
                .unwrap_or(0),
            compression: compression.map(String::from),
        };

        // Update in-memory map
        self.entries.write().insert(segment_id.to_string(), entry.clone());

        // Append to journal file
        let line = serde_json::to_string(&entry)
            .map_err(|e| EngineError::Internal(format!("serialize journal entry: {}", e)))?;

        let mut file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&self.path)
            .map_err(|e| EngineError::Io(format!("open checksum journal: {}", e)))?;

        writeln!(file, "{}", line)
            .map_err(|e| EngineError::Io(format!("write checksum journal: {}", e)))?;

        file.sync_all()
            .map_err(|e| EngineError::Io(format!("sync checksum journal: {}", e)))?;

        Ok(())
    }

    /// Verify a segment's checksum against the journal
    pub fn verify(&self, segment_id: &str, actual_checksum: u64) -> Option<bool> {
        self.entries.read().get(segment_id).map(|entry| entry.checksum == actual_checksum)
    }

    /// Get the expected checksum for a segment
    pub fn get_expected(&self, segment_id: &str) -> Option<u64> {
        self.entries.read().get(segment_id).map(|e| e.checksum)
    }

    /// Remove a segment from the journal
    pub fn remove(&self, segment_id: &str) {
        self.entries.write().remove(segment_id);
    }

    /// Compact the journal file (rewrite without deleted entries)
    pub fn compact(&self) -> Result<(), EngineError> {
        let entries: Vec<_> = self.entries.read().values().cloned().collect();

        let tmp_path = self.path.with_extension("tmp");
        {
            let mut file = OpenOptions::new()
                .create(true)
                .write(true)
                .truncate(true)
                .open(&tmp_path)
                .map_err(|e| EngineError::Io(format!("create tmp journal: {}", e)))?;

            for entry in entries {
                let line = serde_json::to_string(&entry)
                    .map_err(|e| EngineError::Internal(format!("serialize: {}", e)))?;
                writeln!(file, "{}", line)
                    .map_err(|e| EngineError::Io(format!("write: {}", e)))?;
            }

            file.sync_all()
                .map_err(|e| EngineError::Io(format!("sync: {}", e)))?;
        }

        std::fs::rename(&tmp_path, &self.path)
            .map_err(|e| EngineError::Io(format!("rename journal: {}", e)))?;

        Ok(())
    }
}

pub fn record_batches_to_ipc(
    schema: &arrow_schema::Schema,
    batches: &[RecordBatch],
) -> Result<Vec<u8>, EngineError> {
    use arrow_ipc::writer::StreamWriter;
    let mut buf = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut buf, schema)
            .map_err(|e| EngineError::Internal(format!("{e}")))?;
        for b in batches {
            writer
                .write(b)
                .map_err(|e| EngineError::Internal(format!("{e}")))?;
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("{e}")))?;
    }
    Ok(buf)
}

pub fn parse_where_filter(where_clause: Option<&str>) -> Result<QueryFilter, EngineError> {
    let mut filter = QueryFilter::default();

    let clause = match where_clause {
        Some(c) if !c.trim().is_empty() => c.trim(),
        _ => return Ok(filter),
    };

    // Split by " AND " (case insensitive)
    let parts: Vec<&str> = if clause.to_uppercase().contains(" AND ") {
        let upper = clause.to_uppercase();
        let indices: Vec<_> = upper.match_indices(" AND ").map(|(i, _)| i).collect();
        let mut parts = Vec::new();
        let mut start = 0;
        for idx in indices {
            parts.push(&clause[start..idx]);
            start = idx + 5; // " AND " is 5 chars
        }
        parts.push(&clause[start..]);
        parts
    } else {
        vec![clause]
    };

    for part in parts {
        let part = part.trim();
        if part.is_empty() {
            continue;
        }

        // Parse: column = value
        if let Some(eq_idx) = part.find('=') {
            // Make sure it's not != or >=, <=
            let before = if eq_idx > 0 {
                part.chars().nth(eq_idx - 1)
            } else {
                None
            };
            if before == Some('!') || before == Some('>') || before == Some('<') {
                continue;
            }

            let column = part[..eq_idx].trim();
            let value = part[eq_idx + 1..].trim();

            // Check for boolean values
            if value.eq_ignore_ascii_case("true") {
                filter.bool_eq_filters.push((column.to_string(), true));
            } else if value.eq_ignore_ascii_case("false") {
                filter.bool_eq_filters.push((column.to_string(), false));
            }
            // Check for string literals (quoted)
            else if (value.starts_with('\'') && value.ends_with('\''))
                || (value.starts_with('"') && value.ends_with('"'))
            {
                let val = &value[1..value.len() - 1];
                filter
                    .string_eq_filters
                    .push((column.to_string(), val.to_string()));
            }
            // Check for float literals
            else if value.contains('.') {
                if let Ok(f) = value.parse::<f64>() {
                    filter.float_eq_filters.push((column.to_string(), f));
                }
            }
            // Check for integer literals
            else if let Ok(i) = value.parse::<i128>() {
                filter.numeric_eq_filters.push((column.to_string(), i));
            }
        }
    }

    Ok(filter)
}

pub fn filter_is_empty(filter: &QueryFilter) -> bool {
    filter.tenant_id_eq.is_none()
        && filter.route_id_eq.is_none()
        && filter.numeric_eq_filters.is_empty()
        && filter.string_eq_filters.is_empty()
        && filter.like_filters.is_empty()
}

/// Build a WHERE clause for FK cascade operations from column values
fn build_fk_where_clause(columns: &[String], values: &[Vec<SqlValue>]) -> Option<String> {
    if values.is_empty() || columns.is_empty() {
        return None;
    }

    let conditions: Vec<String> = values
        .iter()
        .filter_map(|row| {
            if row.len() != columns.len() {
                return None;
            }

            let row_conds: Vec<String> = columns
                .iter()
                .zip(row.iter())
                .filter_map(|(col, val)| {
                    let val_str = match val {
                        SqlValue::Null => return None, // Can't match NULL with =
                        SqlValue::Integer(i) => i.to_string(),
                        SqlValue::Float(f) => f.to_string(),
                        SqlValue::String(s) => format!("'{}'", s.replace('\'', "''")),
                        SqlValue::Boolean(b) => if *b { "true" } else { "false" }.to_string(),
                    };
                    Some(format!("{} = {}", col, val_str))
                })
                .collect();

            if row_conds.len() == columns.len() {
                Some(format!("({})", row_conds.join(" AND ")))
            } else {
                None
            }
        })
        .collect();

    if conditions.is_empty() {
        None
    } else {
        Some(conditions.join(" OR "))
    }
}

/// Extract a SqlValue from an Arrow array at the given row index
fn extract_sql_value_from_array(array: &ArrayRef, row: usize) -> SqlValue {
    if array.is_null(row) {
        return SqlValue::Null;
    }

    match array.data_type() {
        DataType::Int8 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int8Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::Int16 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int16Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::Int32 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::Int64 => {
            if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
                SqlValue::Integer(arr.value(row))
            } else {
                SqlValue::Null
            }
        }
        DataType::UInt8 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt8Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::UInt16 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt16Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::UInt32 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt32Array>() {
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::UInt64 => {
            if let Some(arr) = array.as_any().downcast_ref::<UInt64Array>() {
                // Note: may truncate for very large u64 values
                SqlValue::Integer(arr.value(row) as i64)
            } else {
                SqlValue::Null
            }
        }
        DataType::Float32 => {
            if let Some(arr) = array.as_any().downcast_ref::<Float32Array>() {
                SqlValue::Float(arr.value(row) as f64)
            } else {
                SqlValue::Null
            }
        }
        DataType::Float64 => {
            if let Some(arr) = array.as_any().downcast_ref::<Float64Array>() {
                SqlValue::Float(arr.value(row))
            } else {
                SqlValue::Null
            }
        }
        DataType::Utf8 | DataType::LargeUtf8 => {
            if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
                SqlValue::String(arr.value(row).to_string())
            } else {
                SqlValue::Null
            }
        }
        DataType::Boolean => {
            if let Some(arr) = array.as_any().downcast_ref::<BooleanArray>() {
                SqlValue::Boolean(arr.value(row))
            } else {
                SqlValue::Null
            }
        }
        DataType::Timestamp(_, _) => {
            // Store timestamp as integer (microseconds since epoch)
            if let Some(arr) = array.as_any().downcast_ref::<TimestampMicrosecondArray>() {
                SqlValue::Integer(arr.value(row))
            } else {
                SqlValue::Null
            }
        }
        _ => SqlValue::Null,
    }
}

/// Apply a filter to a batch and return a boolean mask
fn apply_filter_to_batch(
    batch: &RecordBatch,
    filter: &QueryFilter,
) -> Result<Option<BooleanArray>, EngineError> {
    use arrow::compute::and;
    use arrow_ord::cmp::eq as arr_eq;

    if filter_is_empty(filter) {
        return Ok(None); // No filter = all rows match
    }

    let num_rows = batch.num_rows();
    let mut mask: Option<BooleanArray> = None;

    // Apply numeric equality filters
    for (col, val) in &filter.numeric_eq_filters {
        if let Ok(idx) = batch.schema().index_of(col) {
            let array = batch.column(idx);
            let val_i64 = *val as i64;

            // Create comparison based on array type
            let cmp_result = if let Some(arr) = array.as_any().downcast_ref::<Int64Array>() {
                let scalar = Int64Array::new_scalar(val_i64);
                arr_eq(arr, &scalar).ok()
            } else if let Some(arr) = array.as_any().downcast_ref::<Int32Array>() {
                let scalar = Int32Array::new_scalar(val_i64 as i32);
                arr_eq(arr, &scalar).ok()
            } else {
                None
            };

            if let Some(cmp) = cmp_result {
                mask = Some(match mask {
                    Some(m) => and(&m, &cmp)
                        .map_err(|e| EngineError::Internal(format!("filter and failed: {}", e)))?,
                    None => cmp,
                });
            }
        }
    }

    // Apply string equality filters
    for (col, val) in &filter.string_eq_filters {
        if let Ok(idx) = batch.schema().index_of(col) {
            let array = batch.column(idx);
            if let Some(arr) = array.as_any().downcast_ref::<StringArray>() {
                let scalar = StringArray::new_scalar(val);
                if let Ok(cmp) = arr_eq(arr, &scalar) {
                    mask = Some(match mask {
                        Some(m) => and(&m, &cmp)
                            .map_err(|e| EngineError::Internal(format!("filter and failed: {}", e)))?,
                        None => cmp,
                    });
                }
            }
        }
    }

    Ok(mask)
}

pub fn filter_batch_for_delete(
    batch: &RecordBatch,
    filter: &QueryFilter,
) -> Result<(Option<RecordBatch>, usize), EngineError> {
    use arrow::compute::{and, filter_record_batch, not};
    use arrow_array::{Array, BooleanArray, Int64Array, UInt64Array};
    use arrow_ord::cmp::eq;

    let num_rows = batch.num_rows();
    if num_rows == 0 {
        return Ok((None, 0));
    }

    // Build a mask of rows to DELETE (true = delete this row)
    let mut delete_mask = BooleanArray::from(vec![false; num_rows]);

    // If no filter, delete all rows
    if filter_is_empty(filter) {
        return Ok((None, num_rows));
    }

    // Check tenant_id_eq filter
    if let Some(tid) = filter.tenant_id_eq {
        if let Some(col_idx) = batch.schema().index_of("tenant_id").ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let scalar = UInt64Array::new_scalar(tid);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                // If any previous delete conditions exist, OR them with this one
                if delete_mask.true_count() > 0 {
                    // Already have some deletes - this is unlikely on first filter
                } else {
                    delete_mask = matches;
                }
            }
        }
    }

    // Check tenant_id_in filter
    if let Some(ref tids) = filter.tenant_id_in {
        if let Some(col_idx) = batch.schema().index_of("tenant_id").ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let mut in_mask = BooleanArray::from(vec![false; num_rows]);
                for tid in tids {
                    let scalar = UInt64Array::new_scalar(*tid);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    in_mask = arrow::compute::or(&in_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("or error: {}", e)))?;
                }
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &in_mask)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = in_mask;
                }
            }
        }
    }

    // Check numeric_eq_filters
    for (col_name, value) in &filter.numeric_eq_filters {
        if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let scalar = UInt64Array::new_scalar(*value as u64);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = matches;
                }
            } else if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
                let scalar = Int64Array::new_scalar(*value as i64);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = matches;
                }
            }
        }
    }

    let deleted_count = delete_mask.true_count();
    if deleted_count == 0 {
        return Ok((Some(batch.clone()), 0));
    }

    if deleted_count == num_rows {
        return Ok((None, num_rows));
    }

    // Invert mask to get rows to KEEP
    let keep_mask =
        not(&delete_mask).map_err(|e| EngineError::Internal(format!("not error: {}", e)))?;

    // Filter batch to keep only non-deleted rows
    let filtered = filter_record_batch(batch, &keep_mask)
        .map_err(|e| EngineError::Internal(format!("filter batch error: {}", e)))?;

    Ok((Some(filtered), deleted_count))
}

/// Filter batch for delete and return BOTH kept rows and deleted rows.
/// Returns (kept_batch, deleted_batch, deleted_count).
pub fn filter_batch_for_delete_returning(
    batch: &RecordBatch,
    filter: &QueryFilter,
) -> Result<(Option<RecordBatch>, Option<RecordBatch>, usize), EngineError> {
    use arrow::compute::{and, filter_record_batch, not};
    use arrow_array::{Array, BooleanArray, Int64Array, UInt64Array};
    use arrow_ord::cmp::eq;

    let num_rows = batch.num_rows();
    if num_rows == 0 {
        return Ok((None, None, 0));
    }

    // Build a mask of rows to DELETE (true = delete this row)
    let mut delete_mask = BooleanArray::from(vec![false; num_rows]);

    // If no filter, delete all rows
    if filter_is_empty(filter) {
        return Ok((None, Some(batch.clone()), num_rows));
    }

    // Check tenant_id_eq filter
    if let Some(tid) = filter.tenant_id_eq {
        if let Some(col_idx) = batch.schema().index_of("tenant_id").ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let scalar = UInt64Array::new_scalar(tid);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() == 0 {
                    delete_mask = matches;
                }
            }
        }
    }

    // Check tenant_id_in filter
    if let Some(ref tids) = filter.tenant_id_in {
        if let Some(col_idx) = batch.schema().index_of("tenant_id").ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let mut in_mask = BooleanArray::from(vec![false; num_rows]);
                for tid in tids {
                    let scalar = UInt64Array::new_scalar(*tid);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    in_mask = arrow::compute::or(&in_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("or error: {}", e)))?;
                }
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &in_mask)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = in_mask;
                }
            }
        }
    }

    // Check numeric_eq_filters
    for (col_name, value) in &filter.numeric_eq_filters {
        if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                let scalar = UInt64Array::new_scalar(*value as u64);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = matches;
                }
            } else if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
                let scalar = Int64Array::new_scalar(*value as i64);
                let matches = eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = matches;
                }
            }
        }
    }

    // Check string_eq_filters
    for (col_name, value) in &filter.string_eq_filters {
        if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
            let col = batch.column(col_idx);
            if let Some(arr) = col.as_any().downcast_ref::<StringArray>() {
                let scalar = StringArray::new_scalar(value);
                let matches = arrow_ord::cmp::eq(arr, &scalar)
                    .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                if delete_mask.true_count() > 0 {
                    delete_mask = and(&delete_mask, &matches)
                        .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                } else {
                    delete_mask = matches;
                }
            }
        }
    }

    let deleted_count = delete_mask.true_count();
    if deleted_count == 0 {
        return Ok((Some(batch.clone()), None, 0));
    }

    if deleted_count == num_rows {
        return Ok((None, Some(batch.clone()), num_rows));
    }

    // Invert mask to get rows to KEEP
    let keep_mask =
        not(&delete_mask).map_err(|e| EngineError::Internal(format!("not error: {}", e)))?;

    // Filter batch to get kept rows
    let kept = filter_record_batch(batch, &keep_mask)
        .map_err(|e| EngineError::Internal(format!("filter batch error: {}", e)))?;

    // Filter batch to get deleted rows
    let deleted = filter_record_batch(batch, &delete_mask)
        .map_err(|e| EngineError::Internal(format!("filter batch error: {}", e)))?;

    Ok((Some(kept), Some(deleted), deleted_count))
}

/// Apply assignments to batch and return the updated rows.
/// Returns (full_updated_batch, updated_rows_only, count).
pub fn apply_assignments_to_batch_returning(
    batch: &RecordBatch,
    filter: &QueryFilter,
    assigns: &[(String, crate::sql::SqlValue)],
) -> Result<(RecordBatch, Option<RecordBatch>, usize), EngineError> {
    use crate::sql::SqlValue;
    use arrow::compute::{and, filter_record_batch};
    use arrow_array::{Array, BooleanArray, Int64Array, UInt64Array};
    use arrow_ord::cmp::eq;

    let num_rows = batch.num_rows();
    if num_rows == 0 || assigns.is_empty() {
        return Ok((batch.clone(), None, 0));
    }

    // Build a mask of rows to UPDATE (true = update this row)
    let mut update_mask = BooleanArray::from(vec![true; num_rows]); // Update all if no filter

    if !filter_is_empty(filter) {
        update_mask = BooleanArray::from(vec![false; num_rows]);

        // Check numeric_eq_filters
        for (col_name, value) in &filter.numeric_eq_filters {
            if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
                let col = batch.column(col_idx);
                if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                    let scalar = UInt64Array::new_scalar(*value as u64);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = matches;
                    }
                } else if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
                    let scalar = Int64Array::new_scalar(*value as i64);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = matches;
                    }
                }
            }
        }

        // Check string_eq_filters
        for (col_name, value) in &filter.string_eq_filters {
            if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
                let col = batch.column(col_idx);
                if let Some(arr) = col.as_any().downcast_ref::<StringArray>() {
                    let scalar = StringArray::new_scalar(value);
                    let matches = arrow_ord::cmp::eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = matches;
                    }
                }
            }
        }
    }

    let update_count = update_mask.true_count();
    if update_count == 0 {
        return Ok((batch.clone(), None, 0));
    }

    // Apply assignments to create the updated batch
    let (updated_batch, _) = apply_assignments_to_batch(batch, filter, assigns)?;

    // Extract only the rows that were updated from the new batch
    let updated_rows = filter_record_batch(&updated_batch, &update_mask)
        .map_err(|e| EngineError::Internal(format!("filter batch error: {}", e)))?;

    Ok((updated_batch, Some(updated_rows), update_count))
}

pub fn apply_assignments_to_batch(
    batch: &RecordBatch,
    filter: &QueryFilter,
    assigns: &[(String, crate::sql::SqlValue)],
) -> Result<(RecordBatch, usize), EngineError> {
    use crate::sql::SqlValue;
    use arrow::compute::and;
    use arrow_array::{Array, BooleanArray, Int64Array, UInt64Array};
    use arrow_ord::cmp::eq;

    let num_rows = batch.num_rows();
    if num_rows == 0 || assigns.is_empty() {
        return Ok((batch.clone(), 0));
    }

    // Build a mask of rows to UPDATE (true = update this row)
    let mut update_mask = BooleanArray::from(vec![true; num_rows]); // Update all if no filter

    if !filter_is_empty(filter) {
        update_mask = BooleanArray::from(vec![false; num_rows]);

        // Check route_id_eq filter
        if let Some(rid) = filter.route_id_eq {
            if let Some(col_idx) = batch.schema().index_of("route_id").ok() {
                let col = batch.column(col_idx);
                if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                    let scalar = UInt64Array::new_scalar(rid);
                    update_mask = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                }
            }
        }

        // Check route_id_in filter
        if let Some(ref rids) = filter.route_id_in {
            if let Some(col_idx) = batch.schema().index_of("route_id").ok() {
                let col = batch.column(col_idx);
                if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                    let mut in_mask = BooleanArray::from(vec![false; num_rows]);
                    for rid in rids {
                        let scalar = UInt64Array::new_scalar(*rid);
                        let matches = eq(arr, &scalar)
                            .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                        in_mask = arrow::compute::or(&in_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("or error: {}", e)))?;
                    }
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &in_mask)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = in_mask;
                    }
                }
            }
        }

        // Check numeric_eq_filters
        for (col_name, value) in &filter.numeric_eq_filters {
            if let Some(col_idx) = batch.schema().index_of(col_name).ok() {
                let col = batch.column(col_idx);
                if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                    let scalar = UInt64Array::new_scalar(*value as u64);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = matches;
                    }
                } else if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
                    let scalar = Int64Array::new_scalar(*value as i64);
                    let matches = eq(arr, &scalar)
                        .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))?;
                    if update_mask.true_count() > 0 {
                        update_mask = and(&update_mask, &matches)
                            .map_err(|e| EngineError::Internal(format!("and error: {}", e)))?;
                    } else {
                        update_mask = matches;
                    }
                }
            }
        }
    }

    let updated_count = update_mask.true_count();
    if updated_count == 0 {
        return Ok((batch.clone(), 0));
    }

    // Build new columns with assignments applied to matching rows
    let schema = batch.schema();
    let mut new_columns: Vec<ArrayRef> = Vec::with_capacity(schema.fields().len());

    for (col_idx, field) in schema.fields().iter().enumerate() {
        let col = batch.column(col_idx);

        // Check if this column has an assignment
        if let Some((_, value)) = assigns.iter().find(|(name, _)| name == field.name()) {
            // Apply assignment to matching rows
            let updated_col = apply_value_to_column(col, &update_mask, value, field.data_type())?;
            new_columns.push(updated_col);
        } else {
            // Keep original column
            new_columns.push(col.clone());
        }
    }

    let updated_batch = RecordBatch::try_new(schema.clone(), new_columns)
        .map_err(|e| EngineError::Internal(format!("create updated batch error: {}", e)))?;

    Ok((updated_batch, updated_count))
}

/// Apply a value to specific rows in a column based on a mask
fn apply_value_to_column(
    col: &ArrayRef,
    mask: &BooleanArray,
    value: &crate::sql::SqlValue,
    dtype: &DataType,
) -> Result<ArrayRef, EngineError> {
    use crate::sql::SqlValue;
    use arrow_array::{
        BooleanArray as BoolArr, Float64Array, Int64Array, StringArray, UInt64Array,
    };

    let num_rows = col.len();

    match dtype {
        DataType::Int64 => {
            let new_val = match value {
                SqlValue::Integer(i) => *i,
                SqlValue::Float(f) => *f as i64,
                _ => {
                    return Err(EngineError::InvalidArgument(
                        "cannot assign non-numeric to Int64".into(),
                    ))
                }
            };
            let arr = col
                .as_any()
                .downcast_ref::<Int64Array>()
                .ok_or_else(|| EngineError::Internal("expected Int64Array".into()))?;
            let mut builder = arrow_array::builder::Int64Builder::with_capacity(num_rows);
            for i in 0..num_rows {
                if mask.value(i) {
                    builder.append_value(new_val);
                } else {
                    if arr.is_null(i) {
                        builder.append_null();
                    } else {
                        builder.append_value(arr.value(i));
                    }
                }
            }
            Ok(Arc::new(builder.finish()) as ArrayRef)
        }
        DataType::UInt64 => {
            let new_val = match value {
                SqlValue::Integer(i) => *i as u64,
                SqlValue::Float(f) => *f as u64,
                _ => {
                    return Err(EngineError::InvalidArgument(
                        "cannot assign non-numeric to UInt64".into(),
                    ))
                }
            };
            let arr = col
                .as_any()
                .downcast_ref::<UInt64Array>()
                .ok_or_else(|| EngineError::Internal("expected UInt64Array".into()))?;
            let mut builder = arrow_array::builder::UInt64Builder::with_capacity(num_rows);
            for i in 0..num_rows {
                if mask.value(i) {
                    builder.append_value(new_val);
                } else {
                    if arr.is_null(i) {
                        builder.append_null();
                    } else {
                        builder.append_value(arr.value(i));
                    }
                }
            }
            Ok(Arc::new(builder.finish()) as ArrayRef)
        }
        DataType::Float64 => {
            let new_val = match value {
                SqlValue::Integer(i) => *i as f64,
                SqlValue::Float(f) => *f,
                _ => {
                    return Err(EngineError::InvalidArgument(
                        "cannot assign non-numeric to Float64".into(),
                    ))
                }
            };
            let arr = col
                .as_any()
                .downcast_ref::<Float64Array>()
                .ok_or_else(|| EngineError::Internal("expected Float64Array".into()))?;
            let mut builder = arrow_array::builder::Float64Builder::with_capacity(num_rows);
            for i in 0..num_rows {
                if mask.value(i) {
                    builder.append_value(new_val);
                } else {
                    if arr.is_null(i) {
                        builder.append_null();
                    } else {
                        builder.append_value(arr.value(i));
                    }
                }
            }
            Ok(Arc::new(builder.finish()) as ArrayRef)
        }
        DataType::Utf8 => {
            let new_val = match value {
                SqlValue::String(s) => s.clone(),
                SqlValue::Integer(i) => i.to_string(),
                SqlValue::Float(f) => f.to_string(),
                SqlValue::Boolean(b) => b.to_string(),
                _ => {
                    return Err(EngineError::InvalidArgument(
                        "cannot convert to string".into(),
                    ))
                }
            };
            let arr = col
                .as_any()
                .downcast_ref::<StringArray>()
                .ok_or_else(|| EngineError::Internal("expected StringArray".into()))?;
            let mut builder =
                arrow_array::builder::StringBuilder::with_capacity(num_rows, num_rows * 16);
            for i in 0..num_rows {
                if mask.value(i) {
                    builder.append_value(&new_val);
                } else {
                    if arr.is_null(i) {
                        builder.append_null();
                    } else {
                        builder.append_value(arr.value(i));
                    }
                }
            }
            Ok(Arc::new(builder.finish()) as ArrayRef)
        }
        _ => {
            // For unsupported types, return original column
            Ok(col.clone())
        }
    }
}

pub fn align_batch_to_fields(
    _fields: &[arrow_schema::Field],
    batch: &RecordBatch,
) -> Result<RecordBatch, EngineError> {
    Ok(batch.clone())
}

pub fn decode_binary_literal(_v: &str) -> Vec<u8> {
    vec![]
}

pub fn arrow_type_from_str(s: &str) -> Result<arrow_schema::DataType, EngineError> {
    use arrow_schema::DataType;
    let s_lower = s.to_lowercase();
    let s_trimmed = s_lower.trim();

    // Handle decimal with precision/scale: decimal(p,s)
    if s_trimmed.starts_with("decimal") {
        if let Some(params) = s_trimmed.strip_prefix("decimal").and_then(|rest| {
            let rest = rest.trim();
            if rest.starts_with('(') && rest.ends_with(')') {
                Some(&rest[1..rest.len() - 1])
            } else {
                None
            }
        }) {
            let parts: Vec<&str> = params.split(',').collect();
            if parts.len() == 2 {
                let precision: u8 = parts[0].trim().parse().unwrap_or(38);
                let scale: i8 = parts[1].trim().parse().unwrap_or(0);
                return Ok(DataType::Decimal128(precision, scale));
            }
        }
        // Default decimal without params
        return Ok(DataType::Decimal128(38, 0));
    }

    match s_trimmed {
        // String types
        "string" | "text" | "varchar" | "char" => Ok(DataType::Utf8),
        "largestring" | "largetext" => Ok(DataType::LargeUtf8),

        // Integer types
        "int8" | "tinyint" => Ok(DataType::Int8),
        "int16" | "smallint" => Ok(DataType::Int16),
        "int32" | "int" | "integer" => Ok(DataType::Int32),
        "int64" | "bigint" | "long" => Ok(DataType::Int64),

        // Unsigned integer types
        "uint8" => Ok(DataType::UInt8),
        "uint16" => Ok(DataType::UInt16),
        "uint32" => Ok(DataType::UInt32),
        "uint64" => Ok(DataType::UInt64),

        // Float types
        "float32" | "float" | "real" => Ok(DataType::Float32),
        "float64" | "double" => Ok(DataType::Float64),

        // Boolean
        "bool" | "boolean" => Ok(DataType::Boolean),

        // Binary types
        "binary" | "blob" | "bytea" => Ok(DataType::LargeBinary),

        // Date/Time types
        "date" | "date32" => Ok(DataType::Date32),
        "timestamp" | "datetime" => Ok(DataType::Timestamp(
            arrow_schema::TimeUnit::Microsecond,
            None,
        )),

        // Special types
        "uuid" => Ok(DataType::FixedSizeBinary(16)),
        "json" | "jsonb" => Ok(DataType::LargeUtf8),

        // Null type
        "null" => Ok(DataType::Null),

        _ => Err(EngineError::InvalidArgument(format!("unknown type: {}", s))),
    }
}

pub fn canonicalize_schema_spec<T: Clone>(fields: &[T]) -> Result<Vec<T>, EngineError> {
    Ok(fields.to_vec())
}

/// Check if two schema JSONs represent compatible schemas (same fields)
/// Returns true if schemas have the same field count and matching field names
fn schemas_are_compatible(schema1_json: &str, schema2_json: &str) -> bool {
    // Try to extract field names from both schemas
    fn extract_field_names(json: &str) -> Option<Vec<String>> {
        // Try parsing as array of objects with "name" field
        if let Ok(fields) = serde_json::from_str::<Vec<serde_json::Value>>(json) {
            let names: Vec<String> = fields
                .iter()
                .filter_map(|f| {
                    f.get("name")
                        .and_then(|n| n.as_str())
                        .map(|s| s.to_string())
                })
                .collect();
            if !names.is_empty() {
                return Some(names);
            }
        }
        // Try parsing as TableFieldSpec
        if let Ok(fields) = serde_json::from_str::<Vec<TableFieldSpec>>(json) {
            let names: Vec<String> = fields.iter().map(|f| f.name.clone()).collect();
            if !names.is_empty() {
                return Some(names);
            }
        }
        None
    }

    match (
        extract_field_names(schema1_json),
        extract_field_names(schema2_json),
    ) {
        (Some(names1), Some(names2)) => {
            if names1.len() != names2.len() {
                return false;
            }
            // Check if all field names match (in same order)
            names1.iter().zip(names2.iter()).all(|(a, b)| a == b)
        }
        _ => true, // If we can't parse, assume compatible
    }
}

pub fn canonical_schema_from_json(s: &str) -> Result<SchemaWrapper, EngineError> {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};

    // Try to parse as TableFieldSpec array first (from create_table)
    if let Ok(fields) = serde_json::from_str::<Vec<TableFieldSpec>>(s) {
        // Build a canonical string for hash computation (just field names for compatibility)
        let field_names: Vec<&str> = fields.iter().map(|f| f.name.as_str()).collect();
        let canonical_for_hash = serde_json::to_string(&field_names).unwrap_or_default();

        // Compute hash from field names (more stable across format changes)
        let hash = {
            let mut hasher = DefaultHasher::new();
            canonical_for_hash.hash(&mut hasher);
            hasher.finish()
        };

        // IMPORTANT: Return the ORIGINAL json (TableFieldSpec format) so it can be parsed later
        return Ok(SchemaWrapper {
            json: s.to_string(),
            hash,
        });
    }

    // Try to parse as validate_and_stats format (raw JSON with data_type field)
    if let Ok(fields) = serde_json::from_str::<Vec<serde_json::Value>>(s) {
        // Check if this is already in TableFieldSpec format (has data_type)
        // or if it's the old format (has type)
        let needs_conversion = fields
            .iter()
            .any(|f| f.get("type").is_some() && f.get("data_type").is_none());

        let result_json = if needs_conversion {
            // Convert from old format (type) to TableFieldSpec format (data_type)
            let converted: Vec<serde_json::Value> = fields
                .iter()
                .map(|f| {
                    let type_val = f
                        .get("type")
                        .and_then(|t| t.as_str())
                        .or_else(|| f.get("data_type").and_then(|t| t.as_str()))
                        .unwrap_or("string");
                    // Convert Arrow DataType string back to our format
                    let data_type_str = match type_val {
                        "Int64" => "int64",
                        "Int32" => "int32",
                        "Int16" => "int16",
                        "Int8" => "int8",
                        "UInt64" => "uint64",
                        "UInt32" => "uint32",
                        "UInt16" => "uint16",
                        "UInt8" => "uint8",
                        "Float64" => "float64",
                        "Float32" => "float32",
                        "Boolean" => "bool",
                        "Utf8" => "string",
                        "LargeUtf8" => "string",
                        "Binary" => "binary",
                        "Date32" | "Date64" => "date",
                        s if s.starts_with("Timestamp") => "timestamp",
                        other => other,
                    };
                    serde_json::json!({
                        "name": f.get("name").and_then(|n| n.as_str()).unwrap_or(""),
                        "data_type": data_type_str,
                        "nullable": f.get("nullable").and_then(|n| n.as_bool()).unwrap_or(true)
                    })
                })
                .collect();
            serde_json::to_string(&converted).unwrap_or_default()
        } else {
            // Already has data_type or original format
            s.to_string()
        };

        // Compute hash from field names
        let field_names: Vec<&str> = fields
            .iter()
            .filter_map(|f| f.get("name").and_then(|n| n.as_str()))
            .collect();
        let canonical_for_hash = serde_json::to_string(&field_names).unwrap_or_default();
        let hash = {
            let mut hasher = DefaultHasher::new();
            canonical_for_hash.hash(&mut hasher);
            hasher.finish()
        };
        return Ok(SchemaWrapper {
            json: result_json,
            hash,
        });
    }

    // Fallback: empty schema
    Ok(SchemaWrapper {
        json: "[]".to_string(),
        hash: 0,
    })
}

/// Validates IPC payload and computes column statistics for segment pruning.
/// This is the core function that enables zone-map based query optimization.
pub fn validate_and_stats<T>(
    ipc: &[u8],
    _meta: Option<&T>,
) -> Result<ValidatedSegment, EngineError> {
    use crate::replication::{ColumnStats, PrimitiveValue};
    use arrow_array::{
        Array, BooleanArray, Date32Array, Float32Array, Float64Array, Int16Array, Int32Array,
        Int64Array, Int8Array, TimestampMicrosecondArray, UInt16Array, UInt32Array, UInt64Array,
        UInt8Array,
    };
    use std::collections::HashMap;

    if ipc.is_empty() {
        return Ok(ValidatedSegment::default());
    }

    let batches = read_ipc_batches(ipc)?;
    if batches.is_empty() {
        return Ok(ValidatedSegment::default());
    }

    let schema = batches[0].schema();
    let mut column_stats: HashMap<String, ColumnStats> = HashMap::new();
    let mut total_rows: u64 = 0;

    // Legacy stats for backward compatibility
    let mut event_time_min: Option<u64> = None;
    let mut event_time_max: Option<u64> = None;
    let mut tenant_id_min: Option<u64> = None;
    let mut tenant_id_max: Option<u64> = None;
    let mut route_id_min: Option<u64> = None;
    let mut route_id_max: Option<u64> = None;
    let mut tenant_ids: Vec<u64> = Vec::new();
    let mut route_ids: Vec<u64> = Vec::new();

    for batch in &batches {
        total_rows += batch.num_rows() as u64;

        for (col_idx, field) in schema.fields().iter().enumerate() {
            let col_name = field.name().to_string();
            let col = batch.column(col_idx);
            let null_count = col.null_count() as u64;

            let stats = column_stats
                .entry(col_name.clone())
                .or_insert_with(|| ColumnStats {
                    min: None,
                    max: None,
                    bloom_filter: None,
                    null_count: 0,
                    row_count: 0,
                    distinct_count: None,
                });

            stats.null_count += null_count;
            stats.row_count += batch.num_rows() as u64;

            // Compute min/max based on column type
            match field.data_type() {
                DataType::Int64 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Int64Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::Int64(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::Int64(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Int32 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Int32Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::Int32(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::Int32(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::UInt64 => {
                    if let Some(arr) = col.as_any().downcast_ref::<UInt64Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::UInt64(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::UInt64(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                        // Legacy tenant_id/route_id handling
                        if col_name == "tenant_id" {
                            for i in 0..arr.len() {
                                if !arr.is_null(i) {
                                    let v = arr.value(i);
                                    tenant_ids.push(v);
                                    tenant_id_min = Some(tenant_id_min.map_or(v, |m| m.min(v)));
                                    tenant_id_max = Some(tenant_id_max.map_or(v, |m| m.max(v)));
                                }
                            }
                        } else if col_name == "route_id" {
                            for i in 0..arr.len() {
                                if !arr.is_null(i) {
                                    let v = arr.value(i);
                                    route_ids.push(v);
                                    route_id_min = Some(route_id_min.map_or(v, |m| m.min(v)));
                                    route_id_max = Some(route_id_max.map_or(v, |m| m.max(v)));
                                }
                            }
                        }
                    }
                }
                DataType::UInt32 => {
                    if let Some(arr) = col.as_any().downcast_ref::<UInt32Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::UInt32(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::UInt32(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Float64 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Float64Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::Float64(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::Float64(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Float32 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Float32Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::Float32(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::Float32(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Timestamp(_, _) => {
                    if let Some(arr) = col.as_any().downcast_ref::<TimestampMicrosecondArray>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::TimestampMicros(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::TimestampMicros(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                        // Legacy event_time handling
                        if col_name == "event_time" {
                            for i in 0..arr.len() {
                                if !arr.is_null(i) {
                                    let v = arr.value(i) as u64;
                                    event_time_min = Some(event_time_min.map_or(v, |m| m.min(v)));
                                    event_time_max = Some(event_time_max.map_or(v, |m| m.max(v)));
                                }
                            }
                        }
                    }
                }
                DataType::Date32 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Date32Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            let new_min = PrimitiveValue::Date32(min_val);
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            let new_max = PrimitiveValue::Date32(max_val);
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Utf8 => {
                    if let Some(arr) = col.as_any().downcast_ref::<StringArray>() {
                        if let Some(min_val) = arrow::compute::min_string(arr) {
                            let new_min = PrimitiveValue::String(min_val.to_string());
                            if stats.min.is_none()
                                || new_min.is_less_than(stats.min.as_ref().unwrap())
                            {
                                stats.min = Some(new_min);
                            }
                        }
                        if let Some(max_val) = arrow::compute::max_string(arr) {
                            let new_max = PrimitiveValue::String(max_val.to_string());
                            if stats.max.is_none()
                                || new_max.is_greater_than(stats.max.as_ref().unwrap())
                            {
                                stats.max = Some(new_max);
                            }
                        }
                    }
                }
                DataType::Boolean => {
                    if let Some(arr) = col.as_any().downcast_ref::<BooleanArray>() {
                        let mut has_false = false;
                        let mut has_true = false;
                        for i in 0..arr.len() {
                            if !arr.is_null(i) {
                                if arr.value(i) {
                                    has_true = true;
                                } else {
                                    has_false = true;
                                }
                            }
                        }
                        if has_false {
                            stats.min = Some(PrimitiveValue::Boolean(false));
                        }
                        if has_true {
                            stats.max = Some(PrimitiveValue::Boolean(true));
                        }
                    }
                }
                // Handle smaller integer types
                DataType::Int8 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Int8Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            stats.min = Some(PrimitiveValue::Int32(min_val as i32));
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            stats.max = Some(PrimitiveValue::Int32(max_val as i32));
                        }
                    }
                }
                DataType::Int16 => {
                    if let Some(arr) = col.as_any().downcast_ref::<Int16Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            stats.min = Some(PrimitiveValue::Int32(min_val as i32));
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            stats.max = Some(PrimitiveValue::Int32(max_val as i32));
                        }
                    }
                }
                DataType::UInt8 => {
                    if let Some(arr) = col.as_any().downcast_ref::<UInt8Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            stats.min = Some(PrimitiveValue::UInt32(min_val as u32));
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            stats.max = Some(PrimitiveValue::UInt32(max_val as u32));
                        }
                    }
                }
                DataType::UInt16 => {
                    if let Some(arr) = col.as_any().downcast_ref::<UInt16Array>() {
                        if let Some(min_val) = arrow::compute::min(arr) {
                            stats.min = Some(PrimitiveValue::UInt32(min_val as u32));
                        }
                        if let Some(max_val) = arrow::compute::max(arr) {
                            stats.max = Some(PrimitiveValue::UInt32(max_val as u32));
                        }
                    }
                }
                _ => {
                    // Unsupported type - no stats collected
                }
            }
        }
    }

    // Build bloom filters for tenant_id and route_id (legacy compatibility)
    let bloom_tenant = if !tenant_ids.is_empty() {
        let mut bloom = Bloom::new_for_fp_rate(tenant_ids.len().max(100), 0.01);
        for id in &tenant_ids {
            bloom.set(id);
        }
        crate::bloom_utils::serialize_bloom(&bloom).ok()
    } else {
        None
    };

    let bloom_route = if !route_ids.is_empty() {
        let mut bloom = Bloom::new_for_fp_rate(route_ids.len().max(100), 0.01);
        for id in &route_ids {
            bloom.set(id);
        }
        crate::bloom_utils::serialize_bloom(&bloom).ok()
    } else {
        None
    };

    // Compute schema hash for validation
    // Use TableFieldSpec format for consistency with create_table
    let schema_json = serde_json::to_string(
        &schema
            .fields()
            .iter()
            .map(|f| {
                // Convert Arrow DataType to our string format
                let data_type_str = match f.data_type() {
                    DataType::Int8 => "int8",
                    DataType::Int16 => "int16",
                    DataType::Int32 => "int32",
                    DataType::Int64 => "int64",
                    DataType::UInt8 => "uint8",
                    DataType::UInt16 => "uint16",
                    DataType::UInt32 => "uint32",
                    DataType::UInt64 => "uint64",
                    DataType::Float32 => "float32",
                    DataType::Float64 => "float64",
                    DataType::Boolean => "bool",
                    DataType::Utf8 => "string",
                    DataType::LargeUtf8 => "string",
                    DataType::Binary => "binary",
                    DataType::LargeBinary => "binary",
                    DataType::Date32 => "date",
                    DataType::Date64 => "date",
                    DataType::Timestamp(_, _) => "timestamp",
                    _ => "string", // Default fallback
                };
                serde_json::json!({
                    "name": f.name(),
                    "data_type": data_type_str,
                    "nullable": f.is_nullable()
                })
            })
            .collect::<Vec<_>>(),
    )
    .unwrap_or_default();

    let schema_hash = {
        let mut hasher = DefaultHasher::new();
        schema_json.hash(&mut hasher);
        hasher.finish()
    };

    Ok(ValidatedSegment {
        stats: SegmentStats {
            event_time_min,
            event_time_max,
            tenant_id_min,
            tenant_id_max,
            route_id_min,
            route_id_max,
            bloom_tenant,
            bloom_route,
            column_stats,
        },
        schema_hash,
        schema_spec: Some(schema_json),
    })
}

/// Check if a segment can be pruned based on column statistics (zone maps).
/// Returns true if the segment might contain matching rows, false if it can be skipped.
pub fn segment_matches_column_stats(entry: &ManifestEntry, filter: &QueryFilter) -> bool {
    use crate::replication::PrimitiveValue;
    use crate::sql::NumericOp;

    // If no column stats, assume segment might match
    let stats_map = match &entry.column_stats {
        Some(map) if !map.is_empty() => map,
        _ => return true,
    };

    // Check numeric equality filters (i128 values)
    for (col_name, value) in &filter.numeric_eq_filters {
        if let Some(col_stats) = stats_map.get(col_name) {
            // Convert i128 to Int64 for comparison (lossy but covers most cases)
            let prim_val = PrimitiveValue::Int64(*value as i64);
            if !col_stats.value_in_range(&prim_val) {
                return false; // Value is outside segment's min/max range
            }
        }
    }

    // Check float equality filters
    for (col_name, value) in &filter.float_eq_filters {
        if let Some(col_stats) = stats_map.get(col_name) {
            let prim_val = PrimitiveValue::Float64(*value);
            if !col_stats.value_in_range(&prim_val) {
                return false;
            }
        }
    }

    // Check numeric range filters
    for nf in &filter.numeric_range_filters {
        if let Some(col_stats) = stats_map.get(&nf.column) {
            let filter_val = nf.value.to_primitive();

            match nf.op {
                NumericOp::Eq => {
                    // segment.min <= val <= segment.max
                    if !col_stats.value_in_range(&filter_val) {
                        return false;
                    }
                }
                NumericOp::Lt | NumericOp::Le => {
                    // Looking for rows where col < val (or col <= val)
                    // Can skip segment if segment.min >= val (for Lt) or segment.min > val (for Le)
                    if let Some(ref seg_min) = col_stats.min {
                        match nf.op {
                            NumericOp::Lt => {
                                // col < val means we need seg_min < val
                                if !seg_min.is_less_than(&filter_val)
                                    && seg_min.partial_cmp_value(&filter_val)
                                        != Some(std::cmp::Ordering::Less)
                                {
                                    return false;
                                }
                            }
                            NumericOp::Le => {
                                // col <= val means we need seg_min <= val
                                if seg_min.is_greater_than(&filter_val) {
                                    return false;
                                }
                            }
                            _ => {}
                        }
                    }
                }
                NumericOp::Gt | NumericOp::Ge => {
                    // Looking for rows where col > val (or col >= val)
                    // Can skip segment if segment.max <= val (for Gt) or segment.max < val (for Ge)
                    if let Some(ref seg_max) = col_stats.max {
                        match nf.op {
                            NumericOp::Gt => {
                                // col > val means we need seg_max > val
                                if !seg_max.is_greater_than(&filter_val)
                                    && seg_max.partial_cmp_value(&filter_val)
                                        != Some(std::cmp::Ordering::Greater)
                                {
                                    return false;
                                }
                            }
                            NumericOp::Ge => {
                                // col >= val means we need seg_max >= val
                                if seg_max.is_less_than(&filter_val) {
                                    return false;
                                }
                            }
                            _ => {}
                        }
                    }
                }
                NumericOp::Ne => {
                    // Can only skip if segment has exactly one value and it equals the filter value
                    if let (Some(ref seg_min), Some(ref seg_max)) = (&col_stats.min, &col_stats.max)
                    {
                        if seg_min.partial_cmp_value(seg_max) == Some(std::cmp::Ordering::Equal) {
                            if seg_min.partial_cmp_value(&filter_val)
                                == Some(std::cmp::Ordering::Equal)
                            {
                                return false; // Segment only has the value we're excluding
                            }
                        }
                    }
                }
            }
        }
    }

    // Check string equality filters against column stats
    for (col_name, value) in &filter.string_eq_filters {
        if let Some(col_stats) = stats_map.get(col_name) {
            let prim_val = PrimitiveValue::String(value.clone());
            if !col_stats.value_in_range(&prim_val) {
                return false;
            }
        }
    }

    true
}

pub fn column_encodings_from_schema_json(
    _j: Option<&String>,
) -> Result<std::collections::HashMap<String, String>, EngineError> {
    Ok(std::collections::HashMap::new())
}

pub fn apply_column_encodings(
    ipc: &[u8],
    enc: &std::collections::HashMap<String, String>,
) -> Result<Vec<u8>, EngineError> {
    // If no encodings specified, return original data
    if enc.is_empty() {
        return Ok(ipc.to_vec());
    }

    // Parse IPC and apply encodings
    let batches = read_ipc_batches(ipc)?;
    if batches.is_empty() {
        return Ok(ipc.to_vec());
    }

    let schema = batches[0].schema();
    let mut encoded_batches = Vec::with_capacity(batches.len());

    for batch in &batches {
        let mut new_columns: Vec<ArrayRef> = Vec::with_capacity(batch.num_columns());

        for (idx, field) in schema.fields().iter().enumerate() {
            let col = batch.column(idx);
            let encoding = enc.get(field.name());

            let encoded_col = match encoding.map(|s| s.as_str()) {
                Some("dictionary") => apply_dictionary_encoding_to_column(col),
                _ => col.clone(),
            };
            new_columns.push(encoded_col);
        }

        let new_batch = RecordBatch::try_new(schema.clone(), new_columns)
            .map_err(|e| EngineError::Internal(format!("encoding batch error: {e}")))?;
        encoded_batches.push(new_batch);
    }

    // Re-encode to IPC
    record_batches_to_ipc(&schema, &encoded_batches)
}

/// Apply dictionary encoding to a string column
/// Replaces repeated strings with integer indices into a dictionary
/// Effective for columns with <50% unique values
fn apply_dictionary_encoding_to_column(col: &ArrayRef) -> ArrayRef {
    use arrow::compute::cast;
    use arrow::datatypes::DataType;

    // Try to cast to dictionary-encoded type for string columns
    if col.as_any().downcast_ref::<StringArray>().is_some() {
        // Cast to DictionaryArray<Int32>
        match cast(col, &DataType::Dictionary(
            Box::new(DataType::Int32),
            Box::new(DataType::Utf8),
        )) {
            Ok(dict_arr) => return dict_arr,
            Err(_) => return col.clone(), // Fall back if cast fails
        }
    }

    col.clone()
}

pub fn parse_uuid_string(s: &str) -> Option<[u8; 16]> {
    let s = s.trim();
    // With hyphens: xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx (36 chars)
    if s.len() == 36 && s.chars().filter(|c| *c == '-').count() == 4 {
        let hex: String = s.chars().filter(|c| *c != '-').collect();
        if hex.len() == 32 && hex.chars().all(|c| c.is_ascii_hexdigit()) {
            if let Ok(bytes) = hex::decode(&hex) {
                if bytes.len() == 16 {
                    let mut arr = [0u8; 16];
                    arr.copy_from_slice(&bytes);
                    return Some(arr);
                }
            }
        }
        return None;
    }
    // Without hyphens: 32 hex chars
    if s.len() == 32 && s.chars().all(|c| c.is_ascii_hexdigit()) {
        if let Ok(bytes) = hex::decode(s) {
            if bytes.len() == 16 {
                let mut arr = [0u8; 16];
                arr.copy_from_slice(&bytes);
                return Some(arr);
            }
        }
    }
    None
}

pub fn current_time_micros() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_micros() as u64
}

pub fn segment_age_micros(entry: &ManifestEntry, now: u64) -> Option<u64> {
    // Calculate segment age based on watermark or event time
    let segment_time = entry
        .watermark_micros
        .max(entry.event_time_max.unwrap_or(0));
    if segment_time == 0 {
        return None;
    }
    if now >= segment_time {
        Some(now - segment_time)
    } else {
        Some(0) // Segment is in the future (clock skew)
    }
}

