/// Filter a record batch using a boolean mask
fn filter_record_batch(
    batch: &RecordBatch,
    mask: &BooleanArray,
) -> Result<RecordBatch, EngineError> {
    let filtered_columns: Result<Vec<ArrayRef>, _> = batch
        .columns()
        .iter()
        .map(|col| {
            arrow_filter(col.as_ref(), mask)
                .map_err(|e| EngineError::Internal(format!("filter error: {}", e)))
        })
        .collect();

    RecordBatch::try_new(batch.schema(), filtered_columns?)
        .map_err(|e| EngineError::Internal(format!("batch creation error: {}", e)))
}
/// Aggregator for computing aggregations over record batches
/// Supports COUNT(*), COUNT(DISTINCT), SUM, AVG, MIN, MAX and GROUP BY
/// Includes memory bounds to prevent OOM on high-cardinality GROUP BY
pub struct Aggregator {
    plan: AggPlan,
    /// Accumulated state for non-grouped aggregations
    global_state: Option<AggState>,
    /// Accumulated state for grouped aggregations: HashMap<GroupKey, AggState>
    grouped_state: HashMap<Vec<GroupKeyValue>, AggState>,
    /// Schema from first batch for output generation
    schema: Option<Arc<Schema>>,
    /// Estimated memory usage in bytes
    estimated_memory_bytes: u64,
    /// Memory limit for aggregation (0 = unlimited)
    memory_limit_bytes: u64,
    /// Number of groups (for monitoring)
    group_count: u64,
}

/// Group key value for HashMap keys
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
enum GroupKeyValue {
    Int64(i64),
    UInt64(u64),
    String(String),
    Null,
}

/// Internal aggregation state
#[derive(Debug, Clone, Default)]
struct AggState {
    /// COUNT(*) - total rows
    count_star: u64,
    /// COUNT(DISTINCT col) - using HashSet
    count_distinct_sets: HashMap<String, HashSet<u64>>, // Hash of values for distinct count
    /// SUM accumulators per column
    sum_values: HashMap<String, f64>,
    /// MIN values per column
    min_values: HashMap<String, f64>,
    /// MAX values per column
    max_values: HashMap<String, f64>,
    /// For AVG: sum and count per column
    avg_sums: HashMap<String, f64>,
    avg_counts: HashMap<String, u64>,
    /// For MEDIAN/PERCENTILE: collect all values per column
    percentile_values: HashMap<String, Vec<f64>>,
    /// For ARRAY_AGG: collect all values per column as strings
    array_agg_values: HashMap<String, Vec<String>>,
    /// For STRING_AGG: collect all string values per column
    string_agg_values: HashMap<String, Vec<String>>,
    /// For filtered aggregates: separate count by aggregate name
    filtered_counts: HashMap<String, u64>,
    /// For filtered SUM: separate sum by aggregate name
    filtered_sums: HashMap<String, f64>,
    /// For filtered MIN: separate min by aggregate name
    filtered_mins: HashMap<String, f64>,
    /// For filtered MAX: separate max by aggregate name
    filtered_maxs: HashMap<String, f64>,
    /// For filtered AVG: sum and count by aggregate name
    filtered_avg_sums: HashMap<String, f64>,
    filtered_avg_counts: HashMap<String, u64>,
    /// For ordered aggregates: store (value, order_key) pairs
    ordered_values: HashMap<String, Vec<(String, f64)>>,
    /// For MODE: count occurrences of each value
    mode_counts: HashMap<String, HashMap<String, u64>>,
}

impl Aggregator {
    pub fn new(plan: AggPlan) -> Result<Self, EngineError> {
        Self::new_with_limit(plan, 0)
    }

    /// Create aggregator with memory limit (0 = unlimited)
    pub fn new_with_limit(plan: AggPlan, memory_limit_bytes: u64) -> Result<Self, EngineError> {
        let has_group_by = !matches!(plan.group_by, GroupBy::None);
        Ok(Self {
            plan,
            global_state: if has_group_by {
                None
            } else {
                Some(AggState::default())
            },
            grouped_state: HashMap::new(),
            schema: None,
            estimated_memory_bytes: 0,
            memory_limit_bytes,
            group_count: 0,
        })
    }

    /// Estimate memory usage of a single AggState entry
    fn estimate_agg_state_bytes(state: &AggState) -> u64 {
        let mut bytes: u64 = std::mem::size_of::<AggState>() as u64;
        // Count distinct sets (each hash set entry ~16 bytes)
        for (_col, set) in &state.count_distinct_sets {
            bytes += (set.len() * 16) as u64;
        }
        // Percentile values (each f64 = 8 bytes)
        for (_col, vals) in &state.percentile_values {
            bytes += (vals.len() * 8) as u64;
        }
        // Array agg values (estimate ~32 bytes per string on average)
        for (_col, vals) in &state.array_agg_values {
            bytes += (vals.len() * 32) as u64;
        }
        // String agg values
        for (_col, vals) in &state.string_agg_values {
            bytes += vals.iter().map(|s| s.len() as u64).sum::<u64>();
        }
        bytes
    }

    /// Check if memory limit is exceeded
    fn check_memory_limit(&self) -> Result<(), EngineError> {
        if self.memory_limit_bytes > 0 && self.estimated_memory_bytes > self.memory_limit_bytes {
            return Err(EngineError::InvalidArgument(format!(
                "aggregation memory limit exceeded: {} bytes used, {} bytes limit ({} groups). Consider adding more filters or reducing cardinality.",
                self.estimated_memory_bytes,
                self.memory_limit_bytes,
                self.group_count
            )));
        }
        Ok(())
    }

    pub fn consume_ipc(&mut self, ipc: &[u8], filter: &QueryFilter) -> Result<(), EngineError> {
        if ipc.is_empty() {
            return Ok(());
        }

        // Decode batches
        let batches = read_ipc_batches(ipc)?;

        // Apply filters first
        let filtered_batches = filter_ipc_batches(batches, filter)?;

        for batch in filtered_batches {
            self.consume_batch(&batch)?;
        }

        Ok(())
    }

    fn consume_batch(&mut self, batch: &RecordBatch) -> Result<(), EngineError> {
        if self.schema.is_none() {
            self.schema = Some(batch.schema());
        }

        // Clone to avoid borrow conflicts with self
        let group_by = self.plan.group_by.clone();
        match &group_by {
            GroupBy::None => {
                // Global aggregation (no GROUP BY)
                // Ensure state exists
                if self.global_state.is_none() {
                    self.global_state = Some(AggState::default());
                }
                // Now accumulate - separate borrow to satisfy borrow checker
                let aggs = self.plan.aggs.clone();
                let state = self.global_state.as_mut().unwrap();
                accumulate_aggs_into(state, &aggs, batch)?;
            }
            GroupBy::Tenant => {
                // Group by tenant_id
                self.accumulate_grouped(batch, &["tenant_id"])?;
            }
            GroupBy::Route => {
                // Group by route_id
                self.accumulate_grouped(batch, &["route_id"])?;
            }
            GroupBy::Columns(cols) => {
                // Group by specified columns
                let col_names: Vec<String> = cols
                    .iter()
                    .map(|c| match c {
                        GroupByColumn::TenantId => "tenant_id".to_string(),
                        GroupByColumn::RouteId => "route_id".to_string(),
                        GroupByColumn::Named(name) => name.clone(),
                    })
                    .collect();
                let col_refs: Vec<&str> = col_names.iter().map(|s| s.as_str()).collect();
                self.accumulate_grouped(batch, &col_refs)?;
            }
            GroupBy::All => {
                // GROUP BY ALL: treat as global aggregation for now
                if self.global_state.is_none() {
                    self.global_state = Some(AggState::default());
                }
                let aggs = self.plan.aggs.clone();
                let state = self.global_state.as_mut().unwrap();
                accumulate_aggs_into(state, &aggs, batch)?;
            }
            GroupBy::GroupingSets(sets) => {
                // Execute aggregation for each grouping set
                for set in sets {
                    let col_names: Vec<String> = set
                        .iter()
                        .map(|c| match c {
                            GroupByColumn::TenantId => "tenant_id".to_string(),
                            GroupByColumn::RouteId => "route_id".to_string(),
                            GroupByColumn::Named(name) => name.clone(),
                        })
                        .collect();
                    if col_names.is_empty() {
                        // Empty set = global aggregation
                        if self.global_state.is_none() {
                            self.global_state = Some(AggState::default());
                        }
                        let aggs = self.plan.aggs.clone();
                        let state = self.global_state.as_mut().unwrap();
                        accumulate_aggs_into(state, &aggs, batch)?;
                    } else {
                        let col_refs: Vec<&str> = col_names.iter().map(|s| s.as_str()).collect();
                        self.accumulate_grouped(batch, &col_refs)?;
                    }
                }
            }
            GroupBy::Rollup(cols) => {
                // ROLLUP: progressive subtotals
                let col_names: Vec<String> = cols
                    .iter()
                    .map(|c| match c {
                        GroupByColumn::TenantId => "tenant_id".to_string(),
                        GroupByColumn::RouteId => "route_id".to_string(),
                        GroupByColumn::Named(name) => name.clone(),
                    })
                    .collect();

                for i in (0..=col_names.len()).rev() {
                    let prefix: Vec<&str> = col_names[..i].iter().map(|s| s.as_str()).collect();
                    if prefix.is_empty() {
                        if self.global_state.is_none() {
                            self.global_state = Some(AggState::default());
                        }
                        let aggs = self.plan.aggs.clone();
                        let state = self.global_state.as_mut().unwrap();
                        accumulate_aggs_into(state, &aggs, batch)?;
                    } else {
                        self.accumulate_grouped(batch, &prefix)?;
                    }
                }
            }
            GroupBy::Cube(cols) => {
                // CUBE: all combinations
                let col_names: Vec<String> = cols
                    .iter()
                    .map(|c| match c {
                        GroupByColumn::TenantId => "tenant_id".to_string(),
                        GroupByColumn::RouteId => "route_id".to_string(),
                        GroupByColumn::Named(name) => name.clone(),
                    })
                    .collect();

                let n = col_names.len();
                for mask in 0..(1 << n) {
                    let subset: Vec<&str> = (0..n)
                        .filter(|i| (mask & (1 << i)) != 0)
                        .map(|i| col_names[i].as_str())
                        .collect();

                    if subset.is_empty() {
                        if self.global_state.is_none() {
                            self.global_state = Some(AggState::default());
                        }
                        let aggs = self.plan.aggs.clone();
                        let state = self.global_state.as_mut().unwrap();
                        accumulate_aggs_into(state, &aggs, batch)?;
                    } else {
                        self.accumulate_grouped(batch, &subset)?;
                    }
                }
            }
        }

        Ok(())
    }

    fn accumulate_grouped(
        &mut self,
        batch: &RecordBatch,
        group_cols: &[&str],
    ) -> Result<(), EngineError> {
        let num_rows = batch.num_rows();
        if num_rows == 0 {
            return Ok(());
        }

        // Extract group key columns
        let key_arrays: Vec<&ArrayRef> = group_cols
            .iter()
            .filter_map(|col| {
                batch
                    .schema()
                    .index_of(col)
                    .ok()
                    .map(|idx| batch.column(idx))
            })
            .collect();

        if key_arrays.is_empty() {
            // No group columns found, treat as global aggregation
            let num_rows = batch.num_rows();
            let state = self.global_state.get_or_insert_with(AggState::default);
            state.count_star += num_rows as u64;
            // Accumulate aggregates directly without calling self.accumulate_aggs to avoid borrow issues
            for agg in &self.plan.aggs.clone() {
                match &agg.kind {
                    AggKind::CountStar => {}
                    AggKind::CountDistinct { column } | AggKind::ApproxCountDistinct { column } => {
                        if let Ok(col_idx) = batch.schema().index_of(column) {
                            let col = batch.column(col_idx);
                            let set = state
                                .count_distinct_sets
                                .entry(column.clone())
                                .or_insert_with(HashSet::new);
                            let _ = add_distinct_values(col, set);
                        }
                    }
                    AggKind::Sum { column } => {
                        if let Ok(col_idx) = batch.schema().index_of(column) {
                            let col = batch.column(col_idx);
                            let sum = compute_sum(col).unwrap_or(0.0);
                            *state.sum_values.entry(column.clone()).or_insert(0.0) += sum;
                        }
                    }
                    AggKind::Avg { column } => {
                        if let Ok(col_idx) = batch.schema().index_of(column) {
                            let col = batch.column(col_idx);
                            let sum = compute_sum(col).unwrap_or(0.0);
                            let count = col.len() - col.null_count();
                            *state.avg_sums.entry(column.clone()).or_insert(0.0) += sum;
                            *state.avg_counts.entry(column.clone()).or_insert(0) += count as u64;
                        }
                    }
                    AggKind::Min { column } => {
                        if let Ok(col_idx) = batch.schema().index_of(column) {
                            let col = batch.column(col_idx);
                            if let Ok(Some(min)) = compute_min(col) {
                                let entry = state
                                    .min_values
                                    .entry(column.clone())
                                    .or_insert(f64::INFINITY);
                                if min < *entry {
                                    *entry = min;
                                }
                            }
                        }
                    }
                    AggKind::Max { column } => {
                        if let Ok(col_idx) = batch.schema().index_of(column) {
                            let col = batch.column(col_idx);
                            if let Ok(Some(max)) = compute_max(col) {
                                let entry = state
                                    .max_values
                                    .entry(column.clone())
                                    .or_insert(f64::NEG_INFINITY);
                                if max > *entry {
                                    *entry = max;
                                }
                            }
                        }
                    }
                    _ => {}
                }
            }
            return Ok(());
        }

        // Track new groups added in this batch
        let initial_group_count = self.grouped_state.len();

        // For each row, compute the group key and accumulate
        for row in 0..num_rows {
            let key: Vec<GroupKeyValue> = key_arrays
                .iter()
                .map(|arr| extract_group_key_value(arr, row))
                .collect();

            let state = self
                .grouped_state
                .entry(key)
                .or_insert_with(AggState::default);
            state.count_star += 1;

            // Accumulate individual row aggregations
            for agg in &self.plan.aggs {
                accumulate_single_row(state, agg, batch, row)?;
            }
        }

        // Update memory tracking after batch processing
        let new_groups = self.grouped_state.len() - initial_group_count;
        if new_groups > 0 {
            self.group_count += new_groups as u64;
            // Estimate: ~200 bytes per group (key + state overhead)
            self.estimated_memory_bytes += (new_groups * 200) as u64;
        }

        // Check memory limit at end of batch
        self.check_memory_limit()?;

        Ok(())
    }

    pub fn finish(&self) -> Result<Vec<u8>, EngineError> {
        let schema = self.build_output_schema()?;

        let batch = match &self.plan.group_by {
            GroupBy::None => {
                // Global aggregation result (single row)
                if let Some(ref state) = self.global_state {
                    self.build_global_result(&schema, state)?
                } else {
                    // No data consumed - return empty result with zero counts
                    self.build_global_result(&schema, &AggState::default())?
                }
            }
            _ => {
                // Grouped aggregation result
                self.build_grouped_result(&schema)?
            }
        };

        // Encode to IPC
        let mut buf = Vec::new();
        {
            let mut writer = StreamWriter::try_new(&mut buf, &schema)
                .map_err(|e| EngineError::Internal(format!("IPC write error: {}", e)))?;
            writer
                .write(&batch)
                .map_err(|e| EngineError::Internal(format!("IPC write error: {}", e)))?;
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("IPC finish error: {}", e)))?;
        }

        Ok(buf)
    }

    fn build_output_schema(&self) -> Result<Arc<Schema>, EngineError> {
        let mut fields = Vec::new();

        // Add group by columns first
        match &self.plan.group_by {
            GroupBy::None => {}
            GroupBy::Tenant => {
                fields.push(Field::new("tenant_id", DataType::UInt64, true));
            }
            GroupBy::Route => {
                fields.push(Field::new("route_id", DataType::UInt64, true));
            }
            GroupBy::Columns(cols) => {
                for col in cols {
                    match col {
                        GroupByColumn::TenantId => {
                            fields.push(Field::new("tenant_id", DataType::UInt64, true));
                        }
                        GroupByColumn::RouteId => {
                            fields.push(Field::new("route_id", DataType::UInt64, true));
                        }
                        GroupByColumn::Named(name) => {
                            // Use Utf8 as default type for named columns
                            fields.push(Field::new(name, DataType::Utf8, true));
                        }
                    }
                }
            }
            GroupBy::All => {
                // GROUP BY ALL: columns determined at runtime
            }
            GroupBy::GroupingSets(sets) => {
                // Add all unique columns from all sets
                let mut added = std::collections::HashSet::new();
                for set in sets {
                    for col in set {
                        let name = match col {
                            GroupByColumn::TenantId => "tenant_id",
                            GroupByColumn::RouteId => "route_id",
                            GroupByColumn::Named(n) => n.as_str(),
                        };
                        if added.insert(name.to_string()) {
                            let dtype = match col {
                                GroupByColumn::TenantId | GroupByColumn::RouteId => DataType::UInt64,
                                GroupByColumn::Named(_) => DataType::Utf8,
                            };
                            fields.push(Field::new(name, dtype, true));
                        }
                    }
                }
            }
            GroupBy::Rollup(cols) | GroupBy::Cube(cols) => {
                for col in cols {
                    let name = match col {
                        GroupByColumn::TenantId => "tenant_id",
                        GroupByColumn::RouteId => "route_id",
                        GroupByColumn::Named(n) => n.as_str(),
                    };
                    let dtype = match col {
                        GroupByColumn::TenantId | GroupByColumn::RouteId => DataType::UInt64,
                        GroupByColumn::Named(_) => DataType::Utf8,
                    };
                    fields.push(Field::new(name, dtype, true));
                }
            }
        }

        // Add aggregate columns
        for agg in &self.plan.aggs {
            let name = agg.output_name();
            let dtype = match &agg.kind {
                AggKind::CountStar => DataType::UInt64,
                AggKind::CountDistinct { .. } => DataType::UInt64,
                AggKind::Sum { .. } => DataType::Int64,
                AggKind::Avg { .. } => DataType::Float64,
                AggKind::Min { .. } => DataType::Int64,
                AggKind::Max { .. } => DataType::Int64,
                AggKind::StddevSamp { .. } => DataType::Float64,
                AggKind::StddevPop { .. } => DataType::Float64,
                AggKind::VarianceSamp { .. } => DataType::Float64,
                AggKind::VariancePop { .. } => DataType::Float64,
                AggKind::ApproxCountDistinct { .. } => DataType::UInt64,
                AggKind::Median { .. } => DataType::Float64,
                AggKind::PercentileCont { .. } => DataType::Float64,
                AggKind::PercentileDisc { .. } => DataType::Float64,
                AggKind::ArrayAgg { .. } => DataType::Utf8, // Store as JSON string for now
                AggKind::StringAgg { .. } => DataType::Utf8,
                AggKind::Mode { .. } => DataType::Utf8, // Mode can be any type, store as string
                AggKind::StringAggOrdered { .. } => DataType::Utf8,
                AggKind::ArrayAggOrdered { .. } => DataType::Utf8,
                AggKind::NthValue { .. } => DataType::Utf8, // Value type varies
                AggKind::FirstValue { .. } => DataType::Utf8,
                AggKind::LastValue { .. } => DataType::Utf8,
            };
            fields.push(Field::new(name, dtype, true));
        }

        Ok(Arc::new(Schema::new(fields)))
    }

    fn build_global_result(
        &self,
        schema: &Arc<Schema>,
        state: &AggState,
    ) -> Result<RecordBatch, EngineError> {
        let mut columns: Vec<ArrayRef> = Vec::new();

        for agg in &self.plan.aggs {
            let agg_name = agg.output_name();
            let has_filter = agg.filter.is_some();

            let arr: ArrayRef = match &agg.kind {
                AggKind::CountStar => {
                    // For filtered COUNT(*), use filtered_counts
                    let count = if has_filter {
                        state.filtered_counts.get(&agg_name).copied().unwrap_or(0)
                    } else {
                        state.count_star
                    };
                    Arc::new(UInt64Array::from(vec![count]))
                }
                AggKind::CountDistinct { column } => {
                    let key = if has_filter { &agg_name } else { column };
                    let count = state
                        .count_distinct_sets
                        .get(key)
                        .map(|s| s.len())
                        .unwrap_or(0);
                    Arc::new(UInt64Array::from(vec![count as u64]))
                }
                AggKind::Sum { column } => {
                    let sum = if has_filter {
                        state.filtered_sums.get(&agg_name).copied().unwrap_or(0.0)
                    } else {
                        state.sum_values.get(column).copied().unwrap_or(0.0)
                    };
                    Arc::new(Int64Array::from(vec![sum as i64]))
                }
                AggKind::Avg { column } => {
                    let (sum, count) = if has_filter {
                        (
                            state.filtered_avg_sums.get(&agg_name).copied().unwrap_or(0.0),
                            state.filtered_avg_counts.get(&agg_name).copied().unwrap_or(0),
                        )
                    } else {
                        (
                            state.avg_sums.get(column).copied().unwrap_or(0.0),
                            state.avg_counts.get(column).copied().unwrap_or(0),
                        )
                    };
                    let avg = if count > 0 { sum / count as f64 } else { 0.0 };
                    Arc::new(Float64Array::from(vec![avg]))
                }
                AggKind::Min { column } => {
                    let min = if has_filter {
                        state.filtered_mins.get(&agg_name).copied().unwrap_or(f64::INFINITY)
                    } else {
                        state.min_values.get(column).copied().unwrap_or(f64::INFINITY)
                    };
                    Arc::new(Int64Array::from(vec![if min.is_infinite() {
                        0
                    } else {
                        min as i64
                    }]))
                }
                AggKind::Max { column } => {
                    let max = if has_filter {
                        state.filtered_maxs.get(&agg_name).copied().unwrap_or(f64::NEG_INFINITY)
                    } else {
                        state.max_values.get(column).copied().unwrap_or(f64::NEG_INFINITY)
                    };
                    Arc::new(Int64Array::from(vec![if max.is_infinite() {
                        0
                    } else {
                        max as i64
                    }]))
                }
                AggKind::ApproxCountDistinct { column } => {
                    let key = if has_filter { &agg_name } else { column };
                    let count = state
                        .count_distinct_sets
                        .get(key)
                        .map(|s| s.len())
                        .unwrap_or(0);
                    Arc::new(UInt64Array::from(vec![count as u64]))
                }
                AggKind::Median { column } => {
                    let result = if let Some(values) = state.percentile_values.get(column) {
                        let mut sorted = values.clone();
                        compute_percentile(&mut sorted, 0.5, true)
                    } else {
                        0.0
                    };
                    Arc::new(Float64Array::from(vec![result]))
                }
                AggKind::PercentileCont { column, percentile } => {
                    let result = if let Some(values) = state.percentile_values.get(column) {
                        let mut sorted = values.clone();
                        compute_percentile(&mut sorted, *percentile, true)
                    } else {
                        0.0
                    };
                    Arc::new(Float64Array::from(vec![result]))
                }
                AggKind::PercentileDisc { column, percentile } => {
                    let result = if let Some(values) = state.percentile_values.get(column) {
                        let mut sorted = values.clone();
                        compute_percentile(&mut sorted, *percentile, false)
                    } else {
                        0.0
                    };
                    Arc::new(Float64Array::from(vec![result]))
                }
                AggKind::ArrayAgg { column, .. } => {
                    let json = if let Some(values) = state.array_agg_values.get(column) {
                        serde_json::to_string(values).unwrap_or_else(|_| "[]".to_string())
                    } else {
                        "[]".to_string()
                    };
                    Arc::new(StringArray::from(vec![json]))
                }
                AggKind::StringAgg { column, delimiter, .. } => {
                    let result = if let Some(values) = state.string_agg_values.get(column) {
                        values.join(delimiter)
                    } else {
                        String::new()
                    };
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::Mode { column } => {
                    // Find most frequent value
                    let result = if let Some(values) = state.string_agg_values.get(column) {
                        compute_mode(values)
                    } else {
                        String::new()
                    };
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::StringAggOrdered { column, delimiter, order_by, order_desc } => {
                    // Get values with their order keys, sort, then join
                    let result = if let Some(values) = state.ordered_values.get(column) {
                        let mut sorted: Vec<_> = values.iter().cloned().collect();
                        sorted.sort_by(|a, b| {
                            let cmp = a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal);
                            if *order_desc { cmp.reverse() } else { cmp }
                        });
                        sorted.iter().map(|(v, _)| v.as_str()).collect::<Vec<_>>().join(delimiter)
                    } else if let Some(values) = state.string_agg_values.get(column) {
                        values.join(delimiter)
                    } else {
                        String::new()
                    };
                    let _ = order_by; // suppress unused warning
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::ArrayAggOrdered { column, order_by, order_desc } => {
                    let json = if let Some(values) = state.ordered_values.get(column) {
                        let mut sorted: Vec<_> = values.iter().cloned().collect();
                        sorted.sort_by(|a, b| {
                            let cmp = a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal);
                            if *order_desc { cmp.reverse() } else { cmp }
                        });
                        let vals: Vec<_> = sorted.iter().map(|(v, _)| v.as_str()).collect();
                        serde_json::to_string(&vals).unwrap_or_else(|_| "[]".to_string())
                    } else if let Some(values) = state.array_agg_values.get(column) {
                        serde_json::to_string(values).unwrap_or_else(|_| "[]".to_string())
                    } else {
                        "[]".to_string()
                    };
                    let _ = order_by; // suppress unused warning
                    Arc::new(StringArray::from(vec![json]))
                }
                AggKind::NthValue { column, n } => {
                    let result = if let Some(values) = state.array_agg_values.get(column) {
                        values.get(*n - 1).cloned().unwrap_or_default()
                    } else {
                        String::new()
                    };
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::FirstValue { column } => {
                    let result = if let Some(values) = state.array_agg_values.get(column) {
                        values.first().cloned().unwrap_or_default()
                    } else {
                        String::new()
                    };
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::LastValue { column } => {
                    let result = if let Some(values) = state.array_agg_values.get(column) {
                        values.last().cloned().unwrap_or_default()
                    } else {
                        String::new()
                    };
                    Arc::new(StringArray::from(vec![result]))
                }
                AggKind::StddevSamp { .. }
                | AggKind::StddevPop { .. }
                | AggKind::VarianceSamp { .. }
                | AggKind::VariancePop { .. } => {
                    // Not implemented - return NULL
                    Arc::new(Float64Array::from(vec![None::<f64>]))
                }
            };
            columns.push(arr);
        }

        RecordBatch::try_new(schema.clone(), columns)
            .map_err(|e| EngineError::Internal(format!("batch creation error: {}", e)))
    }

    fn build_grouped_result(&self, schema: &Arc<Schema>) -> Result<RecordBatch, EngineError> {
        if self.grouped_state.is_empty() {
            // Return empty batch
            let columns: Vec<ArrayRef> = schema
                .fields()
                .iter()
                .map(|f| match f.data_type() {
                    DataType::Int64 => Arc::new(Int64Array::from(Vec::<i64>::new())) as ArrayRef,
                    DataType::UInt64 => Arc::new(UInt64Array::from(Vec::<u64>::new())) as ArrayRef,
                    DataType::Float64 => {
                        Arc::new(Float64Array::from(Vec::<f64>::new())) as ArrayRef
                    }
                    _ => Arc::new(Int64Array::from(Vec::<i64>::new())) as ArrayRef,
                })
                .collect();
            return RecordBatch::try_new(schema.clone(), columns)
                .map_err(|e| EngineError::Internal(format!("batch creation error: {}", e)));
        }

        let num_groups = self.grouped_state.len();
        let group_cols = self.get_group_column_names();
        let num_group_cols = group_cols.len();

        // Build group key columns
        let mut key_builders: Vec<UInt64Builder> = (0..num_group_cols)
            .map(|_| UInt64Builder::with_capacity(num_groups))
            .collect();

        // Build aggregate columns
        let mut agg_columns: Vec<Vec<f64>> = self
            .plan
            .aggs
            .iter()
            .map(|_| Vec::with_capacity(num_groups))
            .collect();
        let mut count_star_values: Vec<i64> = Vec::with_capacity(num_groups);

        for (key, state) in &self.grouped_state {
            // Add key values
            for (i, kv) in key.iter().enumerate() {
                if i < key_builders.len() {
                    match kv {
                        GroupKeyValue::UInt64(v) => key_builders[i].append_value(*v),
                        GroupKeyValue::Int64(v) => key_builders[i].append_value(*v as u64),
                        GroupKeyValue::Null => key_builders[i].append_null(),
                        _ => key_builders[i].append_null(),
                    }
                }
            }

            // Add aggregate values
            for (i, agg) in self.plan.aggs.iter().enumerate() {
                let value = match &agg.kind {
                    AggKind::CountStar => state.count_star as f64,
                    AggKind::CountDistinct { column } => state
                        .count_distinct_sets
                        .get(column)
                        .map(|s| s.len() as f64)
                        .unwrap_or(0.0),
                    AggKind::Sum { column } => state.sum_values.get(column).copied().unwrap_or(0.0),
                    AggKind::Avg { column } => {
                        let sum = state.avg_sums.get(column).copied().unwrap_or(0.0);
                        let count = state.avg_counts.get(column).copied().unwrap_or(0);
                        if count > 0 {
                            sum / count as f64
                        } else {
                            0.0
                        }
                    }
                    AggKind::Min { column } => {
                        let v = state.min_values.get(column).copied().unwrap_or(f64::NAN);
                        if v.is_infinite() {
                            f64::NAN
                        } else {
                            v
                        }
                    }
                    AggKind::Max { column } => {
                        let v = state.max_values.get(column).copied().unwrap_or(f64::NAN);
                        if v.is_infinite() {
                            f64::NAN
                        } else {
                            v
                        }
                    }
                    _ => f64::NAN,
                };
                agg_columns[i].push(value);
            }
        }

        // Build final columns
        let mut columns: Vec<ArrayRef> = Vec::new();

        // Add group key columns
        for mut builder in key_builders {
            columns.push(Arc::new(builder.finish()));
        }

        // Add aggregate columns
        for (i, agg) in self.plan.aggs.iter().enumerate() {
            let arr: ArrayRef = match &agg.kind {
                AggKind::CountStar
                | AggKind::CountDistinct { .. }
                | AggKind::ApproxCountDistinct { .. } => Arc::new(UInt64Array::from(
                    agg_columns[i].iter().map(|v| *v as u64).collect::<Vec<_>>(),
                )),
                AggKind::Sum { .. } | AggKind::Min { .. } | AggKind::Max { .. } => Arc::new(
                    Int64Array::from(agg_columns[i].iter().map(|v| *v as i64).collect::<Vec<_>>()),
                ),
                _ => Arc::new(Float64Array::from(agg_columns[i].clone())),
            };
            columns.push(arr);
        }

        RecordBatch::try_new(schema.clone(), columns)
            .map_err(|e| EngineError::Internal(format!("batch creation error: {}", e)))
    }

    fn get_group_column_names(&self) -> Vec<String> {
        match &self.plan.group_by {
            GroupBy::None => vec![],
            GroupBy::Tenant => vec!["tenant_id".to_string()],
            GroupBy::Route => vec!["route_id".to_string()],
            GroupBy::Columns(cols) => cols
                .iter()
                .map(|c| match c {
                    GroupByColumn::TenantId => "tenant_id".to_string(),
                    GroupByColumn::RouteId => "route_id".to_string(),
                    GroupByColumn::Named(name) => name.clone(),
                })
                .collect(),
            GroupBy::All => vec![],
            GroupBy::GroupingSets(sets) => {
                // Return all unique column names
                let mut names = Vec::new();
                for set in sets {
                    for col in set {
                        let name = match col {
                            GroupByColumn::TenantId => "tenant_id".to_string(),
                            GroupByColumn::RouteId => "route_id".to_string(),
                            GroupByColumn::Named(n) => n.clone(),
                        };
                        if !names.contains(&name) {
                            names.push(name);
                        }
                    }
                }
                names
            }
            GroupBy::Rollup(cols) | GroupBy::Cube(cols) => cols
                .iter()
                .map(|c| match c {
                    GroupByColumn::TenantId => "tenant_id".to_string(),
                    GroupByColumn::RouteId => "route_id".to_string(),
                    GroupByColumn::Named(name) => name.clone(),
                })
                .collect(),
        }
    }
}

/// Extract a group key value from an array at a specific row
fn extract_group_key_value(arr: &ArrayRef, row: usize) -> GroupKeyValue {
    if arr.is_null(row) {
        return GroupKeyValue::Null;
    }

    if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        GroupKeyValue::UInt64(a.value(row))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        GroupKeyValue::Int64(a.value(row))
    } else if let Some(a) = arr.as_any().downcast_ref::<StringArray>() {
        GroupKeyValue::String(a.value(row).to_string())
    } else {
        GroupKeyValue::Null
    }
}

/// Add distinct values from an array to a HashSet (using hash of value)
fn add_distinct_values(arr: &ArrayRef, set: &mut HashSet<u64>) -> Result<(), EngineError> {
    for i in 0..arr.len() {
        if arr.is_null(i) {
            continue;
        }
        let hash = hash_array_value_u64(arr, i);
        set.insert(hash);
    }
    Ok(())
}

/// Hash a value from an array at a specific index (returns u64)
fn hash_array_value_u64(arr: &ArrayRef, row: usize) -> u64 {
    let mut hasher = DefaultHasher::new();
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        a.value(row).hash(&mut hasher);
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        a.value(row).hash(&mut hasher);
    } else if let Some(a) = arr.as_any().downcast_ref::<StringArray>() {
        a.value(row).hash(&mut hasher);
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        a.value(row).to_bits().hash(&mut hasher);
    }
    hasher.finish()
}

/// Compute sum of an array
fn compute_sum(arr: &ArrayRef) -> Result<f64, EngineError> {
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        Ok(aggregate::sum(a).unwrap_or(0) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        Ok(aggregate::sum(a).unwrap_or(0) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        Ok(aggregate::sum(a).unwrap_or(0.0))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        Ok(aggregate::sum(a).unwrap_or(0) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<Float32Array>() {
        Ok(aggregate::sum(a).unwrap_or(0.0) as f64)
    } else {
        Ok(0.0)
    }
}

/// Compute min of an array
fn compute_min(arr: &ArrayRef) -> Result<Option<f64>, EngineError> {
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        Ok(aggregate::min(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        Ok(aggregate::min(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        Ok(aggregate::min(a))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        Ok(aggregate::min(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float32Array>() {
        Ok(aggregate::min(a).map(|v| v as f64))
    } else {
        Ok(None)
    }
}

/// Compute max of an array
fn compute_max(arr: &ArrayRef) -> Result<Option<f64>, EngineError> {
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        Ok(aggregate::max(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        Ok(aggregate::max(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        Ok(aggregate::max(a))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        Ok(aggregate::max(a).map(|v| v as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float32Array>() {
        Ok(aggregate::max(a).map(|v| v as f64))
    } else {
        Ok(None)
    }
}

/// Accumulate aggregations into state (standalone function to avoid borrow issues)
fn accumulate_aggs_into(
    state: &mut AggState,
    aggs: &[AggregateExpr],
    batch: &RecordBatch,
) -> Result<(), EngineError> {
    let num_rows = batch.num_rows();
    state.count_star += num_rows as u64;

    for agg in aggs {
        match &agg.kind {
            AggKind::CountStar => {
                // Already counted above
            }
            AggKind::CountDistinct { column } | AggKind::ApproxCountDistinct { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let set = state
                        .count_distinct_sets
                        .entry(column.clone())
                        .or_insert_with(HashSet::new);
                    add_distinct_values(col, set)?;
                }
            }
            AggKind::Sum { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let sum = compute_sum(col)?;
                    *state.sum_values.entry(column.clone()).or_insert(0.0) += sum;
                }
            }
            AggKind::Avg { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let sum = compute_sum(col)?;
                    let count = col.len() - col.null_count();
                    *state.avg_sums.entry(column.clone()).or_insert(0.0) += sum;
                    *state.avg_counts.entry(column.clone()).or_insert(0) += count as u64;
                }
            }
            AggKind::Min { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let min_val = compute_min(col)?;
                    if let Some(min) = min_val {
                        let entry = state
                            .min_values
                            .entry(column.clone())
                            .or_insert(f64::INFINITY);
                        if min < *entry {
                            *entry = min;
                        }
                    }
                }
            }
            AggKind::Max { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let max_val = compute_max(col)?;
                    if let Some(max) = max_val {
                        let entry = state
                            .max_values
                            .entry(column.clone())
                            .or_insert(f64::NEG_INFINITY);
                        if max > *entry {
                            *entry = max;
                        }
                    }
                }
            }
            AggKind::StddevSamp { .. }
            | AggKind::StddevPop { .. }
            | AggKind::VarianceSamp { .. }
            | AggKind::VariancePop { .. } => {
                // Not yet implemented - would need two-pass or online algorithms
            }
            AggKind::Median { column } | AggKind::PercentileCont { column, .. } | AggKind::PercentileDisc { column, .. } => {
                // Collect all values for percentile computation
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let values = state
                        .percentile_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_numeric_values(col, values);
                }
            }
            AggKind::ArrayAgg { column, distinct } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let values = state
                        .array_agg_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_string_values(col, values, *distinct);
                }
            }
            AggKind::StringAgg { column, distinct, .. } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let values = state
                        .string_agg_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_string_values(col, values, *distinct);
                }
            }
            AggKind::Mode { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let counts = state
                        .mode_counts
                        .entry(column.clone())
                        .or_insert_with(HashMap::new);
                    collect_mode_values(col, counts);
                    // Also collect for string_agg_values for fallback
                    let values = state
                        .string_agg_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_string_values(col, values, false);
                }
            }
            AggKind::StringAggOrdered { column, order_by, .. } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let order_col = if let Ok(order_idx) = batch.schema().index_of(order_by) {
                        Some(batch.column(order_idx))
                    } else {
                        None
                    };
                    let values = state
                        .ordered_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_ordered_values(col, order_col, values);
                }
            }
            AggKind::ArrayAggOrdered { column, order_by, .. } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let order_col = if let Ok(order_idx) = batch.schema().index_of(order_by) {
                        Some(batch.column(order_idx))
                    } else {
                        None
                    };
                    let values = state
                        .ordered_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_ordered_values(col, order_col, values);
                }
            }
            AggKind::NthValue { column, .. } | AggKind::FirstValue { column } | AggKind::LastValue { column } => {
                if let Ok(col_idx) = batch.schema().index_of(column) {
                    let col = batch.column(col_idx);
                    let values = state
                        .array_agg_values
                        .entry(column.clone())
                        .or_insert_with(Vec::new);
                    collect_string_values(col, values, false);
                }
            }
        }
    }
    Ok(())
}

/// Collect numeric values from an array column into a Vec
fn collect_numeric_values(col: &ArrayRef, values: &mut Vec<f64>) {
    use arrow_array::*;

    match col.data_type() {
        DataType::Int8 => {
            let arr = col.as_any().downcast_ref::<Int8Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::Int16 => {
            let arr = col.as_any().downcast_ref::<Int16Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::Int32 => {
            let arr = col.as_any().downcast_ref::<Int32Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::Int64 => {
            let arr = col.as_any().downcast_ref::<Int64Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::UInt8 => {
            let arr = col.as_any().downcast_ref::<UInt8Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::UInt16 => {
            let arr = col.as_any().downcast_ref::<UInt16Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::UInt32 => {
            let arr = col.as_any().downcast_ref::<UInt32Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::UInt64 => {
            let arr = col.as_any().downcast_ref::<UInt64Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::Float32 => {
            let arr = col.as_any().downcast_ref::<Float32Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i) as f64);
                }
            }
        }
        DataType::Float64 => {
            let arr = col.as_any().downcast_ref::<Float64Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    values.push(arr.value(i));
                }
            }
        }
        _ => {} // Unsupported type
    }
}

/// Collect string values from an array column into a Vec
fn collect_string_values(col: &ArrayRef, values: &mut Vec<String>, distinct: bool) {
    use arrow_array::*;
    use std::collections::HashSet;

    let mut seen: HashSet<String> = if distinct {
        values.iter().cloned().collect()
    } else {
        HashSet::new()
    };

    match col.data_type() {
        DataType::Utf8 => {
            let arr = col.as_any().downcast_ref::<StringArray>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    let s = arr.value(i).to_string();
                    if distinct {
                        if !seen.contains(&s) {
                            seen.insert(s.clone());
                            values.push(s);
                        }
                    } else {
                        values.push(s);
                    }
                }
            }
        }
        DataType::LargeUtf8 => {
            let arr = col.as_any().downcast_ref::<LargeStringArray>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    let s = arr.value(i).to_string();
                    if distinct {
                        if !seen.contains(&s) {
                            seen.insert(s.clone());
                            values.push(s);
                        }
                    } else {
                        values.push(s);
                    }
                }
            }
        }
        _ => {
            // For non-string types, convert to string representation
            for i in 0..col.len() {
                if !col.is_null(i) {
                    let s = format!("{:?}", col);
                    if distinct {
                        if !seen.contains(&s) {
                            seen.insert(s.clone());
                            values.push(s);
                        }
                    } else {
                        values.push(s);
                    }
                }
            }
        }
    }
}

/// Collect values for MODE aggregate (count occurrences)
fn collect_mode_values(col: &ArrayRef, counts: &mut HashMap<String, u64>) {
    use arrow_array::*;

    match col.data_type() {
        DataType::Utf8 => {
            let arr = col.as_any().downcast_ref::<StringArray>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    let s = arr.value(i).to_string();
                    *counts.entry(s).or_insert(0) += 1;
                }
            }
        }
        DataType::Int64 => {
            let arr = col.as_any().downcast_ref::<Int64Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    let s = arr.value(i).to_string();
                    *counts.entry(s).or_insert(0) += 1;
                }
            }
        }
        DataType::Float64 => {
            let arr = col.as_any().downcast_ref::<Float64Array>().unwrap();
            for i in 0..arr.len() {
                if !arr.is_null(i) {
                    let s = arr.value(i).to_string();
                    *counts.entry(s).or_insert(0) += 1;
                }
            }
        }
        _ => {
            // Generic fallback using debug format
            for i in 0..col.len() {
                if !col.is_null(i) {
                    let s = format!("{:?}", col.slice(i, 1));
                    *counts.entry(s).or_insert(0) += 1;
                }
            }
        }
    }
}

/// Compute mode (most frequent value) from occurrence counts
fn compute_mode(values: &[String]) -> String {
    let mut counts: HashMap<&str, usize> = HashMap::new();
    for v in values {
        *counts.entry(v.as_str()).or_insert(0) += 1;
    }
    counts
        .into_iter()
        .max_by_key(|(_, count)| *count)
        .map(|(val, _)| val.to_string())
        .unwrap_or_default()
}

/// Collect values with their order keys for ordered aggregates
fn collect_ordered_values(
    col: &ArrayRef,
    order_col: Option<&ArrayRef>,
    values: &mut Vec<(String, f64)>,
) {
    use arrow_array::*;

    for i in 0..col.len() {
        if col.is_null(i) {
            continue;
        }

        // Get value as string
        let val = match col.data_type() {
            DataType::Utf8 => {
                col.as_any()
                    .downcast_ref::<StringArray>()
                    .unwrap()
                    .value(i)
                    .to_string()
            }
            DataType::Int64 => {
                col.as_any()
                    .downcast_ref::<Int64Array>()
                    .unwrap()
                    .value(i)
                    .to_string()
            }
            DataType::Float64 => {
                col.as_any()
                    .downcast_ref::<Float64Array>()
                    .unwrap()
                    .value(i)
                    .to_string()
            }
            _ => format!("{:?}", col.slice(i, 1)),
        };

        // Get order key (default to insertion order)
        let order_key = if let Some(order) = order_col {
            if order.is_null(i) {
                values.len() as f64
            } else {
                match order.data_type() {
                    DataType::Int64 => {
                        order
                            .as_any()
                            .downcast_ref::<Int64Array>()
                            .unwrap()
                            .value(i) as f64
                    }
                    DataType::Float64 => {
                        order
                            .as_any()
                            .downcast_ref::<Float64Array>()
                            .unwrap()
                            .value(i)
                    }
                    DataType::Utf8 => {
                        // Use string ordering - hash as f64
                        let s = order
                            .as_any()
                            .downcast_ref::<StringArray>()
                            .unwrap()
                            .value(i);
                        use std::collections::hash_map::DefaultHasher;
                        use std::hash::{Hash, Hasher};
                        let mut hasher = DefaultHasher::new();
                        s.hash(&mut hasher);
                        hasher.finish() as f64
                    }
                    _ => values.len() as f64,
                }
            }
        } else {
            values.len() as f64
        };

        values.push((val, order_key));
    }
}

/// Compute percentile from sorted values
fn compute_percentile(values: &mut [f64], percentile: f64, continuous: bool) -> f64 {
    if values.is_empty() {
        return 0.0;
    }

    values.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));

    let n = values.len();
    let idx = percentile * (n - 1) as f64;

    if continuous {
        // Interpolate between adjacent values
        let lower_idx = idx.floor() as usize;
        let upper_idx = idx.ceil() as usize;
        let frac = idx - lower_idx as f64;

        if lower_idx == upper_idx || upper_idx >= n {
            values[lower_idx.min(n - 1)]
        } else {
            values[lower_idx] * (1.0 - frac) + values[upper_idx] * frac
        }
    } else {
        // Return the nearest value
        values[idx.round() as usize]
    }
}

/// Accumulate aggregation for a single row (used in GROUP BY)
fn accumulate_single_row(
    state: &mut AggState,
    agg: &AggregateExpr,
    batch: &RecordBatch,
    row: usize,
) -> Result<(), EngineError> {
    // Check if this row passes the aggregate's FILTER clause
    if !row_passes_filter(&agg.filter, batch, row) {
        return Ok(());
    }

    let agg_name = agg.output_name();
    let has_filter = agg.filter.is_some();

    match &agg.kind {
        AggKind::CountStar => {
            // For filtered COUNT(*), track in filtered_counts
            if has_filter {
                *state.filtered_counts.entry(agg_name).or_insert(0) += 1;
            }
            // Unfiltered count is already tracked in outer loop
        }
        AggKind::CountDistinct { column } | AggKind::ApproxCountDistinct { column } => {
            if let Ok(col_idx) = batch.schema().index_of(column) {
                let col = batch.column(col_idx);
                if !col.is_null(row) {
                    let hash = hash_array_value_u64(col, row);
                    // For filtered COUNT DISTINCT, use aggregate name as key
                    let key = if has_filter { agg_name.clone() } else { column.clone() };
                    let set = state
                        .count_distinct_sets
                        .entry(key)
                        .or_insert_with(HashSet::new);
                    set.insert(hash);
                }
            }
        }
        AggKind::Sum { column } => {
            if let Ok(col_idx) = batch.schema().index_of(column) {
                let col = batch.column(col_idx);
                if !col.is_null(row) {
                    if let Some(v) = extract_f64(col, row) {
                        if has_filter {
                            *state.filtered_sums.entry(agg_name).or_insert(0.0) += v;
                        } else {
                            *state.sum_values.entry(column.clone()).or_insert(0.0) += v;
                        }
                    }
                }
            }
        }
        AggKind::Avg { column } => {
            if let Ok(col_idx) = batch.schema().index_of(column) {
                let col = batch.column(col_idx);
                if !col.is_null(row) {
                    if let Some(v) = extract_f64(col, row) {
                        if has_filter {
                            *state.filtered_avg_sums.entry(agg_name.clone()).or_insert(0.0) += v;
                            *state.filtered_avg_counts.entry(agg_name).or_insert(0) += 1;
                        } else {
                            *state.avg_sums.entry(column.clone()).or_insert(0.0) += v;
                            *state.avg_counts.entry(column.clone()).or_insert(0) += 1;
                        }
                    }
                }
            }
        }
        AggKind::Min { column } => {
            if let Ok(col_idx) = batch.schema().index_of(column) {
                let col = batch.column(col_idx);
                if !col.is_null(row) {
                    if let Some(v) = extract_f64(col, row) {
                        if has_filter {
                            let entry = state.filtered_mins.entry(agg_name).or_insert(f64::INFINITY);
                            if v < *entry {
                                *entry = v;
                            }
                        } else {
                            let entry = state.min_values.entry(column.clone()).or_insert(f64::INFINITY);
                            if v < *entry {
                                *entry = v;
                            }
                        }
                    }
                }
            }
        }
        AggKind::Max { column } => {
            if let Ok(col_idx) = batch.schema().index_of(column) {
                let col = batch.column(col_idx);
                if !col.is_null(row) {
                    if let Some(v) = extract_f64(col, row) {
                        if has_filter {
                            let entry = state.filtered_maxs.entry(agg_name).or_insert(f64::NEG_INFINITY);
                            if v > *entry {
                                *entry = v;
                            }
                        } else {
                            let entry = state.max_values.entry(column.clone()).or_insert(f64::NEG_INFINITY);
                            if v > *entry {
                                *entry = v;
                            }
                        }
                    }
                }
            }
        }
        _ => {}
    }
    Ok(())
}

/// Check if a row passes the aggregate's FILTER clause condition
/// Returns true if no filter is set or if the row matches the filter criteria
fn row_passes_filter(
    filter: &Option<crate::sql::AggregateFilter>,
    batch: &RecordBatch,
    row: usize,
) -> bool {
    let filter = match filter {
        Some(f) => f,
        None => return true, // No filter means include all rows
    };

    // Get the filter column
    let col_idx = match batch.schema().index_of(&filter.column) {
        Ok(idx) => idx,
        Err(_) => return false, // Column not found
    };
    let col = batch.column(col_idx);

    // Extract value from column
    let value = if col.is_null(row) {
        None
    } else {
        extract_value_for_filter(col, row)
    };

    // Apply the filter comparison
    filter.matches(value.as_ref())
}

/// Extract a value from an array for filter comparison
fn extract_value_for_filter(arr: &ArrayRef, row: usize) -> Option<serde_json::Value> {
    if arr.is_null(row) {
        return Some(serde_json::Value::Null);
    }

    // Try different array types
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<Float32Array>() {
        Some(serde_json::json!(a.value(row) as f64))
    } else if let Some(a) = arr.as_any().downcast_ref::<arrow_array::StringArray>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<arrow_array::LargeStringArray>() {
        Some(serde_json::json!(a.value(row)))
    } else if let Some(a) = arr.as_any().downcast_ref::<arrow_array::BooleanArray>() {
        Some(serde_json::json!(a.value(row)))
    } else {
        None
    }
}

/// Extract a float value from an array at a specific row
fn extract_f64(arr: &ArrayRef, row: usize) -> Option<f64> {
    if arr.is_null(row) {
        return None;
    }
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        Some(a.value(row) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        Some(a.value(row) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        Some(a.value(row))
    } else if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        Some(a.value(row) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<Float32Array>() {
        Some(a.value(row) as f64)
    } else if let Some(a) = arr
        .as_any()
        .downcast_ref::<arrow_array::TimestampMicrosecondArray>()
    {
        Some(a.value(row) as f64)
    } else if let Some(a) = arr.as_any().downcast_ref::<arrow_array::Date32Array>() {
        Some(a.value(row) as f64)
    } else {
        None
    }
}

pub fn aggregation_projection(agg: &AggPlan, proj: &[String]) -> Vec<String> {
    let mut needed = proj.to_vec();

    // Helper to add column if not present
    let mut add_col = |name: String| {
        if !needed.contains(&name) {
            needed.push(name);
        }
    };

    // Add group by columns
    match &agg.group_by {
        GroupBy::None | GroupBy::All => {}
        GroupBy::Tenant => add_col("tenant_id".to_string()),
        GroupBy::Route => add_col("route_id".to_string()),
        GroupBy::Columns(cols) => {
            for col in cols {
                let col_name = match col {
                    GroupByColumn::TenantId => "tenant_id".to_string(),
                    GroupByColumn::RouteId => "route_id".to_string(),
                    GroupByColumn::Named(name) => name.clone(),
                };
                add_col(col_name);
            }
        }
        GroupBy::GroupingSets(sets) => {
            for set in sets {
                for col in set {
                    let col_name = match col {
                        GroupByColumn::TenantId => "tenant_id".to_string(),
                        GroupByColumn::RouteId => "route_id".to_string(),
                        GroupByColumn::Named(name) => name.clone(),
                    };
                    add_col(col_name);
                }
            }
        }
        GroupBy::Rollup(cols) | GroupBy::Cube(cols) => {
            for col in cols {
                let col_name = match col {
                    GroupByColumn::TenantId => "tenant_id".to_string(),
                    GroupByColumn::RouteId => "route_id".to_string(),
                    GroupByColumn::Named(name) => name.clone(),
                };
                add_col(col_name);
            }
        }
    }

    // Add columns needed by aggregations
    for a in &agg.aggs {
        match &a.kind {
            AggKind::CountStar => {}
            AggKind::CountDistinct { column }
            | AggKind::Sum { column }
            | AggKind::Avg { column }
            | AggKind::Min { column }
            | AggKind::Max { column }
            | AggKind::StddevSamp { column }
            | AggKind::StddevPop { column }
            | AggKind::VarianceSamp { column }
            | AggKind::VariancePop { column }
            | AggKind::ApproxCountDistinct { column }
            | AggKind::Median { column }
            | AggKind::PercentileCont { column, .. }
            | AggKind::PercentileDisc { column, .. }
            | AggKind::ArrayAgg { column, .. }
            | AggKind::StringAgg { column, .. }
            | AggKind::Mode { column }
            | AggKind::NthValue { column, .. }
            | AggKind::FirstValue { column }
            | AggKind::LastValue { column } => {
                if !needed.contains(column) {
                    needed.push(column.clone());
                }
            }
            AggKind::StringAggOrdered { column, order_by, .. }
            | AggKind::ArrayAggOrdered { column, order_by, .. } => {
                if !needed.contains(column) {
                    needed.push(column.clone());
                }
                if !needed.contains(order_by) {
                    needed.push(order_by.clone());
                }
            }
        }
    }

    needed
}
pub fn split_filter_for_join(
    f: &QueryFilter,
    _l: Option<&arrow_schema::Schema>,
    _r: Option<&arrow_schema::Schema>,
) -> (QueryFilter, QueryFilter, QueryFilter) {
    (f.clone(), QueryFilter::default(), QueryFilter::default())
}
pub fn join_projection_sets(
    _l: &arrow_schema::Schema,
    _r: &arrow_schema::Schema,
    _p: Option<&[String]>,
    _lc: &str,
    _rc: &str,
    _k: &[String],
) -> Result<(Option<Vec<String>>, Option<Vec<String>>), EngineError> {
    Ok((None, None))
}
pub fn extend_needed_with_filter(
    _n: &mut Vec<String>,
    _f: &QueryFilter,
    _s: Option<&arrow_schema::Schema>,
) {
}
// Duplicates removed

/// Execute a recursive CTE
/// Recursive CTEs have the form: anchor_query UNION [ALL] recursive_query
/// The recursive query references the CTE itself
fn execute_recursive_cte(
    db: &Db,
    cte: &crate::sql::CteDefinition,
    _cte_context: &CteContext,
    timeout_millis: u32,
) -> Result<Vec<u8>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use arrow_ipc::writer::StreamWriter;

    // Parse the CTE query to extract anchor and recursive parts
    // The raw_sql should be something like:
    // "SELECT 1 as n UNION ALL SELECT n + 1 FROM cte_name WHERE n < 10"
    let (anchor_sql, recursive_sql, is_union_all) =
        parse_recursive_cte_parts(&cte.raw_sql, &cte.name)?;

    // Execute the anchor query
    let anchor_result = db.query(QueryRequest {
        sql: anchor_sql.clone(),
        timeout_millis,
        collect_stats: false,
        transaction_id: None,
    })?;

    if anchor_result.records_ipc.is_empty() {
        return Ok(Vec::new());
    }

    // Parse anchor results into batches
    let mut all_batches: Vec<RecordBatch> = Vec::new();
    let mut current_batches: Vec<RecordBatch> = Vec::new();
    {
        let cursor = Cursor::new(&anchor_result.records_ipc);
        let mut reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("failed to read anchor result: {e}")))?;
        while let Some(batch_result) = reader.next() {
            let batch = batch_result
                .map_err(|e| EngineError::Internal(format!("failed to read anchor batch: {e}")))?;
            all_batches.push(batch.clone());
            current_batches.push(batch);
        }
    }

    if current_batches.is_empty() {
        return Ok(anchor_result.records_ipc);
    }

    // Get the schema from the anchor result
    let schema = current_batches[0].schema();

    // Recursive iteration with a maximum depth to prevent infinite loops
    const MAX_RECURSION_DEPTH: usize = 1000;
    let mut iteration = 0;

    while iteration < MAX_RECURSION_DEPTH {
        iteration += 1;

        // Create a temporary table with the current iteration's data
        let _temp_table_name = format!("__recursive_temp_{}", cte.name);

        // Serialize current batches to IPC for the temp table
        let mut temp_ipc = Vec::new();
        {
            let mut writer = StreamWriter::try_new(&mut temp_ipc, schema.as_ref())
                .map_err(|e| EngineError::Internal(format!("failed to create temp IPC: {e}")))?;
            for batch in &current_batches {
                writer.write(batch).map_err(|e| {
                    EngineError::Internal(format!("failed to write temp batch: {e}"))
                })?;
            }
            writer
                .finish()
                .map_err(|e| EngineError::Internal(format!("failed to finish temp IPC: {e}")))?;
        }

        // For now, we execute the recursive query by replacing references to the CTE name
        // with a subquery or inline values. This is a simplified approach.
        // A more complete implementation would use a temporary table.

        // Replace CTE name references with inline VALUES or subquery
        let recursive_with_data =
            replace_cte_reference_with_values(&recursive_sql, &cte.name, &current_batches)?;

        // Execute the recursive step
        let recursive_result = db.query(QueryRequest {
            sql: recursive_with_data,
            timeout_millis,
            collect_stats: false,
            transaction_id: None,
        });

        match recursive_result {
            Ok(result) => {
                if result.records_ipc.is_empty() {
                    // No more results, recursion complete
                    break;
                }

                // Parse new results
                current_batches.clear();
                let cursor = Cursor::new(&result.records_ipc);
                let mut reader = StreamReader::try_new(cursor, None).map_err(|e| {
                    EngineError::Internal(format!("failed to read recursive result: {e}"))
                })?;

                let mut has_rows = false;
                while let Some(batch_result) = reader.next() {
                    let batch = batch_result.map_err(|e| {
                        EngineError::Internal(format!("failed to read recursive batch: {e}"))
                    })?;
                    if batch.num_rows() > 0 {
                        has_rows = true;
                        if is_union_all {
                            all_batches.push(batch.clone());
                        } else {
                            // For UNION (not ALL), we'd need to deduplicate
                            // For simplicity, we'll just add them
                            all_batches.push(batch.clone());
                        }
                        current_batches.push(batch);
                    }
                }

                if !has_rows {
                    break;
                }
            }
            Err(_) => {
                // Query failed, likely no more valid results
                break;
            }
        }
    }

    if iteration >= MAX_RECURSION_DEPTH {
        return Err(EngineError::InvalidArgument(
            "recursive CTE exceeded maximum recursion depth (1000)".into(),
        ));
    }

    // Serialize all accumulated batches
    if all_batches.is_empty() {
        return Ok(Vec::new());
    }

    let mut output_ipc = Vec::new();
    {
        let mut writer =
            StreamWriter::try_new(&mut output_ipc, all_batches[0].schema().as_ref())
                .map_err(|e| EngineError::Internal(format!("failed to create output IPC: {e}")))?;
        for batch in &all_batches {
            writer
                .write(batch)
                .map_err(|e| EngineError::Internal(format!("failed to write output batch: {e}")))?;
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("failed to finish output IPC: {e}")))?;
    }

    Ok(output_ipc)
}

/// Parse a recursive CTE query into anchor and recursive parts
/// Returns (anchor_sql, recursive_sql, is_union_all)
fn parse_recursive_cte_parts(
    raw_sql: &str,
    cte_name: &str,
) -> Result<(String, String, bool), EngineError> {
    let upper = raw_sql.to_uppercase();

    // Find UNION ALL or UNION
    let (union_pos, is_union_all) = if let Some(pos) = upper.find("UNION ALL") {
        (pos, true)
    } else if let Some(pos) = upper.find("UNION") {
        (pos, false)
    } else {
        return Err(EngineError::InvalidArgument(format!(
            "recursive CTE '{}' must contain UNION or UNION ALL",
            cte_name
        )));
    };

    let anchor_sql = raw_sql[..union_pos].trim().to_string();
    let recursive_start = if is_union_all {
        union_pos + 9 // "UNION ALL".len()
    } else {
        union_pos + 5 // "UNION".len()
    };
    let recursive_sql = raw_sql[recursive_start..].trim().to_string();

    Ok((anchor_sql, recursive_sql, is_union_all))
}

/// Replace CTE name references in the recursive query with actual values
fn replace_cte_reference_with_values(
    recursive_sql: &str,
    cte_name: &str,
    current_batches: &[RecordBatch],
) -> Result<String, EngineError> {
    fn is_safe_cte_name(name: &str) -> bool {
        if name.is_empty() || name.len() > 128 {
            return false;
        }
        let mut chars = name.chars();
        let first = match chars.next() {
            Some(c) => c,
            None => return false,
        };
        if !(first.is_ascii_alphabetic() || first == '_') {
            return false;
        }
        chars.all(|c| c.is_ascii_alphanumeric() || c == '_')
    }

    fn sql_literal_for_value(col: &ArrayRef, row_idx: usize) -> Result<String, EngineError> {
        use arrow_array::{
            BooleanArray, Float32Array, Float64Array, Int32Array, Int64Array, LargeStringArray,
            StringArray, UInt64Array,
        };

        if col.is_null(row_idx) {
            return Ok("NULL".to_string());
        }

        match col.data_type() {
            arrow_schema::DataType::Utf8 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<StringArray>()
                    .ok_or_else(|| EngineError::Internal("invalid Utf8 array".into()))?;
                let value = arr.value(row_idx).replace('\'', "''");
                Ok(format!("'{}'", value))
            }
            arrow_schema::DataType::LargeUtf8 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<LargeStringArray>()
                    .ok_or_else(|| EngineError::Internal("invalid LargeUtf8 array".into()))?;
                let value = arr.value(row_idx).replace('\'', "''");
                Ok(format!("'{}'", value))
            }
            arrow_schema::DataType::Int64 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<Int64Array>()
                    .ok_or_else(|| EngineError::Internal("invalid Int64 array".into()))?;
                Ok(arr.value(row_idx).to_string())
            }
            arrow_schema::DataType::Int32 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<Int32Array>()
                    .ok_or_else(|| EngineError::Internal("invalid Int32 array".into()))?;
                Ok(arr.value(row_idx).to_string())
            }
            arrow_schema::DataType::UInt64 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<UInt64Array>()
                    .ok_or_else(|| EngineError::Internal("invalid UInt64 array".into()))?;
                Ok(arr.value(row_idx).to_string())
            }
            arrow_schema::DataType::Float64 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<Float64Array>()
                    .ok_or_else(|| EngineError::Internal("invalid Float64 array".into()))?;
                Ok(arr.value(row_idx).to_string())
            }
            arrow_schema::DataType::Float32 => {
                let arr = col
                    .as_any()
                    .downcast_ref::<Float32Array>()
                    .ok_or_else(|| EngineError::Internal("invalid Float32 array".into()))?;
                Ok(arr.value(row_idx).to_string())
            }
            arrow_schema::DataType::Boolean => {
                let arr = col
                    .as_any()
                    .downcast_ref::<BooleanArray>()
                    .ok_or_else(|| EngineError::Internal("invalid Boolean array".into()))?;
                Ok(if arr.value(row_idx) { "true" } else { "false" }.to_string())
            }
            other => Err(EngineError::InvalidArgument(format!(
                "unsupported CTE value type: {other}"
            ))),
        }
    }

    if !is_safe_cte_name(cte_name) {
        return Err(EngineError::InvalidArgument("invalid CTE name".into()));
    }

    // If no data, return a query that returns no results
    if current_batches.is_empty() || current_batches.iter().all(|b| b.num_rows() == 0) {
        // Return a query that produces empty results with the same structure
        return Ok(format!("{} WHERE 1=0", recursive_sql));
    }

    // Build a VALUES clause or subquery from the current data
    let first_batch = &current_batches[0];
    let schema = first_batch.schema();
    let num_cols = schema.fields().len();

    // Collect column names
    let col_names: Vec<&str> = schema.fields().iter().map(|f| f.name().as_str()).collect();

    // Build VALUES rows from all batches
    let mut value_rows = Vec::new();
    for batch in current_batches {
        for row_idx in 0..batch.num_rows() {
            let mut row_values = Vec::new();
            for col_idx in 0..num_cols {
                let col = batch.column(col_idx);
                let val = sql_literal_for_value(col, row_idx)?;
                row_values.push(val);
            }
            value_rows.push(format!("({})", row_values.join(", ")));
        }
    }

    if value_rows.is_empty() {
        return Ok(format!("{} WHERE 1=0", recursive_sql));
    }

    // Create a subquery that returns the current values
    // (SELECT col1, col2, ... FROM (VALUES (v1, v2), (v3, v4), ...) AS t(col1, col2))
    let values_sql = format!(
        "(SELECT * FROM (VALUES {}) AS {}({}))",
        value_rows.join(", "),
        cte_name,
        col_names.join(", ")
    );

    // Replace references to the CTE name with the VALUES subquery
    // We need to be careful to only replace table references, not column names
    let pattern = format!(r"\b{}\b", regex::escape(cte_name));
    let re = regex::Regex::new(&pattern)
        .map_err(|e| EngineError::Internal(format!("regex error: {e}")))?;

    // Replace FROM cte_name with FROM (VALUES ...)
    let result = re
        .replace_all(recursive_sql, values_sql.as_str())
        .to_string();

    Ok(result)
}

/// Build a WHERE clause from a ParsedQuery
///
/// # Security Note
/// All filter values (watermark_ge, watermark_le, event_time_ge, event_time_le,
/// tenant_id_eq, route_id_eq) are typed as Option<u64> in QueryFilter.
/// This makes them inherently safe from SQL injection since u64 values can only
/// contain numeric digits and cannot represent SQL injection strings.
fn build_where_clause(query: &crate::sql::ParsedQuery) -> String {
    let mut clauses = Vec::new();

    if let Some(ge) = query.filter.watermark_ge {
        clauses.push(format!("watermark_micros >= {ge}"));
    }
    if let Some(le) = query.filter.watermark_le {
        clauses.push(format!("watermark_micros <= {le}"));
    }
    if let Some(ge) = query.filter.event_time_ge {
        clauses.push(format!("event_time >= {ge}"));
    }
    if let Some(le) = query.filter.event_time_le {
        clauses.push(format!("event_time <= {le}"));
    }
    if let Some(eq) = query.filter.tenant_id_eq {
        clauses.push(format!("tenant_id = {eq}"));
    }
    if let Some(eq) = query.filter.route_id_eq {
        clauses.push(format!("route_id = {eq}"));
    }

    if clauses.is_empty() {
        String::new()
    } else {
        format!("WHERE {}", clauses.join(" AND "))
    }
}

/// Merge CTE results with main query results
/// Used when the main query references CTEs that need to be combined
pub fn merge_cte_results(
    main_result: &[u8],
    cte_context: &CteContext,
    cte_names: &[String],
) -> Result<Vec<u8>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use arrow_ipc::writer::StreamWriter;

    if cte_names.is_empty() {
        return Ok(main_result.to_vec());
    }

    let mut all_batches = Vec::new();

    // Add main result batches
    if !main_result.is_empty() {
        let cursor = Cursor::new(main_result);
        let mut reader = StreamReader::try_new(cursor, None)
            .map_err(|e| EngineError::Internal(format!("failed to read main result: {e}")))?;
        while let Some(batch_result) = reader.next() {
            let batch = batch_result
                .map_err(|e| EngineError::Internal(format!("failed to read batch: {e}")))?;
            all_batches.push(batch);
        }
    }

    // Add CTE result batches
    for cte_name in cte_names {
        if let Some(cte_data) = cte_context.get_result(cte_name) {
            if !cte_data.is_empty() {
                let cursor = Cursor::new(cte_data);
                let mut reader = StreamReader::try_new(cursor, None).map_err(|e| {
                    EngineError::Internal(format!("failed to read CTE result: {e}"))
                })?;
                while let Some(batch_result) = reader.next() {
                    let batch = batch_result.map_err(|e| {
                        EngineError::Internal(format!("failed to read CTE batch: {e}"))
                    })?;
                    all_batches.push(batch);
                }
            }
        }
    }

    if all_batches.is_empty() {
        return Ok(Vec::new());
    }

    // Encode all batches back to IPC
    let mut output_ipc = Vec::new();
    {
        let mut writer =
            StreamWriter::try_new(&mut output_ipc, all_batches[0].schema().as_ref())
                .map_err(|e| EngineError::Internal(format!("failed to create IPC writer: {e}")))?;
        for batch in &all_batches {
            writer
                .write(batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {e}")))?;
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("failed to finish IPC: {e}")))?;
    }

    Ok(output_ipc)
}

// ============================================================================
// Window Function Support
// ============================================================================

use crate::sql::{SelectColumn, WindowFunction, WindowSpec};

/// Apply window functions to query results
/// This function evaluates window functions like ROW_NUMBER(), RANK(), LAG(), LEAD()
pub fn apply_window_functions(
    ipc_data: &[u8],
    window_columns: &[SelectColumn],
) -> Result<Vec<u8>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use arrow_ipc::writer::StreamWriter;

    if window_columns.is_empty() || ipc_data.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    // Check if there are any window functions to evaluate
    let has_window_functions = window_columns
        .iter()
        .any(|c| matches!(&c.expr, crate::sql::SelectExpr::Window { .. }));

    if !has_window_functions {
        return Ok(ipc_data.to_vec());
    }

    // Decode the IPC data
    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("failed to read IPC: {e}")))?;

    // Collect all batches first (window functions need all data)
    let mut all_batches: Vec<RecordBatch> = Vec::new();
    while let Some(batch_result) = reader.next() {
        let batch = batch_result
            .map_err(|e| EngineError::Internal(format!("failed to read batch: {e}")))?;
        all_batches.push(batch);
    }

    if all_batches.is_empty() {
        return Ok(Vec::new());
    }

    // Get the schema from first batch
    let schema = all_batches[0].schema();

    // Convert all batches to rows for window function evaluation
    let mut all_rows: Vec<std::collections::HashMap<String, ComputedValue>> = Vec::new();
    for batch in &all_batches {
        let num_rows = batch.num_rows();
        for row_idx in 0..num_rows {
            let mut row = std::collections::HashMap::new();
            for (col_idx, field) in batch.schema().fields().iter().enumerate() {
                let col = batch.column(col_idx);
                let val = extract_value_at(col, row_idx);
                row.insert(field.name().clone(), val);
            }
            all_rows.push(row);
        }
    }

    let num_rows = all_rows.len();

    // Evaluate each window function
    let mut window_results: Vec<(String, Vec<ComputedValue>)> = Vec::new();

    for select_col in window_columns {
        if let crate::sql::SelectExpr::Window { function, spec } = &select_col.expr {
            let alias = select_col
                .alias
                .clone()
                .unwrap_or_else(|| format!("window_{}", window_results.len()));

            // Evaluate the window function
            let results = evaluate_window_function(function, spec, &all_rows)?;
            window_results.push((alias, results));
        }
    }

    // Build new batches with window function results added
    let mut new_fields: Vec<Field> = schema.fields().iter().map(|f| f.as_ref().clone()).collect();
    for (alias, _) in &window_results {
        new_fields.push(Field::new(alias, DataType::Int64, true));
    }
    let new_schema = Arc::new(Schema::new(new_fields));

    // Build new arrays for window results
    let mut new_arrays: Vec<ArrayRef> = Vec::new();

    // Copy original columns
    // For simplicity, we merge all batches into one
    for col_idx in 0..schema.fields().len() {
        let mut values: Vec<ComputedValue> = Vec::with_capacity(num_rows);
        for row in &all_rows {
            let field_name = schema.field(col_idx).name();
            values.push(row.get(field_name).cloned().unwrap_or(ComputedValue::Null));
        }
        let (arr, _) = build_array_from_computed_values(&values, "")?;
        new_arrays.push(arr);
    }

    // Add window function result columns
    for (_, results) in &window_results {
        let (arr, _) = build_array_from_computed_values(results, "")?;
        new_arrays.push(arr);
    }

    // Create the output batch
    let new_batch = RecordBatch::try_new(new_schema.clone(), new_arrays)
        .map_err(|e| EngineError::Internal(format!("failed to create batch: {e}")))?;

    // Encode back to IPC
    let mut output_ipc = Vec::new();
    {
        let mut writer = StreamWriter::try_new(&mut output_ipc, new_schema.as_ref())
            .map_err(|e| EngineError::Internal(format!("failed to create IPC writer: {e}")))?;
        writer
            .write(&new_batch)
            .map_err(|e| EngineError::Internal(format!("failed to write batch: {e}")))?;
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("failed to finish IPC: {e}")))?;
    }

    Ok(output_ipc)
}

/// Evaluate a window function over all rows
fn evaluate_window_function(
    function: &WindowFunction,
    spec: &WindowSpec,
    rows: &[std::collections::HashMap<String, ComputedValue>],
) -> Result<Vec<ComputedValue>, EngineError> {
    let num_rows = rows.len();
    let mut results = Vec::with_capacity(num_rows);

    // Get partition groups (if PARTITION BY is specified)
    let partitions = get_partitions(rows, &spec.partition_by);

    // For each partition, evaluate the window function
    for (partition_rows, partition_indices) in &partitions {
        let partition_size = partition_rows.len();

        // Sort partition if ORDER BY is specified
        let ordered_indices = if spec.order_by.is_empty() {
            partition_indices.clone()
        } else {
            sort_partition_indices(partition_rows, partition_indices, &spec.order_by)
        };

        // Evaluate function for each row in partition
        let partition_results = match function {
            WindowFunction::RowNumber => {
                // ROW_NUMBER() - sequential number within partition
                (1..=partition_size)
                    .map(|n| ComputedValue::Integer(n as i64))
                    .collect()
            }
            WindowFunction::Rank => {
                // RANK() - rank with gaps for ties
                compute_rank(partition_rows, &spec.order_by, false)
            }
            WindowFunction::DenseRank => {
                // DENSE_RANK() - rank without gaps for ties
                compute_rank(partition_rows, &spec.order_by, true)
            }
            WindowFunction::PercentRank => {
                // PERCENT_RANK() = (rank - 1) / (total_rows - 1)
                let ranks = compute_rank(partition_rows, &spec.order_by, false);
                if partition_size <= 1 {
                    vec![ComputedValue::Float(0.0); partition_size]
                } else {
                    ranks
                        .into_iter()
                        .map(|r| {
                            if let ComputedValue::Integer(rank) = r {
                                ComputedValue::Float(
                                    (rank - 1) as f64 / (partition_size - 1) as f64,
                                )
                            } else {
                                ComputedValue::Float(0.0)
                            }
                        })
                        .collect()
                }
            }
            WindowFunction::CumeDist => {
                // CUME_DIST() = number of rows with value <= current / total_rows
                let ranks = compute_rank(partition_rows, &spec.order_by, false);
                // Group by rank to find how many rows have each rank or lower
                let mut result = Vec::with_capacity(partition_size);
                for (i, _) in ranks.iter().enumerate() {
                    // Count rows with rank <= current row's rank
                    let current_rank = match &ranks[i] {
                        ComputedValue::Integer(r) => *r,
                        _ => (i + 1) as i64,
                    };
                    let count = ranks
                        .iter()
                        .filter(|r| {
                            if let ComputedValue::Integer(rank) = r {
                                *rank <= current_rank
                            } else {
                                false
                            }
                        })
                        .count();
                    result.push(ComputedValue::Float(count as f64 / partition_size as f64));
                }
                result
            }
            WindowFunction::NTile(n) => {
                // NTILE(n) - divide into n roughly equal groups
                let bucket_size = (partition_size + *n as usize - 1) / *n as usize;
                (0..partition_size)
                    .map(|i| ComputedValue::Integer((i / bucket_size + 1) as i64))
                    .collect()
            }
            WindowFunction::Lag {
                expr,
                offset,
                default,
            } => {
                // LAG(expr, offset, default) - value from offset rows before
                compute_lag_lead(partition_rows, expr, *offset, default.as_deref(), true)
            }
            WindowFunction::Lead {
                expr,
                offset,
                default,
            } => {
                // LEAD(expr, offset, default) - value from offset rows after
                compute_lag_lead(partition_rows, expr, *offset, default.as_deref(), false)
            }
            WindowFunction::FirstValue(expr) => {
                // FIRST_VALUE(expr) - first value in partition
                let first_val = if partition_rows.is_empty() {
                    ComputedValue::Null
                } else {
                    let ctx = EvalContext::new(&partition_rows[0]);
                    evaluate_expr(expr, &ctx)?
                };
                vec![first_val; partition_size]
            }
            WindowFunction::LastValue(expr) => {
                // LAST_VALUE(expr) - last value in partition
                let last_val = if partition_rows.is_empty() {
                    ComputedValue::Null
                } else {
                    let ctx = EvalContext::new(&partition_rows[partition_size - 1]);
                    evaluate_expr(expr, &ctx)?
                };
                vec![last_val; partition_size]
            }
            WindowFunction::NthValue { expr, n } => {
                // NTH_VALUE(expr, n) - nth value in partition
                let nth_val = if *n < 1 || (*n as usize) > partition_size {
                    ComputedValue::Null
                } else {
                    let ctx = EvalContext::new(&partition_rows[(*n - 1) as usize]);
                    evaluate_expr(expr, &ctx)?
                };
                vec![nth_val; partition_size]
            }
            WindowFunction::WindowSum(expr) => {
                // SUM() OVER - sum within partition
                compute_window_aggregate(partition_rows, expr, |vals| {
                    let sum: f64 = vals.iter().filter_map(|v| v.as_f64()).sum();
                    ComputedValue::Float(sum)
                })
            }
            WindowFunction::WindowAvg(expr) => {
                // AVG() OVER - average within partition
                compute_window_aggregate(partition_rows, expr, |vals| {
                    let non_null: Vec<f64> = vals.iter().filter_map(|v| v.as_f64()).collect();
                    if non_null.is_empty() {
                        ComputedValue::Null
                    } else {
                        ComputedValue::Float(non_null.iter().sum::<f64>() / non_null.len() as f64)
                    }
                })
            }
            WindowFunction::WindowMin(expr) => {
                // MIN() OVER - minimum within partition
                compute_window_aggregate(partition_rows, expr, |vals| {
                    vals.iter()
                        .filter(|v| !v.is_null())
                        .min_by(|a, b| compare_values(a, b).cmp(&0))
                        .cloned()
                        .unwrap_or(ComputedValue::Null)
                })
            }
            WindowFunction::WindowMax(expr) => {
                // MAX() OVER - maximum within partition
                compute_window_aggregate(partition_rows, expr, |vals| {
                    vals.iter()
                        .filter(|v| !v.is_null())
                        .max_by(|a, b| compare_values(a, b).cmp(&0))
                        .cloned()
                        .unwrap_or(ComputedValue::Null)
                })
            }
            WindowFunction::WindowCount(expr_opt) => {
                // COUNT() OVER - count within partition
                compute_window_aggregate(
                    partition_rows,
                    expr_opt.as_deref().unwrap_or(&SelectExpr::Null),
                    |vals| {
                        let count = if expr_opt.is_some() {
                            vals.iter().filter(|v| !v.is_null()).count()
                        } else {
                            vals.len()
                        };
                        ComputedValue::Integer(count as i64)
                    },
                )
            }
        };

        // Map partition results back to original row order
        for (partition_idx, _) in ordered_indices.iter().enumerate() {
            if partition_idx < partition_results.len() {
                results.push(partition_results[partition_idx].clone());
            }
        }
    }

    Ok(results)
}

/// Group rows by PARTITION BY columns
fn get_partitions(
    rows: &[std::collections::HashMap<String, ComputedValue>],
    partition_by: &[String],
) -> Vec<(
    Vec<std::collections::HashMap<String, ComputedValue>>,
    Vec<usize>,
)> {
    if partition_by.is_empty() {
        // No partitioning - all rows in one partition
        return vec![(rows.to_vec(), (0..rows.len()).collect())];
    }

    let mut partitions: std::collections::HashMap<
        String,
        (
            Vec<std::collections::HashMap<String, ComputedValue>>,
            Vec<usize>,
        ),
    > = std::collections::HashMap::new();

    for (idx, row) in rows.iter().enumerate() {
        // Build partition key from PARTITION BY columns
        let key: String = partition_by
            .iter()
            .map(|col| {
                row.get(col)
                    .map(|v| v.to_string_value())
                    .unwrap_or_default()
            })
            .collect::<Vec<_>>()
            .join("|");

        let entry = partitions
            .entry(key)
            .or_insert_with(|| (Vec::new(), Vec::new()));
        entry.0.push(row.clone());
        entry.1.push(idx);
    }

    partitions.into_values().collect()
}

/// Sort partition indices according to ORDER BY
fn sort_partition_indices(
    _partition_rows: &[std::collections::HashMap<String, ComputedValue>],
    partition_indices: &[usize],
    _order_by: &[crate::sql::OrderByClause],
) -> Vec<usize> {
    // For now, return original order (full ORDER BY sorting can be added later)
    partition_indices.to_vec()
}

/// Compute RANK or DENSE_RANK
fn compute_rank(
    _partition_rows: &[std::collections::HashMap<String, ComputedValue>],
    _order_by: &[crate::sql::OrderByClause],
    _dense: bool,
) -> Vec<ComputedValue> {
    // Without ORDER BY, all rows have rank 1
    // With ORDER BY, compute ranks based on value comparisons
    // For now, simple implementation: sequential ranks
    _partition_rows
        .iter()
        .enumerate()
        .map(|(i, _)| ComputedValue::Integer((i + 1) as i64))
        .collect()
}

/// Compute LAG or LEAD
fn compute_lag_lead(
    partition_rows: &[std::collections::HashMap<String, ComputedValue>],
    expr: &SelectExpr,
    offset: i64,
    default: Option<&SelectExpr>,
    is_lag: bool,
) -> Vec<ComputedValue> {
    let n = partition_rows.len();
    let mut results = Vec::with_capacity(n);

    for i in 0..n {
        let target_idx = if is_lag {
            i as i64 - offset
        } else {
            i as i64 + offset
        };

        let val = if target_idx >= 0 && (target_idx as usize) < n {
            let ctx = EvalContext::new(&partition_rows[target_idx as usize]);
            evaluate_expr(expr, &ctx).unwrap_or(ComputedValue::Null)
        } else if let Some(def_expr) = default {
            let ctx = EvalContext::new(&partition_rows[i]);
            evaluate_expr(def_expr, &ctx).unwrap_or(ComputedValue::Null)
        } else {
            ComputedValue::Null
        };

        results.push(val);
    }

    results
}

/// Compute a window aggregate function
fn compute_window_aggregate<F>(
    partition_rows: &[std::collections::HashMap<String, ComputedValue>],
    expr: &SelectExpr,
    aggregate_fn: F,
) -> Vec<ComputedValue>
where
    F: Fn(&[ComputedValue]) -> ComputedValue,
{
    // Evaluate expression for all rows in partition
    let values: Vec<ComputedValue> = partition_rows
        .iter()
        .map(|row| {
            let ctx = EvalContext::new(row);
            evaluate_expr(expr, &ctx).unwrap_or(ComputedValue::Null)
        })
        .collect();

    // Apply aggregate function
    let result = aggregate_fn(&values);

    // Return same value for all rows in partition
    vec![result; partition_rows.len()]
}

/// Apply computed columns (expressions) to query results
/// This function evaluates SELECT expressions like UPPER(name), price * 1.1, etc.
pub fn apply_computed_columns(
    ipc_data: &[u8],
    computed_columns: &[crate::sql::SelectColumn],
) -> Result<Vec<u8>, EngineError> {
    use arrow_ipc::reader::StreamReader;
    use arrow_ipc::writer::StreamWriter;

    if computed_columns.is_empty() || ipc_data.is_empty() {
        return Ok(ipc_data.to_vec());
    }

    // Check if there are any actual expressions to evaluate (not just column references)
    let has_expressions = computed_columns
        .iter()
        .any(|c| !matches!(&c.expr, crate::sql::SelectExpr::Column(_)));

    if !has_expressions {
        // No expressions to evaluate, just pass through
        return Ok(ipc_data.to_vec());
    }

    // Decode the IPC data
    let cursor = Cursor::new(ipc_data);
    let mut reader = StreamReader::try_new(cursor, None)
        .map_err(|e| EngineError::Internal(format!("failed to read IPC: {e}")))?;

    let mut output_batches = Vec::new();

    while let Some(batch_result) = reader.next() {
        let batch = batch_result
            .map_err(|e| EngineError::Internal(format!("failed to read batch: {e}")))?;

        let num_rows = batch.num_rows();
        let schema = batch.schema();

        // Build row data for expression evaluation
        let mut all_rows: Vec<std::collections::HashMap<String, ComputedValue>> =
            Vec::with_capacity(num_rows);

        // Convert batch columns to rows for evaluation
        for row_idx in 0..num_rows {
            let mut row = std::collections::HashMap::new();
            for (col_idx, field) in schema.fields().iter().enumerate() {
                let col = batch.column(col_idx);
                let val = extract_value_at(col, row_idx);
                row.insert(field.name().clone(), val);
            }
            all_rows.push(row);
        }

        // Evaluate expressions and build new columns
        let mut new_columns: Vec<ArrayRef> = Vec::new();
        let mut new_fields: Vec<Field> = Vec::new();

        for select_col in computed_columns {
            let alias = select_col
                .alias
                .clone()
                .unwrap_or_else(|| format!("expr_{}", new_fields.len()));

            // Evaluate the expression for each row
            let mut results: Vec<ComputedValue> = Vec::with_capacity(num_rows);
            for row in &all_rows {
                let ctx = EvalContext::new(row);
                let val = evaluate_expr(&select_col.expr, &ctx)?;
                results.push(val);
            }

            // Determine the output type based on results
            let (arr, dt) = build_array_from_computed_values(&results, &alias)?;
            new_columns.push(arr);
            new_fields.push(Field::new(&alias, dt, true));
        }

        // Combine original columns with computed columns
        let mut all_fields: Vec<Field> =
            schema.fields().iter().map(|f| f.as_ref().clone()).collect();
        let mut all_columns: Vec<ArrayRef> = (0..batch.num_columns())
            .map(|i| batch.column(i).clone())
            .collect();

        all_fields.extend(new_fields);
        all_columns.extend(new_columns);

        let new_schema = Arc::new(Schema::new(all_fields));
        let new_batch = RecordBatch::try_new(new_schema, all_columns)
            .map_err(|e| EngineError::Internal(format!("failed to create batch: {e}")))?;

        output_batches.push(new_batch);
    }

    // Encode back to IPC
    if output_batches.is_empty() {
        return Ok(Vec::new());
    }

    let mut output_ipc = Vec::new();
    {
        let mut writer =
            StreamWriter::try_new(&mut output_ipc, output_batches[0].schema().as_ref())
                .map_err(|e| EngineError::Internal(format!("failed to create IPC writer: {e}")))?;
        for batch in &output_batches {
            writer
                .write(batch)
                .map_err(|e| EngineError::Internal(format!("failed to write batch: {e}")))?;
        }
        writer
            .finish()
            .map_err(|e| EngineError::Internal(format!("failed to finish IPC: {e}")))?;
    }

    Ok(output_ipc)
}

/// Extract a value from an Arrow array at a given row index
fn extract_value_at(arr: &ArrayRef, row_idx: usize) -> ComputedValue {
    use arrow_array::{
        BinaryArray, BooleanArray, Date32Array, Decimal128Array, FixedSizeBinaryArray,
        Float32Array, Float64Array, Int16Array, Int32Array, Int64Array, Int8Array,
        LargeBinaryArray, LargeStringArray, StringArray, TimestampMicrosecondArray, UInt16Array,
        UInt32Array, UInt64Array, UInt8Array,
    };

    if arr.is_null(row_idx) {
        return ComputedValue::Null;
    }

    match arr.data_type() {
        DataType::Int8 => {
            let a = arr.as_any().downcast_ref::<Int8Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::Int16 => {
            let a = arr.as_any().downcast_ref::<Int16Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::Int32 => {
            let a = arr.as_any().downcast_ref::<Int32Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::Int64 => {
            let a = arr.as_any().downcast_ref::<Int64Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx))
        }
        DataType::UInt8 => {
            let a = arr.as_any().downcast_ref::<UInt8Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::UInt16 => {
            let a = arr.as_any().downcast_ref::<UInt16Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::UInt32 => {
            let a = arr.as_any().downcast_ref::<UInt32Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::UInt64 => {
            let a = arr.as_any().downcast_ref::<UInt64Array>().unwrap();
            ComputedValue::Integer(a.value(row_idx) as i64)
        }
        DataType::Float32 => {
            let a = arr.as_any().downcast_ref::<Float32Array>().unwrap();
            ComputedValue::Float(a.value(row_idx) as f64)
        }
        DataType::Float64 => {
            let a = arr.as_any().downcast_ref::<Float64Array>().unwrap();
            ComputedValue::Float(a.value(row_idx))
        }
        DataType::Utf8 => {
            let a = arr.as_any().downcast_ref::<StringArray>().unwrap();
            ComputedValue::String(a.value(row_idx).to_string())
        }
        DataType::LargeUtf8 => {
            // Used for JSON storage
            let a = arr.as_any().downcast_ref::<LargeStringArray>().unwrap();
            ComputedValue::Json(a.value(row_idx).to_string())
        }
        DataType::Boolean => {
            let a = arr.as_any().downcast_ref::<BooleanArray>().unwrap();
            ComputedValue::Boolean(a.value(row_idx))
        }
        DataType::FixedSizeBinary(16) => {
            // UUID stored as 16 bytes
            let a = arr.as_any().downcast_ref::<FixedSizeBinaryArray>().unwrap();
            let bytes = a.value(row_idx);
            let mut uuid_bytes = [0u8; 16];
            uuid_bytes.copy_from_slice(bytes);
            ComputedValue::Uuid(uuid_bytes)
        }
        DataType::FixedSizeBinary(_) => {
            // Other fixed-size binary
            let a = arr.as_any().downcast_ref::<FixedSizeBinaryArray>().unwrap();
            ComputedValue::Binary(a.value(row_idx).to_vec())
        }
        DataType::Binary => {
            let a = arr.as_any().downcast_ref::<BinaryArray>().unwrap();
            ComputedValue::Binary(a.value(row_idx).to_vec())
        }
        DataType::LargeBinary => {
            let a = arr.as_any().downcast_ref::<LargeBinaryArray>().unwrap();
            ComputedValue::Binary(a.value(row_idx).to_vec())
        }
        DataType::Date32 => {
            let a = arr.as_any().downcast_ref::<Date32Array>().unwrap();
            ComputedValue::Date(a.value(row_idx))
        }
        DataType::Timestamp(_, _) => {
            let a = arr
                .as_any()
                .downcast_ref::<TimestampMicrosecondArray>()
                .unwrap();
            ComputedValue::Timestamp(a.value(row_idx))
        }
        DataType::Decimal128(precision, scale) => {
            let a = arr.as_any().downcast_ref::<Decimal128Array>().unwrap();
            ComputedValue::Decimal {
                value: a.value(row_idx),
                precision: *precision,
                scale: *scale,
            }
        }
        _ => ComputedValue::Null,
    }
}

/// Build an Arrow array from computed values
fn build_array_from_computed_values(
    values: &[ComputedValue],
    _alias: &str,
) -> Result<(ArrayRef, DataType), EngineError> {
    use arrow_array::{
        ArrayRef, BooleanArray, Date32Array, Decimal128Array, Float64Array, Int64Array,
        LargeBinaryArray, LargeStringArray, StringArray,
    };

    // Determine the predominant type
    let mut has_int = false;
    let mut has_float = false;
    let mut has_string = false;
    let mut has_bool = false;
    let mut has_timestamp = false;
    let mut has_uuid = false;
    let mut has_json = false;
    let mut has_decimal = false;
    let mut decimal_precision: u8 = 38;
    let mut decimal_scale: i8 = 0;
    let mut has_binary = false;
    let mut has_date = false;

    for v in values {
        match v {
            ComputedValue::Integer(_) => has_int = true,
            ComputedValue::Float(_) => has_float = true,
            ComputedValue::String(_) => has_string = true,
            ComputedValue::Boolean(_) => has_bool = true,
            ComputedValue::Timestamp(_) => has_timestamp = true,
            ComputedValue::Uuid(_) => has_uuid = true,
            ComputedValue::Json(_) => has_json = true,
            ComputedValue::Decimal {
                precision, scale, ..
            } => {
                has_decimal = true;
                decimal_precision = *precision;
                decimal_scale = *scale;
            }
            ComputedValue::Binary(_) => has_binary = true,
            ComputedValue::Date(_) => has_date = true,
            ComputedValue::Null => {}
        }
    }

    // Priority: specific types first, then generic coercion
    // UUID - must be all UUIDs or nulls
    if has_uuid && !has_string && !has_int && !has_float && !has_json && !has_decimal && !has_binary
    {
        use arrow_array::builder::FixedSizeBinaryBuilder;
        let mut builder = FixedSizeBinaryBuilder::with_capacity(values.len(), 16);
        for v in values {
            match v {
                ComputedValue::Uuid(bytes) => builder
                    .append_value(bytes)
                    .map_err(|e| EngineError::Internal(format!("UUID append error: {e}")))?,
                ComputedValue::Null => builder.append_null(),
                _ => builder.append_null(),
            }
        }
        let arr = builder.finish();
        return Ok((Arc::new(arr) as ArrayRef, DataType::FixedSizeBinary(16)));
    }

    // JSON - stored as LargeUtf8
    if has_json && !has_uuid && !has_binary {
        let json_strings: Vec<Option<String>> = values
            .iter()
            .map(|v| match v {
                ComputedValue::Json(s) => Some(s.clone()),
                ComputedValue::String(s) => Some(s.clone()),
                ComputedValue::Null => None,
                _ => Some(v.to_string_value()),
            })
            .collect();
        let arr: LargeStringArray = json_strings.iter().map(|s| s.as_deref()).collect();
        return Ok((Arc::new(arr) as ArrayRef, DataType::LargeUtf8));
    }

    // Decimal - stored as Decimal128
    if has_decimal && !has_string && !has_uuid && !has_json && !has_binary {
        let arr = Decimal128Array::from_iter(values.iter().map(|v| match v {
            ComputedValue::Decimal { value, .. } => Some(*value),
            ComputedValue::Integer(n) => Some(*n as i128),
            ComputedValue::Null => None,
            _ => None,
        }))
        .with_precision_and_scale(decimal_precision, decimal_scale)
        .map_err(|e| EngineError::Internal(format!("Decimal array error: {e}")))?;
        return Ok((
            Arc::new(arr) as ArrayRef,
            DataType::Decimal128(decimal_precision, decimal_scale),
        ));
    }

    // Binary - stored as LargeBinary
    if has_binary && !has_string && !has_uuid && !has_json {
        let arr: LargeBinaryArray = values
            .iter()
            .map(|v| match v {
                ComputedValue::Binary(bytes) => Some(bytes.as_slice()),
                ComputedValue::Null => None,
                _ => None,
            })
            .collect();
        return Ok((Arc::new(arr) as ArrayRef, DataType::LargeBinary));
    }

    // Date - stored as Date32
    if has_date && !has_string && !has_uuid && !has_json && !has_binary && !has_decimal {
        let arr: Date32Array = values
            .iter()
            .map(|v| match v {
                ComputedValue::Date(d) => Some(*d),
                ComputedValue::Integer(n) => Some(*n as i32),
                ComputedValue::Null => None,
                _ => None,
            })
            .collect();
        return Ok((Arc::new(arr) as ArrayRef, DataType::Date32));
    }

    // Priority: String > Float > Integer > Boolean > Timestamp
    if has_string {
        let arr: StringArray = values
            .iter()
            .map(|v| {
                if matches!(v, ComputedValue::Null) {
                    None
                } else {
                    Some(v.to_string_value())
                }
            })
            .collect();
        Ok((Arc::new(arr) as ArrayRef, DataType::Utf8))
    } else if has_float {
        let arr: Float64Array = values.iter().map(|v| v.as_f64()).collect();
        Ok((Arc::new(arr) as ArrayRef, DataType::Float64))
    } else if has_int || has_timestamp {
        let arr: Int64Array = values.iter().map(|v| v.as_i64()).collect();
        Ok((Arc::new(arr) as ArrayRef, DataType::Int64))
    } else if has_bool {
        let arr: BooleanArray = values
            .iter()
            .map(|v| match v {
                ComputedValue::Boolean(b) => Some(*b),
                ComputedValue::Null => None,
                _ => Some(false),
            })
            .collect();
        Ok((Arc::new(arr) as ArrayRef, DataType::Boolean))
    } else {
        // All nulls - return as string nulls
        let arr: StringArray = values.iter().map(|_| Option::<&str>::None).collect();
        Ok((Arc::new(arr) as ArrayRef, DataType::Utf8))
    }
}

// -----------------------------------------------------------------------------
// LIKE Pattern Matching Helpers
// -----------------------------------------------------------------------------

/// Maximum length for LIKE patterns to prevent ReDoS attacks
pub const MAX_LIKE_PATTERN_LEN: usize = 1000;

/// Convert a SQL LIKE pattern to a regex pattern
/// - % matches zero or more characters
/// - _ matches exactly one character
/// - Special regex characters are escaped
pub fn like_pattern_to_regex(pattern: &str) -> Option<String> {
    if pattern.len() > MAX_LIKE_PATTERN_LEN {
        return None;
    }

    let mut regex = String::with_capacity(pattern.len() * 2 + 2);
    regex.push('^');

    let mut chars = pattern.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            '%' => regex.push_str(".*"),
            '_' => regex.push('.'),
            // Escape regex metacharacters
            '.' | '+' | '*' | '?' | '[' | ']' | '{' | '}' | '(' | ')' | '|' | '^' | '$' | '\\' => {
                regex.push('\\');
                regex.push(c);
            }
            _ => regex.push(c),
        }
    }

    regex.push('$');
    Some(regex)
}

/// Check if a string matches a SQL LIKE pattern
pub fn matches_like_pattern(value: &str, pattern: &str) -> bool {
    let Some(regex_pattern) = like_pattern_to_regex(pattern) else {
        return false;
    };

    match regex::Regex::new(&regex_pattern) {
        Ok(re) => re.is_match(value),
        Err(_) => false,
    }
}

/// Build a match mask for filtering records
/// Returns a BooleanArray with true for rows that match all filter conditions
pub fn build_match_mask(
    batch: &RecordBatch,
    filter: &QueryFilter,
) -> Result<BooleanArray, EngineError> {
    let num_rows = batch.num_rows();
    if num_rows == 0 {
        return Ok(BooleanArray::from(vec![] as Vec<bool>));
    }

    // Start with all true
    let mut mask = vec![true; num_rows];

    // Apply LIKE filters - tuple of (column, pattern, negate)
    // Supports both String and numeric columns (converts to string for matching)
    for (column, pattern, negate) in &filter.like_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            for i in 0..num_rows {
                if mask[i] && !col.is_null(i) {
                    // Get string value - either directly or by converting
                    let val = if let Some(str_arr) = col.as_any().downcast_ref::<StringArray>() {
                        str_arr.value(i).to_string()
                    } else {
                        array_value_to_string(col.as_ref(), i).unwrap_or_default()
                    };
                    let matches = matches_like_pattern(&val, pattern);
                    mask[i] = if *negate { !matches } else { matches };
                } else if col.is_null(i) {
                    mask[i] = false;
                }
            }
        }
    }

    // Apply ILIKE filters (case-insensitive) - tuple of (column, pattern, negate)
    // Supports both String and numeric columns (converts to string for matching)
    for (column, pattern, negate) in &filter.ilike_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            for i in 0..num_rows {
                if mask[i] && !col.is_null(i) {
                    // Get string value - either directly or by converting
                    let val = if let Some(str_arr) = col.as_any().downcast_ref::<StringArray>() {
                        str_arr.value(i).to_lowercase()
                    } else {
                        array_value_to_string(col.as_ref(), i).unwrap_or_default().to_lowercase()
                    };
                    // Convert pattern to lowercase for case-insensitive match
                    let matches = matches_like_pattern(&val, &pattern.to_lowercase());
                    mask[i] = if *negate { !matches } else { matches };
                } else if col.is_null(i) {
                    mask[i] = false;
                }
            }
        }
    }

    // Apply numeric range filters
    for nf in &filter.numeric_range_filters {
        if let Ok(col_idx) = batch.schema().index_of(&nf.column) {
            let col = batch.column(col_idx);
            let filter_val = match &nf.value {
                crate::sql::NumericValue::Int64(v) => *v as f64,
                crate::sql::NumericValue::UInt64(v) => *v as f64,
                crate::sql::NumericValue::Float64(v) => *v,
            };
            for i in 0..num_rows {
                if mask[i] && !col.is_null(i) {
                    let val = extract_f64(col, i);
                    if let Some(v) = val {
                        let matches = match nf.op {
                            crate::sql::NumericOp::Eq => (v - filter_val).abs() < f64::EPSILON,
                            crate::sql::NumericOp::Ne => (v - filter_val).abs() >= f64::EPSILON,
                            crate::sql::NumericOp::Gt => v > filter_val,
                            crate::sql::NumericOp::Ge => v >= filter_val,
                            crate::sql::NumericOp::Lt => v < filter_val,
                            crate::sql::NumericOp::Le => v <= filter_val,
                        };
                        mask[i] = matches;
                    }
                } else if col.is_null(i) {
                    mask[i] = false;
                }
            }
        }
    }

    // Apply numeric equality filters
    for (column, filter_val) in &filter.numeric_eq_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            let filter_val_f64 = *filter_val as f64;
            for i in 0..num_rows {
                if mask[i] && !col.is_null(i) {
                    let val = extract_f64(col, i);
                    if let Some(v) = val {
                        mask[i] = (v - filter_val_f64).abs() < 0.5; // Integer comparison
                    }
                } else if col.is_null(i) {
                    mask[i] = false;
                }
            }
        }
    }

    // Apply boolean equality filters
    for (column, filter_val) in &filter.bool_eq_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            if let Some(bool_arr) = col.as_any().downcast_ref::<BooleanArray>() {
                for i in 0..num_rows {
                    if mask[i] && !bool_arr.is_null(i) {
                        mask[i] = bool_arr.value(i) == *filter_val;
                    } else if bool_arr.is_null(i) {
                        mask[i] = false;
                    }
                }
            }
        }
    }

    // Apply float equality filters
    for (column, filter_val) in &filter.float_eq_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            for i in 0..num_rows {
                if mask[i] && !col.is_null(i) {
                    let val = extract_f64(col, i);
                    if let Some(v) = val {
                        mask[i] = (v - filter_val).abs() < 1e-9;
                    }
                } else if col.is_null(i) {
                    mask[i] = false;
                }
            }
        }
    }

    // Apply string equality filters
    for (column, filter_val) in &filter.string_eq_filters {
        if let Ok(col_idx) = batch.schema().index_of(column) {
            let col = batch.column(col_idx);
            if let Some(str_arr) = col.as_any().downcast_ref::<StringArray>() {
                for i in 0..num_rows {
                    if mask[i] && !str_arr.is_null(i) {
                        mask[i] = str_arr.value(i) == filter_val;
                    } else if str_arr.is_null(i) {
                        mask[i] = false;
                    }
                }
            // Handle FixedSizeBinary (UUIDs stored as strings in filter)
            } else if let Some(fsb_arr) = col
                .as_any()
                .downcast_ref::<arrow_array::FixedSizeBinaryArray>()
            {
                // Try to parse the filter value as UUID
                if let Some(uuid_bytes) = parse_uuid_string(filter_val) {
                    for i in 0..num_rows {
                        if mask[i] && !fsb_arr.is_null(i) {
                            mask[i] = fsb_arr.value(i) == uuid_bytes;
                        } else if fsb_arr.is_null(i) {
                            mask[i] = false;
                        }
                    }
                }
            }
        }
    }

    Ok(BooleanArray::from(mask))
}

// -----------------------------------------------------------------------------
// Type Casting and Parsing Helpers
// -----------------------------------------------------------------------------

/// Result of parsing a decimal string
#[derive(Debug, Clone, PartialEq)]
pub struct DecimalParseResult {
    pub integer_part: i128,
    pub fractional_part: i128,
    pub scale: u8,
    pub is_negative: bool,
}

/// Parse a decimal string into its components
pub fn parse_decimal_string(s: &str) -> Option<DecimalParseResult> {
    let s = s.trim();
    if s.is_empty() {
        return None;
    }

    let (is_negative, s) = if s.starts_with('-') {
        (true, &s[1..])
    } else if s.starts_with('+') {
        (false, &s[1..])
    } else {
        (false, s)
    };

    let parts: Vec<&str> = s.split('.').collect();
    if parts.len() > 2 {
        return None;
    }

    let integer_str = parts[0];
    let integer_part: i128 = if integer_str.is_empty() {
        0
    } else {
        integer_str.parse().ok()?
    };

    let (fractional_part, scale) = if parts.len() == 2 {
        let frac_str = parts[1];
        let scale = frac_str.len() as u8;
        let frac: i128 = if frac_str.is_empty() {
            0
        } else {
            frac_str.parse().ok()?
        };
        (frac, scale)
    } else {
        (0, 0)
    };

    Some(DecimalParseResult {
        integer_part,
        fractional_part,
        scale,
        is_negative,
    })
}

/// Cast a computed value to a target type
pub fn cast_value(value: &ComputedValue, target_type: &str) -> Option<ComputedValue> {
    match target_type.to_lowercase().as_str() {
        "uuid" => {
            match value {
                ComputedValue::String(s) => {
                    // Validate UUID format (simple check)
                    let s = s.trim();
                    if s.len() == 36 && s.chars().filter(|&c| c == '-').count() == 4 {
                        // Parse into bytes and create Uuid variant
                        let hex: String = s.chars().filter(|c| *c != '-').collect();
                        if let Ok(bytes) = hex::decode(&hex) {
                            if bytes.len() == 16 {
                                let mut arr = [0u8; 16];
                                arr.copy_from_slice(&bytes);
                                return Some(ComputedValue::Uuid(arr));
                            }
                        }
                        Some(ComputedValue::String(s.to_lowercase()))
                    } else if s.len() == 32 && s.chars().all(|c| c.is_ascii_hexdigit()) {
                        // Parse 32-char hex string directly
                        if let Ok(bytes) = hex::decode(s) {
                            if bytes.len() == 16 {
                                let mut arr = [0u8; 16];
                                arr.copy_from_slice(&bytes);
                                return Some(ComputedValue::Uuid(arr));
                            }
                        }
                        None
                    } else {
                        None
                    }
                }
                _ => None,
            }
        }
        "decimal" | "numeric" => {
            match value {
                ComputedValue::Integer(i) => Some(ComputedValue::Decimal {
                    value: *i as i128,
                    precision: 38,
                    scale: 0,
                }),
                ComputedValue::Float(f) => {
                    // Convert float to decimal with reasonable precision
                    let scale = 6i8;
                    let multiplier = 10i128.pow(scale as u32);
                    let value = (*f * multiplier as f64).round() as i128;
                    Some(ComputedValue::Decimal {
                        value,
                        precision: 38,
                        scale,
                    })
                }
                ComputedValue::String(s) => {
                    if let Some(result) = parse_decimal_string(s) {
                        let multiplier = 10i128.pow(result.scale as u32);
                        let value = result.integer_part * multiplier + result.fractional_part;
                        let final_value = if result.is_negative { -value } else { value };
                        Some(ComputedValue::Decimal {
                            value: final_value,
                            precision: 38,
                            scale: result.scale as i8,
                        })
                    } else {
                        None
                    }
                }
                ComputedValue::Decimal {
                    value,
                    precision,
                    scale,
                } => Some(ComputedValue::Decimal {
                    value: *value,
                    precision: *precision,
                    scale: *scale,
                }),
                _ => None,
            }
        }
        "json" | "jsonb" => {
            match value {
                ComputedValue::String(s) => {
                    // Validate JSON - if valid, use as-is; if not, wrap as JSON string
                    if serde_json::from_str::<serde_json::Value>(s).is_ok() {
                        Some(ComputedValue::Json(s.clone()))
                    } else {
                        // Wrap as JSON string
                        Some(ComputedValue::Json(format!(
                            "\"{}\"",
                            s.replace('\\', "\\\\").replace('"', "\\\"")
                        )))
                    }
                }
                ComputedValue::Integer(i) => Some(ComputedValue::Json(i.to_string())),
                ComputedValue::Float(f) => Some(ComputedValue::Json(f.to_string())),
                ComputedValue::Boolean(b) => Some(ComputedValue::Json(b.to_string())),
                ComputedValue::Null => Some(ComputedValue::Json("null".to_string())),
                _ => None,
            }
        }
        "date" => {
            match value {
                ComputedValue::String(s) => {
                    // Try to parse common date formats
                    let s = s.trim();
                    // YYYY-MM-DD format
                    if s.len() >= 10
                        && s.chars().nth(4) == Some('-')
                        && s.chars().nth(7) == Some('-')
                    {
                        // Parse to days since epoch
                        if let Ok(date) = chrono::NaiveDate::parse_from_str(&s[0..10], "%Y-%m-%d") {
                            let epoch = chrono::NaiveDate::from_ymd_opt(1970, 1, 1).unwrap();
                            let days = (date - epoch).num_days() as i32;
                            Some(ComputedValue::Date(days))
                        } else {
                            None
                        }
                    } else {
                        None
                    }
                }
                ComputedValue::Integer(i) => {
                    // Assume Unix timestamp in seconds
                    let days_since_epoch = (*i / 86400) as i32;
                    Some(ComputedValue::Date(days_since_epoch))
                }
                ComputedValue::Timestamp(micros) => {
                    // Convert microseconds to days
                    let seconds = micros / 1_000_000;
                    let days_since_epoch = (seconds / 86400) as i32;
                    Some(ComputedValue::Date(days_since_epoch))
                }
                ComputedValue::Date(d) => Some(ComputedValue::Date(*d)),
                _ => None,
            }
        }
        "text" | "varchar" | "string" => Some(ComputedValue::String(match value {
            ComputedValue::String(s) => s.clone(),
            ComputedValue::Integer(i) => i.to_string(),
            ComputedValue::Float(f) => f.to_string(),
            ComputedValue::Boolean(b) => b.to_string(),
            ComputedValue::Null => "NULL".to_string(),
            ComputedValue::Binary(b) => format!("{:?}", b),
            ComputedValue::Timestamp(ts) => ts.to_string(),
            ComputedValue::Date(d) => {
                let epoch = chrono::NaiveDate::from_ymd_opt(1970, 1, 1).unwrap();
                let date = epoch + chrono::Duration::days(*d as i64);
                date.format("%Y-%m-%d").to_string()
            }
            ComputedValue::Decimal { value, scale, .. } => {
                let divisor = 10_i128.pow(*scale as u32);
                let int_part = value / divisor;
                let frac_part = (value % divisor).abs();
                format!(
                    "{}.{:0>width$}",
                    int_part,
                    frac_part,
                    width = *scale as usize
                )
            }
            ComputedValue::Uuid(bytes) => {
                format!(
                        "{:02x}{:02x}{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}{:02x}{:02x}{:02x}{:02x}",
                        bytes[0], bytes[1], bytes[2], bytes[3],
                        bytes[4], bytes[5], bytes[6], bytes[7],
                        bytes[8], bytes[9], bytes[10], bytes[11],
                        bytes[12], bytes[13], bytes[14], bytes[15]
                    )
            }
            ComputedValue::Json(j) => j.clone(),
        })),
        "int" | "integer" | "bigint" => match value {
            ComputedValue::Integer(i) => Some(ComputedValue::Integer(*i)),
            ComputedValue::Float(f) => Some(ComputedValue::Integer(*f as i64)),
            ComputedValue::String(s) => s.parse::<i64>().ok().map(ComputedValue::Integer),
            ComputedValue::Boolean(b) => Some(ComputedValue::Integer(if *b { 1 } else { 0 })),
            _ => None,
        },
        "float" | "double" | "real" => match value {
            ComputedValue::Float(f) => Some(ComputedValue::Float(*f)),
            ComputedValue::Integer(i) => Some(ComputedValue::Float(*i as f64)),
            ComputedValue::String(s) => s.parse::<f64>().ok().map(ComputedValue::Float),
            _ => None,
        },
        "bool" | "boolean" => match value {
            ComputedValue::Boolean(b) => Some(ComputedValue::Boolean(*b)),
            ComputedValue::Integer(i) => Some(ComputedValue::Boolean(*i != 0)),
            ComputedValue::String(s) => {
                let lower = s.to_lowercase();
                match lower.as_str() {
                    "true" | "t" | "yes" | "y" | "1" => Some(ComputedValue::Boolean(true)),
                    "false" | "f" | "no" | "n" | "0" => Some(ComputedValue::Boolean(false)),
                    _ => None,
                }
            }
            _ => None,
        },
        _ => None,
    }
}

/// Shared state for the auto-repair background task
pub struct AutoRepairState {
    /// The database instance being monitored
    db: Arc<Db>,
    /// Configuration for auto-repair
    config: AutoRepairConfig,
    /// Last scan timestamp (Unix timestamp in seconds)
    last_scan_timestamp: AtomicU64,
    /// Total segments repaired since start
    total_repaired: AtomicU64,
    /// Pending damaged segment count from last scan
    pending_count: std::sync::atomic::AtomicUsize,
    /// Shutdown flag
    shutdown: std::sync::atomic::AtomicBool,
}

impl AutoRepairState {
    /// Create a new auto-repair state
    pub fn new(db: Arc<Db>, config: AutoRepairConfig) -> Self {
        Self {
            db,
            config,
            last_scan_timestamp: AtomicU64::new(0),
            total_repaired: AtomicU64::new(0),
            pending_count: std::sync::atomic::AtomicUsize::new(0),
            shutdown: std::sync::atomic::AtomicBool::new(false),
        }
    }

    /// Get current repair statistics
    pub fn get_stats(&self) -> AutoRepairStats {
        AutoRepairStats {
            enabled: self.config.enabled,
            last_scan_timestamp: {
                let ts = self.last_scan_timestamp.load(Ordering::Relaxed);
                if ts > 0 {
                    Some(ts)
                } else {
                    None
                }
            },
            total_repaired: self.total_repaired.load(Ordering::Relaxed),
            pending_count: self.pending_count.load(Ordering::Relaxed),
            scan_interval_secs: self.config.scan_interval_secs,
            max_repairs_per_scan: self.config.max_repairs_per_scan,
        }
    }

    /// Signal shutdown
    pub fn shutdown(&self) {
        self.shutdown.store(true, Ordering::Release);
    }

    /// Check if shutdown has been requested
    pub fn is_shutdown(&self) -> bool {
        self.shutdown.load(Ordering::Acquire)
    }
}

/// Start the auto-repair background task
///
/// This function spawns a background thread that periodically scans for damaged
/// segments and repairs them automatically.
///
/// Returns an Arc to the AutoRepairState which can be used to query statistics
/// and control the task.
pub fn start_auto_repair_task(
    db: Arc<Db>,
    config: AutoRepairConfig,
) -> Arc<AutoRepairState> {
    let state = Arc::new(AutoRepairState::new(db, config));
    let state_clone = state.clone();

    std::thread::spawn(move || {
        let scan_interval = std::time::Duration::from_secs(state_clone.config.scan_interval_secs);

        loop {
            // Sleep first, allowing immediate shutdown
            let sleep_start = std::time::Instant::now();
            while sleep_start.elapsed() < scan_interval {
                if state_clone.is_shutdown() {
                    tracing::debug!("auto-repair task shutting down");
                    return;
                }
                std::thread::sleep(std::time::Duration::from_millis(100));
            }

            if !state_clone.config.enabled {
                continue;
            }

            // Find all damaged segments (missing + corrupted)
            let damaged = match state_clone.db.find_damaged_segments(None, None) {
                Ok(d) => d,
                Err(e) => {
                    tracing::warn!("auto-repair scan failed: {}", e);
                    continue;
                }
            };

            // Update pending count
            state_clone.pending_count.store(damaged.len(), Ordering::Relaxed);

            // Update last scan timestamp
            let now = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .map(|d| d.as_secs())
                .unwrap_or(0);
            state_clone.last_scan_timestamp.store(now, Ordering::Relaxed);

            if damaged.is_empty() {
                continue;
            }

            // Limit repairs per scan
            let to_repair_count = damaged.len().min(state_clone.config.max_repairs_per_scan);

            tracing::info!(
                "auto-repair: found {} damaged segments, repairing up to {}",
                damaged.len(),
                to_repair_count
            );

            // Group damaged segments by table for efficient batch repair
            let mut by_table: HashMap<(String, String), Vec<&DamagedSegment>> = HashMap::new();
            for seg in damaged.iter().take(to_repair_count) {
                let (database, table) = match seg {
                    DamagedSegment::Missing(m) => (m.database.clone(), m.table.clone()),
                    DamagedSegment::Corrupted(c) => (c.database.clone(), c.table.clone()),
                };
                by_table.entry((database, table)).or_default().push(seg);
            }

            // Repair each table's segments with WAL recovery attempt
            let mut total_recovered = 0usize;
            let mut total_removed = 0usize;
            for ((database, table), _segments) in by_table {
                match state_clone.db.repair_segments_with_recovery(Some(&database), Some(&table)) {
                    Ok((recovered, removed)) => {
                        if !recovered.is_empty() {
                            tracing::info!(
                                "auto-repair: recovered {} segments from WAL for {}.{}",
                                recovered.len(),
                                database,
                                table
                            );
                            total_recovered += recovered.len();
                        }

                        if !removed.is_empty() {
                            tracing::info!(
                                "auto-repair: removed {} unrecoverable segments from {}.{}",
                                removed.len(),
                                database,
                                table
                            );

                            // Log to file if configured
                            if let Some(ref path) = state_clone.config.repair_log_path {
                                log_repair_to_file(path, &database, &table, &removed);
                            }

                            total_removed += removed.len();
                        }
                    }
                    Err(e) => {
                        tracing::warn!(
                            "auto-repair failed for {}.{}: {}",
                            database,
                            table,
                            e
                        );
                    }
                }
            }

            // Update total repaired count (recovered + removed = repaired)
            state_clone
                .total_repaired
                .fetch_add((total_recovered + total_removed) as u64, Ordering::Relaxed);

            // Run background scrubbing if enabled
            if state_clone.db.cfg.scrubbing_enabled {
                match state_clone.db.scrub_segments(state_clone.db.cfg.scrubbing_batch_size) {
                    Ok(corrupted) => {
                        if !corrupted.is_empty() {
                            tracing::warn!(
                                "Scrubbing detected {} corrupted segments, will repair on next scan",
                                corrupted.len()
                            );
                        }
                    }
                    Err(e) => {
                        tracing::warn!("Scrubbing failed: {}", e);
                    }
                }
            }

            // Clean up orphaned files if enabled
            if state_clone.db.cfg.orphan_cleanup_enabled {
                match state_clone.db.cleanup_orphaned_files() {
                    Ok(cleaned) => {
                        if !cleaned.is_empty() {
                            tracing::info!(
                                "Cleaned up {} orphaned segment files",
                                cleaned.len()
                            );
                        }
                    }
                    Err(e) => {
                        tracing::warn!("Orphan cleanup failed: {}", e);
                    }
                }
            }
        }
    });

    state
}

/// Log repair operations to a CSV file
fn log_repair_to_file(path: &Path, database: &str, table: &str, removed: &[String]) {
    use std::io::Write;

    let file_result = OpenOptions::new().create(true).append(true).open(path);

    match file_result {
        Ok(mut file) => {
            let timestamp = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .map(|d| d.as_secs())
                .unwrap_or(0);

            for seg_id in removed {
                if let Err(e) = writeln!(file, "{},{},{},{}", timestamp, database, table, seg_id) {
                    tracing::warn!("failed to write repair log: {}", e);
                    break;
                }
            }
        }
        Err(e) => {
            tracing::warn!("failed to open repair log file {:?}: {}", path, e);
        }
    }
}

/// Parse a MERGE ON condition to extract target and source column names.
/// Supports simple "target.col = source.col" or "col = col" patterns.
fn parse_merge_condition(condition: &str) -> Result<(String, String), EngineError> {
    let condition = condition.trim();
    // Remove outer parentheses if present
    let condition = condition.trim_start_matches('(').trim_end_matches(')').trim();

    // Look for = sign
    let parts: Vec<&str> = condition.split('=').collect();
    if parts.len() != 2 {
        return Err(EngineError::InvalidArgument(format!(
            "MERGE ON condition must be a simple equality: {}",
            condition
        )));
    }

    let left = parts[0].trim();
    let right = parts[1].trim();

    // Extract column names (handle table.column format)
    let target_col = if left.contains('.') {
        left.split('.').last().unwrap_or(left).to_string()
    } else {
        left.to_string()
    };

    let source_col = if right.contains('.') {
        right.split('.').last().unwrap_or(right).to_string()
    } else {
        right.to_string()
    };

    Ok((target_col, source_col))
}

/// Convert an array value at a specific index to a string for comparison.
fn merge_array_value_to_string(arr: &dyn arrow_array::Array, idx: usize) -> Option<String> {
    use arrow_array::Array;

    if arr.is_null(idx) {
        return None;
    }

    if let Some(a) = arr.as_any().downcast_ref::<StringArray>() {
        return Some(a.value(idx).to_string());
    }
    if let Some(a) = arr.as_any().downcast_ref::<Int64Array>() {
        return Some(a.value(idx).to_string());
    }
    if let Some(a) = arr.as_any().downcast_ref::<UInt64Array>() {
        return Some(a.value(idx).to_string());
    }
    if let Some(a) = arr.as_any().downcast_ref::<Int32Array>() {
        return Some(a.value(idx).to_string());
    }
    if let Some(a) = arr.as_any().downcast_ref::<Float64Array>() {
        return Some(a.value(idx).to_string());
    }

    None
}

